-- Poems batch 185
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d526a95c-1f0f-4b91-8b54-76dfbe311ac6','古斷腸曲三十首  其一四','周端臣','宋','宋诗','song-poetry','','[]','錦屏殘睡思忡忡，心緒無聊酒易中。',32,'全唐诗/poet.song.179000.json','["錦屏殘睡思忡忡，心緒無聊酒易中。", "柳院蘚廳慵不到，斑鳩啼煖落花風。"]'),
('156b237e-77d0-4f79-8588-aeed030d6e36','古斷腸曲三十首  其一五','周端臣','宋','宋诗','song-poetry','','[]','風色翻成料峭晴，閒期女伴踏青行。',32,'全唐诗/poet.song.179000.json','["風色翻成料峭晴，閒期女伴踏青行。", "怪來昨夜燈花好，却是今朝鬭草贏。"]'),
('7750b907-5c19-409b-9fbe-7313393a06dc','古斷腸曲三十首  其一六','周端臣','宋','宋诗','song-poetry','','[]','花庭梨雪疊香痕，燕子歸來亦斷魂。',32,'全唐诗/poet.song.179000.json','["花庭梨雪疊香痕，燕子歸來亦斷魂。", "懊惱一場春不管，月明空自立黄昏。"]'),
('ca350042-7441-46e4-9496-74fe0d0eaa6f','古斷腸曲三十首  其一七','周端臣','宋','宋诗','song-poetry','','[]','裛裛羅巾淚粉光，綠琴哀怨調凄凉。',32,'全唐诗/poet.song.179000.json','["裛裛羅巾淚粉光，綠琴哀怨調凄凉。", "芳容自覺隨風老，落盡桃花暗斷腸。"]'),
('9a9782fa-0013-4145-8071-789f887c8621','古斷腸曲三十首  其一八','周端臣','宋','宋诗','song-poetry','','[]','窗下親裁白苧衣，日長花影上階遲。',32,'全唐诗/poet.song.179000.json','["窗下親裁白苧衣，日長花影上階遲。", "不堪杜宇啼春苦，又是去年腸斷時。"]'),
('48bce4d4-d846-449d-ac17-5ad3e0408429','古斷腸曲三十首  其一九','周端臣','宋','宋诗','song-poetry','','[]','金風幾日老庭莎，經下窗櫺換碧紗。',32,'全唐诗/poet.song.179000.json','["金風幾日老庭莎，經下窗櫺換碧紗。", "天氣已凉人尚遠，晚粧羞戴麗秋花。"]'),
('bd9f2844-3a8c-4eac-b106-c4c0772b374e','古斷腸曲三十首  其二○','周端臣','宋','宋诗','song-poetry','','[]','玉纖無力怯梳頭，鏡裏容顔見自羞。',32,'全唐诗/poet.song.179000.json','["玉纖無力怯梳頭，鏡裏容顔見自羞。", "一陣落紅簾外雨，十分春是十分愁。"]'),
('959d2236-d73f-4855-a3af-0cdc7fcf61b0','古斷腸曲三十首  其二一','周端臣','宋','宋诗','song-poetry','','[]','舊家院落舊秋風，只有當時人不同。',32,'全唐诗/poet.song.179000.json','["舊家院落舊秋風，只有當時人不同。", "惆悵一窗無用月，爲誰凉夜曬梧桐。"]'),
('3fbb15f9-688d-4d4b-9158-a67452111096','古斷腸曲三十首  其二二','周端臣','宋','宋诗','song-poetry','','[]','脩竹生煙晚逗陰，翠羅香袖怯寒侵。',32,'全唐诗/poet.song.179000.json','["脩竹生煙晚逗陰，翠羅香袖怯寒侵。", "恨同社燕身爲客，怕剝秋蓮苦在心。"]'),
('fd9d819b-7658-4dd2-983d-7e8532094a7a','古斷腸曲三十首  其二三','周端臣','宋','宋诗','song-poetry','','[]','壓髻慵簪雙鳳釵，傷心羞覷合歡鞋。',32,'全唐诗/poet.song.179000.json','["壓髻慵簪雙鳳釵，傷心羞覷合歡鞋。", "折花暗卜郎音信，旋繫羅裙走下階。"]'),
('541ad620-64ed-4001-b8cd-dcd0f6cd1450','古斷腸曲三十首  其二四','周端臣','宋','宋诗','song-poetry','','[]','雙蛾顰翠恨天涯，睡起蜂黄沁臉霞。',32,'全唐诗/poet.song.179000.json','["雙蛾顰翠恨天涯，睡起蜂黄沁臉霞。", "燕子日長深院靜，東風無力到楊花。"]'),
('1986e5c9-a88d-4b9b-8f35-866d32fd636d','古斷腸曲三十首  其二五','周端臣','宋','宋诗','song-poetry','','[]','春嬌殘醉睡初回，索酒扶頭强起來。',32,'全唐诗/poet.song.179000.json','["春嬌殘醉睡初回，索酒扶頭强起來。", "金斗壓灰熏篤耨，玉缾𣂏水養徘徊。"]'),
('c5ce8e33-3699-4d41-a5d8-436fb93d6e18','古斷腸曲三十首  其二六','周端臣','宋','宋诗','song-poetry','','[]','蜂蝶飛飛春事忙，煖風池館百花香。',32,'全唐诗/poet.song.179000.json','["蜂蝶飛飛春事忙，煖風池館百花香。", "連花折得青梅子，怕觸心酸不敢嘗。"]'),
('66abe309-b54e-4fff-aa8b-45a8a28e112f','古斷腸曲三十首  其二七','周端臣','宋','宋诗','song-poetry','','[]','楝花篩雪糝蒼苔，人未歸來燕已來。',32,'全唐诗/poet.song.179000.json','["楝花篩雪糝蒼苔，人未歸來燕已來。", "滿眼春驚連日老，兩眉愁是幾時開。"]'),
('22a1b561-159f-4c75-a084-d1b018a77028','古斷腸曲三十首  其二八','周端臣','宋','宋诗','song-poetry','','[]','依舊斜陽燕子樓，共誰把酒話閒愁。',32,'全唐诗/poet.song.179000.json','["依舊斜陽燕子樓，共誰把酒話閒愁。", "韋娘去後西風老，爛漫黄花滿院秋。"]'),
('037cdb9b-14ff-46ee-96fa-24ba2c9c936e','古斷腸曲三十首  其二九','周端臣','宋','宋诗','song-poetry','','[]','彈罷瑶箏歇雁行，月移花影上回廊。',32,'全唐诗/poet.song.179000.json','["彈罷瑶箏歇雁行，月移花影上回廊。", "離情不奈秋蕭索，更著寒螿管夜長。"]'),
('4edf8c3a-01d5-4fdd-b502-d36663f32971','古斷腸曲三十首  其三○','周端臣','宋','宋诗','song-poetry','','[]','小雨班班濕畫欄，一番重做杏花寒。',32,'全唐诗/poet.song.179000.json','["小雨班班濕畫欄，一番重做杏花寒。", "春衫拈起還慵著，却憶天涯客袂單。"]'),
('79f6ca1b-21a0-48ac-bbe6-1de8e0b809fa','湖山園','周端臣','宋','宋诗','song-poetry','','[]','丹樓碧閣面山開，綠樹紅芳遶水栽。',32,'全唐诗/poet.song.179000.json','["丹樓碧閣面山開，綠樹紅芳遶水栽。", "多少好春閒過却，主人無暇不曾來。"]'),
('84a5ce42-5c24-4dbd-b71e-83eb17190210','落葉','周端臣','宋','宋诗','song-poetry','','[]','西風不管鵲巢寒，成陣飄來響更乾。',32,'全唐诗/poet.song.179000.json','["西風不管鵲巢寒，成陣飄來響更乾。", "最是山房秋思客，夢回疑作雨聲看。"]'),
('879661c7-c2bd-4771-ad18-6296fcb72cc1','清明湖上','周端臣','宋','宋诗','song-poetry','','[]','誰家園裏一聲鶑，啼向春風似有情。',32,'全唐诗/poet.song.179000.json','["誰家園裏一聲鶑，啼向春風似有情。", "驚起少年遊冶興，插花沽酒醉清明。"]'),
('b8f812b4-6412-42fd-ab7f-b5ccd8521c02','古墳詩','周端臣','宋','宋诗','song-poetry','','[]','短牆摧倒樹欹斜，碧薺春開滿地花。',32,'全唐诗/poet.song.179000.json','["短牆摧倒樹欹斜，碧薺春開滿地花。", "馬鬣就荒無認處，墓前碑在野人家。"]'),
('da98e985-574a-45a2-9973-116a80bf3daf','題真妃出浴圖','周端臣','宋','宋诗','song-poetry','','[]','百媚千嬌出浴時，君王凝盼轉魂迷。',32,'全唐诗/poet.song.179000.json','["百媚千嬌出浴時，君王凝盼轉魂迷。", "香肌猶恐紅綃重，可忍他年踐馬蹄。"]'),
('ff98075e-4abf-48a3-8ed8-3f485be1ee3b','秋曉','周端臣','宋','宋诗','song-poetry','','[]','一抹凉烟曉未收，露籬踈雨濕牽牛。',32,'全唐诗/poet.song.179000.json','["一抹凉烟曉未收，露籬踈雨濕牽牛。", "不知天上秋多少，昨夜西風到小樓。"]'),
('3ad4cbe9-2f61-4c3a-bafa-c88aacdb06f0','湖上歸','周端臣','宋','宋诗','song-poetry','','[]','別却吳姬舊酒壚，扁舟吹笛過平湖。',32,'全唐诗/poet.song.179000.json','["別却吳姬舊酒壚，扁舟吹笛過平湖。", "晚雲又是商量雨，遮得秋山一半無。"]'),
('17977105-7ac5-4592-8191-247e165dbbd8','簡雪窗董寺丞  其一','周端臣','宋','宋诗','song-poetry','','[]','世路機心走兔迒，雪窗一縷不遮藏。',32,'全唐诗/poet.song.179000.json','["世路機心走兔迒，雪窗一縷不遮藏。", "籋雲梯月真游戯，茅舍何曾外玉堂。"]'),
('dc0f4cfe-b55f-4f92-aa5e-e9b21a20b0e7','簡雪窗董寺丞  其二','周端臣','宋','宋诗','song-poetry','','[]','聖賢事業在心槃，禹稷顔回豈異觀。',32,'全唐诗/poet.song.179000.json','["聖賢事業在心槃，禹稷顔回豈異觀。", "世故波瀾同起滅，姓名千古要清寒。"]'),
('ae72965b-978f-4670-9a97-0b9592f2b6dd','鄰園晚步','周端臣','宋','宋诗','song-poetry','','[]','忽然楊柳幾絲風，零落桃花數片紅。',32,'全唐诗/poet.song.179000.json','["忽然楊柳幾絲風，零落桃花數片紅。", "滿面好春吟不得，一園蝴蝶過牆東。"]'),
('7e9510fd-b4bc-48d8-b5a9-cf389980e431','寒食湖隄','周端臣','宋','宋诗','song-poetry','','[]','紫陌笙歌簇禁烟，幾年無此好晴天。',32,'全唐诗/poet.song.179000.json','["紫陌笙歌簇禁烟，幾年無此好晴天。", "畫橋日晚遊人醉，花插滿頭扶上船。"]'),
('c6927de0-005c-4c59-83e3-da04efa38637','春月送人','周端臣','宋','宋诗','song-poetry','','[]','一湖春綠染初成，柳色東風二月晴。',32,'全唐诗/poet.song.179000.json','["一湖春綠染初成，柳色東風二月晴。", "燕子來時人却別，梨花雖好負清明。"]'),
('ac2e68cb-5685-443e-a0df-68f82cb57a52','元夕','周端臣','宋','宋诗','song-poetry','','[]','小院春寒月到遲，閉門閒課上元詩。',32,'全唐诗/poet.song.179000.json','["小院春寒月到遲，閉門閒課上元詩。", "南來父老消磨盡，耳畔無人說舊時。"]'),
('573d2c40-7dd2-42df-a168-c6d9406b9332','謝人惠天花','周端臣','宋','宋诗','song-poetry','','[]','花從天上落人間，北客來稀路阻難。',32,'全唐诗/poet.song.179000.json','["花從天上落人間，北客來稀路阻難。", "勝味忽驚藜莧腹，春風腸斷五臺山。"]'),
('e1283bef-79a2-40f2-8133-8c9e61c51d91','內人燒香圖','周端臣','宋','宋诗','song-poetry','','[]','花底燒香深閉門，宮鴉棲了已黄昏。',32,'全唐诗/poet.song.179000.json','["花底燒香深閉門，宮鴉棲了已黄昏。", "君王未識無人妒，雖不承恩却感恩。"]'),
('4c4ab4f4-59c9-4a54-ab77-3997044132d2','買木犀花','周端臣','宋','宋诗','song-poetry','','[]','拚却杖頭沽酒物，湖邊博得木犀花。',32,'全唐诗/poet.song.179000.json','["拚却杖頭沽酒物，湖邊博得木犀花。", "西風可是無拘束，一路吹香直到家。"]'),
('8b9437f1-ba85-4634-bab5-93f3071e2209','題葉靖逸東庵','周端臣','宋','宋诗','song-poetry','','[]','一庵自隠古城邊，不是山林不市廛。',32,'全唐诗/poet.song.179000.json','["一庵自隠古城邊，不是山林不市廛。", "落月半窗霜滿屋，卧聽宰相去朝天。"]'),
('641f1e0f-251f-4e12-ae2b-88e63acbd884','二月五日西郊口占','周端臣','宋','宋诗','song-poetry','','[]','晴日西郊按物華，東風寒峭帽簷斜。',32,'全唐诗/poet.song.179000.json','["晴日西郊按物華，東風寒峭帽簷斜。", "江梅已辦調羹事，交割春光與杏花。"]'),
('6c91a9db-8685-4d98-b939-49e720738067','秋晚孤山','周端臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山夾寒雲晚不收，蘋花洲渚雁聲秋。',32,'全唐诗/poet.song.179000.json','["山夾寒雲晚不收，蘋花洲渚雁聲秋。", "西湖處士無消息，落日丹楓處處愁。"]'),
('79160c65-ae28-41e2-8e33-4eca81917179','夜歸','周端臣','宋','宋诗','song-poetry','','[]','側側梅寒戀客衣，市樓燈比舊年稀。',32,'全唐诗/poet.song.179000.json','["側側梅寒戀客衣，市樓燈比舊年稀。", "酒徒歌伴凋零盡，獨自吟詩月下歸。"]'),
('0a15c5cb-fbe6-44c4-88a2-916b675a2bc8','朱門','周端臣','宋','宋诗','song-poetry','','[]','朱門茅屋偶爲隣，北阮那憐南阮貧。',32,'全唐诗/poet.song.179000.json','["朱門茅屋偶爲隣，北阮那憐南阮貧。", "却是梅花無世態，隔牆分送一枝春。"]'),
('7c6706e0-37b2-48ad-becb-1045ea3784e5','早冬湖上','周端臣','宋','宋诗','song-poetry','','[]','晴湖水落葑田乾，白鳥飛來立晚寒。',32,'全唐诗/poet.song.179000.json','["晴湖水落葑田乾，白鳥飛來立晚寒。", "楊柳不知秋已遠，尚摇疎翠拂欄干。"]'),
('af61f2f3-5a92-4604-a2b2-df634eb73ee1','遣興寄徐抱獨','周端臣','宋','宋诗','song-poetry','','[]','樓外垂楊啼曉鴉，樓中倦客醉思家。',32,'全唐诗/poet.song.179000.json','["樓外垂楊啼曉鴉，樓中倦客醉思家。", "東風不管春將半，一夜清寒勒杏花。"]'),
('2c7a3e25-d3d4-4012-898b-c99d379bb00a','挽芸居二首  其一','周端臣','宋','宋诗','song-poetry','','[]','天地英靈在，江湖名姓香。',48,'全唐诗/poet.song.179000.json','["天地英靈在，江湖名姓香。", "良田書滿屋，樂事酒盈觴。", "字畫堪追晉，詩刊欲徧唐。", "音容今已矣，老我倍凄凉。"]'),
('f73a81de-5875-4a07-b256-68721212fa91','挽芸居二首  其二','周端臣','宋','宋诗','song-poetry','','[]','詩思閒逾健，儀容老更清。',48,'全唐诗/poet.song.179000.json','["詩思閒逾健，儀容老更清。", "遽聞身染患，不見子成名。", "易簀終婚娶，求棺達死生。", "典刑無復覩，空有淚如傾。"]'),
('5636dd37-02d3-4158-a8ee-8ddc6d74052e','觀潮行','周端臣','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u94b1\u5858\u6c5f"]','吳山越山相對青，中有滾滾長江橫。',96,'全唐诗/poet.song.179000.json','["吳山越山相對青，中有滾滾長江橫。", "長江誰道不曾改，年來一半沙填平。", "潮生潮落何時了，萬古人間一昏曉。", "歲歲吳儂來看潮，不知潮送吳儂老。", "酒樓笙歌喧醉耳，客帆翻覆雲濤裏。", "悠悠哀樂永相忘，空江落日秋風起。"]'),
('12baf6bf-846c-45be-a352-f1105658df22','偶成','周端臣','宋','宋诗','song-poetry','','[]','一灑斑斑小雨晴，杖藜隨意散幽情。',32,'全唐诗/poet.song.179000.json','["一灑斑斑小雨晴，杖藜隨意散幽情。", "不論城市山林地，纔有梅花處便清。"]'),
('9aebb5a2-1d72-4795-8dc4-5bad733ba86f','宿劉仲悅山齋','周端臣','宋','宋诗','song-poetry','','[]','欹枕蕭齋酒易醒，夜來愁殺庾蘭成。',64,'全唐诗/poet.song.179000.json','["欹枕蕭齋酒易醒，夜來愁殺庾蘭成。", "一窗明月人無寐，滿地落花春薄情。", "隔屋有山雲氣冷，傍簷多竹鳥聲清。", "如君得此閑居趣，未羨人間利祿榮。"]'),
('31e79fd0-b99e-4320-8cca-f8e684abc963','村路','周端臣','宋','宋诗','song-poetry','','[]','雨餘村落迥，祇有鵲營巢。',48,'全唐诗/poet.song.179000.json','["雨餘村落迥，祇有鵲營巢。", "一逕曉煙合，千林春翠交。", "斷橋斜搭板，破屋倒鋪茅。", "聞說蠶初浴，柴門不敢敲。"]'),
