('e094e760-814e-4a69-8110-727c5d01efa7','存目  其一九','周端臣','宋','宋诗','song-poetry','','[]','詩題：謝劉大著寄惠玉牋首句：皎潔分明如我鬢。',22,'全唐诗/poet.song.179000.json','["詩題：謝劉大著寄惠玉牋首句：皎潔分明如我鬢。"]'),
('3fab34bf-9058-4443-b90f-5e61d760cfda','臨終偈','楊權','宋','宋诗','song-poetry','','[]','七十九年夢覺，五湖四海隨緣。',28,'全唐诗/poet.song.179000.json','["七十九年夢覺，五湖四海隨緣。", "撥轉雲頭歸去，曉日東升赤然。"]'),
('1c4fbfd6-b8b6-4b1a-bb72-f55539cce857','涵碧亭  其一','許復道','宋','宋诗','song-poetry','','[]','飛泉當面玉虹垂，收拾驚濤貯小池。',64,'全唐诗/poet.song.179000.json','["飛泉當面玉虹垂，收拾驚濤貯小池。", "□□倚岩山骨秀，激湍成雨澗毛滋。", "壁閒遺墨淒塵□，眼底新篇□色絲。", "却憶謝公山更好，夢中時不負心期。"]'),
('bfa7a6eb-8bff-4655-8dfc-d5a6d1bb6bb6','涵碧亭  其二','許復道','宋','宋诗','song-poetry','','[]','繞竹沿崖一徑垂，穿山飛玉落芳池。',64,'全唐诗/poet.song.179000.json','["繞竹沿崖一徑垂，穿山飛玉落芳池。", "林深坐覺塵埃遠，岩潤長含雨露滋。", "雙鯉對浮波面石，一綸難擲掌中絲。", "月明歸路烟霞外，更與山公再訂期。"]'),
('0f16b3e8-793b-4c06-abde-e7826d813e0e','涵碧亭  其三','許復道','宋','宋诗','song-poetry','','[]','沿途聽潺湲，蒙茸冒沙石。',168,'全唐诗/poet.song.179000.json','["沿途聽潺湲，蒙茸冒沙石。", "誰知此山下，千里在咫尺。", "潭潭光明宮，皎皎心印宅。", "石細泉自香，水凈林逾碧。", "太清無潛鱗，至弱而能力。", "玉龍出蒼峽，威勇壯莫敵。", "風雨填空來，萬夫助推激。", "座中起波濤，足下殷霹靂。", "我來縱雄觀，神意了莫逆。", "心鏡浄表裏，坐久萬籟息。", "悠然到平淡，渙若春冰釋。", "棲遲羅書記，想像劉賓客。", "勝緣在山閒，每至忽有得。", "何以謝山靈，作詩慰岑寂。"]'),
('5bca3c09-76ee-4292-b255-e29a337c2e90','趙金氏墓','許復道','宋','宋诗','song-poetry','','[]','埋骨青山足古今，北邙深鎖暮雲平。',32,'全唐诗/poet.song.179000.json','["埋骨青山足古今，北邙深鎖暮雲平。", "夜台長寄千秋烈，子燕何須吊王京。"]'),
('e41f312e-e5cb-43c9-b8a0-acb0b121efb8','靜樂軒喜成','張諤','宋','宋诗','song-poetry','','[]','山縣爲官不見山，一朝列嶂忽當關。',64,'全唐诗/poet.song.179000.json','["山縣爲官不見山，一朝列嶂忽當關。", "抽身牒訴時舒眼，領客杖藜聊解顔。", "常樂本來由我靜，倦飛每爾愧知還。", "莫嫌邑小仍兼陋，曾有涪翁賞是間。"]'),
('5c311c92-198b-42e0-b347-aca6187edd62','題貢院','趙善晤','宋','宋诗','song-poetry','','[]','天約閑雲結嫩陰，苦無詩酒懶登臨。',32,'全唐诗/poet.song.179000.json','["天約閑雲結嫩陰，苦無詩酒懶登臨。", "一聲雞唱日初午，滿地花寒秋已深。"]'),
('f12d46e7-6546-4716-9b24-cc34071dc757','白龍寺','徐綱','宋','宋诗','song-poetry','','[]','萬木梢頭見塔尖，道人於此卜幽潜。',64,'全唐诗/poet.song.179000.json','["萬木梢頭見塔尖，道人於此卜幽潜。", "深林六月風敲竹，古寺三更月入龕。", "天旱蛟龍藏窟宅，水枯魚鱉露鬚髯。", "我來赤日祈甘雨，卧聽蕭蕭瀉屋簷。"]'),
('9c2feb8d-5779-48b2-ad76-310413687df1','望吳亭次黄二尹韻','錢宏','宋','宋诗','song-poetry','','[]','東望長安山復山，數峯還出兩峯間。',64,'全唐诗/poet.song.179000.json','["東望長安山復山，數峯還出兩峯間。", "攬衣來即三年戍，引客聊爲一日閑。", "身似暮雲低更好，心如歸鳥倦知還。", "聖朝倘得收遺物，歎息搔頭鬢已斑。"]'),
('e4b8e212-0ad6-494d-bdf7-6e6715bd23c3','白石巖','錢宏','宋','宋诗','song-poetry','','[]','巖下碧藤掛紫烟，巖頭白石插青天。',32,'全唐诗/poet.song.179000.json','["巖下碧藤掛紫烟，巖頭白石插青天。", "精靈屹作鄉邦鎮，一劍霜寒二百年。"]'),
('a58c2445-3d92-4870-b1ed-92ebf2ac406d','清心堂爲余宰題','程應申','宋','宋诗','song-poetry','','[]','靈臺元自與天通，一點塵飛失太空。',64,'全唐诗/poet.song.179000.json','["靈臺元自與天通，一點塵飛失太空。", "六鑿爾時俱偃息，八窗何處不玲瓏。", "公田有秫猶難色，暮夜無金即直躬。", "要識此中清入妙，也忘堂上古絲桐。"]'),
('6e1b944d-795e-4555-9b59-988b20bfaabf','次韻李使君追悼雪巢先生','錢文子','宋','宋诗','song-poetry','','[]','文龍竟復老污池，一笑應從造化期。',64,'全唐诗/poet.song.179000.json','["文龍竟復老污池，一笑應從造化期。", "環顧室廬無長物，流傳人世有新詩。", "殷勤池上相從處，悽愴床前永訣時。", "更有後來賢太守，遡風猶解挹清規。"]'),
('3b840b8b-5261-43ce-ba60-fcce53e4db6f','窊尊絕句','錢文子','宋','宋诗','song-poetry','','[]','招邀風月須坡叟，管領江山屬漫郎。',32,'全唐诗/poet.song.179000.json','["招邀風月須坡叟，管領江山屬漫郎。", "更築危亭依巨石，願從二子老滄浪。"]'),
('ba714389-497f-46bb-930f-c43cfe28d48d','狀元去春用楊吉州子直韵賦玉蕊詩老誖久稽奉酬今承秩滿還朝就以爲餞','錢文子','宋','宋诗','song-poetry','','[]','晝攬羣芳博物華，夕披衆說聚螢車。',64,'全唐诗/poet.song.179000.json','["晝攬羣芳博物華，夕披衆說聚螢車。", "花來北固無新唱，詩到西崑有故家。", "鄉里孝廉流澤遠，弟兄科甲搢紳夸。", "盍歸史觀開群玉，徐步詞垣判五花。"]'),
('8d967738-6c84-43dc-a845-47a7ee0ccdec','詠苔梅','張沄','宋','宋诗','song-poetry','','[]','老龍全身著艾蒳，不耐久蟄潛拏空。',32,'全唐诗/poet.song.179000.json','["老龍全身著艾蒳，不耐久蟄潛拏空。", "爪頭撥動陽春信，香在霜痕雪點中。"]'),
('ee569bd7-a85c-46bd-857b-01e8fb04e94e','題黄碧酒肆','張沄','宋','宋诗','song-poetry','','[]','東風吹雨水平沙，下却籃輿訪酒家。',32,'全唐诗/poet.song.179000.json','["東風吹雨水平沙，下却籃輿訪酒家。", "行役不知春早暮，牆頭紅杏欲飛花。"]'),
('bfa4a64d-f7fa-4c3c-b550-f7d5d151d597','淵靚亭','黄伯固','宋','宋诗','song-poetry','','[]','江山無古今，闡發自我輩。',240,'全唐诗/poet.song.179000.json','["江山無古今，闡發自我輩。", "心期得地勝，有目皆一快。", "負郭西繚川，衆流翕以匯。", "水光開三面，結屋此其最。", "囂塵劃清漪，景象極爽塏。", "泓澄湛寒碧，潭影尤可愛。", "巖前列烟樹，翠色聯不解。", "盤坳石下瞰，林立錯奇怪。", "雄觀喜新獲，曠境了無碍。", "人謀孰使然，天作若有待。", "學宮爾多士，游息於此在。", "豈但濯爾纓，亦可湔爾佩。", "翛然魚在藻，行矣鯤化海。", "維茲淵靚名，妙處默領會。", "中庸至矣夫，智者樂在內。", "水德本無虛，人心亦清灑。", "即物以察己，致之不在大。", "清源堪疏瀹，世慮滌昏昧。", "曾子浴乎沂，不出一唯外。", "淡乎賈傅心，或可分一派。"]'),
('f19bc407-1b2a-482a-96a2-a68ac7929757','雙清閣詠雪','黄伯固','宋','宋诗','song-poetry','','[]','箕伯宵聲怒，髽童早語咍。',192,'全唐诗/poet.song.179000.json','["箕伯宵聲怒，髽童早語咍。", "飛花先臘白，和氣覺春回。", "暗動雲都簇，先憑雨作媒。", "有情皆噤慘，無物不低摧。", "闊灑吞平野，斜飛透隙埃。", "朦朧山下路，孤絕水邊桅。", "厚載危傾壓，陰機巧剪裁。", "溪流連底瀝，蒙嶺徹尖堆。", "妬舞時飄袖，催詩賸遣材。", "高將凌玉闕，清可並瑶臺。", "密密疑霏屑，紛紛認落梅。", "諏龜占䆉䅉，宿鷺歛毰毸。", "凍案呵吟筆，高樓殢酒盃。", "市衢停轍迹，香篆冷爐灰。", "試問麻衣詠，何如柳絮才。", "一時聊紀事，著句郢難陪。"]'),
('dcd91c25-dee7-4270-85ae-e2231971bd1d','公餘漫興','黄伯固','宋','宋诗','song-poetry','','[]','蓼花秋水漫官衙，令尹情懷自一家。',32,'全唐诗/poet.song.179000.json','["蓼花秋水漫官衙，令尹情懷自一家。", "退食小齋無俗事，閒呼童子問桑麻。"]'),
('26ea9452-6761-4b9d-96c5-241de26a830e','留題石堂院','章師古','宋','宋诗','song-poetry','','[]','何處足清凉，山南古石堂。',48,'全唐诗/poet.song.179000.json','["何處足清凉，山南古石堂。", "溪沙留虎跡，水影上僧房。", "萬景因深僻，無人爲發揚。", "侵苔寫澀句，筆凍不成行。"]'),
('79022bc9-e658-419f-a93b-d07695858738','釣魚磯','倪德元','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',272,'全唐诗/poet.song.179000.json','["□□□□□□□，□□□□□□□。", "以文會友真足樂，寬我老懷百歲憂。", "盍簪况乃□□席，□□□□注黄流。", "□□□□擊鼉鼓，滿酌玉斝羅珍羞。", "溪迴斷岸顛崖出，千仞插天如立壁。", "信知神禹疏鑿功，懸溜黯然長湛碧。", "波光照影肝胆寒，嵐氣逼人毛髮立。", "第恐喧呼鳥雀驚，□□□行隨湍急。", "□□□□□桃花，徘徊一望朝霞赤。", "疑有秦人住洞天，□來艤舟携酒入。", "花洞□□□落紅，□鋪萬里□□□。", "家童採山□殽䔩，稚子屬文資戲劇。", "須臾嶺頭新月上，歸棹將詩冩岩石。", "春光都來無百日，憂愁風雨十居七。", "古今會合不易得，邂逅□今□成昔。", "郭君退翁世□賢，我欲從之終吾年。", "年年與君來載酒，此樂人間豈常有。"]'),
('dcd3a7a3-1aea-4fa2-ab60-79dd2d63fa88','雨花臺','劉端之','宋','宋诗','song-poetry','','[]','六朝宮苑帝王州，何事興衰若置郵。',64,'全唐诗/poet.song.179000.json','["六朝宮苑帝王州，何事興衰若置郵。", "可是戰爭收拾後，却將歌舞破除休。", "千門盡鎖梧桐雨，萬堞深籠薜荔秋。", "試陟雨花臺上望，夕陽烟水替人愁。"]'),
('888fd8e4-3c29-4beb-be02-d566f83a2358','落花','李檝','宋','宋诗','song-poetry','','[]','拾得紅英不忍殘，殷勤更覓舊枝安。',32,'全唐诗/poet.song.179000.json','["拾得紅英不忍殘，殷勤更覓舊枝安。", "情知不似開時好，猶勝溪頭水面看。"]'),
('5cd1fd6a-5fba-46a4-9eae-84ed021aba78','山家','李檝','宋','宋诗','song-poetry','','[]','日長無客到山家，蘚暈封苔一逕斜。',32,'全唐诗/poet.song.179000.json','["日長無客到山家，蘚暈封苔一逕斜。", "睡美不知中夜雨，起來驚落半岩花。"]'),
('49d80ae3-b51b-4514-9e5c-e768595fb058','晚春曲','李檝','宋','宋诗','song-poetry','','[]','春欲歸何處，流鶑也不知。',24,'全唐诗/poet.song.179000.json','["春欲歸何處，流鶑也不知。", "只應江上水，暗與落花期。"]'),
('6de9c4b6-dca7-448a-ae14-a9b2b4732575','有約','李檝','宋','宋诗','song-poetry','','[]','楊柳垂隄水遶門，可人清景近黄昏。',32,'全唐诗/poet.song.179000.json','["楊柳垂隄水遶門，可人清景近黄昏。", "明朝有約誰先到，手掐花梢記月痕。"]'),
('cdc472b7-1d92-4bfd-88f2-a7f353da3d38','寄無爲居士','釋真浄','宋','宋诗','song-poetry','','[]','世俗事無盡，養高心自閒。',48,'全唐诗/poet.song.179000.json','["世俗事無盡，養高心自閒。", "蔬園通綠野，林塢带青山。", "丹竈忘添火，雲菴懶著關。", "別應修省術，七十見朱顔。"]'),
('6bac34f0-e005-49a8-b439-908306687ffa','送張簽判遊開先','釋真浄','宋','宋诗','song-poetry','','[]','步入青松裏，迢迢一徑通。',48,'全唐诗/poet.song.179000.json','["步入青松裏，迢迢一徑通。", "漸分華藏界，深隠法王宮。", "道與神仙別，人非世俗同。", "欲知西祖意，庭柏老春風。"]'),
('5e473eca-809a-4097-b691-fa9be1c9894a','留題紹公寂照軒','釋真浄','宋','宋诗','song-poetry','','[]','幽軒名寂照，四海坐中閒。',48,'全唐诗/poet.song.179000.json','["幽軒名寂照，四海坐中閒。", "景物有遷色，主人無異顔。", "野泉澄檻外，香藹起簷間。", "涼夜誰相問，寥寥月滿山。"]'),
('d76a0435-2f48-4d90-b8b0-3b75d3a62623','送人之南嶽','釋真浄','宋','宋诗','song-poetry','','["\u8861\u5c71"]','境幽南嶽寺，路向碧巖分。',48,'全唐诗/poet.song.179000.json','["境幽南嶽寺，路向碧巖分。", "遠近松相接，高低鐘共聞。", "靈禽時奏樂，香石日籠雲。", "想到經行處，超然趣不羣。"]'),
('3c1ee821-e361-45f9-8675-f633389e18a5','送張判官歸巴州','王翥','宋','宋诗','song-poetry','','[]','回首三巴曲，平生萬里橋。',24,'全唐诗/poet.song.179000.json','["回首三巴曲，平生萬里橋。", "衣冠無頼客，花月可憐宵。"]'),
('3390d293-efee-4b8a-846b-2421733c0723','浮世','王翥','宋','宋诗','song-poetry','','[]','浮世惟高枕，平生有敝裘。',48,'全唐诗/poet.song.179000.json','["浮世惟高枕，平生有敝裘。", "江花中酒日，巴雨落帆秋。", "老矣英雄事，愚哉盜賊謀。", "啼猿長自在，一笑下滄洲。"]'),
('a99cecb5-24fe-4c63-a7da-7932dfe64d43','灌口秋漲','王翥','宋','宋诗','song-poetry','','[]','所向愁無地，窮源欲上天。',48,'全唐诗/poet.song.179000.json','["所向愁無地，窮源欲上天。", "蛟龍胡爾怒，鷗鷺更誰憐。", "萬里朝宗意，群凶跋扈年。", "生涯秋色裏，獨立問漁船。"]'),
('7769cfe1-4223-48d6-9e31-7e7968a05706','吳宣撫故宅','王翥','宋','宋诗','song-poetry','','[]','社稷疲奔命，乾坤服至誠。',96,'全唐诗/poet.song.179000.json','["社稷疲奔命，乾坤服至誠。", "扶持三蜀在，出入兩朝榮。", "豕犬有遺恨，麒麟空復情。", "家聲隤已盡，國法用猶輕。", "成季翻無後，花卿浪得名。", "門庭黄鳥語，几杖綠苔生。", "威福何偏重，精神恐不平。", "庶幾蒙世立，凡百慎持盈。"]'),
('e0e834e1-a5c6-4187-96df-883067b72a22','憶舍弟','王翥','宋','宋诗','song-poetry','','[]','藥物吾仍病，花時汝未歸。',48,'全唐诗/poet.song.179000.json','["藥物吾仍病，花時汝未歸。", "不眠愁月落，獨立看雲飛。", "詩禮自持律，饑寒誰解圍。", "遥知理舟檝，西望涕沾衣。"]'),
('0dea20e6-ae87-46f3-8711-a34bbf6dd3c2','題會春苑','趙汝譡','宋','宋诗','song-poetry','','[]','草荒故苑幾春風，尚想花開春樹紅。',32,'全唐诗/poet.song.179000.json','["草荒故苑幾春風，尚想花開春樹紅。", "欲問當時馬王事，寂寥殘照野亭中。"]'),
('1a5238b5-e757-47ba-8dc9-bb04b12cfd59','宿枕峰寺懷舅氏有作','趙汝譡','宋','宋诗','song-poetry','','[]','野竹有慈性，叢生不相離。',96,'全唐诗/poet.song.179000.json','["野竹有慈性，叢生不相離。", "永懷寒泉感，昨與渭陽期。", "寺閣共秋晚，山雲獨移時。", "尚想談論閒，丹顴映雪髭。", "氣豪機事少，所嗜平生詩。", "起居今何如，會合渺難知。", "霜清雁蕩骨，春藹天台姿。", "混融入老筆，遠寄江湖思。"]'),
('856ed3f7-c0c8-4582-9037-b581f9a3ec73','爲趙振文賦馬塍歌','趙汝譡','宋','宋诗','song-poetry','','[]','舊聞城北有馬塍，聚花成錦常留春。',144,'全唐诗/poet.song.179000.json','["舊聞城北有馬塍，聚花成錦常留春。", "我家苕水近來到，輸他年少尋芳人。", "相誇此地百金惜，閒出奇花萬錢直。", "接貼翻騰費工巧，揀搆移將鬭顔色。", "園翁愛花如子孫，寸生尺長勤培根。", "南鄰北鄰貧富改，獨守養性經涼溫。", "兄今已得閒居趣，扁舟暫向官塘路。", "攀條摘蘂娛性情，對月看雲想風度。", "歌長詞逸不可當，鬢髮垂白吟滄浪。"]'),
('d1a93fb0-211e-48fc-9a77-d76cfe49ddab','和葉水心馬塍歌','趙汝譡','宋','宋诗','song-poetry','','[]','昔年家住長安里，春風盡日香塵起。',192,'全唐诗/poet.song.179000.json','["昔年家住長安里，春風盡日香塵起。", "紛紛車馬過綺陌，買花人多少人識。", "王侯第宅連苑牆，粲若瓊蘂敷丹房。", "花窠近取馬塍本，曲欄高檻深迷藏。", "主歡對客小舉袖，擊鼓吹簫滿前後。", "真珠一斛聘國姝，琥珀千杯酌天酒。", "幾年農器不鑄兵，雨耕雲穫歌且行。", "種花土腴無水旱，園稅十倍田租平。", "挐音來近菰蒲住，演漾迴溪通枉渚。", "霜晴沙淺橘林明，日暮水渾魚網聚。", "東門故侯應自許，灞陵醉尉寧須怒。", "何當學稼隨老農，荷鋤驅犢田中去。"]'),
('4ffe2911-02a3-4a6f-a715-50ecf34e95e7','和鞏栗齋豐翠蛟亭','趙汝譡','宋','宋诗','song-poetry','','[]','衆峯抱蒼龍，蟠屈翠蛟水。',204,'全唐诗/poet.song.179000.json','["衆峯抱蒼龍，蟠屈翠蛟水。", "放之兩崖閒，奔洶不得止。", "濤瀾生席上，雷雹轉石底。", "恍疑天柱摇，將拔陰洞起。", "蘇公雄氣壓，詩骨得山髓。", "指麾驅鯤鯨，赫奕動箕尾。", "紛紛下土人，蟻垤自封侈。", "驟觀目睛眩，筆墜汗流泚。", "坐令空谷嘯，聲徹霄漢裏。", "君來松根吟，仙者相去咫。", "老蛟破鎖出，餘怒猶未已。", "決開澗千丈，散作霧五里。", "今年溪湖乾，草樹生意靡。", "寸泉落山苗，靈藥起垂死。", "遺吾雲子飯，報汝青玉几。", "野人尋泉竇，筒壞方復理。", "泓然山巔池，冬夏常若此。"]'),
('989eb021-d327-473a-be5f-933d898a728c','冰壺亭','趙汝譡','宋','宋诗','song-poetry','','[]','孰是群動主，天機在靈關。',60,'全唐诗/poet.song.179000.json','["孰是群動主，天機在靈關。", "深居默自照，瑕垢寧得干。", "昭昭素絲義，幕佐實郡端。", "身潔吏所貴，心精士其難。", "請將秋月擬，亦作冰壺觀。"]'),
('f320d73b-f995-477a-92e4-8ea3c3eb53d4','游雷氏園懷吳公德夫','趙汝譡','宋','宋诗','song-poetry','','[]','城丘煥朝景，郊甸熙春陽。',120,'全唐诗/poet.song.179000.json','["城丘煥朝景，郊甸熙春陽。", "誰能不行游，及爾聊徜徉。", "華棟敞中園，珍潭注方塘。", "惠風翼嘉殖，時鳥流音翔。", "豈伊丹卉間，而有修幹蒼。", "靡迤既徐步，縈紆亦深藏。", "憶與仁里親，攀翻玩幽芳。", "撫迹已成故，斯人安可亡。", "前洲起新漲，遠岫收殘光。", "憑檻久悵望，江雲眇何長。"]'),
('4250a05d-a11a-405a-8bc7-860a4dd640c7','贈景建將入都贈別','趙汝譡','宋','宋诗','song-poetry','','[]','子先文章宗，秀種凌孔翠。',180,'全唐诗/poet.song.179000.json','["子先文章宗，秀種凌孔翠。", "觀風多儒郡，籍籍罕與輩。", "客遠紆勞思，交新愜清會。", "說詩延秋色，造極超古對。", "敏識入悞領，玄功謝彫繪。", "頗云幼把筆，濤湧亦川匯。", "中探陰符膸，意躡海蟾背。", "悄然忽坐愁，窮老少所遂。", "雄都始旋軫，上國專結佩。", "八紘張雲羅，局士繩墨內。", "名場沾童膚，奇質委蒿艾。", "卿侯雅如賞，榮爵寧爾愛。", "早拜王命歸，聲明耀群昧。", "吾衰愧尸職，箋劾力自退。", "奮身登金臺，農野甘秉耒。"]'),
('ab614533-4754-491c-96e7-f36cb4d6c74d','謝葉水心作先銘','趙汝譡','宋','宋诗','song-poetry','','[]','隙駒日月馳，拱木霜露莘。',240,'全唐诗/poet.song.179000.json','["隙駒日月馳，拱木霜露莘。", "孤生望蒼旻，永念負慈地。", "內德不越閫，先銘欲存世。", "以茲瀝丹素，延首冀嘉惠。", "大匠斡九京，篇成重覃思。", "發函已百拜，陳廟復三喟。", "石之表故阡，脩麓出光氣。", "耿如瞻其親，端用貽爾類。", "道歸統會闊，躬探玄頤祕。", "雲章開人文，天筆垂古製。", "照照訓典立，亹亹倫紀備。", "遂登秦漢前，上與騷雅儷。", "碑板落東南，貝玉失瓌異。", "膏濡淪朽骨，黼藻被幽隧。", "史職補王明，陋巷壓高位。", "餘波揚懿則，懼忝弗克嗣。", "士恢宇宙心，學竟聖賢事。", "整駕期遠造，爲基戒中墜。", "嶽峻尚可攀，海深安可計。", "勗哉奉格言，沒齒無敢替。"]'),
('360cd81a-f433-4ea6-96f3-b1a582e4f662','遺虎皮謝','趙汝譡','宋','宋诗','song-poetry','','[]','龍巖縣令亦好奇，臘月贈我生虎皮。',96,'全唐诗/poet.song.179000.json','["龍巖縣令亦好奇，臘月贈我生虎皮。", "霜牙電睛已寂寞，鵲形剪斑猶陸離。", "最珍肩脊不受箭，鬚爪皆具無缺虧。", "革工入手硝使熟，軟可寢藉忘其威。", "想當枯草窮秋時，風皞谷震落日低。", "豈知與世玩文采，嘆息摩挲爲賦詩。"]'),
('e8b8c59b-80eb-4c08-95b1-e84cc38678b7','屈原祠','趙汝譡','宋','宋诗','song-poetry','','[]','忠深獨逢尤，怨極翻作歌。',204,'全唐诗/poet.song.179000.json','["忠深獨逢尤，怨極翻作歌。", "豈云嗜好異，奈此芳潔何。", "郢都值末造，聽惑賢佞訛。", "令尹專國事，君王信秦和。", "內思謀諫盡，旁困讒嫉多。", "秉道身必斥，徇時則同波。", "我生帝降直，臣節安敢頗。", "痛心易激烈，危步難逶迤。", "忍觀宗緒墜，去復念本柯。", "采藻或澗濱，茹芝亦巖阿。", "下將從彭咸，終已投汨羅。", "湘水碧湛湛，湘山鬰峩峩。", "昔存懷沙恨，今見垂綸過。", "仲夏草樹蕃，初華粲蓮荷。", "禪棲寄幽祀，羈思發長哦。", "風雅尚遺音，景宋寖殊科。", "遠游一感嘆，白首留江沱。"]'),
('fa73ffe4-f0cf-4383-9c8d-8f50ab8364eb','高文廟','趙汝譡','宋','宋诗','song-poetry','','[]','盛朝陵谷遠，遺廟林麓長。',192,'全唐诗/poet.song.179000.json','["盛朝陵谷遠，遺廟林麓長。", "美哉漢二君，百世常流光。", "功高拯塗炭，德盛敦農桑。", "興禮表儒化，授經恢士方。", "盡令秦網壞，汔復周道康。", "下國崇明祀，令人薦嘉嘗。", "豆籩列臣佐，冠佩參侯王。", "蒼髮商山中，素編穀城傍。", "曾云絳灌輩，敢厠蕭曹行。", "奇才洛陽子，抱策意激揚。", "蘭芷弔沉汨，風沙歎遊湘。", "遇合從古難，賦騷空自傷。", "逮平襲衰緒，終獻委絕綱。", "罔念開承初，巍巍炎祚昌。", "階庭上蘚迹，祝史陳椒漿。", "跪起敢不敬，詠歌獨無忘。"]'),
('4aef22f6-c86e-4a2a-8ab1-0dc7c2835024','直州','趙汝譡','宋','宋诗','song-poetry','','[]','時潦匯衆川，朝暾耀中洲。',120,'全唐诗/poet.song.179000.json','["時潦匯衆川，朝暾耀中洲。", "岸迴挐音急，水抱禪宇幽。", "竹樹相覆带，雲沙更蕩浮。", "估船乘波發，漁艇沿潭遊。", "他嶼亦可登，愛此所覽周。", "東軒既延佇，西閣復夷猶。", "歸求種嘉橘，老欲守故丘。", "賈誼何遠去，屈原竟深投。", "俗卑忌才高，世濁憎多修。", "請將招隠作，往和滄浪謳。"]'),
('aecfa8d6-fe92-411f-ba08-9d877524c3c9','溪次','趙汝譡','宋','宋诗','song-poetry','','[]','霧開辨石色，日出還溪光。',72,'全唐诗/poet.song.179000.json','["霧開辨石色，日出還溪光。", "午炊蒼林間，暮宿寒沙傍。", "山徑葉自下，泠然若飄霜。", "鳥雀靜四野，田家已冬藏。", "我車獨未停，王命嚴所將。", "瞻雲懼霰集，明復踰崇岡。"]'),
('3448a674-594c-4248-9b5c-a7cb33bd0acf','齋居即事','趙汝譡','宋','宋诗','song-poetry','','[]','累石欲擬山，附垠愛生竹。',108,'全唐诗/poet.song.179000.json','["累石欲擬山，附垠愛生竹。", "半尋裁方沼，筒水注茲足。", "鸂鶒游其內，焉知海鷗浴。", "始收春葩丹，倏長夏條綠。", "觀物各自遂，撫時一何速。", "深居有廣思，紆履無遠矚。", "聖出營世寧，哲潜避身辱。", "高情或貽誚，散跡乃見局。", "逝將從負樵，歸老寒澗曲。"]'),
('3a2b882f-7739-4795-94b1-837de4626bcb','鬰孤臺','趙汝譡','宋','宋诗','song-poetry','','[]','杖藜登高臺，四遠披天風。',120,'全唐诗/poet.song.179000.json','["杖藜登高臺，四遠披天風。", "清川漾光遠，碧嶂含姿濃。", "閭井滿後前，雉譙夾西東。", "雄爲一州表，闊會群境從。", "摧頹久籠鶴，迅逸遐征鴻。", "矯首望丹闕，煙氛多翳蒙。", "南方少佳月，竟歲四五逢。", "稍喜今夕霽，迥當凉秋中。", "衰影朗在照，空庭恣鳴蛩。", "石欄葉露下，吟思殊未終。"]'),
('ca66453d-1614-4ea9-b4f1-883839ed35f2','南湖書院','趙汝譡','宋','宋诗','song-poetry','','[]','捍川始成邑，巡甸遂建都。',144,'全唐诗/poet.song.179000.json','["捍川始成邑，巡甸遂建都。", "千載倚脩堤，三吳達高塗。", "衛軍弛馬牧，令尹司官湖。", "濬中深有蓄，豐外堅無虞。", "往者水冒沒，傷哉人愁吁。", "雨常夏潦盈，旱必秋田枯。", "民功念久隳，邦患諗預圖。", "忽驚華構敞，豈爲縱覽娛。", "溪落露魴鯉，草長戲鷗鳬。", "丹霞出雲表，翠巘亙天隅。", "緬懷謝公言，希迹巖棲徒。", "且復與閭里，共守桑麻區。"]'),
('7c1f2924-a889-4e42-ba44-431cee68c1e2','寄題王宗卿答春堂','趙汝譡','宋','宋诗','song-poetry','','[]','天德不可名，煦濡在三春。',120,'全唐诗/poet.song.179000.json','["天德不可名，煦濡在三春。", "母恩不可報，愛慕極終身。", "粲粲白華士，築堂奉其親。", "堂前種叢蘭，堂後植脩筠。", "列卿禁武近，出牧藩條新。", "起居佩慈訓，平讞宣皇仁。", "屬懷音書遥，曷慰色笑頻。", "馳神越海嶠，竦睇徹昏晨。", "鼎鍾曾足多，滫瀡良未珍。", "請將蓼莪義，一爲君子陳。"]'),
('a292fb35-8a05-4ae9-8eef-f7c2335bb245','樓望','趙汝譡','宋','宋诗','song-poetry','','[]','倚牆茂樹陰，交覆狀垂蓋。',96,'全唐诗/poet.song.179000.json','["倚牆茂樹陰，交覆狀垂蓋。", "面岑可爲樓，所惜著亭隘。", "試憑工師手，高取空闊界。", "材章來何山，得補榱棟壞。", "泮宮對突兀，雉堞隠縈带。", "老榕剪東枝，遂破群碧礙。", "閑雲入秋眺，遠靄增暮慨。", "心知飛鳥邊，歷歷歸路在。"]'),
('26e7d777-cc24-41a0-9758-31153e061661','登定王臺','趙汝譡','宋','宋诗','song-poetry','','[]','湘中十七門，層層居中央。',120,'全唐诗/poet.song.179000.json','["湘中十七門，層層居中央。", "經營自何代，傳是漢定王。", "窮力致遠士，側身思咸陽。", "地褊乃後絕，炎靈久無光。", "今非昔所望，林麓深青蒼。", "歌舞來其上，軍營在其旁。", "國人記本始，祠典脩烝嘗。", "嘉節近楚俗，羈懷渺湖鄉。", "野菊豈不採，含英待秋霜。", "風騷企高調，登覽獨成章。"]'),
('525a4b90-6628-4e9f-870f-acdf49c2c5c0','休日黄推官登臺','趙汝譡','宋','宋诗','song-poetry','','[]','禪閣自何代，萬緣委飛埃。',96,'全唐诗/poet.song.179000.json','["禪閣自何代，萬緣委飛埃。", "碑圖久亦滅，棟宗半欲摧。", "一水中貫野，練光遠縈回。", "山容媚煙日，澹若今碧開。", "清言已忘暑，况復同此杯。", "攀登曠士情，感寓騷人才。", "停坡引歸騎，表郭瞻高臺。", "空夜兩古柏，颯颯吹凉來。"]'),
('84d3c100-e052-4116-be0b-504a29ae497d','訪張宣公書院','趙汝譡','宋','宋诗','song-poetry','','[]','神龍翔慶霄，威鳳乘陽暉。',192,'全唐诗/poet.song.179000.json','["神龍翔慶霄，威鳳乘陽暉。", "德隆昌運合，教薄英才衰。", "聖武起王功，哲儒植邦基。", "溫純州殿講，深切玉璪規。", "賢軌寧遽傾，休風倏潜移。", "巧緣一州將，輟此萬乘師。", "退抱康世模，濟川舍其維。", "收士雲麓深，會友雪嶽奇。", "閔曾行獨顯，呂葛策未施。", "絕響曠孰嗣，素編烟今垂。", "永眷游習地，載瞻燕居儀。", "駕言往城南，翻動湘中思。", "景迫昧見道，登堂惘如遺。", "方池秋泉清，脩徑晨露滋。", "荷老莫採折，草荒欲芟治。", "徘徊重撫事，詠歎空復辭。"]'),
('ff2d17ee-e3cd-4cdc-9c28-604b1ff97ba4','夏日與客飲水雲館','趙汝譡','宋','宋诗','song-poetry','','[]','虛館涵景闊，遐觀展幽心。',96,'全唐诗/poet.song.179000.json','["虛館涵景闊，遐觀展幽心。", "水雲自閑澹，千載寧異今。", "潮生泛舟去，欄楯動黝深。", "野樹開田廬，平綠日半陰。", "浙塘似髣髴，久客含沉吟。", "頗忻溪庖鮮，笋荔供斟酌。", "孤塔忽心晚，林飛羨歸禽。", "丘樊會當返，即此思投簪。"]'),
('54cd00c1-429f-494a-942a-bd39d74385b0','開福寺','趙汝譡','宋','宋诗','song-poetry','','[]','蕭辰款招提，近郭野趣深。',108,'全唐诗/poet.song.179000.json','["蕭辰款招提，近郭野趣深。", "廣池映茂樹，秋水涵夕陰。", "及茲塵事暇，誰與同幽襟。", "竹密隠江艇，荷衰浄雲岑。", "暑宮覆玉井，春囿開丹林。", "繁華荒王迹，寂寞英霸心。", "圖劍歸把玩，光稜就銷沉。", "哀樂物所感，興廢理可尋。", "聊以舒永眺，庶將慰孤吟。"]'),
('3ac45fe1-cee6-431f-9f35-8ac461c174f0','囊山寺','趙汝譡','宋','宋诗','song-poetry','','[]','松門包土囊，石徑駐塵鞅。',96,'全唐诗/poet.song.179000.json','["松門包土囊，石徑駐塵鞅。", "征途悄愁辛，意豁金利爽。", "鼓鐘殷林際，堂殿攀磴上。", "有亭依後岡，極眺一何朗。", "海光混蒼碧，雲思浮渺漭。", "良久空雨霏，風泉谷交響。", "巖龕寄禪迹，古佛瞻刻像。", "更欲步層巔，荒煙晚迷罔。"]'),
('2705c6f2-0e15-4a74-8e6e-9ab6c2f80ad2','道林寺','趙汝譡','宋','宋诗','song-poetry','','[]','伐鼓發東津，弭楫游西林。',108,'全唐诗/poet.song.179000.json','["伐鼓發東津，弭楫游西林。", "渺看汀渚隔，迥入煙雲深。", "脩廡澗風凉，古殿山氣陰。", "晨彩發穉竹，夏音轉幽禽。", "寥寥放逐跡，落落羈旅吟。", "奇翰動屋壁，高名照岡岑。", "文精公侯小，道勝天人欽。", "誠願息世紛，儻期開士尋。", "從之未可得，年鬢上愁侵。"]'),
('083fbd61-55f0-4873-aba1-5c290ebf683a','嶽麓寺','趙汝譡','宋','宋诗','song-poetry','','[]','霽景映蒼麓，嵐光泛層巒。',120,'全唐诗/poet.song.179000.json','["霽景映蒼麓，嵐光泛層巒。", "清和愜幽步，窈繚窮遐觀。", "偶與文會俱，未覺心賞闌。", "一窗奧明具，萬象高下寬。", "城郭隠沙際，廟宮見林端。", "引澗日流厨，取泉時出山。", "摩挲雲杉去，惆悵煙竹寒。", "嚶鳴感伐木，肥遯思考槃。", "鄒公有荒臺，百世名不刊。", "悠悠湘波去，使我空長歎。"]'),
('e14e6fdd-2e2b-4246-9ab0-19024aec3c36','題浯溪中興碑','趙汝譡','宋','宋诗','song-poetry','','[]','蒼崖插浯溪，清漲濕元頌。',120,'全唐诗/poet.song.179000.json','["蒼崖插浯溪，清漲濕元頌。", "費墨合屋高，千年此安用。", "鯨翻天寶末，雲滃朔方衆。", "還都迎上皇，嗚咽抱餘痛。", "兩宮重宴樂，萬國盡朝貢。", "當時紀成功，小雅見微諷。", "顔公發勁畫，金玉相錯綜。", "我於碑刻間，衆羽得孤鳳。", "艱危人物難，忠烈鬼神重。", "摹取掛野堂，英風凜生棟。"]'),
('79b01482-ba74-4016-b196-7755334cf98e','讀昭君曲','趙汝譡','宋','宋诗','song-poetry','','[]','昭君死作千年土，曲在人間調不同。',64,'全唐诗/poet.song.179000.json','["昭君死作千年土，曲在人間調不同。", "絕塞煙沙空玉質，深宮日月自春風。", "當時有恨傳騷客，往事無心論畫工。", "已分二坐終寂寞，雁飛曾過上林中。"]'),
('e086b536-8512-49a0-8db1-bda6a1aa013a','句  其一','趙汝譡','宋','宋诗','song-poetry','','[]','人家插柳春將過，時節澆松老未歸。',16,'全唐诗/poet.song.179000.json','["人家插柳春將過，時節澆松老未歸。"]'),
('7d84730e-adbe-4aa6-b0e6-2be911346d10','句  其二','趙汝譡','宋','宋诗','song-poetry','','[]','先朝懷族遠，平世責人深。',12,'全唐诗/poet.song.179000.json','["先朝懷族遠，平世責人深。"]'),
('fa6b287b-9283-4766-8057-f2f632952527','三池丁祭宿齋所賦','虞剛簡','宋','宋诗','song-poetry','','[]','洙泗微言日夜行，天高地下昨猶今。',64,'全唐诗/poet.song.179000.json','["洙泗微言日夜行，天高地下昨猶今。", "□□□□六經意，識得皇皇萬古心。", "宗廟百官誰不見，朱絃疏越有知音。", "同人得似三池盛，屬目冠裳儼若林。"]'),
('bea1bfbb-9c4d-4256-9848-e62c8ee50f89','游靈巖寺  其一','虞剛簡','宋','宋诗','song-poetry','','[]','八年前識茲山面，今日幽盟許重尋。',64,'全唐诗/poet.song.179000.json','["八年前識茲山面，今日幽盟許重尋。", "亂石懸崖僧易少，疎林淺薄寺難深。", "流泉藥得何人病，絕壁靈通古佛心。", "老我泊然元會得，俯空一笑晚風臨。"]'),
('96a081a0-2c54-4c94-8286-bacd46624434','游靈巖寺  其二','虞剛簡','宋','宋诗','song-poetry','','[]','摩挲石刻拜方興，誤國從初恨老秦。',64,'全唐诗/poet.song.179000.json','["摩挲石刻拜方興，誤國從初恨老秦。", "十六州歸仍遺虜，百餘年事語誰人。", "出師表在今如昔，墜淚碑存舊似新。", "江水江花豈終極，風光一任轉青春。"]'),
('efff0ca3-fd54-4da9-8189-0fb8f59827c9','送子就試帖','虞剛簡','宋','宋诗','song-poetry','','[]','兒有掌中杯但把，歸期苦苦催奕世。',64,'全唐诗/poet.song.179000.json','["兒有掌中杯但把，歸期苦苦催奕世。", "衣冠仍上第公臺，元自詩書裏面來。", "秋色爲渠開先我，梁山馬首回猿鶴。", "莫輕窺蕙帳驚猜，苔步歸休亦樂哉。"]'),
('e5bcdd75-c0fa-4042-8ffc-953ebe771598','句','虞剛簡','宋','宋诗','song-poetry','','[]','天上人間元一氣，如何頃刻爛樵柯。',16,'全唐诗/poet.song.179000.json','["天上人間元一氣，如何頃刻爛樵柯。"]'),
('6e650ee5-fd18-4af2-b9c9-2a6d90c4bf50','句','高某','宋','宋诗','song-poetry','','[]','擬約滄江異姓兄。',8,'全唐诗/poet.song.179000.json','["擬約滄江異姓兄。"]'),
('a9329b3d-0287-43d5-9434-557f6a269aca','輓象山先生','王有大','宋','宋诗','song-poetry','','[]','篤學光前哲，知言衆所迷。',48,'全唐诗/poet.song.179000.json','["篤學光前哲，知言衆所迷。", "學同顔氏好，功與孟軻齊。", "獻替心彌切，藩經政可稽。", "儒宮儼遺像，垂範自江西。"]'),
('e9fa8de6-6f69-46a6-8d73-d3351e3aba0a','句','應傃','宋','宋诗','song-poetry','','[]','嘉木灌叢春意好，可憐不種紫荆花。',16,'全唐诗/poet.song.179000.json','["嘉木灌叢春意好，可憐不種紫荆花。"]'),
('baf853a7-027a-42b2-8894-de31d455f494','餞呂子敬赴漕臺','朱睎顔','宋','宋诗','song-poetry','','[]','北風吹海波，寒氣已慘栗。',216,'全唐诗/poet.song.179000.json','["北風吹海波，寒氣已慘栗。", "歲功方告成，上計倉廩實。", "大府督先期，列城群彥集。", "公來親奉辭，王事有遠役。", "入登和鈞堂，諮諏侍前席。", "力陳功利源，首先二三策。", "民實吾同胞，苛痛體均一。", "商賈趁懋遷，負販致其力。", "上以奉王供，下以和民食。", "嗟余忝命吏，三載貳下邑。", "適丁歲屢艱，課計虛所入。", "使車勤遠人，問俗考肥瘠。", "念茲災疹餘，推額減其籍。", "寒者煦之溫，饑者哺之粒。", "嚮非大府嚴，雲雨手轉劇。", "公歸被顧問，爲我對以臆。", "倘能出泥澤，窮困非所惜。", "相期在歲寒，梅邊問消息。"]'),
('dfad9227-4010-4dbc-a145-8495f0e80f75','吳興雜詠','朱睎顔','宋','宋诗','song-poetry','','[]','吳興山水窟，清遠古今聞。',48,'全唐诗/poet.song.179000.json','["吳興山水窟，清遠古今聞。", "水入孤城合，山來別縣分。", "寒川明野燒，曉碓濕溪雲。", "試貰烏程酒，微聲透客醺。"]'),
('f8194c24-4637-4ade-9ff7-137be47c1c2d','題觀政堂','薛極','宋','宋诗','song-poetry','','[]','野水瀰茫春更多，文昌觀政意如何。',32,'全唐诗/poet.song.179000.json','["野水瀰茫春更多，文昌觀政意如何。", "了無慚色清相照，試聽當年襦袴歌。"]'),
('c3e48dcd-f124-41d7-86c5-2c968bf0693b','羅盞山','張灝','宋','宋诗','song-poetry','','[]','道盞原非盞，言羅不是羅。',24,'全唐诗/poet.song.179000.json','["道盞原非盞，言羅不是羅。", "只因山突起，個個盡如螺。"]'),
('4cc6693a-abee-47fb-9052-fef2cdf9de9b','水簾','張灝','宋','宋诗','song-poetry','','[]','朝來雨急飛瀑雄，黑雲壓屋江挂虹。',96,'全唐诗/poet.song.179000.json','["朝來雨急飛瀑雄，黑雲壓屋江挂虹。", "晚來雨定瀑亦小，散作水鏤鏘簾櫳。", "垂簷初似玉成綴，觸石但見珠跳空。", "嗟哉山泉一物耳，朝態莫狀不爾窮。", "乃知造物解戲人，千變萬化頃刻中。", "吾恐文章要如此，好把泉源驅筆鋒。"]'),
('a964cc3b-7563-44be-8906-dc52ab5456bb','潢河','趙彥珖','宋','宋诗','song-poetry','','[]','潢河繞出郡城樓，樓枕潢南城上頭。',32,'全唐诗/poet.song.179000.json','["潢河繞出郡城樓，樓枕潢南城上頭。", "天闊星連翼軫分，地長川带漢江流。"]'),
('cd0b2714-cd8b-4593-8d95-a0650c886c5d','山居雜興','張次賢','宋','宋诗','song-poetry','','[]','深林樹色翠重重，一枕蘧蘧蝶翅濃。',32,'全唐诗/poet.song.179000.json','["深林樹色翠重重，一枕蘧蘧蝶翅濃。", "好鳥乍啼驚夢覺，可人山色入簾櫳。"]'),
('2559af64-5f1c-4409-9105-dd919d04668c','同陳提舉庸郭安撫睎宗玩月南峰','張次賢','宋','宋诗','song-poetry','','[]','山中有佳客，山上月增明。',48,'全唐诗/poet.song.179000.json','["山中有佳客，山上月增明。", "廊廟心同赤，江湖夢獨清。", "半庭叢樹影，萬籟淡秋聲。", "把手情何極，呼童問麴生。"]'),
('b63472de-5ab2-48cc-8123-630dfb66b7bd','過郭繼一處士草堂','張次賢','宋','宋诗','song-poetry','','[]','愛寂塵軒冕，辭榮結草茨。',48,'全唐诗/poet.song.179000.json','["愛寂塵軒冕，辭榮結草茨。", "午雲封石磴，春鳥語花枝。", "茶熟琴三弄，詩成酒一卮。", "笑予長鞅掌，暫此共棲遲。"]'),
('24f4cea2-35bc-491a-bc13-3422731fec52','茉莉花','許景迂','宋','宋诗','song-poetry','','[]','自是天上冰雪種，占盡人間富貴香。',48,'全唐诗/poet.song.179000.json','["自是天上冰雪種，占盡人間富貴香。", "不煩鼻觀偷馥郁，解使心地俱清凉。", "南船賈客俱到岸，東道主人容寄廊。"]'),
('60463a2a-aefa-42a5-ba3a-c023bd9bfb49','虞美人草','許景迂','宋','宋诗','song-poetry','','[]','合歡枝葉想腰身，不共長安草木春。',32,'全唐诗/poet.song.179000.json','["合歡枝葉想腰身，不共長安草木春。", "若聽楚歌能楚舞，未央空有戚夫人。"]'),
('8b8ce655-5af2-48c7-b09d-64b5f448f67b','茭白','許景迂','宋','宋诗','song-poetry','','[]','翠葉森森劍有棱，柔條鬆甚比輕冰。',32,'全唐诗/poet.song.179000.json','["翠葉森森劍有棱，柔條鬆甚比輕冰。", "江湖若借秋風便，好與蓴鱸伴季鷹。"]'),
('0f3aad0a-980a-4f7b-bf55-790f58f542f5','贈製刻漏前挈壺王君囦','許景迂','宋','宋诗','song-poetry','','[]','蛩吟秋方來，鶴鳴夜參半。',144,'全唐诗/poet.song.179000.json','["蛩吟秋方來，鶴鳴夜參半。", "山中無曆日，榮悴知節換。", "王君太多事，絲杪察昏旦。", "辛苦窮河源，把彼注罌罐。", "綫溜來不停，會見白石爛。", "旁有減水壺，節水使之緩。", "儻無乘除法，巧曆安得算。", "反求諸吾身，自有子午觀。", "百刻呼吸調，勿使魂去幹。", "冤哉張壽王，課最密於漢。", "信史不足徵，徒興千載歎。", "抱籌付木仙，試判此公案。"]'),
('84af18ac-20fd-432a-86c8-2d8500e27025','東湖生雙蓮花守者以爲郡齋獻館賓黄雲夫有詩述其事應史君屬和且以見示輒次韵','許景迂','宋','宋诗','song-poetry','','[]','王業根本在豳岐，郡國千萬分柯枝。',128,'全唐诗/poet.song.179000.json','["王業根本在豳岐，郡國千萬分柯枝。", "使君駟馬一馬馳，三台瑞應天爲之。", "視吏輿臺民如子，不煩頤指而氣使。", "鈴齋宴坐揚仁風，披拂東湖花十里。", "六月爲霖報政成，山光水容朝暮新。", "春王淘珠登早穡，比隣果是華胥國。", "采蓮游艇獻駢芳，蜀客作歌紀其祥。", "轉而上聞君相喜，佇待來歸政事堂。"]'),
('dbd40dbb-20c1-4aed-b8cc-f0a5fb052e24','句','許景迂','宋','宋诗','song-poetry','','[]','野店青闢戶，春船綠漲篙。',12,'全唐诗/poet.song.179000.json','["野店青闢戶，春船綠漲篙。"]'),
('d2932ba0-9d1d-464e-b4d1-f62f2e8d001e','和楊禮侍六言','趙載','宋','宋诗','song-poetry','','[]','圍青繞綠近在，虛白羊玄本同。',28,'全唐诗/poet.song.179000.json','["圍青繞綠近在，虛白羊玄本同。", "須知滿眼疊嶂，不礙舉頭太空。"]'),
('200bd397-89c2-45b6-ad49-29cd5442b0b4','游麻姑山瀑布泉','孫伯溫','宋','宋诗','song-poetry','','[]','九關守不嚴，失却兩玉龍。',48,'全唐诗/poet.song.179000.json','["九關守不嚴，失却兩玉龍。", "塵世著不得，忽來此山中。", "雷霆白晝間，冰雪詩人胸。", "天公不汝尤，爲人作年豐。"]'),
('393501fc-b9d2-4565-8af3-643e2265ac28','過山陰希瓐姪新居','趙師呂','宋','宋诗','song-poetry','','[]','美哉輪奐構華堂，如鳥飛兮接大荒。',64,'全唐诗/poet.song.179000.json','["美哉輪奐構華堂，如鳥飛兮接大荒。", "廣植門牆容駟馬，洞開扃戶透書香。", "滿簾濕翠怡情遠，入座清暉引興長。", "會見祝言千萬載，紛紛燕雀賀高堂。"]'),
('092e20cc-c86a-4da6-8f95-187fe325d5bb','賀希瓐姪得男','趙師呂','宋','宋诗','song-poetry','','[]','天潢一派福流長，旅邸重聞夾烏香。',64,'全唐诗/poet.song.179000.json','["天潢一派福流長，旅邸重聞夾烏香。", "海上蟠桃千古秀，月中仙桂萬年芳。", "象賢應擬家聲振，繕德還期國運長。", "端是吾宗能厚積，故生麟鳳兆禎祥。"]'),
('fa0d7ab5-75e4-464a-b93e-629dabf3eaec','鶴林寺','馮多福','宋','宋诗','song-poetry','','[]','春郊躬勸相，稅駕擬禪關。',48,'全唐诗/poet.song.179000.json','["春郊躬勸相，稅駕擬禪關。", "院古深藏竹，堂虛浄對山。", "日曛農父醉，雲伴老僧閑。", "暇日還携茗，同來瀹虎斑。"]'),
('9c024e29-abc1-4b13-9eef-69ba102af213','句','鄭爚','宋','宋诗','song-poetry','','[]','月似故人能赴約，鷺如小友可忘年。',16,'全唐诗/poet.song.179000.json','["月似故人能赴約，鷺如小友可忘年。"]'),
('651d92e5-4ebb-4799-a4fc-5efbeba8d8c9','咏歸亭','馮椅','宋','宋诗','song-poetry','','[]','弓轉寒溪月一灣，下臨虎豹踞斕斑。',64,'全唐诗/poet.song.179000.json','["弓轉寒溪月一灣，下臨虎豹踞斕斑。", "林煙開處飛層閣，雲市窮頭護遠山。", "衿佩光陰弦誦裏，舟梁人物畫圖間。", "紅塵堆案那能到，只有漁舟自往還。"]'),
('4be1cb24-6220-4912-a4af-3af3537bfed6','即事','陳揆','宋','宋诗','song-poetry','','[]','誰家庭院冷蕭蕭，閉却朱門不許敲。',32,'全唐诗/poet.song.179000.json','["誰家庭院冷蕭蕭，閉却朱門不許敲。", "惟有東風藏不得，隔牆露出杏花梢。"]'),
('ede510a0-46b8-4c00-a477-de7627f7be4f','三高祠','袁聘儒','宋','宋诗','song-poetry','','[]','功成但可將身去，逃難安貧適所遭。',32,'全唐诗/poet.song.179000.json','["功成但可將身去，逃難安貧適所遭。", "三子有靈應共笑，一時何意故爲高。"]'),
('f7b575f5-5243-463e-a393-34ad88faf31f','董端公墓','董煟','宋','宋诗','song-poetry','','[]','從來正氣關天地，扞禦功成死不妨。',64,'全唐诗/poet.song.179000.json','["從來正氣關天地，扞禦功成死不妨。", "守土忠貞唐許遠，埋輪節概漢張綱。", "麒麟高冢閒金盌，屓贔豐碑重玉堂。", "曠代衣冠誰解識，令人終古泣斜陽。"]'),
('a6b92a2c-e09f-4633-a570-fc405c14aed7','黄燕山','楊琛','宋','宋诗','song-poetry','','[]','蒼蒼終日鎖春愁，欲去迴翔更少留。',32,'全唐诗/poet.song.179000.json','["蒼蒼終日鎖春愁，欲去迴翔更少留。", "傳說王家飼燕女，今朝珠報始知由。"]'),
('bd9ce5e6-5e16-46c6-8ff0-1a914e442088','幽居','楊與立','宋','宋诗','song-poetry','','[]','柴門閴寂人少過，盡日觀書口自哦。',32,'全唐诗/poet.song.179000.json','["柴門閴寂人少過，盡日觀書口自哦。", "餘地不妨添竹木，放教啼鳥往來多。"]'),
('26a7331c-227e-4b2e-b3e4-67718d63536c','溪頭','楊與立','宋','宋诗','song-poetry','','[]','溪頭石磴坐盤桓，時見修鱗自往還。',32,'全唐诗/poet.song.179000.json','["溪頭石磴坐盤桓，時見修鱗自往還。", "可是水深魚極樂，不須妄想要垂竿。"]'),
('d74e3b31-0f82-4afb-9531-2333ea82de60','巖桂','楊與立','宋','宋诗','song-poetry','','[]','自從月窟得靈根，使擅人間衆木尊。',64,'全唐诗/poet.song.179000.json','["自從月窟得靈根，使擅人間衆木尊。", "萬斛天香非世有，十分秋色至今存。", "林高直接孤輪影，枝老休尋舊斧痕。", "午夜樓頭足心賞，天低風細欲飛魂。"]'),
('0ca4e346-d745-4e73-88e8-675de1f409e2','妙峰亭','趙䈣夫','宋','宋诗','song-poetry','','[]','塵世有仙境，清絕不可言。',48,'全唐诗/poet.song.179000.json','["塵世有仙境，清絕不可言。", "寒江露沙迹，晚嶂埋雲根。", "暇日推吏案，呵道穿僧門。", "來飲巖下水，何必携芳樽。"]'),
('2374afb8-6121-4596-8f40-930be71a000a','開禧丁卯制置使葉寶文團結淮西山水寨四十七處繪圖見示','孔蓋','宋','宋诗','song-poetry','','[]','專閫威名仰四馳，韜鈐祕鑰快圖披。',64,'全唐诗/poet.song.179000.json','["專閫威名仰四馳，韜鈐祕鑰快圖披。", "守江不若守淮險，御敵何如料敵奇。", "棋墅無驚惟太傅，風寒能護是良醫。", "投鞭那有流堪斷，屹立長城報主知。"]'),
('0047261f-b628-4c40-a1d4-2b878de5ef9e','句','陳伯震','宋','宋诗','song-poetry','','[]','修眉濃淡裏，寸碧有無間。',12,'全唐诗/poet.song.179000.json','["修眉濃淡裏，寸碧有無間。"]'),
('98dcde66-3d64-495f-ab38-189009a955d3','壽皇子  其一','程珌','宋','宋诗','song-poetry','','[]','磊魁晶熒，歲有常期，見於秋分。',100,'全唐诗/poet.song.179000.json','["磊魁晶熒，歲有常期，見於秋分。", "秋分維何，天高氣清。", "玉蟾吐煇，銀漢無聲。", "澄霄一色，萬里雲平。", "此時候之，出丙入丁。", "所出之國，政化和平。", "人生其時，既壽且寧。", "矧復前星，以及子星，與之並明。", "天啟休期，應期挺生。"]'),
('2ba77cf1-160f-4e60-b940-d3dfd418d27a','壽皇子  其二','程珌','宋','宋诗','song-poetry','','[]','太初孰元，渾淪蒙密。',259,'全唐诗/poet.song.179000.json','["太初孰元，渾淪蒙密。", "彌漫宇宙，一氣沕潏。", "孰知是時，無極有極。", "天高地下，人生物出。", "疇雖未分，易雖未畫。", "行乎其間，充滿周悉。", "炎黄啟序，姬孔抉機。", "陶爲泰和，數千其期。", "寫爲六經，萬言具垂。", "太史變法，漢唐續維。", "迄于我宋，皇皇巍巍。", "百代以下，上接農羲。", "畏天若臨，視民如傷。", "消斥姦佞，登崇雋良。", "急將寬兵，我武維揚。", "選牧與部，仁風以翔。", "節用裕下，根深本强。", "身修國治，綱舉目張。", "由經而史，自皇而王。", "以暨我朝，同此一綱。", "天賦高妙，學力深詳。", "上而河洛之圖畫，近而我祖之憲章。", "貫千古於旦暮，歛一心於混茫。", "大哉斯學，夫豈經生學士析解章句而已哉。"]'),
('b8d4d3bb-f817-4975-83d2-d524cdfc3d8b','壽皇子  其三','程珌','宋','宋诗','song-poetry','','[]','皇穹發靈，炎圖中興。',195,'全唐诗/poet.song.179000.json','["皇穹發靈，炎圖中興。", "南呂調儀，運叶千齡。", "金相玉質，虎步龍行。", "親師問道，日進月新。", "以是事親，忠孝一忱。", "以是格天，昭徹一心。", "人之忠佞，事之幾萌。", "至則能斷，舉無遁情。", "夫是以清明在躬，志氣如神。", "綿綿若存，爲天地根。", "非道之外，他有長生。", "又况秋飲沆瀣，宵見南極。", "風雲叶和，海邦寧謐。", "楓宸椒禁，兩宮怡愉。", "忠厚所根，仁浹閻閭。", "願壽多男，洋洋康衢。", "天賜玉巵，人歌紫芝。", "磐石蘿圖，維熊夢奇。", "孔蔓且碩，時萬時億。"]'),
('79fb3aa2-e754-4496-8c44-c3211237d909','三月十八鎖試童子侍其行卷蕭然無事成二十韻謾呈同省','程珌','宋','宋诗','song-poetry','','[]','旬雨埋青冥，今晨浴新陽。',240,'全唐诗/poet.song.179000.json','["旬雨埋青冥，今晨浴新陽。", "老紅墮萬劫，稚綠羅千行。", "葉碎青槐古，條凈紫薇香。", "去歲護篔簹，今年已蒼筤。", "翩翻鵲引雛，伊優雀繞牆。", "有象咸熙愉，對時多慨慷。", "門外車馬喧，省中日月長。", "要之非大快，大快在滄浪。", "滄浪興何窮，風帆十丈檣。", "明日酌嚴君，浮丘蔚南翔。", "快馬抹青山，恍入萬松莊。", "山中多老人，雪巔更眉龐。", "持酒相勞苦，兒童紛迎將。", "小卧聽雪塢，徐步堆雲鄉。", "玉界梅萬本，煙海杉千章。", "三峽桃源浪，九夏冰巖霜。", "危橋跨長虹，曲水飛輕觴。", "兩日足可周，百年事難量。", "送客出松關，壯楗設門旁。", "揮手謝世人，從今永相忘。"]'),
('2e31002d-f068-4b3e-bccf-189523561c69','勉子姪','程珌','宋','宋诗','song-poetry','','[]','外物不足恃，翻覆百年間。',96,'全唐诗/poet.song.179000.json','["外物不足恃，翻覆百年間。", "唯有萬卷書，可以解我顔。", "男兒貴立志，達人得大觀。", "百川日夜流，與海會波瀾。", "丘陵安於卑，寧復望太山。", "方當少年時，髮齒未凋殘。", "聖賢戶庭闊，人人可躋攀。", "謹勿隨餘子，碌碌走丘樊。"]'),
('f1dd280f-89a4-43d2-a8bc-132daace1427','揭富陽孝子門','程珌','宋','宋诗','song-poetry','','[]','去年何明正，有女方笄年。',144,'全唐诗/poet.song.179000.json','["去年何明正，有女方笄年。", "母病偕幼弟，奉佛祈病蠲。", "既蠲未全已，剖肝代蘭荃。", "今年盛立旺，二子亦奇偉。", "兄肝起母病，弟復先割股。", "人生貴男兒，愧此簪笄女。", "峩峩儒冠弁，愧此田家子。", "予謬爲令長，冥愚化不宣。", "彼直天性厚，或以上澤覃。", "勞之緡酒廩，重爲此詩篇。", "揭之旌其門，觀風盛采旃。", "既以勸邦人，庶幾風普天。"]'),
('2681a691-1f50-4a02-b553-9fd41ed322a0','送夏明叔歸建寧','程珌','宋','宋诗','song-poetry','','[]','頃與君別時，君頤未生髭。',132,'全唐诗/poet.song.179000.json','["頃與君別時，君頤未生髭。", "曶曶二十年，驚見紫髯奇。", "相逢不相識，視刺乃得之。", "尊酒出文卷，芙蓉陰未移。", "白露團虛簷，素蟾墮寒池。", "胡爲於此時，與君又語離。", "自言甘旨急，毋失舊舘期。", "丈夫屬有志，富貴無定姿。", "願君勉自力，上以慰親思。", "明年寒鴈來，殷勤寄書詞。", "爲報秋風高，吳仙得桂枝。"]'),
('e0b2ad56-e06f-4a01-8e78-c4b2d05fdc37','送常世卿歸嘉興','程珌','宋','宋诗','song-poetry','','[]','悔作唐山來，山深交友絕。',168,'全唐诗/poet.song.179000.json','["悔作唐山來，山深交友絕。", "相逢忽相得，乍見乃乍別。", "嗟此冰玉人，寒梅疏带雪。", "胸次羅文奎，筆底耀離纈。", "朝家渴英雋，結網仍高設。", "行且收殊科，勉哉嗣先烈。", "一編忠義傳，姦萌嘆先折。", "千載懦夫魂，脆骨變奇節。", "識此吳中奇，復幸拜前哲。", "何異魯國人，一朝獲雙玦。", "晴雲起芝田，東風催啼鴂。", "慈庭有近書，明朝動歸轍。", "新抽草可茵，微露花堪折。", "相思復相思，後夜天邊月。"]'),
('125a48c2-8a88-41a3-8c13-2d061175cc01','讀史有感','程珌','宋','宋诗','song-poetry','','[]','俗士貪芻豢，喜充藜莧腸。',48,'全唐诗/poet.song.179000.json','["俗士貪芻豢，喜充藜莧腸。", "幽人樂清曠，要湔塵土裳。", "嗟予別松林，吳砧九換霜。", "困復不知歸，念之汗如漿。"]'),
('bff9a86c-2a9b-477d-a7d7-14af0a676281','仲冬望日登四顧坡','程珌','宋','宋诗','song-poetry','','[]','往哲有清言，晉人未爲達。',60,'全唐诗/poet.song.179000.json','["往哲有清言，晉人未爲達。", "此身皆假合，既散安用鍤。", "大音不在絃，琴亦安所設。", "當時逃酒徒，往往畏侵及。", "豁哉桴海時，風濤任興息。"]'),
('07061756-d48b-4208-8612-16b524dcfa97','哭吳范二姊','程珌','宋','宋诗','song-poetry','','[]','逝者如斯乎，翩翩北飛鴻。',86,'全唐诗/poet.song.179000.json','["逝者如斯乎，翩翩北飛鴻。", "鴻北來歲南，人去亡回蹤。", "庚寅仲姊去，庚辰伯姊空。", "千里不一見，血淚迸秋風。", "自餘只一弟，留守先人宮。", "我已日崦嵫，安能久轉蓬。", "束擔其歸與，相從十載山之東。"]'),
('1f93c2f0-d520-40b5-b8aa-b82057741456','輓朱侍郎','程珌','宋','宋诗','song-poetry','','[]','卜宅從先壟，駕言練日良。',240,'全唐诗/poet.song.179000.json','["卜宅從先壟，駕言練日良。", "飛盖騖玄駟，古柳被龍㡛。", "按轡且徐驅，聽歌薤露章。", "憶昔朱峯仙，浩劫思陶唐。", "貂蟬換羽衣，翩然來帝旁。", "西車極岷峩，南佩窺瀟湘。", "高牙開桂林，瑞節照襄陽。", "多少經綸業，春風散八荒。", "歸來不言功，低簪鴛鷺行。", "一朝侍甘泉，天渥方對敭。", "堂堂山立姿，九尺鬢眉蒼。", "胡爲勇不留，瑶宮去路長。", "夫人有令德，威鳳趣歸凰。", "輪摩同入道，未忍遽相忘。", "春天渺無際，春花堪斷腸。", "祇今楓林崗，雙玉一時藏。", "西南多甘棠，日莫人凄凉。", "風月三千篇，爛爛光生香。", "佳郎與快婿，門戶未渠央。", "三者無一憾，嗚呼公不亡。"]'),
('fa07260a-8d0b-4211-839a-b6f4fb1f5217','輓致政呂通議','程珌','宋','宋诗','song-poetry','','[]','營築未休臿，曉夕留松區。',168,'全唐诗/poet.song.179000.json','["營築未休臿，曉夕留松區。", "忽聆載輀車，歸自杭與湖。", "冷雨澀不晴，山徑淖如塗。", "間關五百灘，轉軸上雲衢。", "純孝格玄穹，安席若平鋪。", "憶昔祖慈親，六月暑方徂。", "奠酒雖百壺，練溪焦釜枯。", "今日遡長風，辛岨諒一如。", "維公有賢稱，靄然溢枌閭。", "千金手不售，其鍾後人乎。", "天畀此石窌，指顧即吾廬。", "且復愆以平，萬家守者居。", "甚欲一引紱，山寒阻前趨。", "黄羅金紫峯，送目但躊躇。"]'),
('ad355ee1-2ee5-41ae-bd5d-97f6092b4f3a','高宗皇帝寶訓終編錫賚進詩','程珌','宋','宋诗','song-poetry','','[]','紅雲一朵金爐煙，黄傘亭亭午漏傳。',256,'全唐诗/poet.song.179000.json','["紅雲一朵金爐煙，黄傘亭亭午漏傳。", "龍床猶御金華殿，方進群儒讀寶編。", "編中並載神堯語，三十六年真復古。", "祇今安用讀遺書，卓然已復光前緒。", "高皇當日濟艱難，猶在經綸未備間。", "今日山東河北地，百年羶去一朝還。", "更有祖宗傳國璽，琢於元祐隆平際。", "玉光射日篆雲飛，今日煌煌登寶几。", "高皇一笑在天靈，神孫今日再中興。", "錫與千秋萬歲齡，甲兵洗盡年豐登。", "群臣尚或呻佔畢，微臣但拱坳頭立。", "芳筵華秩及龍媒，亦拜聯翩自天錫。", "更憶先朝徹講餘，有臣曰軾感恩腴。", "願對紫薇花影下，試草招來贊普書。", "今也梯航慕中夏，無復更待招來者。", "微臣但摩千丈松，敬賡吉甫中興雅。"]'),
('a70fb9ae-bf3b-450b-b381-34ec339de1e8','秘閣儒榮堂','程珌','宋','宋诗','song-poetry','','[]','天狼騰騰照單于，怒麛抗嶽于上都。',352,'全唐诗/poet.song.179000.json','["天狼騰騰照單于，怒麛抗嶽于上都。", "松漠城高沙萬里，其下穹廬育此胡。", "皇仁配天覆中宇，西垂北際杳無區。", "七十年來軍事絕，謀臣猛將皆丘墟。", "兜鍪摧剝土氣蝕，塞馬不鳴秋草枯。", "祈連山下安穩卧，歲將金帛自膏腴。", "文儒申申武士墮，先生奮臂一長吁。", "當時顛末誰能記，家有中原孤臣書。", "吮血爲墨膚爲紙，驚風吹到玉蜚除。", "誠通精寤動乙覽，天經地緯開廟謨。", "手援神矛截河漢，中天真人正握符。", "蛇龍螭虎雜萬騎，庸蜀荆楚從吳車。", "皇旅如雷鐵嶂碎，汴水沄沄汴風噓。", "尺檄夜傳三秦定，侵田歸魯在須臾。", "向來孽霧漲北極，羲和一旦晴光舒。", "頓紘提綱無虧闕，澶漫萬里宣皇圖。", "怖威報德永無畔，施令酬功偏裨俱。", "上下兩間皆叶序，天錫皇壽天齊驅。", "炎精亦曜暢大鈞，天祐皇業卑唐虞。", "金石並奏告清廟，圓壇紫氣靄堪輿。", "丹門宣赦傳天下，百萬頌聲流康衢。", "此時此書方策勳，先生憂國榮有餘。"]'),
('e5d1d470-246a-4074-91a6-cbf12cb0d2cb','代上楊誠齋','程珌','宋','宋诗','song-poetry','','[]','杜陵已醉老坡仙，生後百年恨不及。',320,'全唐诗/poet.song.179000.json','["杜陵已醉老坡仙，生後百年恨不及。", "那知開眼大江西，突兀見公正冠幘。", "凜然清風不可攀，千載懦夫毛骨栗。", "暇時略吐胸中雲，坐使九霄成五色。", "未辨執樂三千指，不計酒材七百石。", "落然收寶入丹田，歸省廬阜千尋碧。", "那知城裏住相如，但信城東有太白。", "一時餘子皆鷁退，家有諸郎傳正脈。", "世塵千劫都磨盡，獨有詩緣渺亡極。", "天欲留公在世間，管領風月長爲客。", "彩鳳一鳴天地靜，安得微吟容晚出。", "巨止青山吞澤芥，許投頑石博拱璧。", "先丘宰木已參天，幽碣未刊但惕夕。", "魯山四絕先李文，誼貫幽明光存歿。", "先生匹素不可辜，儻得烟雲生勃鬰。", "化爲匹錦授丘遲，磨鈍爲銛希萬一。", "要是人貪常熟書，非關買菜復求益。", "詎敢限字如昔聞，小大當唯意所適。", "庶幾挂在露寒堂，琅然一讀意一釋。", "不須點白鱠松鱸，解衣卧聽歌赤壁。"]'),
('975fd3e4-f0d4-4987-a919-34d5527176b9','辛亥冬交石阻風三日','程珌','宋','宋诗','song-poetry','','[]','陰崖老虎殺氣驕，一噫三日攪泬漻。',112,'全唐诗/poet.song.179000.json','["陰崖老虎殺氣驕，一噫三日攪泬漻。", "日寒不焰雲飛逃，乾坤蟻轉東南高。", "疾勢已作奔天濤，餘威猶捲少陵茅。", "魚鼈怖死蛟龍號，舟中性命如鴻毛。", "起來危立大江皋，白沙黄塵紛驛騷。", "徐呼風伯入苹蒿，指撝八極建六鼇。", "翕張橐籥吾誰曹，太平之風不鳴條。"]'),
('a441ea3a-455b-47f1-8152-4e98f1f5f2c1','登紫微崖','程珌','宋','宋诗','song-poetry','','[]','富池大信江千里，三日醉卧烟蓬底。',128,'全唐诗/poet.song.179000.json','["富池大信江千里，三日醉卧烟蓬底。", "曉來推蓬登斷岸，因憶牧之呼屐齒。", "九華隆隆閘天脊，微雲低度差參是。", "百喚牧之如不聞，剝脫塵痕見文字。", "今年十月天未霜，木葉留露光嶷嶷。", "興亡風流不可論，蒼松怪石還如此。", "我今與子陟層巔，酌酒賦詩云樂只。", "後來誰復是牧之，斜陽歸路芙蓉水。"]'),
('362ba55b-2eb5-4033-9d98-3ed110f4ea84','於潜佳丞四明人同年友也方此掉鞅百未一見而來書羅縷無非歸與語豈醉夢書邪三詩見寄亟占數語正之','程珌','宋','宋诗','song-poetry','','[]','世人眼見真蓮少，真蓮却在玻璃沼。',146,'全唐诗/poet.song.179000.json','["世人眼見真蓮少，真蓮却在玻璃沼。", "浣花溪水入銀河，何人更識月皎皎。", "謫仙不見見梅粧，荷稠搴作芙蓉裳。", "黄龍乾葉何年墮，維摩雨華昨夜芳。", "真華真詩元在眼，要須心地先清凉。", "不然瀟湘水清寒磯月，沙平水晚露低昻。", "勸君休問張子房，鑑湖十里藕華香。", "天駟超河夜未央，胡爲自同太白光。", "何時握手論行藏，江東雲暮天何方。"]'),
('ee3d62b0-169c-40d0-b008-a8cdc65d3a2a','太上虛皇黄庭經句法十篇壽趙帥  其一','程珌','宋','宋诗','song-poetry','','[]','太史告春纔五日，東風昨夜傳消息，斗邊一星下南極。',40,'全唐诗/poet.song.179000.json','["太史告春纔五日，東風昨夜傳消息，斗邊一星下南極。", "飾以貂蟬扶社稷，更昌斯文開民則。"]'),
('6ca233e4-4a70-4cef-9bdd-288e6f7d3604','太上虛皇黄庭經句法十篇壽趙帥  其二','程珌','宋','宋诗','song-poetry','','[]','去年曾說冬葅綠，今年蓼甲春盤簇，綵花金勝相輝屬。',40,'全唐诗/poet.song.179000.json','["去年曾說冬葅綠，今年蓼甲春盤簇，綵花金勝相輝屬。", "五色班衣佩蒼玉，先奉庭幃千歲祝。"]'),
('caa4c94b-01b3-4f1a-9289-a295bb959eef','太上虛皇黄庭經句法十篇壽趙帥  其三','程珌','宋','宋诗','song-poetry','','[]','莫辭金琖十分斟，邇日星郎寵數深，庭前桂子更鮮新。',40,'全唐诗/poet.song.179000.json','["莫辭金琖十分斟，邇日星郎寵數深，庭前桂子更鮮新。", "鰲頭早晚貼塗金，公亦綠殿峩華簪。"]'),
('21c32776-240f-4373-a1b1-ef5140b1476c','太上虛皇黄庭經句法十篇壽趙帥  其四','程珌','宋','宋诗','song-poetry','','[]','漢列土宇封同姓，唐擢宗英持國柄，我宋膺圖臨海鏡。',40,'全唐诗/poet.song.179000.json','["漢列土宇封同姓，唐擢宗英持國柄，我宋膺圖臨海鏡。", "參天杞梓仙源盛，蕭敷艾榮何足訂。"]'),
('67994635-5e85-4d9c-b57a-d03ece85a56a','太上虛皇黄庭經句法十篇壽趙帥  其五','程珌','宋','宋诗','song-poetry','','[]','向也何幸識仙翁，玉栗春明盛德容，又常一再見阿戎。',40,'全唐诗/poet.song.179000.json','["向也何幸識仙翁，玉栗春明盛德容，又常一再見阿戎。", "神情穎異機生鋒，公家流慶無終窮。"]'),
('9bdc12c9-7779-4e70-bfd7-0e098a2a2c5c','太上虛皇黄庭經句法十篇壽趙帥  其六','程珌','宋','宋诗','song-poetry','','[]','明年天使九街馳，御茗名薰宣玉詞，更敕儀鸞餉壽巵。',40,'全唐诗/poet.song.179000.json','["明年天使九街馳，御茗名薰宣玉詞，更敕儀鸞餉壽巵。", "我有新曲名紫芝，會當獻之鳳凰池。"]'),
('97082d71-8b24-462d-9329-a39cd89a970e','太上虛皇黄庭經句法十篇壽趙帥  其七','程珌','宋','宋诗','song-poetry','','[]','喬松落澗節輪囷，詩書萬卷終經綸，日華隔霧光難晨。',40,'全唐诗/poet.song.179000.json','["喬松落澗節輪囷，詩書萬卷終經綸，日華隔霧光難晨。", "公獨知其墮凡塵，何當一爲問大鈞。"]'),
('1abf5197-ba36-40dd-96b2-e395febb20ef','郊臺信筆','程珌','宋','宋诗','song-poetry','','[]','江天欲雪未成雪，推出雲頭照霜月。',64,'全唐诗/poet.song.179000.json','["江天欲雪未成雪，推出雲頭照霜月。", "此夕更長不可辜，何時百萬入彩盧。", "幾年長涎一車麯，輸他獵奴飫生肉。", "也須龍伯坐鰲頭，却看沙磧卧蝦鰍。"]'),
('4b809ca8-0881-487e-a9ef-5dc2aeed47c0','玉堂晝值有懷萬松','程珌','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','鷄籠峯下萬松山，中有游民天地閑。',160,'全唐诗/poet.song.179000.json','["鷄籠峯下萬松山，中有游民天地閑。", "左架虹腰上玄圃，右騎鰲背度飛關。", "幽壑流泉噴三峽，衮衮桃花翻浪雪。", "兩山對峙錦屏開，嫣紫肥紅仍炫白。", "十里松風百哢琴，丹書一枕卧殘春。", "何人共結無生社，冉冉青蜺下玉麟。", "九華突兀匡廬禿，幽深全似入盤谷。", "懷山一夜鬢如霜，畫作烟圖入洛陽。", "玉境那容凡骨洿，急草天章訊歸路。", "磨松琢石歌太平，亦表微臣報國恩。"]'),
('88f7bd66-7269-46ff-bcaa-51621b174ab0','汲井溉田民亦勞止歌以相之','程珌','宋','宋诗','song-poetry','','[]','短綆長缾高下飛，老農雨汗紅淋漓。',48,'全唐诗/poet.song.179000.json','["短綆長缾高下飛，老農雨汗紅淋漓。", "夜來雨意已垂垂，一事不成風又吹。", "决破玉龍太清池，滿浸萬頃碧琉璃。"]'),
('f29e87c8-d312-4f1f-9544-e5549ff3513e','贈毒菴','程珌','宋','宋诗','song-poetry','','[]','高座不知甚面目，當時喚作尸利密。',32,'全唐诗/poet.song.179000.json','["高座不知甚面目，當時喚作尸利密。", "要須勿負此標題，更向托茶山頂立。"]'),
('14340826-2d77-4189-a109-21841db2954d','伐千秋巨木竟梁梅堂','程珌','宋','宋诗','song-poetry','','[]','二木盤根三千秋，萬斧過之無敢視。',112,'全唐诗/poet.song.179000.json','["二木盤根三千秋，萬斧過之無敢視。", "今辰有梓號國工，朋曹十數來睥睨。", "爲言此木難斤斧，上有蟠龍下伏虎。", "莫教驚動萬年枝，掣電轟雷三日雨。", "直須作法起南風，號召百神同力扈。", "昻昻頭角向梅堂，五六鎮星來作輔。", "坐令國勢鞏蘿圖，萬歲千秋奉明主。"]'),
('84c95056-af91-4402-b1a5-4f05cf7d25cd','奉送季清赴山東幕府','程珌','宋','宋诗','song-poetry','','[]','黄雲銜雪天模糊，有客飄然出上都。',323,'全唐诗/poet.song.179000.json','["黄雲銜雪天模糊，有客飄然出上都。", "青絲絡馬銀兜鍪，紅錦䩨弓金僕姑。", "劍光壓匝照路隅，帕首百騎前訶呼。", "不知客本山澤臞，今胡爲者意氣粗。", "自言有將新孫吳，我欲與之同滅胡。", "嗚呼亡胡豈難且，病兵怯將自逃逋。", "胡不觀昔我藝祖造中區，以兵爲國垂洪模。", "河北河東義勇徒，二十四萬鼓應枹。", "中興益振尺五符，世忠淮左聚熊貙，劉錡淮西貔虎俱。", "上流岳飛彎天弧，金陵張浚羆搏狐。", "單于臺下雖寬誅，采石山前已斷顱。", "邇來殘虜尚窺窬，門內群寇更睢盱。", "胡乃朘剝及其膚，豈止牛羊不求蒭。", "我欲別幕飛於菟，十萬一屯淮之區。", "技閑器利整平居，幟明鼓震蒐彼廬。", "精神所折虜如無，而况山東群盜乎。", "五符儻缺聽其虛，十年且盡一賦租。", "斬然圻畫勿牽渠，他時混一更新圖。", "偉哉玉帳得通儒，君復碧油吐良謨，凌烟豈一貂蟬與。"]'),
('e3ff9e2a-89a0-4074-8596-3ec3162184b6','新舊句','程珌','宋','宋诗','song-poetry','','[]','憶昔丙辰還親旁，恰恰先春社三日。',196,'全唐诗/poet.song.179000.json','["憶昔丙辰還親旁，恰恰先春社三日。", "社日侍親行交源，紫蕨兒拳森玉立。", "是日天明風氣柔，入自交源茗源出。", "迤邐又復至前山，涉澗還家日將沒。", "慈親意在營一丘，卷卷欲於近舍求。", "當時議論悉未定，那知今作汪潭游。", "汪潭去家正五里，百里來龍於此止。", "龍止水亦止，清潭窈無底。", "寶劍秋空橫，秀峯春笋峙。", "最愛丫角羊，艮木之印鄉。", "長生亥水來朝丙，千古長溪流不盡。", "雍容冠佩紫薇垣，壽星更出丙丁間。", "神游既安後昆福，賦此銘章皆實錄。"]'),
('3b56eefa-370e-4cf4-b760-d3ea647a2f69','子時歌','程珌','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','順數方來兮，遡而上之洪荒。',120,'全唐诗/poet.song.179000.json','["順數方來兮，遡而上之洪荒。", "今不必短兮，古不必長。", "地有時而玄兮，天有時而黄。", "知靡草之先秋兮，又當知喬松之傲霜。", "知滄溟之連山兮，又當知大華之有長江。", "朝云西暮云東兮，豈期悉避乎陽光。", "入濛汜浴虞淵兮，又孰知其扶桑。", "吾烏乎而折衷兮，但當付萬化於茫茫。"]'),
('1569bb88-c8ca-43a2-a47c-65f42465671f','郊祀慶成詩  其一','程珌','宋','宋诗','song-poetry','','[]','粹古皆頻歲，炎劉或異祠。',48,'全唐诗/poet.song.179000.json','["粹古皆頻歲，炎劉或異祠。", "有唐方定制，我宋遂因儀。", "列聖馨明德，皇穹答顯祺。", "恭惟聖天子，大典應昌期。"]'),
('a1d2bb11-3be8-4230-a025-dcd6cb0248b2','郊祀慶成詩  其二','程珌','宋','宋诗','song-poetry','','[]','涓潔先原廟，純忱歷太宮。',48,'全唐诗/poet.song.179000.json','["涓潔先原廟，純忱歷太宮。", "八神開列闕，萬騎擁豐隆。", "軌道清風肅，洪頤麗日紅。", "康衢聽細語，八彩更重瞳。"]'),
('069084f1-e256-4264-92b0-0385d5afcd34','郊祀慶成詩  其三','程珌','宋','宋诗','song-poetry','','[]','牙籤猶未進，玉冕已先須。',48,'全唐诗/poet.song.179000.json','["牙籤猶未進，玉冕已先須。", "峻級飛平步，端圭却掖扶。", "祥光匝霄極，和氣滃天區。", "福飲煙升已，儐神靄瑞符。"]'),
('2dcb68c6-9e36-4aa5-804e-33c521f9faeb','郊祀慶成詩  其四','程珌','宋','宋诗','song-poetry','','[]','紫畤祗堂陛，蒼龍奉駕回。',48,'全唐诗/poet.song.179000.json','["紫畤祗堂陛，蒼龍奉駕回。", "邊塵知電掃，歲稔十年開。", "丹鳳覃天澤，東朝奉玉杯。", "樓前呼萬歲，砰隠動春雷。"]'),
('a43cf89a-73f5-4aab-81e3-5b6094d428e4','郊祀慶成詩  其五','程珌','宋','宋诗','song-poetry','','[]','謂聖惟能饗，由心克致虔。',48,'全唐诗/poet.song.179000.json','["謂聖惟能饗，由心克致虔。", "天心今答聖，聖意更祈天。", "沖性猶勤德，搜求愈任賢。", "愚臣輸至款，端在賦甘泉。"]'),
('92f66fcd-8505-46bb-9986-32b07f9910e5','丁亥閏五月十日回自真聖道坊車中記事','程珌','宋','宋诗','song-poetry','','[]','列障羅屏合，回泉玉带環。',48,'全唐诗/poet.song.179000.json','["列障羅屏合，回泉玉带環。", "外容三肘密，中著十洲寬。", "天意驅蹲虎，人心見聖蟾。", "煩君招舊隠，來此共潺湲。"]'),
('5d8c717f-4a27-43b8-a102-4476323ec38c','書富陽普照院  其一','程珌','宋','宋诗','song-poetry','','[]','境勝由盤古，聞名自謫仙。',48,'全唐诗/poet.song.179000.json','["境勝由盤古，聞名自謫仙。", "一從江國後，又到老坡年。", "山頂煙仍紫，樓頭月故圓。", "繼今知幾劫，風物更依然。"]'),
('ef4d26cf-bec3-44c9-b309-ad83ed2a43fa','書富陽普照院  其二','程珌','宋','宋诗','song-poetry','','[]','祇愛招提古，那知俗更醇。',48,'全唐诗/poet.song.179000.json','["祇愛招提古，那知俗更醇。", "寺雖炎漢代，人尚葛天民。", "僧定都忘客，林深自鏁春。", "我來千載後，更有後題人。"]'),
('63f7925e-fcd4-4065-b8ee-cdcfab8788a0','紅藥當階翻','程珌','宋','宋诗','song-poetry','','[]','禁近烟光潤，階平日影暄。',72,'全唐诗/poet.song.179000.json','["禁近烟光潤，階平日影暄。", "黄麻方草罷，紅藥正花翻。", "蒨色浮春動，清陰匝午繁。", "心傾青瑣客，香滿紫微垣。", "漏永文書靜，天低雨露溫。", "人言有仙骨，早晚拜明恩。"]'),
('9cfe8d81-b746-4468-8e0f-5194de6923f7','夜登釣石','程珌','宋','宋诗','song-poetry','','[]','頗憶嚴君瀨，還尋釣石緣。',48,'全唐诗/poet.song.179000.json','["頗憶嚴君瀨，還尋釣石緣。", "鄰鷄方叫月，邊鴈恰書天。", "句秀來仙白，聲和應樂全。", "展編真一快，如放五湖船。"]'),
('4e5c1cde-dd08-40e8-9da8-f761c69b2ba9','憲聖慈烈皇后輓詩  其一','程珌','宋','宋诗','song-poetry','','[]','西滸俱來日，東朝極盛時。',48,'全唐诗/poet.song.179000.json','["西滸俱來日，東朝極盛時。", "彫弓平黑海，彩筆照丹墀。", "壟起先裁費，丹成不用醫。", "人間空悵望，風月宴瑶池。"]'),
('ec270eaf-0194-4e9e-8cdc-e78cfb15dfe9','憲聖慈烈皇后輓詩  其二','程珌','宋','宋诗','song-poetry','','[]','聖祖艱難業，重孫擁佑恩。',48,'全唐诗/poet.song.179000.json','["聖祖艱難業，重孫擁佑恩。", "玉妃閑寶簡，仙御送金根。", "杳杳龍先去，翩翩鳳又翻。", "塗山望堯穴，日月萬春存。"]'),
('618f87ca-26b3-4e7d-b463-8fd11f5c4b34','光宗皇帝輓詩','程珌','宋','宋诗','song-poetry','','[]','厭聽人間樂，催成海上丹。',48,'全唐诗/poet.song.179000.json','["厭聽人間樂，催成海上丹。", "雲車分白象，天仗下紅鸞。", "梧野朝烟淡，咸陽莫日寒。", "龍舟宵濟處，清血漲紅干。"]'),
('b037bd79-085a-4530-b0d1-22099dc20485','光宗皇后輓詩','程珌','宋','宋诗','song-poetry','','[]','玉鎖辭椒禁，瑶宮問廣寒。',48,'全唐诗/poet.song.179000.json','["玉鎖辭椒禁，瑶宮問廣寒。", "人間方祝鳦，天上忽飛鸞。", "弱水三山鬲，華胥一夢殘。", "聖情凝望處，仙御景雲端。"]'),
('7c8a5099-cb88-48cf-82d3-8bae2f2e5402','寧宗皇帝輓詩','程珌','宋','宋诗','song-poetry','','[]','聖德同天運，神功並日昇。',48,'全唐诗/poet.song.179000.json','["聖德同天運，神功並日昇。", "韃真懷慄慄，齊魯格烝烝。", "復古周圖盛，中宗漢業升。", "未饒元結輩，磨筆誦中興。"]'),
('8f4991f0-460b-4c73-bdcc-d9f51598e428','輓程給事','程珌','宋','宋诗','song-poetry','','[]','戀闕葵心在，懷山秀野寒。',48,'全唐诗/poet.song.179000.json','["戀闕葵心在，懷山秀野寒。", "華繁常侍媿，草隸折衝難。", "結綠紅輝碎，懸藜夜色殘。", "平生桑梓地，雪涕景雲端。"]'),
('38904545-f752-4cf9-9918-dc05c9d6a9a4','輓汪給事','程珌','宋','宋诗','song-poetry','','[]','抱大難傾橐，隨時欲見田。',48,'全唐诗/poet.song.179000.json','["抱大難傾橐，隨時欲見田。", "星災諸葛日，齒少紫芝年。", "魯國麟枯骨，藍田玉折瑄。", "忍聞環珮響，帝所侍鈞天。"]'),
('1939c7d5-3a54-4d02-8107-db44351c356a','輓范端明','程珌','宋','宋诗','song-poetry','','[]','諸老都淪謝，惟公尚典刑。',48,'全唐诗/poet.song.179000.json','["諸老都淪謝，惟公尚典刑。", "謀謨關社稷，風采聳朝廷。", "政路方虛席，台躔遽折星。", "幸哉芳史在，寧用問丹青。"]'),
('229a4a0e-5bf7-4a9b-a8e5-5029255038c6','輓吳郎中','程珌','宋','宋诗','song-poetry','','[]','志抗金堅厲，材成玉粹溫。',48,'全唐诗/poet.song.179000.json','["志抗金堅厲，材成玉粹溫。", "時哉非不遇，命也更奚言。", "季子風流遠，吳公治行存。", "敬亭無恙否，愁絕暮雲昏。"]'),
('86961a9e-3f41-4646-8d55-17fd311e91be','輓程樞密  其一','程珌','宋','宋诗','song-poetry','','[]','厚德推吾黨，脩名靄列紳。',48,'全唐诗/poet.song.179000.json','["厚德推吾黨，脩名靄列紳。", "明經魁別幙，仗節聘殊鄰。", "南嶠思良牧，西樞失重臣。", "龍原高冢在，千古卧麒麟。"]'),
('4a10c494-edd2-489f-97b1-6e692f2c2c61','輓程樞密  其二','程珌','宋','宋诗','song-poetry','','[]','忠壯源尤遠，新安盛莫偕。',48,'全唐诗/poet.song.179000.json','["忠壯源尤遠，新安盛莫偕。", "千年瑶斗柄，一夜玉樓階。", "學業光文簡，儀刑謝艮齋。", "曉鍾傳恨處，清泪落天涯。"]'),
('affab852-587e-4530-a832-372f12e480f3','輓宜人趙氏','程珌','宋','宋诗','song-poetry','','[]','分胄天皇媛，來嬪相國孫。',48,'全唐诗/poet.song.179000.json','["分胄天皇媛，來嬪相國孫。", "孝慈山上梓，法度澗濱蘩。", "鳳去簫沉響，鸞空鏡掩痕。", "家庭熏沐事，千古說南軒。"]'),
('0a17e497-1d12-48e6-9fbe-7f4b04a5085b','輓徐提舉','程珌','宋','宋诗','song-poetry','','[]','人品真豪爽，天姿尚典刑。',48,'全唐诗/poet.song.179000.json','["人品真豪爽，天姿尚典刑。", "晝簾深院宇，春旆擁郊坰。", "雲子千艘白，鹽烟萬竈青。", "南州高士傳，三嘆一彫零。"]'),
('88b2192b-42d9-4a4c-91a3-293f6ab34b7a','輓蔡祭酒','程珌','宋','宋诗','song-poetry','','[]','孝友尊前哲，詞章裕後生。',48,'全唐诗/poet.song.179000.json','["孝友尊前哲，詞章裕後生。", "柏臺真御史，槐市大司成。", "騏驥風方力，艅艎浪忽傾。", "山寒丹旐急，識者爲霑纓。"]'),
('f57ad312-ce2b-42ad-97c4-0d4710160e45','輓曹監丞  其一','程珌','宋','宋诗','song-poetry','','[]','學渺千江水，才雄百尺樓。',48,'全唐诗/poet.song.179000.json','["學渺千江水，才雄百尺樓。", "鳬飛思葉縣，燕寢憶蘇州。", "有感珠還浦，無苛虎渡洲。", "浦江天闊處，缺月正如鈎。"]'),
('cdd4d35e-75f5-4805-a2e8-a4a1f1dca1bd','輓曹監丞  其二','程珌','宋','宋诗','song-poetry','','[]','威鳳方翔漢，寒鴉已宿林。',48,'全唐诗/poet.song.179000.json','["威鳳方翔漢，寒鴉已宿林。", "平生惟好士，無日不揮金。", "駟牡頻催駕，琵琶遽絕音。", "山名昇白日，回首一霑襟。"]'),
('69af883a-008f-4d2e-9fd8-5bf4e50445de','輓錢塘蔡令君','程珌','宋','宋诗','song-poetry','','[]','少年思賈誼，中壽憶賓王。',48,'全唐诗/poet.song.179000.json','["少年思賈誼，中壽憶賓王。", "軍政存鍾阜，民庸在括蒼。", "馬蹄歸鳳闕，車軸折羊腸。", "喚起青油夢，悲風攪白楊。"]'),
('bccee82b-00f5-4a1c-b6b3-5be4ac66f8ae','輓王柳州','程珌','宋','宋诗','song-poetry','','[]','才華唐令君，名勝晉參軍。',48,'全唐诗/poet.song.179000.json','["才華唐令君，名勝晉參軍。", "善政流郴水，遺風襲縉雲。", "寶釵當自合，神劍不中分。", "心折白巖路，猿吟日未曛。"]'),
('6da5919c-628b-436f-9117-436017b07d7f','輓楊提舉','程珌','宋','宋诗','song-poetry','','[]','風慘琳宮曉，雲愁鐵甕春。',48,'全唐诗/poet.song.179000.json','["風慘琳宮曉，雲愁鐵甕春。", "鴻冥方避弋，鱣集遽成塵。", "金虎多遺愛，銀菟愧後人。", "尋思漢循吏，竹帛逐時新。"]'),
('748ba519-1586-4457-92f7-93165c02f3a7','五十六字庸以告未知野夫者','程珌','宋','宋诗','song-poetry','','[]','寧須山澤論高平，但要曾餐石决明。',64,'全唐诗/poet.song.179000.json','["寧須山澤論高平，但要曾餐石决明。", "三世擊鍾敲石磬，十年學劍斮銅釘。", "倘知狐祖天邊去，肯向蠻奴脚底行。", "更許野夫尋上著，十洲三島一宮城。"]'),
('b881659b-227b-437f-b1ab-977268a2ad54','慶元丁巳十月奉親如臨安宿西菩寺表弟吳克仁俱焉  其一','程珌','宋','宋诗','song-poetry','','[]','熙寧相望百餘年，又有人如古鐵頑。',64,'全唐诗/poet.song.179000.json','["熙寧相望百餘年，又有人如古鐵頑。", "日落尚憐今夕路，月明無恙舊時山。", "朱紅野實堆盤裏，粉白詩牌滿壁間。", "欲爲慈顔供一笑，更留數語任渠刪。"]'),
('62eaa7a0-54c4-4488-8685-fd8d95b2aac5','慶元丁巳十月奉親如臨安宿西菩寺表弟吳克仁俱焉  其二','程珌','宋','宋诗','song-poetry','','[]','安車未向都門移，且攬西菩一段奇。',64,'全唐诗/poet.song.179000.json','["安車未向都門移，且攬西菩一段奇。", "路入山腰須種樹，泉流石齒莫開池。", "重來坡老今誰是，出世參寥不記時。", "結束匆匆出門去，白雲明月舊相知。"]'),
('df6bcd03-7cc6-4e31-83a9-acb6669caff5','用朱經畧韻','程珌','宋','宋诗','song-poetry','','[]','歸來南橐舊蕭蕭，但有新詩照佩瑶。',64,'全唐诗/poet.song.179000.json','["歸來南橐舊蕭蕭，但有新詩照佩瑶。", "峴首溪山歸點染，湘天風月困吟嘲。", "輕裘詩帥風流在，岳牧詞臣意氣饒。", "見說玉堂須翰手，公當歸侍紫宸朝。"]'),
('e912e01f-a5a9-4462-a680-a1c9921610ed','用丘樞密韻','程珌','宋','宋诗','song-poetry','','[]','起自澄江應夢求，天還河北百餘州。',64,'全唐诗/poet.song.179000.json','["起自澄江應夢求，天還河北百餘州。", "嵩瀍處士歸羅致，淮蔡奇謀入彀收。", "午夜金陵瞻斗極，千年胡昴滅旄頭。", "會須再作中興曆，還許諸生執筆不。"]'),
('86de698d-3e7f-4286-bbea-c6627e7f14d4','作堂六桂之東命之曰桂生取漢人招隠篇桂樹叢生之語也詩以記之','程珌','宋','宋诗','song-poetry','','[]','幾年列植擅清芳，今日標題始作堂。',64,'全唐诗/poet.song.179000.json','["幾年列植擅清芳，今日標題始作堂。", "遠向松岡分老蔭，近於菊畹借寒香。", "地雖未離人間世，心已全然物外鄉。", "最好夜來清絕處，飛霜带月下南塘。"]'),
('5299ec78-f130-4fba-9b3a-f215029e1a85','賀費樞密登卞忠貞公墓','程珌','宋','宋诗','song-poetry','','[]','底用荒村訪野墳，青編相對儼如存。',64,'全唐诗/poet.song.179000.json','["底用荒村訪野墳，青編相對儼如存。", "當年但識清談樂，今日方知節概尊。", "千載腐儒空吊古，幾章冷語自消魂。", "便當僇力清河洛，一洗新亭舊泪痕。"]'),
('438d623b-25b8-4c0b-9603-c3cfd0477888','流觴西湖用范左史韻','程珌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','畫航同載若登仙，却笑泥韉馬不前。',64,'全唐诗/poet.song.179000.json','["畫航同載若登仙，却笑泥韉馬不前。", "要識冷煙催穀雨，須知澹日養花天。", "千條翠柳隨風舞，一樹夭桃照水妍。", "須信人生行樂耳，虛名那用世間傳。"]'),
('021af059-3597-4cc9-9659-21e44e04fcde','雪','程珌','宋','宋诗','song-poetry','','[]','北風傳信報登平，白帝宸遊墮玉英。',64,'全唐诗/poet.song.179000.json','["北風傳信報登平，白帝宸遊墮玉英。", "月下草玄疑蜀客，鼎邊得句失軒明。", "莊嚴東閣若爲好，點綴南枝分外清。", "惟恨蔡州城北水，一池鵝鴨更無聲。"]'),
('92e95db6-11a4-42c4-b15f-12d645bacf99','小憩許由亭','程珌','宋','宋诗','song-poetry','','[]','曆數河南去，乾坤一草亭。',24,'全唐诗/poet.song.179000.json','["曆數河南去，乾坤一草亭。", "一亭猶是累，千古盡浮萍。"]'),
('d3629d7c-e8e0-476c-8ac8-1dd0ce73cc6f','喬松','程珌','宋','宋诗','song-poetry','','[]','風細吹吟鳳，雷驚起蟄龍。',24,'全唐诗/poet.song.179000.json','["風細吹吟鳳，雷驚起蟄龍。", "幾年卧空谷，今日享真封。"]'),
('2d9c296e-a4ea-4368-8706-7f3e0fa847df','歲暮','程珌','宋','宋诗','song-poetry','','[]','綵帖隃麋濕，屠蘇琥珀濃。',24,'全唐诗/poet.song.179000.json','["綵帖隃麋濕，屠蘇琥珀濃。", "夕陽猶臘日，午夜已春風。"]'),
('9a94bb77-bccb-498d-b0fa-a8791a83759b','三月三日度白際','程珌','宋','宋诗','song-poetry','','[]','日望黄尖杪，今登白際巔。',24,'全唐诗/poet.song.179000.json','["日望黄尖杪，今登白際巔。", "千山皆委地，一臂獨擎天。"]'),
('33ceb3be-0e3d-42c8-bdc7-746568f7d523','戊子正旦賀壽慈宮  其一','程珌','宋','宋诗','song-poetry','','[]','曙色浮丹栱，春風煖禁街。',24,'全唐诗/poet.song.179000.json','["曙色浮丹栱，春風煖禁街。", "微瀾迷秀石，纖草蔭新槐。"]'),
('f0c69a22-44f2-45b2-ae23-e65d303cc1cb','戊子正旦賀壽慈宮  其二','程珌','宋','宋诗','song-poetry','','[]','鳳駕回天仗，鴛班集露門。',24,'全唐诗/poet.song.179000.json','["鳳駕回天仗，鴛班集露門。", "須臾趨魏闕，杲日正中暾。"]'),
('d23b10f5-cae1-44b0-8671-a64f467036b0','粥罷','程珌','宋','宋诗','song-poetry','','[]','飯已茶三啜，隅中粥一盂。',24,'全唐诗/poet.song.179000.json','["飯已茶三啜，隅中粥一盂。", "陶然詠皇化，安用東封書。"]'),
('be92933a-04c5-4871-b68f-a20fe72defb3','冰','程珌','宋','宋诗','song-poetry','','[]','白日黄流漲渭城，三更風緊盡成冰。',32,'全唐诗/poet.song.179000.json','["白日黄流漲渭城，三更風緊盡成冰。", "莫言此物渾無用，曾向滹沱渡漢兵。"]'),
('64da2dac-1a0d-41ef-b1d9-cffea32d9547','甘將軍廟','程珌','宋','宋诗','song-poetry','','[]','沙寒日薄水雲愁，賊魏王吳一夜休。',32,'全唐诗/poet.song.179000.json','["沙寒日薄水雲愁，賊魏王吳一夜休。", "自是英雄元不死，至今猶占大江流。"]'),
('af17ef77-2012-45a3-a6ff-1bdd02b5859d','晚發富池','程珌','宋','宋诗','song-poetry','','[]','甘王樓下一帆風，獵獵舟旗照日紅。',32,'全唐诗/poet.song.179000.json','["甘王樓下一帆風，獵獵舟旗照日紅。", "釃酒三江飲龍腹，摩挲冠冕是誰功。"]'),
('65acbf5b-c3e9-4936-be78-d9d5b8adc5eb','昭明太子宮','程珌','宋','宋诗','song-poetry','','[]','千章喬木烟蒼蒼，一帙遺文字字香。',32,'全唐诗/poet.song.179000.json','["千章喬木烟蒼蒼，一帙遺文字字香。", "梁鼎西沉何處問，至今戟手看興亡。"]'),
('b23ea9cc-8272-4398-8a56-bb05896c15a1','陳時柏','程珌','宋','宋诗','song-poetry','','[]','陳未亡時柏已蒼，風來歷歷說興亡。',32,'全唐诗/poet.song.179000.json','["陳未亡時柏已蒼，風來歷歷說興亡。", "世臣元不如喬木，閲盡中原幾戰場。"]'),
('121af5b9-90d4-4de9-b44b-0312f08f1ee9','夜雨','程珌','宋','宋诗','song-poetry','','[]','玄機粗透古人胸，每說匡來晚未工。',32,'全唐诗/poet.song.179000.json','["玄機粗透古人胸，每說匡來晚未工。", "珍重芭蕉前夜雨，爲傳消息到牆東。"]'),
('4b828a32-4033-49eb-afc9-ecef5f361a7c','築徑','程珌','宋','宋诗','song-poetry','','[]','入門一徑小紆回，百本芙蓉手自栽。',32,'全唐诗/poet.song.179000.json','["入門一徑小紆回，百本芙蓉手自栽。", "寄語後來須善護，三年猶及見三開。"]'),
('435f640a-03de-408c-bb79-7e8d0349f261','觀史有感','程珌','宋','宋诗','song-poetry','','[]','紛紛賓客趨驃騎，何事任安太樸疏。',32,'全唐诗/poet.song.179000.json','["紛紛賓客趨驃騎，何事任安太樸疏。", "却笑君非王太傅，不容朝士不回車。"]'),
('94f75171-2357-42e5-9de6-eebe0c192730','別金陵官舍雙柏','程珌','宋','宋诗','song-poetry','','[]','手自移時尺許長，三年拂拂及宮牆。',32,'全唐诗/poet.song.179000.json','["手自移時尺許長，三年拂拂及宮牆。", "願言勿負栽培力，保此堅貞傲雪霜。"]'),
('91a9eacf-8f06-4b81-b30d-096db4a15d30','復朱教授  其一','程珌','宋','宋诗','song-poetry','','[]','詩成催雪豈無功，今果裝嚴七寶公。',32,'全唐诗/poet.song.179000.json','["詩成催雪豈無功，今果裝嚴七寶公。", "休說春花那解舞，也教耳熱慰新豐。"]'),
('1bba33dd-aa3e-43e0-a94e-83ae26181d12','復朱教授  其二','程珌','宋','宋诗','song-poetry','','[]','朝來照眼百瓊瑰，爲有詩筒打雪來。',32,'全唐诗/poet.song.179000.json','["朝來照眼百瓊瑰，爲有詩筒打雪來。", "不止梁園許分簡，詩壇高築比雲臺。"]'),
('cd0c95b8-bc9f-4e34-8333-e4a3751bde89','送李侍郎安撫浙東  其一','程珌','宋','宋诗','song-poetry','','[]','通明殿上紫芝仙，乞得閑身下九天。',32,'全唐诗/poet.song.179000.json','["通明殿上紫芝仙，乞得閑身下九天。", "今日都門臨祖處，幾人驚嘆著鞭先。"]'),
('6ae98d96-8c9c-427a-bb6f-7f7bb91d4176','送李侍郎安撫浙東  其二','程珌','宋','宋诗','song-poetry','','[]','夜來天闕望文昌，移在藩臣斗極旁。',32,'全唐诗/poet.song.179000.json','["夜來天闕望文昌，移在藩臣斗極旁。", "千尺濤江元不遠，公當早晚對明光。"]'),
('c3b4dfcc-cd73-44e9-8305-978ca6e20a06','直廬閒賦  其一','程珌','宋','宋诗','song-poetry','','[]','一陪鸞鳳入仙臺，四見薰風舞禁槐。',32,'全唐诗/poet.song.179000.json','["一陪鸞鳳入仙臺，四見薰風舞禁槐。", "自笑平生無夢到，那知今日以身來。"]'),
('f2f7e27e-abbc-4ecd-a3cf-e10ab682358a','直廬閒賦  其二','程珌','宋','宋诗','song-poetry','','[]','紫宸朝退曉光寒，百吏奔曹一吏閑。',32,'全唐诗/poet.song.179000.json','["紫宸朝退曉光寒，百吏奔曹一吏閑。", "便可雲卿稱散秩，柰何名籍尚人間。"]'),
('9eebcb98-89ef-4913-a6dc-dcdd4902465f','雪霽玉堂曉眺','程珌','宋','宋诗','song-poetry','','[]','當年銀界隔鯨江，今日分明玉作堂。',32,'全唐诗/poet.song.179000.json','["當年銀界隔鯨江，今日分明玉作堂。", "不是瓊林宮樹密，也應白虎接明光。"]'),
('90e557bf-e946-4364-91ff-4f3e1d16c03f','兩炬並花','程珌','宋','宋诗','song-poetry','','[]','雙蓮合蕊更開花，報道金鑾日未斜。',32,'全唐诗/poet.song.179000.json','["雙蓮合蕊更開花，報道金鑾日未斜。", "已草禁中新鳳詔，趣君十日覲東華。"]'),
('fcd415fd-b276-4186-8e15-30bdc7121f5f','脩玉牒官閣子坐屏甚古詰吏亦不知曷始數語紀之  其一','程珌','宋','宋诗','song-poetry','','[]','摩詰何年留此筆，至今雙壁猶崷崒。',32,'全唐诗/poet.song.179000.json','["摩詰何年留此筆，至今雙壁猶崷崒。", "老松掀甲作風雲，亂石激流殷霹靂。"]'),
('b96cc7c4-f8a4-4f4a-8b0e-0c57a7c1fa58','脩玉牒官閣子坐屏甚古詰吏亦不知曷始數語紀之  其二','程珌','宋','宋诗','song-poetry','','[]','吳綃一幅苦無多，中涵大華及黄河。',32,'全唐诗/poet.song.179000.json','["吳綃一幅苦無多，中涵大華及黄河。", "偶然乘風山下坐，紫烟翠靄坐中過。"]'),
('50d2b57c-ef04-4b44-a785-f4b321f7c201','早入','程珌','宋','宋诗','song-poetry','','[]','紫薇浥露翠條深，捷捷靈烏振好音。',32,'全唐诗/poet.song.179000.json','["紫薇浥露翠條深，捷捷靈烏振好音。", "全似冰巖亭上坐，四屏煙靄奏春禽。"]'),
('c4f43eee-c603-4220-be93-7a487010cdf5','直廬多暇新綠鬰然信筆二絕  其一','程珌','宋','宋诗','song-poetry','','[]','朝絕倖恩除目少，邊清妖祲檄書希。',32,'全唐诗/poet.song.179000.json','["朝絕倖恩除目少，邊清妖祲檄書希。", "飯餘摩腹閑行立，一抹牆東新翠薇。"]'),
('596a8713-fd5e-4fd8-90f4-77454ae61d07','直廬多暇新綠鬰然信筆二絕  其二','程珌','宋','宋诗','song-poetry','','["\u592a\u6e56"]','壁右方壺浸碧天，依然全似太湖邊。',32,'全唐诗/poet.song.179000.json','["壁右方壺浸碧天，依然全似太湖邊。", "清風一夜生新興，好把漁竿上釣船。"]'),
('bb6e2b7b-3f5c-4891-b2c9-e683cb9f06ad','江山道中瀑布','程珌','宋','宋诗','song-poetry','','[]','松風一壑逼人寒，老石瑽瑽響碧湍。',32,'全唐诗/poet.song.179000.json','["松風一壑逼人寒，老石瑽瑽響碧湍。", "疑是銀河天不鎖，瀉從雲際下人間。"]'),
('55630fe5-4d8d-4c01-b9ed-08f030e0216a','梔花','程珌','宋','宋诗','song-poetry','','[]','青琅削葉玉花鈿，獨占炎皇第一天。',32,'全唐诗/poet.song.179000.json','["青琅削葉玉花鈿，獨占炎皇第一天。", "未羨冰桃垂夏後，且看金子粲秋前。"]'),
('b434d757-b7d2-434e-b2fc-0b433ef76a20','朱生論天','程珌','宋','宋诗','song-poetry','','[]','不知占得幾躔星，閲盡人間聚散萍。',32,'全唐诗/poet.song.179000.json','["不知占得幾躔星，閲盡人間聚散萍。", "今日重來橋上望，依然楊柳兩行青。"]'),
('b126669b-cb6e-41a5-bfd9-a3d113fe2af5','爲釣臺作','程珌','宋','宋诗','song-poetry','','[]','人道秋風長桂時，天台散種未爲遲。',32,'全唐诗/poet.song.179000.json','["人道秋風長桂時，天台散種未爲遲。", "如君算到白榆窟，揀取南來第一枝。"]'),
('0c1f441d-5253-4686-b998-baa67b09c79d','擁爐','程珌','宋','宋诗','song-poetry','','[]','已甘灰冷竹窗前，那意移來近繡氈。',32,'全唐诗/poet.song.179000.json','["已甘灰冷竹窗前，那意移來近繡氈。", "唯有幽人一寒暑，閉門高卧雪深天。"]'),
('ae64454b-4ea3-4eb3-8059-e19e28cf1501','中秋無月','程珌','宋','宋诗','song-poetry','','[]','常時斗暗猶閑事，無月中秋可若何。',32,'全唐诗/poet.song.179000.json','["常時斗暗猶閑事，無月中秋可若何。", "我欲梯雲千萬丈，取光還月謝羲娥。"]'),
('49f96ddf-5a1d-4c56-849a-cd4078179ada','春帖','程珌','宋','宋诗','song-poetry','','[]','輕烟薄霧鎖平川，全似江南二月天。',32,'全唐诗/poet.song.179000.json','["輕烟薄霧鎖平川，全似江南二月天。", "昨夜溪頭新雨過，分明洗出太平年。"]'),
('2141964d-d4fe-4a58-b5c0-00be1628210a','程掌書  其一','程珌','宋','宋诗','song-poetry','','[]','夜來踏月過臨川，水面粼粼桂魄圓。',32,'全唐诗/poet.song.179000.json','["夜來踏月過臨川，水面粼粼桂魄圓。", "此際高人方熟寐，難爲一扣綠筠軒。"]'),
('a7123b02-6b18-4992-8912-86f7e1243d4f','程掌書  其二','程珌','宋','宋诗','song-poetry','','[]','分明如夢縞玄衣，傍月凌風自在飛。',32,'全唐诗/poet.song.179000.json','["分明如夢縞玄衣，傍月凌風自在飛。", "夢覺出門都不見，不知已上子陵磯。"]'),
('f32a7c7c-0a5f-4e09-a7f3-160f5e65db34','孟夏廿一東作秩然','程珌','宋','宋诗','song-poetry','','[]','不見東耕四十年，茲晨蓑笠去翩翩。',32,'全唐诗/poet.song.179000.json','["不見東耕四十年，茲晨蓑笠去翩翩。", "從今數過三蓂朔，史筆當年大有篇。"]'),
('3a47bfc0-f493-4ece-8839-80490542cac3','五鼓夢中作覺而成之  其一','程珌','宋','宋诗','song-poetry','','[]','人生萬幻一氂輕，須築銅駝萬里城。',32,'全唐诗/poet.song.179000.json','["人生萬幻一氂輕，須築銅駝萬里城。", "莫道斜陽光不遠，斷霞收盡十分明。"]'),
('6078c448-c4d2-4324-8b43-74c56e95c268','五鼓夢中作覺而成之  其二','程珌','宋','宋诗','song-poetry','','[]','當時千駟已無聞，寧說牛羊上塚行。',32,'全唐诗/poet.song.179000.json','["當時千駟已無聞，寧說牛羊上塚行。", "同是博陵評古者，肯令千載尚齦卿。"]'),
('1c3cc2f1-9c2c-49b7-ba1d-e7d4b5e6a338','閏九十四','程珌','宋','宋诗','song-poetry','','[]','午夜青衣海上還，八年兩度雪封山。',32,'全唐诗/poet.song.179000.json','["午夜青衣海上還，八年兩度雪封山。", "如今一水平如鏡，好釣桐江五百灘。"]'),
('048494ce-fd39-4f29-ae0b-454c0bd99c47','送松煤十丸與葉秀才','程珌','宋','宋诗','song-poetry','','[]','雲溪深處萬松林，煙起晴天自作塵。',32,'全唐诗/poet.song.179000.json','["雲溪深處萬松林，煙起晴天自作塵。", "根向九華分結處，與君同是墨仙人。"]'),
('f8b5342a-8c84-47ee-ac8a-8f0b7b5c0029','出南郊清甚','程珌','宋','宋诗','song-poetry','','[]','春風吹屣到南園，著酒塗酥花正繁。',32,'全唐诗/poet.song.179000.json','["春風吹屣到南園，著酒塗酥花正繁。", "更喜滿前無俗物，橫塘疏竹渭南村。"]'),
('0ca5fe48-94d8-46ac-a297-e711e21642af','輓太府丞知徽州韓公','程珌','宋','宋诗','song-poetry','','[]','翊運勛臣第一家，却於翰墨掇英華。',32,'全唐诗/poet.song.179000.json','["翊運勛臣第一家，却於翰墨掇英華。", "誰知忠孝千年事，不逐春風落水花。"]'),
('1c951425-b24a-4540-98c2-0bb8ab12b216','魯國夫人薤露歌','程珌','宋','宋诗','song-poetry','','[]','並海名山萬疊開，太慈太白等蓬萊。',32,'全唐诗/poet.song.179000.json','["並海名山萬疊開，太慈太白等蓬萊。", "自從齊國鋤雲後，又見夫人駕鶴來。"]'),
('f510fdb9-2c5b-405a-847a-bacf96f4d6df','建康鹿鳴宴致語','程珌','宋','宋诗','song-poetry','','[]','河南貢士紫萄詩，不比尋常貢士時。',64,'全唐诗/poet.song.179000.json','["河南貢士紫萄詩，不比尋常貢士時。", "一老堂堂强國棟，四筵濟濟瑞庭芝。", "傳聞座主趨璜召，恰與諸生赴詔期。", "宴罷瓊林如謁謝，請君懷刺鳳凰池。"]'),
('ff9307e5-689d-429a-a69a-91e67e132b2a','建康春教致語','程珌','宋','宋诗','song-poetry','','[]','朝來百鼓殷軍門，知是元戎肅萬屯。',64,'全唐诗/poet.song.179000.json','["朝來百鼓殷軍門，知是元戎肅萬屯。", "殺氣直摧龍尾壘，英風遠薄鬭場村。", "從今吳卒精成勇，却看燕兵脆可掀。", "好入廟堂裨聖畧，指麾諸將定中原。"]'),
('fc2f75f3-2d8a-402c-94ac-48dea40c8651','聖節致語','程珌','宋','宋诗','song-poetry','','[]','雉尾差參寶扇開，九霞雙闕聳蓬萊。',64,'全唐诗/poet.song.179000.json','["雉尾差參寶扇開，九霞雙闕聳蓬萊。", "霜清法駕黄金殿，雲擁仙班紫玉杯。", "天上剖符初繞電，人間作頌已鳴雷。", "長生紀籙知多少，瓠子澄清一萬回。"]'),
('09ce7152-8378-4c2d-b3cb-f6da6af549df','王母致語','程珌','宋','宋诗','song-poetry','','[]','青鳥銜餌海邊來，報道羣仙浴佛回。',64,'全唐诗/poet.song.179000.json','["青鳥銜餌海邊來，報道羣仙浴佛回。", "玉侍雙成開翠箔，雲冠七勝下銀臺。", "萬年黎角丹方轉，千歲冰桃花欲開。", "更待丹成桃熟後，却來親奉紫宸杯。"]'),
('7984d2c3-5583-473b-8ce8-1a75688fa877','用柏梁體題式敬齋','程珌','宋','宋诗','song-poetry','','[]','惟古知哲粲青編，胡爲典獄難其賢。',280,'全唐诗/poet.song.179000.json','["惟古知哲粲青編，胡爲典獄難其賢。", "皋陶蘇公相後先，舍是未見書聯翩。", "果哉知仁人難全，未得其情智欲研。", "既悉其罪乃寬旃，吾心鈞石何所偏。", "服而舍之天則然，畫冠不犯何由緣。", "教明化洽上所宣，上失其道民乃愆。", "又復淫刑如蔓延，立法初意浸天淵。", "苗民作威天棄捐，聖神應運符握乾。", "春風甘雨徧八埏，內外建官相綜絟。", "州復設掾職其專，此蓋椎輪當益虔。", "縣令獄掾非充員，渠用資格宜加銓。", "邢君天資靜不儇，且嘗一飲詩書泉。", "大府獄市來闐闐，嚴明之長日趨前。", "莫難此時周折還，三年一心上通天。", "荻苗水長問歸船，而君胡爲華此扁。", "吾非空扁乃心傳，上遡蘇公歲二千，下視方來漫無邊。", "吾乃𦕈然立中焉，來者式之不計年。"]'),
('484fd401-bf9f-416e-b845-2043b7f5fc68','題朝陽亭','程珌','宋','宋诗','song-poetry','','[]','暉暉朝陽亭，亭前鍾阜青。',252,'全唐诗/poet.song.179000.json','["暉暉朝陽亭，亭前鍾阜青。", "巖陰尚積雪，光彩浮初晴。", "亭下清溪水，滑流新泮冰。", "雙鳬知隨陽，亦逐流澌行。", "亭中賢主人，快此景物清。", "開門延客入，掬雪當泉烹。", "凌蹙淮水漲，修鱗爛銀瓶。", "更酌秦淮春，配此玉豉羹。", "了無一物俗，表裏俱蓬瀛。", "宇宙有佳致，心清境乃并。", "甚愛主人賢，澹然遺世營。", "不言飲人和，恂恂發天誠。", "清處亦絕奇，亭亭秋露莖。", "胸中足丘壑，城頭亦林埛。", "不與風月期，結屋謾茅菁。", "却慚最下客，形穢識不靈。", "宿懷幽深趣，侵尋塵坌攖。", "一官冷於鐵，癡坐如凍蠅。", "喚來俎豆問，不知梅已英。", "清賞可無傳，陋語恐難徵。", "春風送鵬程，睠言尋此盟。"]'),
('290af55c-6ed2-40ef-a2e9-aec4ce78d5e6','金陵驛','程珌','宋','宋诗','song-poetry','','[]','鐵甕高資只半程，柴溝曉發暮金陵。',32,'全唐诗/poet.song.179000.json','["鐵甕高資只半程，柴溝曉發暮金陵。", "莫言三宿何濡滯，已覺匆匆役此生。"]'),
('d43b65dc-33c0-43bc-b0ed-e84e27fe6bfe','登石頭城','程珌','宋','宋诗','song-poetry','','[]','邂逅鄉人却異方，蹇馿仍得瘦東陽。',64,'全唐诗/poet.song.179000.json','["邂逅鄉人却異方，蹇馿仍得瘦東陽。", "不妨令節隨流水，自看寒花吐晚香。", "微岸綸巾風力勁，小亭飛醆午陰長。", "不堪細數淮南樹，獨倚青冥興欲狂。"]'),
('34692dca-7bd6-41b0-a36e-d6b4005b4d75','孤山行','釋居簡','宋','宋诗','song-poetry','','[]','盛時考槃古逸民，湖山草木咸知名。',256,'全唐诗/poet.song.179000.json','["盛時考槃古逸民，湖山草木咸知名。", "至今八篇爛古錦，豈特五字如長城。", "長驅萬騎到其下，束手按甲循牆行。", "大邦維翰蔽騷雅，遐衝既折猶精神。", "抗衡劇孟一敵國，彈壓西子孤山春。", "死諸葛走生仲達，送修靖邀陶淵明。", "聚蚊莫及怒雷迅，老瓦不亂黄鍾鳴。", "清彈豈爲賞音廢，自芳更問林扉扃。", "鷗盟未冷浪拍拍，弋者何慕鴻冥冥。", "水流山空鶴態度，冰枯雪寒梅弟兄。", "梅當成實自調鼎，鶴既生子仍姓丁。", "鄉來偶同賦招隠，老去亦各相忘形。", "故廬夜夜月如晝，少微耿耿天無雲。", "千金儻可市駿骨，萬古適足空凡群。", "百身可贖但虛語，九原喚起知無因。", "爲公滿酌井花水，酹一抔土公應聞。"]'),
('90c89c70-d83a-4c76-bbb1-b8d1af685483','塘淫','釋居簡','宋','宋诗','song-poetry','','[]','蒼官百夫雄，盤錯千仞岡。',264,'全唐诗/poet.song.179000.json','["蒼官百夫雄，盤錯千仞岡。", "鐵幹紫尤勁，銅柯青更剛。", "屢吞霜雪敵，弗受斤斧戕。", "支厦不爲柱，跨壑猶飛梁。", "胡爲在泥滓，斷岸繄關防。", "豈伊堅貞姿，泥滓永相望。", "中分枵其中，脗合相抵當。", "彼巧事穿鑿，我方信行藏。", "惟其司出內，秉彝德之常。", "謹口飽涵畜，與時相抑揚。", "持滿豈無道，損餘端有方。", "尾閭小溟渤，砥柱回污潢。", "瞥爾手翻覆，枯涸隨汪洋。", "叔度萬頃陂，未足與較量。", "匠氏弗遇郢，才不登俊良。", "藐然用其小，約水不得洚。", "有若古豪雋，落落吞湖江。", "遭時發所藴，利澤何其厖。", "時哉倘不逢，蕙帳雲霧窗。", "獨善與兼善，一轍元非雙。", "任大豈遺小，養浩惟能降。", "對此一感慨，勿謂吾言哤。"]'),
('2a26e307-668f-4aae-9b16-67bcb6daf3b1','檄菖蒲','釋居簡','宋','宋诗','song-poetry','','[]','陶器承崑珉，獵獵散綠絲。',192,'全唐诗/poet.song.179000.json','["陶器承崑珉，獵獵散綠絲。", "飲以一杯水，卒歲長如斯。", "露葉矗鋒鍔，霜根蟠嶮巇。", "昌陽欲論功，十駕不得追。", "松柏脚踏土，並驅仍背馳。", "寒苦我所安，泉石皆聞知。", "豈意泉石間，得此償心期。", "澡濯冀懷新，疏剪貴適宜。", "芳潔日以薄，潜逐炎涼移。", "謂我水太清，汝便清漣漪。", "抑我水太渾，古井非污池。", "孤根要特立，晚節須堅持。", "貞姿或不返，終當怨尤誰。", "春葩與秋薌，擅美固有時。", "西風一摇落，不死將安之。", "亦足觀物化，亦足爲箴規。"]'),
('a5eba547-bc14-4f67-9902-ad579f3ff695','次宮講于素齋韻爲別  其一','釋居簡','宋','宋诗','song-poetry','','[]','鳬短何曾計鶴長，從他踽踽復凉凉。',64,'全唐诗/poet.song.179000.json','["鳬短何曾計鶴長，從他踽踽復凉凉。", "馬歸塞上元非失，弓在人間豈是亡。", "旋別薰蕕充子佩，賸栽紅白課蜂房。", "到家趁得梅花在，分遣飛來數點香。"]'),
('1ac9d45f-9460-4825-9b26-ce6634ba171a','次宮講于素齋韻爲別  其二','釋居簡','宋','宋诗','song-poetry','','[]','無言桃李各成春，造化番騰巧入神。',64,'全唐诗/poet.song.179000.json','["無言桃李各成春，造化番騰巧入神。", "佳境駸駸逢蔗尾，苦心隠隠飫猩唇。", "蠖雖善屈難忘直，虹豈長蟠不得伸。", "一日百畦機事了，區區亦有漢陰人。"]'),
('3b7281e0-2219-4ea1-ac9d-82e68935ced3','正月初九日客舍','釋居簡','宋','宋诗','song-poetry','','[]','水凍冰連底，山疑雪滿顛。',48,'全唐诗/poet.song.179000.json','["水凍冰連底，山疑雪滿顛。", "恰纔如舊臘，全不似新年。", "綿折何曾暖，柴生只擁煙。", "較他山店雨，枉自怨秋天。"]'),
('10c56f60-5e1d-4277-8290-cc11bf1629b2','上錢昭文','釋居簡','宋','宋诗','song-poetry','','[]','拄天有佳木，青跨雲沉沉。',240,'全唐诗/poet.song.179000.json','["拄天有佳木，青跨雲沉沉。", "不知幾何高，四海分清陰。", "悠然響虛籟，萬象寂若瘖。", "寒則爲陽和，盎盎春晝深。", "穆若吹清泠，六月消煩衿。", "烈風益遒勁，厚地盤崎嶔。", "濃翠出雲雨，大旱徯作霖。", "巍巍架明堂，枝幹端可尋。", "上有孤鳳凰，下有衆羽禽。", "和樂聲成文，戛擊韶濩音。", "大雅得指歸，一洗鄭衛淫。", "向來艱難際，凡才空滿林。", "天風一披拂，寸碧開遥岑。", "遂使化弦改，人命蟻出燖。", "大哉德曰生，抑見天地心。", "悠悠江海人，蜀道捫井參。", "懷土如仲宣，破囊無一簪。", "回首白玉霄，欲往勇不禁。", "區區竟何有，有句如惜金。", "金亦不足惜，鑄作頌與箴。"]'),
('da6b04a0-8e94-432d-aeba-ae5de185e31e','早課','釋居簡','宋','宋诗','song-poetry','','[]','井花嫩煮熨梅花，先酌芳甘注佛茶。',32,'全唐诗/poet.song.179000.json','["井花嫩煮熨梅花，先酌芳甘注佛茶。", "冷淡工夫相次了，却留窗日看橫斜。"]'),
('f944a2fe-21c6-427f-a7e6-2660f76cbe73','水仙','釋居簡','宋','宋诗','song-poetry','','[]','矮叢傍砌小成陰，凍徹敷腴謝水沉。',64,'全唐诗/poet.song.179000.json','["矮叢傍砌小成陰，凍徹敷腴謝水沉。", "細著鮮風扶弱幹，賸將零露酌芳心。", "華裾冉冉低青綬，柔玉稜稜襯嫩金。", "弱水繞山三萬里，斷魂長記碧蕭森。"]'),
('837ef08e-593f-441a-af90-eb01acc605e1','和六一居士守汝陰禁相似物賦雪','釋居簡','宋','宋诗','song-poetry','','[]','漣漪碎剪成新萼，廉纖带雨尤輕薄。',224,'全唐诗/poet.song.179000.json','["漣漪碎剪成新萼，廉纖带雨尤輕薄。", "人間但見巧番騰，天上不知誰制作。", "九地瑕疵都粉飾，重雲揞塞難恢廓。", "曉光奪目增眩轉，夜色侵燈尤閃爍。", "康莊充斥去無路，老幹壓低摇不落。", "寒稜凍得水生皮，氣艷冷欺裘擁貉。", "可勝思苦相嘲謔，旋忘手凍爭拏攫。", "亂委平堆可照書，圓瑳小握供彈雀。", "靜聞裂竹亟扶顛，勇作探春思躡屩。", "犯寒果勝附炎熱，苦饑預慶歌豐樂。", "長鬚嫩煮蚓方泣，小龍新破團初瀹。", "默觀造物真戲劇，更看一色吞沙漠。", "載賡險韻付銜枚，孤軍大敵空橫槊。", "寡和尤知白雪高，非偶自貽齊大噱。"]'),
('b0456ff3-cbdf-4a48-bc73-621e291cd8ef','和東坡守汝陰禱雨張龍公祠得小雪會飲聚星堂用歐公故事','釋居簡','宋','宋诗','song-poetry','','[]','六花萼萼都無葉，萬花鬭白都輸雪。',160,'全唐诗/poet.song.179000.json','["六花萼萼都無葉，萬花鬭白都輸雪。", "緩飄微霰止還集，急趁回風飛欲絕。", "山固無愁鬢先老，竹非爲米腰頻折。", "鄉來囊螢本同調，今夕風燈不愁滅。", "僧窗處處茶煙濕，漁舟箇箇綸竿掣。", "老坡不犯汝南令，粲如晴午裁新纈。", "乾坤蕩蕩無畛畦，比類區區空瑣屑。", "霧沉雲重記葳蕤，雨收風拾書輕瞥。", "肯爲忠臣六月飛，賸煩太史從頭說。", "粗人金帳暖如春，詩人布衾冷如鐵。"]'),
('25d52eb2-d496-4d6c-a143-8d27173b6008','借榻妙上人小樓簡圓方外','釋居簡','宋','宋诗','song-poetry','','[]','透骨清貧兩苦心，圓方覓句妙方琴。',32,'全唐诗/poet.song.179000.json','["透骨清貧兩苦心，圓方覓句妙方琴。", "尚堪擁鼻麾崔烈，來借樓頭破布衾。"]'),
('da40ca9d-8134-4bab-9fa1-9e2ddfeb85b3','盆菊','釋居簡','宋','宋诗','song-poetry','','[]','葉底金莖沆瀣濃，籬邊令尹酒尊空。',32,'全唐诗/poet.song.179000.json','["葉底金莖沆瀣濃，籬邊令尹酒尊空。", "回頭說與閑花草，自占春三二月風。"]'),
('bb042dcf-13ed-4b25-8ccb-62f7dba9c0d3','寶溪鹿苑寺','釋居簡','宋','宋诗','song-poetry','','[]','唐刻文雖泐，梁時寺可稽。',48,'全唐诗/poet.song.179000.json','["唐刻文雖泐，梁時寺可稽。", "已無金布地，猶有寶名溪。", "水媚珠生浦，雲低篆繞畦。", "夜遥僧定起，璧月在璇題。"]'),
('c582fb0b-de01-48bb-932c-4569e300cede','鹿苑乃月堂昌禪師受業','釋居簡','宋','宋诗','song-poetry','','[]','水自朝宗去，源曾發此來。',48,'全唐诗/poet.song.179000.json','["水自朝宗去，源曾發此來。", "惠琳參政事，澄觀擅公才。", "葩焰古難續，襲衣今未開。", "不知五百世，幾度擢陳荄。"]'),
('a4a35d9a-e06b-4ace-b654-fe34eb6c5d27','送友人歸湖上','釋居簡','宋','宋诗','song-poetry','','[]','雲卷雲舒欠十成，暮霞曾誤客占晴。',32,'全唐诗/poet.song.179000.json','["雲卷雲舒欠十成，暮霞曾誤客占晴。", "不堪滿載朱涇月，冷落陽關第幾聲。"]'),
('4fc0dfc7-9065-4455-861f-f64c7ebe6bc9','雲錦亭','釋居簡','宋','宋诗','song-poetry','','[]','花圍竹護錦成林，簷壓紅雲遶砌深。',32,'全唐诗/poet.song.179000.json','["花圍竹護錦成林，簷壓紅雲遶砌深。", "燕子來時寒未了，莫教簾幕带春陰。"]'),
('2eeeaec1-35fa-4459-95c7-b87a01a22af9','秋塘陳敬父席上餞薛子舒之官建康','釋居簡','宋','宋诗','song-poetry','','[]','秋塘自是眼頭高，倒屣於君老更豪。',64,'全唐诗/poet.song.179000.json','["秋塘自是眼頭高，倒屣於君老更豪。", "興盡有時聊訪戴，法當無酒亦邀陶。", "鄉來文字如翻水，近日工夫又反騷。", "月是秦淮舊時月，平分只合與金刀。"]'),
('6ddf9ba0-d6d3-4365-a2f6-452b17c613f0','哭趙別駕子野','釋居簡','宋','宋诗','song-poetry','','[]','年高唐進士，官小魏諸王。',48,'全唐诗/poet.song.179000.json','["年高唐進士，官小魏諸王。", "落落青雲步，朣朣古錦囊。", "筆隨文塚瘞，劍返虎丘藏。", "分得閑風月，湖山不掩光。"]'),
('0d60eede-bd3f-409e-9cf9-e40f71f24552','謝張丹霞序疎藁','釋居簡','宋','宋诗','song-poetry','','[]','裳織新雲錦，交尋舊布衣。',240,'全唐诗/poet.song.179000.json','["裳織新雲錦，交尋舊布衣。", "荆蠻九鼎重，嶺海一官微。", "心事淵明是，天時伯玉非。", "談高方諤諤，調古獨巍巍。", "亦有蘭爲佩，能無簡絕韋。", "灌纓東磵水，訪舊北山薇。", "老我家何在，顛風鷁退飛。", "襪頭常反著，車轍每殊歸。", "但覺烏仍好，端知驥可睎。", "草中同臭少，爨下賞音稀。", "煮字徒相餉，忘言合見譏。", "牛腰繁卷軸，蚌腹欠珠璣。", "重借言如史，輕因鼠發機。", "毳雲甘寂寞，華衮借光輝。", "雞肋初無取，雲斤不足揮。", "樓寬長挂榻，月好許敲扉。", "踵息寧乖衆，心聲願聽希。", "李雖嘲杜瘦，孟不與韓違。", "末路宜多助，孤軍佇解圍。", "載驅慙款段，忍負鏤金鞿。"]'),
('6cd48437-ed94-4548-a537-cd4b4e710cef','趙紫芝得羌村圖拉余與趙山中同賦','釋居簡','宋','宋诗','song-poetry','','[]','中原聞休兵，久客問歸路。',156,'全唐诗/poet.song.179000.json','["中原聞休兵，久客問歸路。", "窮途倦策蹇，窘步甚脫兔。", "小立候柴荆，互闖走兒女。", "喜極先蹙頞，思苦旋煦嫗。", "觸緒盡愁態，撫膝見濡慕。", "諸鄰稚扶老，旨畜各携具。", "老瓦勇倒瀉，飛觴約深注。", "居者訴徵調，歸者訴羈旅。", "懽呼賀生還，不醉不肯住。", "哂乃驪山夢，奇警在團素。", "生靈果何罪，此禍竟誰與。", "眼明新畫軸，心折舊題處。", "掩卷續微吟，玉倚亭亭樹。"]'),
('c3952cd7-d1a8-4491-ab86-b0dea6a3858e','雪夜懷上人借衾','釋居簡','宋','宋诗','song-poetry','','[]','挾纊如冰薄，無氊替客愁。',48,'全唐诗/poet.song.179000.json','["挾纊如冰薄，無氊替客愁。", "綾衾閑直舍，布被老夔州。", "樓玉方撐起，山冰莫倚休。", "歲寒知小友，餘暖肯珍投。"]'),
('025448f7-e8bc-4a58-be24-13c3fb6e4e44','趙紫芝雪中見寄  其一','釋居簡','宋','宋诗','song-poetry','','[]','易銷知地燥，未濟識天慳。',48,'全唐诗/poet.song.179000.json','["易銷知地燥，未濟識天慳。", "凹凸難行處，模糊轉盼間。", "定應憑小檻，頻看釣滄灣。", "嫩煮添茶興，何須倒玉山。"]'),
('44783c3b-abe2-4c72-8ae5-b4048ffe3291','趙紫芝雪中見寄  其二','釋居簡','宋','宋诗','song-poetry','','[]','群峯驚易老，猶自替人寒。',48,'全唐诗/poet.song.179000.json','["群峯驚易老，猶自替人寒。", "有火雖紅擁，慵吟只白看。", "不妨添冷落，何暇掃零殘。", "小佇蘢葱日，銷鎔却怕難。"]'),
('c2ba978e-027a-4760-bf99-eeb63e6613c0','池雪','釋居簡','宋','宋诗','song-poetry','','[]','填得中心合，鋪成四面齊。',48,'全唐诗/poet.song.179000.json','["填得中心合，鋪成四面齊。", "寶奩方剪玉，璧範直裁圭。", "水鏡難呵霧，冰田不點泥。", "霜蟾都隔斷，弗許透靈犀。"]'),
('c9dfc267-96ff-4345-be19-ee8ff74fcad4','耕雲','釋居簡','宋','宋诗','song-poetry','','[]','雲子炊香欠策勳，無心亦作一廛耕。',32,'全唐诗/poet.song.179000.json','["雲子炊香欠策勳，無心亦作一廛耕。", "石田也似砂田瘦，不是冥搜太瘦生。"]'),
('2e87c2f4-abdd-4f55-897b-81f11697213e','茅屋','釋居簡','宋','宋诗','song-poetry','','[]','索得藑茆不足占，趁晴翦翦插疏簷。',32,'全唐诗/poet.song.179000.json','["索得藑茆不足占，趁晴翦翦插疏簷。", "弗圖炙背干閶闔，試策奇勳到黑甜。"]'),
('8b183d82-46ad-4993-b857-d3001ddaf4eb','酬陳中書楊侯家賞瑞蓮  其一','釋居簡','宋','宋诗','song-poetry','','[]','法自春秋著一王，不曾紀瑞到蓮塘。',64,'全唐诗/poet.song.179000.json','["法自春秋著一王，不曾紀瑞到蓮塘。", "露盤對倚金莖小，水鏡雙尋玉井凉。", "同樣著花仍並蒂，異篷結子不分房。", "會須問字求玄草，接武華風到後堂。"]'),
('46f6b34c-6a0e-46bb-860a-41ca1fd4ed2c','酬陳中書楊侯家賞瑞蓮  其二','釋居簡','宋','宋诗','song-poetry','','[]','傾城傾國儷侯王，千載餘芳託藕塘。',64,'全唐诗/poet.song.179000.json','["傾城傾國儷侯王，千載餘芳託藕塘。", "紅入雙葩相艷冶，綠摇萬柄覺凄凉。", "側承初日聯風袂，並挹殘蟾酌露房。", "花下詩人長不老，岧嶤直禁玉爲堂。"]'),
('8a7ca860-c566-4999-b4f9-85b09da8c323','少陵畫像','釋居簡','宋','宋诗','song-poetry','','[]','我思浣花翁，夢繞浣花水。',72,'全唐诗/poet.song.179000.json','["我思浣花翁，夢繞浣花水。", "有竹一頃餘，杜鵑暮春至。", "開元天寶間，九州暗風塵。", "新詩一洗滌，天地皆清明。", "槐葉一杯春，思君欲走致。", "悠然憂國心，天地相終始。"]'),
('35033d97-6682-40c3-9db5-3f45aad5ae48','賈長江畫像','釋居簡','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','苦吟京華春，韓門得歸鄉。',72,'全唐诗/poet.song.179000.json','["苦吟京華春，韓門得歸鄉。", "但知空啞羊，未暇識龍象。", "逢人問梓州，策蹇來長江。", "長江蛟龍怒，濤瀾相舂撞。", "公來一彈壓，熨帖平如鏡。", "新吟若爲容，萬古秋濤瑩。"]'),
('90ba7fe1-c055-4d78-bba6-48cf95e1bb57','送宇文尚書宣撫荆湘','釋居簡','宋','宋诗','song-poetry','','[]','偉哉不世才，要爲天下奇。',264,'全唐诗/poet.song.179000.json','["偉哉不世才，要爲天下奇。", "一鶚不待薦，自受虛皇知。", "力精運甓處，心切聞雞時。", "去年鎮南徐，前年來合淝。", "至今軍與民，念之如母慈。", "肖象繫遺愛，豈特甘棠思。", "便合登巖廊，虛襟待疇咨。", "春風玉筍班，夜光增陸離。", "荆楚天一方，有生懷保綏。", "不向繁劇地，何以觀設施。", "明明九重意，大任端自茲。", "諸儒浪誇詫，自許傅與伊。", "重內不重外，圖安不圖危。", "一旦大典章，瞢然如亂絲。", "始悟少更歷，雖悔將安追。", "有商六百年，不待試者誰。", "版築與割烹，中有輔相資。", "後世伊傅流，紛紛何多爲。", "公乎風塵際，卓犖起一夔。", "軒昂氣如虹，霹靂手欲龜。", "永懷更一行，策勳早言歸。", "坐理天下事，迎刃而解之。"]'),
('220464e1-4987-4752-9d07-d2bd2228fb94','山中像','釋居簡','宋','宋诗','song-poetry','','[]','之子瘦策湘竹枝，冩我委羽春耕時。',88,'全唐诗/poet.song.179000.json','["之子瘦策湘竹枝，冩我委羽春耕時。", "鞭索在手橫谿湄，看牛飲溪特子隨。", "開窗卷簾驚見之，有二文殊還自疑。", "鏡中瘦影絲髮無，參差又如飲谿牛。", "觜連觜，蹄踏蹄。", "恍然因我得見伊，不知見者端爲誰。"]'),
('ebac5a55-a372-486d-8b5b-a075a090ed73','丁丑除夕','釋居簡','宋','宋诗','song-poetry','','[]','結局又開端，更初數到殘。',48,'全唐诗/poet.song.179000.json','["結局又開端，更初數到殘。", "小須新過割，却問舊平安。", "事事從頭起，悠悠倒指看。", "六千三萬日，逐日度何難。"]'),
('e0d4b31a-7a2a-45de-9705-75ed5c5a20ff','松谿','釋居簡','宋','宋诗','song-poetry','','[]','翠蓋童童勝碧油，老根絡石漱谿流。',32,'全唐诗/poet.song.179000.json','["翠蓋童童勝碧油，老根絡石漱谿流。", "秋池兩部吾無取，留得江聲在屋頭。"]'),
('cd710f87-d55a-40af-bd52-c390e8b33e9a','正月初六觀燈','釋居簡','宋','宋诗','song-poetry','','[]','山歛吳雲暝幾層，卷簾都上內前燈。',32,'全唐诗/poet.song.179000.json','["山歛吳雲暝幾層，卷簾都上內前燈。", "朔蓂六葉初弦月，猶作朝天淡掃痕。"]'),
('779e43ba-e276-4bb7-adf0-cb5ae9e52cae','挽同衣  其一','釋居簡','宋','宋诗','song-poetry','','[]','有地皆堪隠，云胡獨指西。',48,'全唐诗/poet.song.179000.json','["有地皆堪隠，云胡獨指西。", "劫燒翻濁焰，剎說聽新題。", "春薺挑蘋渚，秋荷綴稻畦。", "覺天無落月，耿耿印苕溪。"]'),
('5f3e45e4-945b-4f24-a7b5-87ab35981f6d','挽同衣  其二','釋居簡','宋','宋诗','song-poetry','','[]','印佩三周法，蓮栽十丈花。',48,'全唐诗/poet.song.179000.json','["印佩三周法，蓮栽十丈花。", "源尋南岳正，路革化城差。", "靜與月分座，閑如雲住家。", "不知百世后，誰索紫金車。"]'),
('15d4e544-8b11-49ae-ae24-814946d5ae89','登齊雲樓','釋居簡','宋','宋诗','song-poetry','','[]','雲與簷楹面面齊，脚頭高處覺雲低。',64,'全唐诗/poet.song.179000.json','["雲與簷楹面面齊，脚頭高處覺雲低。", "水圍萬雉半煙雨，天徹四垂漫畛畦。", "冉冉無心猶可拊，堂堂有路亦堪梯。", "若非夢澤胸中小，空倚闌干到日西。"]'),
('d2402e11-52fe-469b-b1d3-6ba8f9bdc6c8','孤山路','釋居簡','宋','宋诗','song-poetry','','[]','截水開平地，浮天界碧空。',48,'全唐诗/poet.song.179000.json','["截水開平地，浮天界碧空。", "有雲分越鏡，無柳似吳虹。", "菱棹闌干外，荷花鑑影中。", "斷橋吟不盡，行過御溝東。"]'),
('0ca87c01-e8ac-4575-94c1-86503f7c0902','四月初八','釋居簡','宋','宋诗','song-poetry','','[]','只麽隨流去，如何慶佛生。',48,'全唐诗/poet.song.179000.json','["只麽隨流去，如何慶佛生。", "飄零嗟劫濁，湔洗俟河清。", "託諷知無益，讒諛又不情。", "韶陽奉塵剎，不薦一杯羹。"]'),
('1ac8dfbb-00bc-4fe3-8c56-627e5afe154f','續懶菴生前索挽章','釋居簡','宋','宋诗','song-poetry','','[]','死向生前辦，銘留去後思。',48,'全唐诗/poet.song.179000.json','["死向生前辦，銘留去後思。", "穴疑龍井迥，隣傍鳥窠移。", "殉有登山屐，傳無跨竈兒。", "它年三尺劍，誰挂碧松枝。"]'),
('2c64ca20-c5df-428d-8e04-b1689da79579','書智遷抵觸圖','釋居簡','宋','宋诗','song-poetry','','[]','力敵難教死鬭心，墨輕毫淡柳陰陰。',32,'全唐诗/poet.song.179000.json','["力敵難教死鬭心，墨輕毫淡柳陰陰。", "莫將抵觸迂奇思，只冩洪川扣角吟。"]'),
('dfafe706-bfed-4b00-8d83-9f5cd888473f','孤山前舉溺死者','釋居簡','宋','宋诗','song-poetry','','[]','柳色經秋草葑湖，菱荷彫盡到菰蒲。',32,'全唐诗/poet.song.179000.json','["柳色經秋草葑湖，菱荷彫盡到菰蒲。", "誰將處士孤山路，幻出天台九想圖。"]'),
('ac9ca7e4-f2c6-4844-8229-aed1c562ec88','酬韓澗泉','釋居簡','宋','宋诗','song-poetry','','[]','鄉來風騷壇，作者肩相摩。',240,'全唐诗/poet.song.179000.json','["鄉來風騷壇，作者肩相摩。", "遂使宋嘉定，不數唐元和。", "磵泉一官冷，門館雀可羅。", "管中既微露，屢倒名勝戈。", "自笑不入時，獨對兒女哦。", "錦瑟豈不好，弗好如之何。", "豈特弗好耳，平地千丈波。", "泠泠玉藕船，豈曾翻釣蓑。", "歸與造物游，坐受醉尉訶。", "雲月相獻酬，泉石供婆娑。", "幽芳時自妍，幽鳥時自歌。", "遺補南磵書，樂勝東山阿。", "懷哉東華門，白玉鳴朝珂。", "忸怩避讒謟，趑趄虞轗軻。", "聊將須臾忍，付與兩鬢皤。", "聽君閑適篇，所得誰最多。", "持此壽閑適，金蟇空坡陁。", "思君令人瘦，水遠山峩峩。", "寄聲謝鴻鵠，爲把青銅磨。", "莫嫌俗眼白，且惜朱顔酡。"]'),
('9c2c236d-8baa-4694-a2c7-8e69a1c0c4c9','吳吾何待制遣四鶴入山','釋居簡','宋','宋诗','song-poetry','','[]','竹扉無人敲，掩關長夕曛。',240,'全唐诗/poet.song.179000.json','["竹扉無人敲，掩關長夕曛。", "一饑苦難療，三篾收奇勳。", "鼎來四胎仙，縞袂垂玄帉。", "其一行且却，隠若避世紛。", "其一擬前邁，步武閑如雲。", "唳者又其次，畫然戛天垠。", "季氏響相答，和樂方誾誾。", "昂然青田英，暫爾北磵濆。", "鸞鵠倘可侶，雞鶩端不群。", "乘軒初何心，在陰當有聞。", "日飲澗底淥，時啄岩根芸。", "華表懷故都，蕙帳悲移文。", "仙凡豈異轍，風月當平分。", "主人爾同調，與俗相蕕薰。", "浪迹傃富貴，永懷酣典墳。", "衡連老蒼官，從合抱節君。", "遣爾尋考槃，亦足張吾軍。", "人方斧槁梧，對此齒沒齦。", "駸駸恐爾及，惴惴令人慬。", "胸中小天地，籠中何足云。"]'),
('ad0b6247-db39-4b05-97de-d71f59745d26','陳卿座上得貴字','釋居簡','宋','宋诗','song-poetry','','[]','後來如積薪，在前類揚粃。',288,'全唐诗/poet.song.179000.json','["後來如積薪，在前類揚粃。", "群飛刺天去，尋墜九地底。", "扶摇轉羊角，力盡固應爾。", "趙孟能賤之，何取趙孟貴。", "譬夫春方妍，處處耀桃李。", "冶容倚皓態，厥類叵勝紀。", "一時顔色鮮，永永曷足恃。", "要當見平生，姑待灝商至。", "楩楠大蔽牛，支厦棟梁器。", "春風不知喜，秋風不知畏。", "炎炎金石流，凜凜復墮指。", "四時有常守，坐看造物戲。", "用大古所難，肯顧萬牛廢。", "懷哉楚令尹，落落差可擬。", "彈冠既三仕，解冠輒三已。", "豈弗曰代耕，豈弗曰行志。", "終將奚以爲，了弗事慍喜。", "一笑付倘來，道在百不理。", "特操固超絕，小智謾嗟異。", "區區榮辱際，判然遂成二。", "炙手苟可熱，駢首爭附麗。", "欣戚變妻孥，况復論州里。", "悠哉經濟才，未始挂牙齒。", "不獨不過口，未必不掩鼻。"]'),
('dcd2dd00-015e-426c-b1ff-a8b9323964d8','黄龍洞前遇倪文昌賦苕之清','釋居簡','宋','宋诗','song-poetry','','[]','止止天連碧，沉沉鏡不磨。',120,'全唐诗/poet.song.179000.json','["止止天連碧，沉沉鏡不磨。", "淵源端有自，潢潦儘從他。", "清可臨流賦，渾貽濯足歌。", "中津誰擊楫，後進自盈科。", "亦有西馳者，其如北注何。", "還元雖一味，到了不同波。", "至潔清嚴瀨，孤忠歎汨羅。", "勺貪懲俗下，汲釀樂天和。", "洗耳成輕去，乘槎倘重過。", "咸池昇曉日，何必挽天河。"]'),
('76b5d255-9cf7-4134-8a5f-d1f6b14b7ad7','苕溪晚歸','釋居簡','宋','宋诗','song-poetry','','[]','輕羅熨帖展谿湄，濺沫飛濤頃刻移。',32,'全唐诗/poet.song.179000.json','["輕羅熨帖展谿湄，濺沫飛濤頃刻移。", "蓮子焦時紅蓼紫，采菱船小不禁吹。"]'),
('f4343a1f-6e8a-47cd-a915-7775767967e6','酬趙天樂','釋居簡','宋','宋诗','song-poetry','','[]','桂爲詩人馥，隣喧羯鼓催。',48,'全唐诗/poet.song.179000.json','["桂爲詩人馥，隣喧羯鼓催。", "秋窗無喚起，海石借飛來。", "眼老因山碧，襟疎並水開。", "何妨不解飲，對客淺持盃。"]'),
('2e0ad4d0-a8bc-4a85-b81d-cdf0437c159d','化周大孺人長明燈','釋居簡','宋','宋诗','song-poetry','','[]','古佛舒光照夜遥，微明欲灺倩誰挑。',32,'全唐诗/poet.song.179000.json','["古佛舒光照夜遥，微明欲灺倩誰挑。", "福田中有光明藏，試遣周郎問小喬。"]'),
('a053e3a2-a50c-4eca-8e53-9639ad9c87dc','吹香','釋居簡','宋','宋诗','song-poetry','','[]','寒壓痕雲凍不消，華風醖藉不鳴條。',32,'全唐诗/poet.song.179000.json','["寒壓痕雲凍不消，華風醖藉不鳴條。", "瘦枝褪煖無多韻，亦有鮮明玉色潮。"]'),
('db65e7a8-99a5-474c-abcc-8411343b62d0','芙蓉','釋居簡','宋','宋诗','song-poetry','','[]','谿痕寒不肥，岸容晚益退。',156,'全唐诗/poet.song.179000.json','["谿痕寒不肥，岸容晚益退。", "其誰憐婆娑，明霞剪零碎。", "爛爛飽泠露，酣酣俯清瀨。", "宛然古銅碧，嫣然靘粧對。", "又若翠袖薄，瘦立煙渚外。", "西風僅如許，晚節尚可待。", "遂拜拒霜號，不受斷腸浼。", "亦豈無老成，試請推行輩。", "桂騰小山馥，菊耀東籬采。", "裳襯芰荷衣，服稱陸離佩。", "芳芷雅相鄉，宿莽安敢背。", "花城隔仙凡，俗說信茫昧。", "獨有離騷經，名氏得先載。"]'),
('74276634-4c2c-41a5-a885-ac3e243e19c0','從聞從思沐髮','釋居簡','宋','宋诗','song-poetry','','[]','絕頂叢林茂林葉，蟣虱象龍爭迅捷。',96,'全唐诗/poet.song.179000.json','["絕頂叢林茂林葉，蟣虱象龍爭迅捷。", "湯沐風晞曝煖簷，藪剔原搜會秋獵。", "齒豁明瑶水爲扈，編密青琅陸爲罟。", "圍潰猶思勇負嵎，匪麈匪麕非虎兕。", "小生束髮能操觚，亦有武備當前驅。", "但知疎散非長計，不知遠岫雲如髻。"]'),
('27427b1b-0e40-48f9-a621-fca4c704f372','黄茶','釋居簡','宋','宋诗','song-poetry','','[]','官焙曾看白玉花，不知黄玉在山茶。',64,'全唐诗/poet.song.179000.json','["官焙曾看白玉花，不知黄玉在山茶。", "淺欺羅柳香仍烈，輕壓荼蘼浄弗瑕。", "著露未晞纔半萼，倚曛欲透忽全葩。", "月團已屬盧仝賦，別調何妨記物華。"]'),
('2f6bc9d5-ac24-4ff9-b34e-443ce5a6a95c','慧日致爽軒','釋居簡','宋','宋诗','song-poetry','','[]','襟懷浄無塵，太山巖巖秋。',96,'全唐诗/poet.song.179000.json','["襟懷浄無塵，太山巖巖秋。", "心聲響虛籟，何俟西山幽。", "悠然一段清，可就不可致。", "苟非可人就，未必蒙倒屣。", "吾家短髯翁，吳霜詫新茁。", "因依眉睫間，凜凜可濯熱。", "鈎簾事晚眺，層翠出林杪。", "一笑自點頭，萬象同颼飀。"]'),
('7053d499-eef8-4638-900f-39ffbb9e848c','福山渡','釋居簡','宋','宋诗','song-poetry','','[]','鯨浪粘雲白，狼山隔岸青。',48,'全唐诗/poet.song.179000.json','["鯨浪粘雲白，狼山隔岸青。", "鳶來方跕跕，鴻去忽冥冥。", "欲濟江程險，先祈海若靈。", "賈胡相習俗，拋擲有殘經。"]'),
('1ef4fc44-7759-4831-987f-93048e6b5ef2','樹經火而殞今復榮茂','釋居簡','宋','宋诗','song-poetry','','[]','無藥醫雙樹，扳枝忽再春。',48,'全唐诗/poet.song.179000.json','["無藥醫雙樹，扳枝忽再春。", "不隨人換世，曾見寺歸真。", "雨露雖全節，風霜只半身。", "榮枯相倚伏，東海復揚塵。"]'),
('61abe80f-1f33-4541-866d-f6751e5dca53','雪窗','釋居簡','宋','宋诗','song-poetry','','[]','小似剡溪船，方方斗底安。',48,'全唐诗/poet.song.179000.json','["小似剡溪船，方方斗底安。", "綠疏雲母透，青瑣水晶寒。", "蟾影從低入，蠅頭得細看。", "人皆苦炎熱，一點不相干。"]'),
('1fbd3510-c4c6-423f-a4c2-89b11200bc4d','姜貧樂青龍征商','釋居簡','宋','宋诗','song-poetry','','[]','月冷孤山幌，潮翻滬瀆春。',48,'全唐诗/poet.song.179000.json','["月冷孤山幌，潮翻滬瀆春。", "關譏今不古，課最食常貧。", "北鴈雲難駐，南枝雪又新。", "莫教詩滿篋，忘却寄來頻。"]'),
('8bf77792-be37-4a23-a505-a76a0be823db','張主簿葵菴','釋居簡','宋','宋诗','song-poetry','','[]','寸金尺地長安土，不種其他只種葵。',64,'全唐诗/poet.song.179000.json','["寸金尺地長安土，不種其他只種葵。", "葵倚太陽知向背，土於生物薦華滋。", "睡醒簷影三竿早，歌徹花陰幾綫遲。", "欲勸飛光一杯酒，要看側盞繞芳枝。"]'),
('35e46817-3db5-40c6-ac60-c806347f9ec8','有虎','釋居簡','宋','宋诗','song-poetry','','[]','悠悠天壤間，務各得其所。',288,'全唐诗/poet.song.179000.json','["悠悠天壤間，務各得其所。", "獸蹄交鳥蹟，堯憂填肺腑。", "偉哉神禹功，明德邁前古。", "九疇既定位，萬生斯按堵。", "奔馳服牛馬，飛潜適鱗羽。", "虎豹嗜殘暴，山林託深阻。", "云胡不奠居，出輒嘯當路。", "昨來東家嫗，云汝三瞰戶。", "西隣競相告，豐豕婁攘取。", "行葦既踐履，生理靡繁橆。", "田野日搔動，老羸困病窶。", "遂使扊扅歌，不待黄昏𢾅。", "唐虞全盛時，四凶怒如汝。", "赫然雷霆奮，四罪同一舉。", "彼無罪汝意，汝特犯其怒。", "商監猶未遠，與汝凶孰愈。", "蝮遭愚溪宥，鰐避昌黎去。", "大信及豚魚，二子吾所與。", "彼暴化爲仁，汝仁亦其伍。", "猶來仁暴心，不隔毫髮許。", "度河速遷徙，負嵎毋跋扈。", "况今屬多事，誅求猛於汝。", "兩雄不俱立，孤蹤曷足怙。", "勿謂三家市，智勇未易數。"]'),
('5af9639b-04f8-45a3-a4dc-4e1dc33fdd28','宥蟻','釋居簡','宋','宋诗','song-poetry','','[]','窮山忍調饑，小窗玄豹蹲。',288,'全唐诗/poet.song.179000.json','["窮山忍調饑，小窗玄豹蹲。", "百行無一羶，爾類曷所聞。", "倏忽來往頻，蠢蠕爭奪繁。", "報王張義氣，賈勇如虎賁。", "鼓行有行伍，回旋呼弟昆。", "陁然方解嚴，滃然新分屯。", "長蛇偶成勢，偃月非無轅。", "咂膚甚蟣虱，足駃不可捫。", "上我古生臺，隙我新垝垣。", "綴我玄兔穎，飲我陶泓渾。", "或循伽梨圈，從朝不知昏。", "小彈復就地，詎忍傷其元。", "屢掃復屢集，再馳仍再奔。", "咄哉誦箒兒，輕儇真少恩。", "不復事掃除，直欲加燖燔。", "斥兒旋呼蟻，請試爲蟻論。", "好生乃大德，略聽吾吻吻。", "爾宮大槐國，附庸檀蘿根。", "南柯在其左，東廂曾偃藩。", "休云城郭卑，中有侯王尊。", "蜩甲貢庭實，蟲臂供盤飧。", "犒享日厭餘，糗粻時有存。", "可以燕族屬，可以蕃子孫。", "悠哉天地間，曉然愚智分。"]'),
('6dfb030e-3e2f-4520-a7a1-f58b27df7fd8','蝗去','釋居簡','宋','宋诗','song-poetry','','[]','人言蝗有知，我謂蝗無知。',288,'全唐诗/poet.song.179000.json','["人言蝗有知，我謂蝗無知。", "使其果有知，不出昌明時。", "傍睨聽我言，飲笑輒見嗤。", "問之何因爾，却立雙顰眉。", "甚矣戇且愚，抑非狂則癡。", "諒不閲圖史，又弗聞書詩。", "不知朝廷尊，但習山林卑。", "耕稼徒勤勞，理亂慵考稽。", "嗟子昧理道，使我繁言辭。", "伊昔貞觀中，民生皆熙熙。", "呻吟化謳歌，文教漸戎夷。", "行旅弗齎糧，道路無拾遺。", "外則方與虎，內則傅與伊。", "腹心頗勝任，股肱良倚毘。", "四海同車書，九重垂裳衣。", "虞夏相較量，毫髮無參差。", "善乎魏鄭公，惜哉封德彜。", "當此全盛際，蝗起夫何爲。", "初傳滿郡國，遄復侵京畿。", "民瘼副所求，丙夜長懷思。", "未旦坐以待，罪己勇不疑。", "奮然事吞噬，厥類舉族移。", "上帝斯下臨，捷於聲響隨。", "良苗曾勿傷，凶歲稔不饑。"]'),
('4ad7ef3d-1212-4374-845f-752123df4403','送陳紫薇分韻得壽字','釋居簡','宋','宋诗','song-poetry','','[]','皇極建五福，筮得一曰壽。',240,'全唐诗/poet.song.179000.json','["皇極建五福，筮得一曰壽。", "人間最殊特，何者出其右。", "持以奉君子，數量未易究。", "樂哉仁者靜，克享本天授。", "况復湖海豪，不在曹劉後。", "良玉市有賈，韞匵敢輕售。", "用大古所難，跼縮萬牛脰。", "巨鏞當簨簴，欲振待洪扣。", "乘槎到叢霄，下士逮圭竇。", "藥物固滿簋，驥子亦盈廐。", "弦歌美遥夜，圖史樂清晝。", "養高知道腴，思苦坐吟瘦。", "淫蛙不停響，老鳳合伸咮。", "想當吟酣時，俗駕不得簉。", "廣居與正位，自有不須僦。", "一篇薦蔬筍，三舍避衮繡。", "桂玉破官舍，芝蘭茁瑶甃。", "莫訝分符速，正恐傳衣驟。", "歸來黄金甌，名氏得先覆。", "看鏡了心期，一笑丹砂就。"]'),
('d2e886b4-fd66-4995-998e-8734a9e8971b','陳紫薇知宛陵出關三日復召歸  其一','釋居簡','宋','宋诗','song-poetry','','[]','竹分宛陵去，環賜北關歸。',48,'全唐诗/poet.song.179000.json','["竹分宛陵去，環賜北關歸。", "出晝只三日，排雲趨九扉。", "春風隨意好，卿月上天飛。", "想見高寒處，朣朣並紫微。"]'),
('e0ee409b-fc67-4497-8d3b-4f60eb8c0436','陳紫薇知宛陵出關三日復召歸  其二','釋居簡','宋','宋诗','song-poetry','','[]','籠鎖新鶑囀，簾容舊燕歸。',48,'全唐诗/poet.song.179000.json','["籠鎖新鶑囀，簾容舊燕歸。", "禁林仍下榻，畫戟漫開扉。", "虛與谷相應，淡如雲自飛。", "升沈知雅量，喜慍不幾微。"]'),
('61b34349-843d-4331-b2d0-dac35b075ec2','西菴惠海棠','釋居簡','宋','宋诗','song-poetry','','[]','妃子驚回午枕時，別無名品略因依。',64,'全唐诗/poet.song.179000.json','["妃子驚回午枕時，別無名品略因依。", "效顰已笑林禽粉，諧俗偏嫌謝豹緋。", "碧酒暈朱猶未褪，丹肌痕露欲全晞。", "同盟更有紅千葉，細剪垂絲緯錦機。"]'),
('05bafb77-b712-447a-863b-169bdd07bac8','送葉桐軒赴永嘉上幕兼簡劉使君  其一','釋居簡','宋','宋诗','song-poetry','','[]','清才出故家，幕府在東嘉。',48,'全唐诗/poet.song.179000.json','["清才出故家，幕府在東嘉。", "吟熟蕃池草，潮回富石花。", "霜垂低樹實，珠滴小槽霞。", "更勺龍翔碧，晴窗試麥畬。"]'),
('0062e923-01d6-46fa-b47d-e80d676eea84','送葉桐軒赴永嘉上幕兼簡劉使君  其二','釋居簡','宋','宋诗','song-poetry','','[]','鴈宕雨初收，遲將部曲留。',48,'全唐诗/poet.song.179000.json','["鴈宕雨初收，遲將部曲留。", "佳山如好友，遠仕當清游。", "憶與白鷗侶，曾盟賢郡侯。", "依劉可無地，莫倚仲宣樓。"]'),
('024283c3-e3d4-41a7-bd49-934746a1d8c6','青龍張賢良四高堂','釋居簡','宋','宋诗','song-poetry','','[]','肯續高人傳，能分鼎足無。',48,'全唐诗/poet.song.179000.json','["肯續高人傳，能分鼎足無。", "煩君添一箇，爲我壯全吳。", "正學非謀士，清吟豈釣徒。", "須知而祖意，斷不在蓴鱸。"]'),
('ef782e61-74a8-4ddc-bd46-9eefec55cbb4','柔桑','釋居簡','宋','宋诗','song-poetry','','[]','羽葆欹牆綠未摇，春風易放麯塵消。',32,'全唐诗/poet.song.179000.json','["羽葆欹牆綠未摇，春風易放麯塵消。", "天教葉葉關機軸，不與群芳一樣彫。"]'),
('e1f300ea-39c0-4e59-8a57-e1108e49842d','攬鏡','釋居簡','宋','宋诗','song-poetry','','[]','新茁吳霜剪不零，臨鸞羞澀對星星。',32,'全唐诗/poet.song.179000.json','["新茁吳霜剪不零，臨鸞羞澀對星星。", "天生兩眼人嫌白，只有青銅照得青。"]'),
('a70732f5-737f-4533-a098-b43e1c155b74','薛子舒半鏡','釋居簡','宋','宋诗','song-poetry','','[]','饑蟇緣雲吞嬋娟，徑圓千里虧一邊。',162,'全唐诗/poet.song.179000.json','["饑蟇緣雲吞嬋娟，徑圓千里虧一邊。", "何年吹缺墮九地，更復幾時飛上天。", "不悟素爲明所誤，削地更無開拓處。", "遂使騎鯨汗漫歸，擬斫婆娑鏡中樹。", "又疑白玉樓居大手筆，喝得倒行輪半仄。", "至今弗作玻璃聲，猶自錚錚作金石。", "不然十連酬賈難，怒髮凜凜衝其冠。", "歸來寒芒耿夜闌，亭亭小試龍文看。", "半規朣朣儘分曉，團團如漆知多少。", "是中觀德又觀空，缺處何曾礙圓照。"]'),
('1696ddc3-719c-41ea-a226-82c1b64951f4','立夏','釋居簡','宋','宋诗','song-poetry','','[]','弦改南薰曲自調，縈回小篆水沉消。',32,'全唐诗/poet.song.179000.json','["弦改南薰曲自調，縈回小篆水沉消。", "葉舟自打窗前過，只有楊花度小橋。"]'),
('000b94be-2590-4cbb-858f-0003ba87c4a8','悼趙紫芝','釋居簡','宋','宋诗','song-poetry','','[]','不解俯華簪，峩峩獨苦心。',48,'全唐诗/poet.song.179000.json','["不解俯華簪，峩峩獨苦心。", "反騷嫌少作，番襪動新吟。", "折玉蘭風急，摧金菊雨霪。", "中年兒女泪，消得幾沾衿。"]'),
('ab74939e-8693-46c9-87b0-ad5a71193464','楊梅','釋居簡','宋','宋诗','song-poetry','','[]','枝繁疑墜地，煙暝欲燉空。',48,'全唐诗/poet.song.179000.json','["枝繁疑墜地，煙暝欲燉空。", "止渴差相似，和羹却不同。", "每嗟龍井白，易變鶴頭紅。", "好在文園令，冰盤對晚風。"]'),
('4e9e5c65-9394-4944-b3fe-d961d70618af','千葉梔子花','釋居簡','宋','宋诗','song-poetry','','[]','雖與餘香別，何曾別樣開。',48,'全唐诗/poet.song.179000.json','["雖與餘香別，何曾別樣開。", "一花分六出，千葉是重臺。", "玉潔渾無玷，金黄謾奪胎。", "尋思天下白，只合友江梅。"]'),
('8bce0a0c-f300-4bd9-bf3d-467db09a0f9c','盤隠陸別駕樓居  其一','釋居簡','宋','宋诗','song-poetry','','[]','別浦潮生玉一痕，倚闌目送渡江雲。',32,'全唐诗/poet.song.179000.json','["別浦潮生玉一痕，倚闌目送渡江雲。", "寶蓮秀色連秦望，商略風煙到十分。"]'),
('a0e1df6a-7351-4f02-9010-e9c563a26226','盤隠陸別駕樓居  其二','釋居簡','宋','宋诗','song-poetry','','[]','隔江便是越州山，無雨無晴儘好看。',32,'全唐诗/poet.song.179000.json','["隔江便是越州山，無雨無晴儘好看。", "不妬卧樓高百尺，妬它終日倚闌干。"]'),
('88353409-db8b-4406-a2da-18fc1c89c3fb','頤齋','釋居簡','宋','宋诗','song-poetry','','[]','有生分貴足，足患不自知。',228,'全唐诗/poet.song.179000.json','["有生分貴足，足患不自知。", "知貴得所止，不止盈益虧。", "盤磵隠淪友，圖史森孫枝。", "閑適壽且康，不止將奚爲。", "卜築脩竹間，養正是用宜。", "惟其得所養，自樂頤之時。", "初筮得上九，頤道皆備之。", "靜默戰紛華，燕晦觀群蜚。", "對月喜秋霽，問柳知春歸。", "鳴鶴聞夜弦，振鷺驚晝棋。", "池寬縱魚樂，機忘悟鷗疑。", "幽草時自妍，歌鳥時自闚。", "釣則鈎可直，藝則芳可移。", "酒酣卧花底，不知吾爲誰。", "起來飛羽觴，萬化同熙熙。", "藥圃雨新霽，徐步觀耘耔。", "眉津雙解顰，心淵平弗欹。", "酡顔渥且丹，老鬢秋不萎。", "從它自逐逐，舍蔡觀朵頤。"]'),
('d5d638b9-b38b-4cd9-8750-e0c31da3eeee','贈冩竹葉生','釋居簡','宋','宋诗','song-poetry','','[]','三年一楮成，九年一弓就。',120,'全唐诗/poet.song.179000.json','["三年一楮成，九年一弓就。", "雖刮造化骨，總落造化後。", "葉生翻襪法，二者竟何有。", "因依霜節勁，繾綣虛心厚。", "細意幻扶疎，與俗洗棼垢。", "慨慷縱一醉，頃刻便千畝。", "不知盤礴時，更有全牛否。", "忍貧不謀富，捉衿見兩肘。", "千愁憐竹瘦，百屋嫌銅臭。", "雖無種秫田，亦有吸川口。"]'),
('912fb86f-6dab-4def-aa9c-fcd2122cddcb','可廬','釋居簡','宋','宋诗','song-poetry','','[]','傍水依山便託栖，百年心事老茆茨。',32,'全唐诗/poet.song.179000.json','["傍水依山便託栖，百年心事老茆茨。", "恰如彭澤歸來後，柳色遮門菊繞籬。"]'),
('f3428c49-c30c-4527-8f1e-ce04134eb428','苕谿行','釋居簡','宋','宋诗','song-poetry','','[]','清苕可鏡亦可漁，風煙佳處畫不如。',152,'全唐诗/poet.song.179000.json','["清苕可鏡亦可漁，風煙佳處畫不如。", "無錢買田傍城闕，擬僦谿叟西隣居。", "得魚換得菰蒲米，菰煮作糜飽則已。", "寧能負腹不負人，以腹負人不若死。", "富春殘火猶堪稼，上時容易艱難下。", "在山遠志山可移，小草還復令人譏。", "菱歌慣濤瀾，樵聲出林疃。", "蘋風爲誰好，璧月待秋滿。", "延月入懷輸懇款，好風未必無人管。", "筆床茶竈散人家，何須去乘牛斗槎。"]'),
('8fe79c8a-4834-4833-b064-88fb16382b1c','九日登蓮峰得二石一石如魚而尾赤名之曰頳尾一石有眼口鼻名之曰山鬼  其一','釋居簡','宋','宋诗','song-poetry','','[]','青巉俯碧潯，潜伏翠層深。',48,'全唐诗/poet.song.179000.json','["青巉俯碧潯，潜伏翠層深。", "雨蝕蓮峯碧，嵐昏鷲嶺陰。", "朵雲生燕寢，片玉下岑崟。", "可拊仍堪擊，依稀一寸心。"]'),
('653bdfa5-ddc6-46f4-a0fd-5494580a26e9','九日登蓮峰得二石一石如魚而尾赤名之曰頳尾一石有眼口鼻名之曰山鬼  其二','釋居簡','宋','宋诗','song-poetry','','[]','怪狀出岩扃，山精死弗靈。',48,'全唐诗/poet.song.179000.json','["怪狀出岩扃，山精死弗靈。", "文如雲子白，質带土花青。", "雨信莓苔濕，蝸涎竅穴腥。", "九歌如可些，爲爾續騷經。"]'),
('0fb53a42-291d-4fdd-92fe-2ff6e117eb13','酬毓齋李尚書','釋居簡','宋','宋诗','song-poetry','','[]','惜閑如惜金，不趲雪侵簪。',48,'全唐诗/poet.song.179000.json','["惜閑如惜金，不趲雪侵簪。", "步向青冥却，交容野逸尋。", "禪深排默照，句熟動酣吟。", "得趣忘弦索，無聲自賞音。"]'),
('6c7c3a3f-4a1b-4085-9dcc-f4a32653ac9a','寄鄉州憲使曹國博','釋居簡','宋','宋诗','song-poetry','','[]','雁宕秀色連脩眉，胸中豈止雁宕奇。',96,'全唐诗/poet.song.179000.json','["雁宕秀色連脩眉，胸中豈止雁宕奇。", "展旗卓筆在懷袖，文事武備皆稱之。", "劍南江山梓最勝，彈壓江山須逸興。", "國子先生繡斧光，一道風煙入評品。", "頗聞邊警喧蜂蠆，談笑從容起凋瘵。", "勿謂生平少作詩，古錦可容空載歸。"]'),
('240eeb90-df35-4704-966d-6aa83e2de10e','酬楊左司','釋居簡','宋','宋诗','song-poetry','','[]','蜜花小春操，自笑雪萼遲。',168,'全唐诗/poet.song.179000.json','["蜜花小春操，自笑雪萼遲。", "中有千斛香，半點不自私。", "逮茲良月半，著得鮮風吹。", "吹作群卉先，以慶此段奇。", "悠然一臨風，粲然一解頤。", "孤芳爾何事，要結斯人知。", "紫荷鄉來橐，綵庭親付衣。", "今茲玉筍班，默贊元化機。", "不知春幾何，但見物自怡。", "藹藹蒸粹和，蕩蕩生華滋。", "問之何因爾，有以潤色之。", "善頌繼善禱，試聽輿人辭。", "亦既多壽祉，頌禱夫奚爲。", "盍觀輿人心，以尉輿人思。"]'),
('185c98e9-71ba-4bd2-9fdd-647cc32c8003','逆風行','釋居簡','宋','宋诗','song-poetry','','[]','大塊噫氣一氣同，條達萬彙參化工。',198,'全唐诗/poet.song.179000.json','["大塊噫氣一氣同，條達萬彙參化工。", "不教扶摇轉羊角，五日一吹零雨濛。", "喚醒枯槁皆蒙茸，假借秋鬢回春容。", "後來見說蘭臺宮，君臣相與論雌雄。", "至今雌雄無辨白，幾回擬問蘭臺客。", "便從平地欲泠然，結口土囊呼不得。", "坐使六月七月背汗揮老農，燥土滴作蘭塘融。", "赫赫炎炎濯無處，積威蓄銳盡數施玄冬。", "一葉東來順流水，怒號不肯吹船尾。", "轉船又復投西去，蓬蓬依舊從東起。", "試從逆境求諸己，可容不拜飛廉賜。", "謹勿顛狂蹈前轍，長不鳴條伴華月。"]'),
('38a03719-0d42-4f2c-88b8-1d5a2a2c88dc','拜真歇了菩薩塔','釋居簡','宋','宋诗','song-poetry','','[]','只作深雲土一抔，象龍螻蟻弗同謀。',64,'全唐诗/poet.song.179000.json','["只作深雲土一抔，象龍螻蟻弗同謀。", "鬰金薰陸不足道，行潦潢污端可羞。", "豈特龍翔開壯麗，也曾雁宕見賡酬。", "人言合瘞凌霄頂，我謂凌霄在下頭。"]'),
('b0cb693f-8509-4975-a49d-26598faf79a7','蔡京葬處女冠居之','釋居簡','宋','宋诗','song-poetry','','[]','觀裏黄蜂晚退衙，觀前桃著小春花。',32,'全唐诗/poet.song.179000.json','["觀裏黄蜂晚退衙，觀前桃著小春花。", "更無尋訪麻姑處，零落風煙似蔡家。"]'),
('1e93c597-e2fa-4784-9570-5f4571de6a98','謝樓別駕','釋居簡','宋','宋诗','song-poetry','','[]','日者鵷鴻序，年來月旦評。',120,'全唐诗/poet.song.179000.json','["日者鵷鴻序，年來月旦評。", "芳騰新令問，絕似老先生。", "特立風塵表，全消鄙吝萌。", "步何妨展驥，樂豈俟專城。", "書卷終長策，雲窗尚短檠。", "不知身富貴，猶遣筆耘耕。", "大雅連城重，籝金一羽輕。", "無弦皆古意，比竹謾新聲。", "玉骨難教俗，金莖只得清。", "試論簪履舊，細細勺高情。"]'),
('b94bf122-9895-4ca1-b647-5cc550fe5bf2','謝人惠鬬綵袱','釋居簡','宋','宋诗','song-poetry','','[]','碎紅零綠盡其宜，駢儷收成一段奇。',64,'全唐诗/poet.song.179000.json','["碎紅零綠盡其宜，駢儷收成一段奇。", "曲砌鱗鱗尤縝密，方聯翼翼自參差。", "大成富有諸家善，小數窮如集句詩。", "蜀錦吳綾重表出，阿蠻針線策勳時。"]'),
('e1bc5c50-963c-4dcc-bcbd-7903790ef827','李燕公生華亭尉廳舊有相公閣可齋洪少府於廢址更爲夢燕堂用玉燕入懷事永嘉趙清曠索同賦','釋居簡','宋','宋诗','song-poetry','','[]','適華胥氏問津來，祥兆其先必有開。',64,'全唐诗/poet.song.179000.json','["適華胥氏問津來，祥兆其先必有開。", "偶爾入懷真是玉，及乎同夢却非梅。", "曰蘭倘可名千古，指李何妨又一回。", "未問讀書堂上客，斲輪堂下亦英才。"]'),
('936f5e7d-5c1f-4388-ada4-18c4ffdb5baa','瑞香兩首  其一','釋居簡','宋','宋诗','song-poetry','','[]','舊從康俗老千峯，紫綺裁葩藐萬紅。',32,'全唐诗/poet.song.179000.json','["舊從康俗老千峯，紫綺裁葩藐萬紅。", "一與宮花分次敘，至今羞殺錦熏籠。"]'),
('6afdbe0a-4202-4a73-ac90-a509ac600a2f','瑞香兩首  其二','釋居簡','宋','宋诗','song-poetry','','[]','低欠闌干護綠雲，紫苞寒褪暖敷英。',32,'全唐诗/poet.song.179000.json','["低欠闌干護綠雲，紫苞寒褪暖敷英。", "服膺不下南枝拜，應使餘香誤得名。"]'),
('cc81b7b5-aefe-4158-a0e7-6f40391ce5cb','隙月','釋居簡','宋','宋诗','song-poetry','','[]','側飛蟾影入簷低，鵲倦烏慵尚繞枝。',32,'全唐诗/poet.song.179000.json','["側飛蟾影入簷低，鵲倦烏慵尚繞枝。", "燈灺小窗簾不卷，定回凍合玉樓時。"]'),
('bf3fc057-02bc-483f-ad1e-6af7a1069fa6','內相洪容齋名諸孫華亭少府曰可齋','釋居簡','宋','宋诗','song-poetry','','[]','濫觴學滄溟，弗至吾弗已。',192,'全唐诗/poet.song.179000.json','["濫觴學滄溟，弗至吾弗已。", "九仞規成功，弗成吾弗止。", "方其未至時，傍睨豈知此。", "及其既成後，豈暇顧傍睨。", "或云山既高，我則揆諸理。", "或云海未深，我則反諸己。", "所立固先定，所詣孰能尼。", "刻瓜大如斗，淺諾復輕唯。", "甚者反自畫，不則中道弛。", "傲然曰山海，不了可齋耻。", "可齋何人斯，故家振番水。", "束髮讀父書，介特固若是。", "幼蒙玉堂印，壯授盤洲記。", "至於自肯時，不見兩君子。", "黄河可爲带，太山可如礪。", "悠然君子心，無同亦無異。"]'),
('c1d72cdd-05c2-4d2c-a783-e7f12604f1eb','酬秋塘古詩之惠','釋居簡','宋','宋诗','song-poetry','','[]','鄉來小朵煙蒼蒼，烏紗瘦策尋初凉。',224,'全唐诗/poet.song.179000.json','["鄉來小朵煙蒼蒼，烏紗瘦策尋初凉。", "囊封借月留雲章，朗吟響答山琅琅。", "寥寥十載遥相望，尺書不得鴻鴈將。", "朅來屢分讀書床，殘編斷柬雜朱黄。", "梅花楮帳芙蓉裳，書傳騰馥掩衆芳。", "前日破雨破竹窗，勃窣倒屣成踉蹌。", "寒暄一語不暇吐，望之巋然魯靈光。", "郊寒豈復療島瘦，齊大叵堪容楚狂。", "亭亭雪茸未下榻，采采霜薺先盈筐。", "長歌爛爛古錦段，十詩亹亹秋圃場。", "離騷大雅得祖述，夜光明月相抵當。", "不貽它人乃見及，三嚥十襲藏緘箱。", "藿葵䫲頷欠瓊玖，誰羹甘露醫滄浪。", "車輪裹蒲碾雲漢，爲我舉手瓢天漿。"]'),
('8dd49596-86a6-4561-9cda-8fa90373f225','南山阻雪  其一','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','裂竹聲乾攪夜林，寬裁玉楮漫重衾。',64,'全唐诗/poet.song.179000.json','["裂竹聲乾攪夜林，寬裁玉楮漫重衾。", "遥知凹凸先平滿，未暇崎嶇探淺深。", "凍折衣稜須煖熨，明穿簷隙怕寒侵。", "西湖凍合方連底，獨釣無人傍湧金。"]'),
('03d7392f-3868-4804-9531-cb056da7cd7f','南山阻雪  其二','釋居簡','宋','宋诗','song-poetry','','[]','密密疎疎忽滿林，小齋冷直欠綾衾。',64,'全唐诗/poet.song.179000.json','["密密疎疎忽滿林，小齋冷直欠綾衾。", "旋疑蟾轂行春曉，細看蠅頭到夜深。", "已有四郊三白瑞，更無一點軟紅侵。", "庭除層砌皆明潔，長笑當時側布金。"]'),
('10c84224-bda2-475e-9697-bdaa6a81d1ca','送魏郎中出守潮陽','釋居簡','宋','宋诗','song-poetry','','[]','臨邛犢鼻裩，環堵長蕭然。',180,'全唐诗/poet.song.179000.json','["臨邛犢鼻裩，環堵長蕭然。", "千金賤賣賦，忍爲俗子妍。", "安知有名勝，文采明相鮮。", "環堵不相下，危行仍危言。", "自有萬間屋，未暇著一椽。", "屹立鵷鷺行，飛作蓬萊仙。", "鮮爲目前計，闊著胸中天。", "千騎潮陽州，旌旆行翩翩。", "身居風化首，鞭著循良先。", "鰐魚碧潭底，瘴海光風前。", "物既不疵癘，俗亦知變遷。", "問之何因爾，儀刑邦伯賢。", "我恐席未煖，十行來日邊。", "哂乃韓退之，袁州小回旋。", "當如黄丞相，登庸由潁川。"]'),
('da3cd569-0154-42b7-a790-ca75ec28c395','李夔州挽章  其一','釋居簡','宋','宋诗','song-poetry','','[]','防拓西南重，皇華賦詠優。',48,'全唐诗/poet.song.179000.json','["防拓西南重，皇華賦詠優。", "忍將憂國泪，來作聽猿愁。", "瘴掃烏蠻俗，吟殘白帝秋。", "脩名磨不得，三峽自東流。"]'),
('d8ce422a-c255-4402-9bb2-d2a55f70e145','李夔州挽章  其二','釋居簡','宋','宋诗','song-poetry','','[]','儉素律豪奢，攻浮復填華。',48,'全唐诗/poet.song.179000.json','["儉素律豪奢，攻浮復填華。", "竹枝謠五袴，棠影懋三巴。", "硤雨催吟翰，江春釀醉霞。", "不知舒嘯地，誰此岸烏紗。"]'),
('cfecf3fd-aa45-468a-b1e7-fea1aec637e4','謝高秘書雪蕈','釋居簡','宋','宋诗','song-poetry','','[]','瘦雲臞雪漱霜漪，煙火無功合茹芝。',32,'全唐诗/poet.song.179000.json','["瘦雲臞雪漱霜漪，煙火無功合茹芝。", "囊錦若編群玉府，樹雞吟續晚唐詩。"]'),
('4bad834a-1e0d-439f-9827-b1f789a01d68','九日侍宴太清樓','張方平','宋','宋诗','song-poetry','','[]','登高聞舊俗，況此奉堯觴。',96,'全唐诗/poet.song.18000.json','["登高聞舊俗，況此奉堯觴。", "鳴蹕遥空下，層樓顥氣傍。", "御溝新過雨，苑樹未經霜。", "楚澤丹苞重，吳畦紫穗香。", "三侯天縱妙，九節召南章。", "中豈矜多藝，威將懾四方。", "清時人共樂，白日坐間長。", "近從叨慈渥，區區祝壽昌。"]'),
('ecda3e50-169a-4dab-a592-e18b115088be','上享郊廟 享廟','張方平','宋','宋诗','song-poetry','','[]','瑞雪清晨集，丹墀發策初。',96,'全唐诗/poet.song.18000.json','["瑞雪清晨集，丹墀發策初。", "德音聞徹蓋，玉色望升車。", "羽衛排閶闔，晴光溢紫虛。", "琳宮陳玉幣，疏屏宿旌旟。", "祼獻多儀備，絃匏九變徐。", "太宮無盛舉，掌次省先除。", "靈鑒紛昭格，天心不自舒。", "孝慈更答告，萬福此攸儲。"]'),
('a08ac53e-3a88-4fd4-b8be-a3102aab30f4','上享郊廟 禋郊','張方平','宋','宋诗','song-poetry','','[]','回仗由黄道，鳴鑾入翠宮。',96,'全唐诗/poet.song.18000.json','["回仗由黄道，鳴鑾入翠宮。", "愾思文武侑，誠與地天通。", "登陛行裀徹，終祠坐幄空。", "風雲歸絕域，星斗下遥穹。", "壝際柴煙白，龕層燭焰紅。", "氣祥書魯觀，福嘏萃堯躬。", "海上雞星動，樓前馬隊雄。", "僕臣殊幸會，獨得近重瞳。"]'),
('c941e7ec-0994-4fc9-83fd-3dbc44c75f40','升祔慶成','張方平','宋','宋诗','song-poetry','','[]','明詔初發中，奉慈講升祔。',240,'全唐诗/poet.song.18000.json','["明詔初發中，奉慈講升祔。", "考典下容臺，集議付近署。", "雙禮稽國章，大義推經據。", "參覆經宰司，裁定皆宸慮。", "獻后正壺儀，仍几被遺顧。", "擁佑隆帝室，清夷贊王路。", "懿主鍾景命，禖宮開慶祚。", "靈長繄發祥，熙洽本垂裕。", "蓬闕邈仙軿，柏城拱寒樹。", "別饗隔昭穆，時思怵霜露。", "陽月日上辛，齋居待清曙。", "當衙薦寶冊，夾道陳鹵簿。", "玉色儼莊栗，淵衷緬馳慕。", "端闈出翟車，黄道回天步。", "千官陪祠庭，祕祐寧神御。", "盛德配不祧，至孝始如素。", "穹厚昭精純，蕃夷入儀注。", "渙汗肆慶宥，需雲均膏飫。", "廣愛形海區，教忠憲侯度。", "下臣叨載筆，書法資典故。"]'),
('d5e922da-6291-42bf-af8c-5661e8450709','大祀禮成','張方平','宋','宋诗','song-poetry','','[]','皇心奉先孝，盛德事天明。',120,'全唐诗/poet.song.18000.json','["皇心奉先孝，盛德事天明。", "嚴配講隆禮，精禋格至誠。", "衣冠先示質，金石始諧聲。", "鬲享初登熟，鋒和用啟牲。", "百神虔受職，萬物樂由庚。", "星斗羅空碧，柴煙徹紫清。", "祥曦回羽衛，佳氣覆瑶甍。", "雷雨金雞動，風雲鐵馬輕。", "靈休紛報貺，宸念在持盈。", "孤陋叨華近，何辭頌泰平。"]'),
('1b07684b-3ed8-436f-a19c-bef88a61a90c','喜雪','張方平','宋','宋诗','song-poetry','','[]','愆陽干歲事，齋殿軫予憂。',96,'全唐诗/poet.song.18000.json','["愆陽干歲事，齋殿軫予憂。", "默爲斯民禱，心從六事求。", "同雲俄蔽景，盈尺忽呈休。", "淅瀝千瓊樹，崢嶸萬玉樓。", "塵氛開紫宙，氣象露皇州。", "鵰鶚精神勁，松筠操稟優。", "邊庭傷久戍，農畝慶來麰。", "咨爾臣鄰地，常期九敘脩。"]'),
('afd11c28-7162-447a-b6e0-04e245a3f454','送內閣蔡公歸闕','張方平','宋','宋诗','song-poetry','','[]','豐宮周舊宅，梁國漢東關。',144,'全唐诗/poet.song.18000.json','["豐宮周舊宅，梁國漢東關。", "尹正司留鑰，賢公出近班。", "教條推愛利，滋蔓悉除刪。", "狹野耕桑急，終年獄市閒。", "燕申鈴閣靜，榮養彩衣斑。", "治迹經綸外，陰功造化間。", "士林歸北海，人望在東山。", "一節遄趨召，西轅不可攀。", "前旌霜樹曉，候騎古河灣。", "和氣均生物，淳風復海寰。", "具瞻知可副，盛德致無艱。", "他日開鑪冶，餘功爲鑄顔。"]'),
('1b94a489-5de6-4244-a58e-343d7538e1ad','送吳春卿赴都','張方平','宋','宋诗','song-poetry','','[]','法座臨軒策俊髦，同君陛見預旌招。',64,'全唐诗/poet.song.18000.json','["法座臨軒策俊髦，同君陛見預旌招。", "疲駑十駕始千里，孤鶚一飛先九霄。", "蘭棹秋風行邐迤，觚稜旭日勢岧嶢。", "石渠爲謝諸時彥，行邁同趨便殿朝。"]'),
('36936252-a06b-4006-ba75-b3fe36ee86fe','送冀州李太傅','張方平','宋','宋诗','song-poetry','','[]','多君貴主子，材識乃名儒。',96,'全唐诗/poet.song.18000.json','["多君貴主子，材識乃名儒。", "青海渥漥種，丹山鸞鳳雛。", "兵家左車後，書法右軍無。", "擁幄羞紈袴，懷章就隼旟。", "亭臺煙水闊，樓堞暮雲扶。", "析木元分冀，滹沱漸近胡。", "雙觥雖藴藉，重閉勿須臾。", "誰道長城遠，今觀出上都。"]'),
('22ccfc53-99e6-4976-ae96-c9d5ffbb7c3b','送李芝東歸','張方平','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','此君齊魯之奇才，三十病廢吁命哉。',64,'全唐诗/poet.song.18000.json','["此君齊魯之奇才，三十病廢吁命哉。", "來遊京國動悽悵，東歸泰山卧崔嵬。", "支離攘臂福所倚，功名累身古共哀。", "但恐人求駿馬骨，未免却上黄金臺。"]'),
('672cfdf1-737a-4477-8341-5daf0a86b060','送蘇學士錢塘監郡','張方平','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','趣時貴近君獨遠，此情於世何所希。',64,'全唐诗/poet.song.18000.json','["趣時貴近君獨遠，此情於世何所希。", "車馬塵中久已倦，湖山勝處即爲歸。", "洞庭霜天柑橘熟，松江秋水鱸魚肥。", "地鄰滄海莫東望，且作阮公離是非。"]'),
('c0affc4a-094e-433a-83d7-1bce080eb8c4','呈資政宋尚書','張方平','宋','宋诗','song-poetry','','[]','當年留鑰守陪都，龍坂因茲得曳裾。',64,'全唐诗/poet.song.18000.json','["當年留鑰守陪都，龍坂因茲得曳裾。", "北海一章慙鷙鳥，松江三歲厭鱸魚。", "賈生感事多垂涕，園令居閒輒著書。", "獨恃明公念孤介，東郊未去逐長沮。"]'),
('15b4c567-4834-453a-881f-3a64c3d06abf','送石曼卿赴闕','張方平','宋','宋诗','song-poetry','','[]','功名本不與人期，人取功名亦繫時。',64,'全唐诗/poet.song.18000.json','["功名本不與人期，人取功名亦繫時。", "蜀相閒居久龍卧，馬周狂醉竟誰知。", "將軍身到衡廬問，英主心驚奏牘奇。", "宣室思賢方空席，去陳經濟勿遲遲。"]'),
('8188e21e-d288-423e-a7fc-00a6af3c9fad','重送趙參','張方平','宋','宋诗','song-poetry','','[]','參也堂堂氣拂雲，十年策蹇四方塵。',64,'全唐诗/poet.song.18000.json','["參也堂堂氣拂雲，十年策蹇四方塵。", "覊窮自古有元叔，精鑒觀今少法真。", "驥在駑羣殊有態，龍初魚服未能神。", "君看渭曲傅巖事，天困斯人必有因。"]'),
('b64035d6-f656-48cb-8662-59dd6917e52b','送馬武','張方平','宋','宋诗','song-poetry','','[]','才命相憎不相並，古來達者齊其中。',64,'全唐诗/poet.song.18000.json','["才命相憎不相並，古來達者齊其中。", "此君寂寞年雖暮，靈府崢嶸事甚雄。", "韝上鷹饑思掠草，車傍驥老尚追風。", "丈夫掩棺始爲了，是故南陽晚立功。"]'),
('bf3eb574-f058-49a8-92e3-cd73a51a4bcd','送張寬','張方平','宋','宋诗','song-poetry','','[]','得喪竟誰尸，人謀不可移。',48,'全唐诗/poet.song.18000.json','["得喪竟誰尸，人謀不可移。", "獨看屠釣叟，達迺帝王師。", "大觀齊諸物，雄圖彼一時。", "君思塞上說，孰可預端蓍。"]'),
('a237ef46-f330-46a3-b40e-8b16bd29b619','送張郎中赴闕','張方平','宋','宋诗','song-poetry','','[]','明公才氣本雄傑，晚戴儒冠腰拖紳。',64,'全唐诗/poet.song.18000.json','["明公才氣本雄傑，晚戴儒冠腰拖紳。", "講劔妙傳色踐術，工書兼得伯英筋。", "外臺共歎郎潛久，中檢行膺帝命新。", "司列不煩詢治狀，幾州欒社有遺仁。"]'),
('52dd4f1e-3b25-43c7-a8fa-5cc3b6e16f3d','送宋祕丞赴任鄱陽','張方平','宋','宋诗','song-poetry','','[]','蕭灑武夷秀，茲人美且偲。',48,'全唐诗/poet.song.18000.json','["蕭灑武夷秀，茲人美且偲。", "治經通古學，應務富時材。", "盍在脩書選，行須造幣迴。", "更研輕重術，歸奏阜民財。"]'),
('af48315c-9b5d-4946-8f77-64c973bd679f','送祝生東陽簿','張方平','宋','宋诗','song-poetry','','[]','之子東南美，聲光滿貴游。',48,'全唐诗/poet.song.18000.json','["之子東南美，聲光滿貴游。", "溪山聊薄宦，才調自名流。", "野趣雖孤艇，清涂即十洲。", "金波沁園宴，遲子有賢侯。"]'),
('8edc59c9-72a6-43d6-bebf-da93c6e44337','送客游兗海','張方平','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','寒飇慄冽響吹空，雪意沈沈歲向窮。',64,'全唐诗/poet.song.18000.json','["寒飇慄冽響吹空，雪意沈沈歲向窮。", "正是兼衣御醇酎，如何孤蹇逐飛蓬。", "杉松古色泰山廟，絲竹遺音夫子宮。", "訪舊自堪寬旅瑣，賢侯況似蜀文翁。"]'),
('17c1676d-4dd0-4372-92eb-533d98b6412c','送楊君西安','張方平','宋','宋诗','song-poetry','','[]','君過嚴陵瀨，扁舟入婺溪。',48,'全唐诗/poet.song.18000.json','["君過嚴陵瀨，扁舟入婺溪。", "灘長秋日短，山亂暮雲齊。", "未探驪龍頷，聊羈駿馬蹄。", "吳江濤正惡，鴻鴈此東西。"]'),
('4bfa24f3-bbe4-4980-8e1f-d472567c2103','送客入洛','張方平','宋','宋诗','song-poetry','','[]','高歌彈鋏酒盈鍾，壯士何須歎道窮。',64,'全唐诗/poet.song.18000.json','["高歌彈鋏酒盈鍾，壯士何須歎道窮。", "客路歲闌天又雪，旗亭醉別氣如虹。", "驥騰夷路思良御，帆破長波待便風。", "今子方爲采蘭役，未宜去揖紫芝翁。"]'),
('0897430d-31c9-41a7-a0c3-047f3556dd16','送福州監郡陳殿丞','張方平','宋','宋诗','song-poetry','','[]','七閩一都會，乃是無諸城。',48,'全唐诗/poet.song.18000.json','["七閩一都會，乃是無諸城。", "海近氣物異，山遥風候清。", "宦游過鄉美，君祿及親榮。", "去去倚門念，溪船歸棹輕。"]'),
('4619c05d-8d1f-4845-a817-ef6a80f25c14','送陳汝玉謁三川大資政左丞吳公','張方平','宋','宋诗','song-poetry','','[]','吳公昔作河南尹，首唱儒風薦賈生。',32,'全唐诗/poet.song.18000.json','["吳公昔作河南尹，首唱儒風薦賈生。", "今日治平承祖德，可無推引助文明。"]'),
('4fb6817a-9881-4b03-a754-e0674d92708e','謁青州范天章','張方平','宋','宋诗','song-poetry','','[]','劍橫驢膊儒裝陋，戟列臺門霸府雄。',64,'全唐诗/poet.song.18000.json','["劍橫驢膊儒裝陋，戟列臺門霸府雄。", "喜似禰衡逢北海，直須雷煥辨南豐。", "謬悠爲說非今味，疎略言詩粗古風。", "更似賈生多歎息，聞公真賞勝吳公。"]'),
('7a6f9e95-4cad-4e07-8a09-a930f83cbd79','送沈生昆弟隨侍之博白四絕句  其一','張方平','宋','宋诗','song-poetry','','[]','炎方景象異中原，海氣昏昏雜瘴煙。',32,'全唐诗/poet.song.18000.json','["炎方景象異中原，海氣昏昏雜瘴煙。", "今日荒夷成雅俗，薰風南播自媯絃。"]'),
('de8af436-0fc4-4f83-912f-5f8e16052ef2','送沈生昆弟隨侍之博白四絕句  其二','張方平','宋','宋诗','song-poetry','','[]','不須南浦懷消黯，好過西山訪隱淪。',32,'全唐诗/poet.song.18000.json','["不須南浦懷消黯，好過西山訪隱淪。", "比到嶺時應近臘，相思可寄一枝春。"]'),
('6b52c228-6333-4e34-a22f-371a1bd642d6','送沈生昆弟隨侍之博白四絕句  其三','張方平','宋','宋诗','song-poetry','','[]','東連海道徹扶桑，北望神皋斗柄旁。',32,'全唐诗/poet.song.18000.json','["東連海道徹扶桑，北望神皋斗柄旁。", "兩處音塵杳難接，征鴻歲只到衡陽。"]'),
('e452f56d-a720-4897-93dd-c7b30d0b4511','送沈生昆弟隨侍之博白四絕句  其四','張方平','宋','宋诗','song-poetry','','[]','夕陽疎葦暮江湄，秋色蕭蕭動客思。',32,'全唐诗/poet.song.18000.json','["夕陽疎葦暮江湄，秋色蕭蕭動客思。", "自侍嚴君領州去，豈同騷客夢邊時。"]'),
('3b14d386-2b89-495d-aeda-8c3634bf652b','吳范天章','張方平','宋','宋诗','song-poetry','','[]','詔起東山對紫庭，清風蕭灑動階蓂。',64,'全唐诗/poet.song.18000.json','["詔起東山對紫庭，清風蕭灑動階蓂。", "讜言幾爲忠邪發，大用須憑廟社靈。", "武庫神兵羅斧戟，大宮禮器列籩鉶。", "願公早入當鈞軸，重演三篇相武丁。"]'),
('9dc113bd-99ba-463e-9c78-0706b51c85c8','送郭誠思歸華下','張方平','宋','宋诗','song-poetry','','[]','忘懷物外且如愚，何事勞精據槁梧。',64,'全唐诗/poet.song.18000.json','["忘懷物外且如愚，何事勞精據槁梧。", "以馬喻馬即非馬，數輿無輿方得輿。", "莫執斧斤過櫟社，懶施几席向蘧廬。", "好歸玉秀峰前坐，閒看晴雲自卷舒。"]'),
('976b051e-4bb0-4dff-8e88-eafe17aa2f88','送汾陽高士歸三峰','張方平','宋','宋诗','song-poetry','','[]','知逢三洞客，曾指九丹方。',48,'全唐诗/poet.song.18000.json','["知逢三洞客，曾指九丹方。", "氣抱冰霜冷，神含日月光。", "閒軒同鶴靜，妙境入龜長。", "它日南峯路，相期過華陽。"]'),
('727e02d5-821f-41e2-9855-0b56f955e252','送邢遁山人','張方平','宋','宋诗','song-poetry','','[]','忽悔輕拋雲水來，便將鶴去指林齋。',64,'全唐诗/poet.song.18000.json','["忽悔輕拋雲水來，便將鶴去指林齋。", "生涯琴劔外無物，日逐醉吟中遣懷。", "舊隱居常因夢到，塵遊動是與心乖。", "送君翻自嗟覉滯，木葉脫時還計偕。"]'),
('203816ae-1db7-41be-a286-bd4ced854f3a','送趙先生','張方平','宋','宋诗','song-poetry','','[]','家住崆峒塞垣上，翩然遊蜀遂忘歸。',64,'全唐诗/poet.song.18000.json','["家住崆峒塞垣上，翩然遊蜀遂忘歸。", "九還氣足通神化，一日丹成是道機。", "曾共靈龜波上隱，又隨蒼雀火中飛。", "只於醉裏藏身去，休入紅塵作是非。"]'),
('941fb6fb-2242-41a7-877d-71ca2380993e','送珪師歸衡嶽','張方平','宋','宋诗','song-poetry','','[]','師通禪律外，外學二篇微。',48,'全唐诗/poet.song.18000.json','["師通禪律外，外學二篇微。", "貌似寒山古，身隨風葉飛。", "瀟湘曾曉夢，鴻鴈伴南歸。", "七十三峯裏，雲庵拂舊扉。"]'),
('c46ce1c5-b878-4531-bd1d-c9ac17f641ce','送僧南遊雪竇','張方平','宋','宋诗','song-poetry','','[]','早出都門何往哉，四明雪竇指崔嵬。',64,'全唐诗/poet.song.18000.json','["早出都門何往哉，四明雪竇指崔嵬。", "便從古道揚眉去，莫到寶山空手回。", "乘月曉行松露濕，迎風晚渡海濤來。", "普賢樓閣知非遠，邐迤南遊想善財。"]'),
('c4073e6d-9a9d-4dfb-b67c-5f3872a2f4d1','贈韋不伐','張方平','宋','宋诗','song-poetry','','[]','莫隨世僞作圓方，坦坦元邪是履祥。',64,'全唐诗/poet.song.18000.json','["莫隨世僞作圓方，坦坦元邪是履祥。", "學鄙淺訛趨古道，天教轗軻與剛腸。", "俛投胯下人皆笑，獨卧隆中自不常。", "畢竟途窮無所合，何妨持釣坐滄浪。"]'),
('e6dad96c-2583-4130-95bf-dbe1d7a9f632','兗海孫學士寄晝錦編述先德宣公進退之美報之長句四韻奉揚盛事','張方平','宋','宋诗','song-poetry','','[]','鄒魯衣冠古士鄉，義方不獨有扶陽。',64,'全唐诗/poet.song.18000.json','["鄒魯衣冠古士鄉，義方不獨有扶陽。", "德名垂世先君子，經術傳家小太常。", "閭巷共榮新晝錦，吏民司愛舊甘棠。", "前人彝鼎銘勳伐，未似盈編盛事光。"]'),
('ca4f8cf4-757d-426e-afc2-944c00c86dc0','贈趙先生','張方平','宋','宋诗','song-poetry','','[]','此老得天樂，自稱雲水人。',48,'全唐诗/poet.song.18000.json','["此老得天樂，自稱雲水人。", "佯狂不妨道，太息漫勞神。", "沈醉少醒日，與遊多逸民。", "常憂忽不見，無處訪清塵。"]'),
('35a44ac9-26b3-4ab7-baeb-cc0156e22f4d','贈三茅朱先生','張方平','宋','宋诗','song-poetry','','[]','鬰儀結鄰太霄道，金鐺玉珮虛皇冠。',64,'全唐诗/poet.song.18000.json','["鬰儀結鄰太霄道，金鐺玉珮虛皇冠。", "鑪中火候煙霞煖，壇上磬聲星斗寒。", "紫節晨遊從玉女，綠軿夜降接靈官。", "願持璧紐充盟信，乞取胎精九化丹。"]'),
('42e78fbe-9919-4eda-8897-3d56f8e6d651','玉泉觀贈高道士','張方平','宋','宋诗','song-poetry','','[]','古屋氣象冷，蒼崖煙翠中。',48,'全唐诗/poet.song.18000.json','["古屋氣象冷，蒼崖煙翠中。", "龍歸半天雨，虎嘯一巖風。", "露後芝房紫，霜餘栢實紅。", "終期把藜杖，來伴白雲翁。"]'),
('469c8514-26cd-4107-8c69-6fb15477db25','贈郭誠思','張方平','宋','宋诗','song-poetry','','[]','壯志本桑弧，當年亦棄繻。',48,'全唐诗/poet.song.18000.json','["壯志本桑弧，當年亦棄繻。", "塵游謝京國，火記得酆都。", "露氣凝瓊樹，冰光澈玉壺。", "世間出世法，胎食即天厨。"]'),
('54e59cf3-f8de-4705-8666-c4bc4b3852d7','贈趙抱一','張方平','宋','宋诗','song-poetry','','[]','石門路已絕塵寰，紫柏高深不可攀。',64,'全唐诗/poet.song.18000.json','["石門路已絕塵寰，紫柏高深不可攀。", "野色蒼茫連遠水，暮雲慘澹裹寒山。", "琴碁有徇皆爲役，松竹無情且共閒。", "卉醴一盃時自釀，陶然亦可發朱顔。"]'),
('0aeecf51-cf0d-4948-8a6e-75f069b3081d','贈青城山威儀觀李鍊師','張方平','宋','宋诗','song-poetry','','[]','天倉三十六峰下，猶有軒轅轍迹存。',64,'全唐诗/poet.song.18000.json','["天倉三十六峰下，猶有軒轅轍迹存。", "丹竈前臨六時水，芎田遠接九仙門。", "火芝夜照千燈迥，江樹朝涵一氣渾。", "道友相邀尋異藥，携筇幾到老人村。"]'),
('afdf34a4-b409-4132-ab40-7b7346b4b15d','贈終南李道人','張方平','宋','宋诗','song-poetry','','[]','神仙靈藥自然功，五色光中一氣通。',32,'全唐诗/poet.song.18000.json','["神仙靈藥自然功，五色光中一氣通。", "借問參同相類法，何如相類即參同。"]'),
('b52c47e9-3373-4d38-aaa9-82a7f4d9ab17','贈琅邪智先長老','張方平','宋','宋诗','song-poetry','','[]','山路層層峻，幽棲最上層。',48,'全唐诗/poet.song.18000.json','["山路層層峻，幽棲最上層。", "凈光懸海月，幻體任春冰。", "四句有爲法，一心無盡燈。", "我來忘所問，相伴久騰騰。"]'),
('63e0f61c-6c5c-4a19-9984-c891abdaec50','贈辰長老','張方平','宋','宋诗','song-poetry','','[]','燕坐非持律，遊方不學禪。',48,'全唐诗/poet.song.18000.json','["燕坐非持律，遊方不學禪。", "長空任飛鳥，古澗自寒泉。", "見月何須指，追風不待鞭。", "平生一破衲，隨處伴閒眠。"]'),
('d3d1e655-973b-44d2-a12c-251afddb15cf','贈崆峒天水公','張方平','宋','宋诗','song-poetry','','[]','天下赤龍訣，人間金液丹。',48,'全唐诗/poet.song.18000.json','["天下赤龍訣，人間金液丹。", "先生今已得，此事古傳難。", "陰德留塵世，仙階在廣寒。", "舊聞三五一，乞取畧開端。"]'),
('25c357d9-f272-4e23-a097-21ce7a1541a5','送徐總','張方平','宋','宋诗','song-poetry','','[]','半醉長呼意若何，官情道味兩蹉跎。',64,'全唐诗/poet.song.18000.json','["半醉長呼意若何，官情道味兩蹉跎。", "眼前漸漸故人少，世上紛紛新事多。", "疎籟自鳴非節奏，虛舟妄觸任風波。", "悲歌深歎流年急，常憶江南藍采和。"]'),
('02bf009c-fba3-49ef-a2b6-08db313f4922','送杜山人','張方平','宋','宋诗','song-poetry','','[]','到不說來處，去安知所之。',48,'全唐诗/poet.song.18000.json','["到不說來處，去安知所之。", "野雲同自在，溪鳥與誰期。", "虎伴閒行遠，猿驚住嘯遲。", "相逢聊一醉，重見又何時。"]'),
('c4cde1ce-cb7d-4182-afb3-8e0ba65b7aeb','宋屯田歸湖南','張方平','宋','宋诗','song-poetry','','[]','舊學孫明復，春秋助發微。',48,'全唐诗/poet.song.18000.json','["舊學孫明復，春秋助發微。", "倦遊驚白首，知已失緇衣。", "乞了朝雞去，南隨社燕歸。", "衡湘多隱逸，道侶未應稀。"]'),
('944687ba-6890-4109-9ade-2f0214c50a5c','筇杖贈凌生','張方平','宋','宋诗','song-poetry','','[]','山居知獨處，一杖代兒曹。',48,'全唐诗/poet.song.18000.json','["山居知獨處，一杖代兒曹。", "試水溪沙淺，挑雲嶺路高。", "訪僧歸有伴，採藥遠忘勞。", "它日蓬萊會，應騎過海濤。"]'),
('5f294e69-0178-48a8-a824-15da0e2b768d','都官葉郎中歸三衢','張方平','宋','宋诗','song-poetry','','[]','宗邸橫經授小侯，跡同半隱久沈浮。',64,'全唐诗/poet.song.18000.json','["宗邸橫經授小侯，跡同半隱久沈浮。", "却尋故國溪山路，多謝朝堂鐘鼓樓。", "冉冉年華年老態，紛紛時事作閒愁。", "一丘一壑平生志，況有門人伴釣遊。"]'),
('74c460d1-d44a-443c-b7a3-909457dc1700','微子廟','張方平','宋','宋诗','song-poetry','','[]','西伯已招二大老，東鄰更棄三仁人。',64,'全唐诗/poet.song.18000.json','["西伯已招二大老，東鄰更棄三仁人。", "元龜遂訖商家命，白馬永爲周室賓。", "抱器幸存天鳳祀，喪邦都爲牝雞晨。", "可憐長發源流遠，舊國猶存廟樹春。"]'),
('9c1c005c-b04a-4748-a63a-248b0734a7ce','秦州北山云是隗囂宮登城樓下瞰偶題','張方平','宋','宋诗','song-poetry','','[]','宛下君臣實兒戲，昆陽勝敗非人力。',64,'全唐诗/poet.song.18000.json','["宛下君臣實兒戲，昆陽勝敗非人力。", "劉秀其來異獨夫，隗囂何事爲西伯。", "送質已是不能强，保險明知本無策。", "惟其得士似田橫，後世英雄共嗟惜。"]'),
('bbf9e9b0-f2ac-43e5-998d-9ca6be41ad16','讀杜工部詩','張方平','宋','宋诗','song-poetry','','[]','文物皇唐盛，詩家老杜豪。',240,'全唐诗/poet.song.18000.json','["文物皇唐盛，詩家老杜豪。", "雅音還正始，感興出離騷。", "運海張鵬翅，追風騁驥髦。", "三春上休苑，八月浙江濤。", "璀璨開鮫室，幽深閉虎牢。", "金晶神鼎重，玉氣霽虹高。", "甲馬騰千隊，戈船下萬艘。", "吳鈎銛莫觸，羿彀巧無逃。", "遠意隨孤鳥，雄筋舉六鼇。", "曲嚴周廟肅，頌美孔圖襃。", "世亂多羣盜，天遥隔九臯。", "途窮傷白髮，行在窘青袍。", "憂國論時事，司功去諫曹。", "七哀同谷寓，一曲錦川遨。", "妻子饑寒累，朝廷戰伐勞。", "倦遊徒右席，樂善伐干旄。", "舊里歸無路，危城至輒遭。", "行吟非楚澤，達觀念莊濠。", "逸思乘秋水，愁腸困濁醪。", "耒陽三尺土，誰爲翦蓬蒿。"]'),
('1c606e1a-cec1-4f8e-9658-28a725993f2e','題楊大年集後','張方平','宋','宋诗','song-poetry','','[]','天上靈仙謫，人間秀氣涵。',144,'全唐诗/poet.song.18000.json','["天上靈仙謫，人間秀氣涵。", "朱絃清廟瑟，美幹豫章柟。", "富艷三千牘，從容八十函。", "典純追古昔，雅正合周南。", "溫粹瓊瑶潤，滋醲稼穡甘。", "微中緘海蚌，巧處吐春蠶。", "璀璨龍宮出，精深虎穴探。", "機衡成臲尯，嵩洛入煙嵐。", "寂忍修禪智，虛柔慕史聃。", "驥轅曾未騁，鸞馭不停驂。", "巖廟登何數，承明入獨三。", "可憐經濟意，舊客記高談。"]'),
('a6aeb282-125a-4ae3-9e9e-1d838e3a0390','讀王樸傳','張方平','宋','宋诗','song-poetry','','[]','世主英威動九陽，高賢事業出巖廊。',64,'全唐诗/poet.song.18000.json','["世主英威動九陽，高賢事業出巖廊。", "何須夢卜疑千古，灼見雲雷定四方。", "小國霸圖微管葛，當時人傑自蕭張。", "不終制作成遺恨，律準今猶在太常。"]'),
('291537ce-2112-4a2b-8781-41e44daa7c0c','讀素書','張方平','宋','宋诗','song-poetry','','[]','孺子圯橋跪履年，七章德在穀城仙。',64,'全唐诗/poet.song.18000.json','["孺子圯橋跪履年，七章德在穀城仙。", "所言道德帝王事，不比盤盂長短篇。", "晚欲出塵應有訣，初行遇漢豈非天。", "蕭曹勳業皆勞力，寧似功成樽俎前。"]'),
('9e71120a-6cc4-4c1c-8401-2c89beecfed6','過豐','張方平','宋','宋诗','song-poetry','','[]','劉季當年在古豐，芒碭王氣已連空。',64,'全唐诗/poet.song.18000.json','["劉季當年在古豐，芒碭王氣已連空。", "天機先露由啼嫗，人意冥符自董公。", "歷數有歸徒勝負，風雲相會盡英雄。", "不然樊酈蕭曹輩，盡老屠商掾吏中。"]'),
('10fd70e7-a3ed-4936-8369-f9c861f6771a','過沛題歌風臺','張方平','宋','宋诗','song-poetry','','[]','落托劉郎作帝歸，樽前感慨大風詩。',32,'全唐诗/poet.song.18000.json','["落托劉郎作帝歸，樽前感慨大風詩。", "淮陰反接英彭族，更欲多求猛士爲。"]'),
('25b99d91-9a2a-4fd7-9dba-567f11f4a90d','題中陽里高祖廟','張方平','宋','宋诗','song-poetry','','[]','縱酒踈狂不治生，中陽有土倚兄耕。',32,'全唐诗/poet.song.18000.json','["縱酒踈狂不治生，中陽有土倚兄耕。", "晚遭亂世成功業，更向公前與仲爭。"]'),
('90e52e0a-b807-4b3a-91d0-65e1ee58d30b','臨淄同劉仲方作','張方平','宋','宋诗','song-poetry','','[]','迴合空山萬疊蒼，磻溪投釣此開疆。',64,'全唐诗/poet.song.18000.json','["迴合空山萬疊蒼，磻溪投釣此開疆。", "儒家俎豆連洙泗，戰圖戈鋋接楚梁。", "四嶽子孫終海嶼，諸田意氣盡尸鄉。", "不惟仲父能輕重，形勝由來自霸强。"]'),
('a5d89518-736c-4d3d-a14a-345c274e4f72','劇孟','張方平','宋','宋诗','song-poetry','','[]','人物無重輕，廟朝有失得。',48,'全唐诗/poet.song.18000.json','["人物無重輕，廟朝有失得。", "世平徒匹夫，時摇一敵國。", "姦雄望風塵，冠劒動慙色。", "治庭不論功，聲名輝典策。"]'),
('4a1c7565-d9d0-4f5f-94dc-fbdb52910fed','讀齊世家','張方平','宋','宋诗','song-poetry','','[]','默坐磻溪素髮垂，商周於此繫興衰。',32,'全唐诗/poet.song.18000.json','["默坐磻溪素髮垂，商周於此繫興衰。", "機深正似忘機者，應被沙鷗靜處窺。"]'),
('f2dfec29-008c-43fd-847e-ea1de45575e1','讀楞伽經','張方平','宋','宋诗','song-poetry','','[]','楞伽三萬六千偈，百八句中成自性。',64,'全唐诗/poet.song.18000.json','["楞伽三萬六千偈，百八句中成自性。", "法法非法離法塵，心心無心入心病。", "漸熟當似菴羅果，頓照猶如大圓鏡。", "龜毛兔角妄有無，海浪空華不清浄。"]'),
('5bab1427-2111-4432-8139-93d7cc85d025','讀混元經','張方平','宋','宋诗','song-poetry','','[]','五行生成本一氣，曉此體用知命樞。',64,'全唐诗/poet.song.18000.json','["五行生成本一氣，曉此體用知命樞。", "還元當復定金鏁，過宿寧更懷蘧廬。", "無質生質是丹地，有象非象真壇圖。", "此途得道亦連袂，遲晚須乘八景輿。"]'),
('2be28452-9f56-447b-b8dc-cb0ca5f5dd56','寂默通真說因戒而定云是小乘漸法然至則成大其致一也趙少師叔平覽之有疑見問以此答','張方平','宋','宋诗','song-poetry','','[]','即定非存出入間，照而常寂所居安。',64,'全唐诗/poet.song.18000.json','["即定非存出入間，照而常寂所居安。", "將心起用知逾遠，有眼無光見亦難。", "向上本來惟一路，初機聊爲立三關。", "莫於此地分延促，彈指時中海水乾。"]'),
('7a2c7304-4341-4f60-b747-79db6c0d2735','讀坐忘論','張方平','宋','宋诗','song-poetry','','[]','正一初傳王遠知，後來體用益精微。',64,'全唐诗/poet.song.18000.json','["正一初傳王遠知，後來體用益精微。", "惟無矜貴爲真地，但涉成虧即世機。", "松徑風聲猶有待，糠鑪火候事終違。", "便令直了九丹術，不到坐忘何處歸。"]'),
('e1392e8f-fa7a-4bcd-ae40-35395337333a','覽九丹上化經寄南都王宣徽君貺','張方平','宋','宋诗','song-poetry','','[]','上清紫簡世傳稀，中有靈都妙旨微。',64,'全唐诗/poet.song.18000.json','["上清紫簡世傳稀，中有靈都妙旨微。", "雲霧披光丹鳳出，風雷接勢赤龍飛。", "琴心三疊胎仙舞，籥筦雙迎帝子歸。", "幸得九天真一訣，塵勞何事尚依依。"]'),
('5bba5bb0-f0c2-4a73-bdb5-8674a9570a37','讀穆天子傳','張方平','宋','宋诗','song-poetry','','[]','八龍長鶩造崑丘，七萃前驅縱逸遊。',64,'全唐诗/poet.song.18000.json','["八龍長鶩造崑丘，七萃前驅縱逸遊。", "遇雪自裁黄竹唱，捧觴喜答白雲謳。", "羽陵廣奏隨風逝，崦阜銘蹤共日留。", "惆悵璧臺人不返，樂池遺恨素波愁。"]'),
('366e4998-cb72-4da8-98f0-b254736e5c6a','讀樊川集','張方平','宋','宋诗','song-poetry','','[]','不遇元和得獻謨，望山東北每長噓。',64,'全唐诗/poet.song.18000.json','["不遇元和得獻謨，望山東北每長噓。", "獨賡唐律雅風後，更注孫篇俎豆餘。", "霅水勝遊成悵望，杜川歸事竟躊躇。", "中年遽使山根折，盡寫雄襟在此書。"]'),
('36fb6f46-68b6-417f-af6a-2c3efd4b8af9','讀杜詩','張方平','宋','宋诗','song-poetry','','[]','杜陵有窮老，白頭惟苦吟。',120,'全唐诗/poet.song.18000.json','["杜陵有窮老，白頭惟苦吟。", "正氣自天降，至音感人深。", "昭回切雲漢，曠眇包古今。", "萬壑入溟海，一枝成鄧林。", "掩抑鬼神泣，寂寥星月沈。", "珠憑罔象得，玉看晶采尋。", "穰穰豐年穀，磊磊殊方琛。", "病源問岐伯，兵畧須淮陰。", "流寓四方路，浩蕩平生心。", "每覽述懷篇，使我清淚淫。"]'),
('31f928e1-4ee1-4da7-8290-8173129b45df','題英烈王廟','張方平','宋','宋诗','song-poetry','','[]','固云志在修私怨，破郢其如不利吳。',32,'全唐诗/poet.song.18000.json','["固云志在修私怨，破郢其如不利吳。", "由此夫差心遂侈，鴟夷豈得謂非辜。"]'),
('8394dbc6-6ac1-478b-a642-0b3fc5ff5365','東方朔','張方平','宋','宋诗','song-poetry','','[]','不獨巖扃與市塵，金門亦可晦吾真。',32,'全唐诗/poet.song.18000.json','["不獨巖扃與市塵，金門亦可晦吾真。", "孤風大義人誰見，宣室聊曾抗倖臣。"]'),
('e8fa435b-158a-4130-b522-b020ab6aa029','天聖中年嘗有異夢熙寧癸丑退居南臺聊記舊事','張方平','宋','宋诗','song-poetry','','[]','凌空素閣彩霞鮮，舊侶相容見九玄。',64,'全唐诗/poet.song.18000.json','["凌空素閣彩霞鮮，舊侶相容見九玄。", "上下登梯一童子，逡巡離座六靈仙。", "跪瞻寶案凝神久，手納金匙受記專。", "病卧夜長思此境，忽驚四十有三年。"]'),
('8e0d9fc9-2350-4588-b921-0681044121d4','侯君房','張方平','宋','宋诗','song-poetry','','[]','爵位功名可自豪，青雲志士豈而曹。',32,'全唐诗/poet.song.18000.json','["爵位功名可自豪，青雲志士豈而曹。", "一朝黄鉞看看下，始愧狂奴故態高。"]'),
('e197ef11-75c8-4c64-bf1e-10fe1765c25d','被命中山以親老不赴書懷寄集賢曾公參政趙公','張方平','宋','宋诗','song-poetry','','[]','野懷常逐白雲飛，疎拙那能合世機。',64,'全唐诗/poet.song.18000.json','["野懷常逐白雲飛，疎拙那能合世機。", "偶似曹溪一宿覺，已多蘧瑗九年非。", "畧呈幻事何須了，惟願朝恩早放歸。", "它日蓮華峯下去，猶期話道過黄扉。"]'),
('c75a373c-aa90-44f7-b1cf-63c8d9b54b5f','上三司蔡內閣','張方平','宋','宋诗','song-poetry','','[]','此日河南念賈生，留將名字徹丹庭。',64,'全唐诗/poet.song.18000.json','["此日河南念賈生，留將名字徹丹庭。", "秋聲漸覺寒生樹，親老遥知獨倚扃。", "徒繫車傍淹白晝，得離韝上必青冥。", "公如未信牛間氣，試掘豐城必有靈。"]'),
('5888bc95-9689-4187-bb4c-62e1663587e8','謝范天章薦應制科','張方平','宋','宋诗','song-poetry','','[]','初闢明堂見帝軒，此時寧得戀丘園。',64,'全唐诗/poet.song.18000.json','["初闢明堂見帝軒，此時寧得戀丘園。", "程文懶謁春官氏，决策思干法扆尊。", "千古聲名傳鶚表，四方豪俊望龍門。", "若趨丹陛承清問，何以酬知或敢言。"]'),
('dc748635-bf8f-4cfb-b1f8-3927f40fc02d','次韻酬潭州周沆學士見寄','張方平','宋','宋诗','song-poetry','','[]','鼇背三山壓海濤，雲臺高議接時髦。',64,'全唐诗/poet.song.18000.json','["鼇背三山壓海濤，雲臺高議接時髦。", "一麾忽到江湖外，回首方驚日月高。", "不善取容同曼倩，且歌樂職學王襃。", "賈生自是長沙遠，更弔湘纍賦廣騷。"]'),
('08a1e928-ce0e-4855-be6a-7e44fc3c5c2c','貽龔懋','張方平','宋','宋诗','song-poetry','','[]','所至輒驚座，歸來成淚痕。',48,'全唐诗/poet.song.18000.json','["所至輒驚座，歸來成淚痕。", "憐君孤劔客，擲謁五侯門。", "驕氣羞紈袴，凉風憶故園。", "時清經世事，捫蝨爲誰言。"]'),
('941dea01-35f9-4f10-85ef-a61f81bae1d2','寄徐白久客襄漢','張方平','宋','宋诗','song-poetry','','[]','避暑鹿門寺，虛齋風竹凉。',48,'全唐诗/poet.song.18000.json','["避暑鹿門寺，虛齋風竹凉。", "草連鄖國遠，水接漢川長。", "寓客懷江表，騷人愛楚鄉。", "京塵誠可厭，君未捨名場。"]'),
('dbe0386b-b628-4e41-9a77-467471e212d6','寄高弁侍郎','張方平','宋','宋诗','song-poetry','','[]','大雅久頹弊，夫君真古人。',96,'全唐诗/poet.song.18000.json','["大雅久頹弊，夫君真古人。", "道維皇極正，文著帝刑淳。", "美望鏘金石，深誠照鬼神。", "立朝惟一介，爲郡有遺仁。", "素尚陶弘景，風流賀季真。", "歲寒松有節，明瑩玉無塵。", "霜簡雖清重，銅符亦久迍。", "老成急登用，必有及斯民。"]'),
('c600b828-5b0e-42e1-ac9c-7f8e5d7143e8','寄汾陽郭先生','張方平','宋','宋诗','song-poetry','','[]','君家白雲外，巖溜響嘈嘈。',48,'全唐诗/poet.song.18000.json','["君家白雲外，巖溜響嘈嘈。", "絕壑風煙澹，孤峰冰雪高。", "自能無世累，誰見有生勞。", "指我蓬壺路，瓊宮隔海濤。"]'),
('8c90d684-9523-4abb-90a0-9ee957737e6e','寄三峰郭誠思','張方平','宋','宋诗','song-poetry','','[]','松檜峰前古柏林，結茅無伴對幽禽。',64,'全唐诗/poet.song.18000.json','["松檜峰前古柏林，結茅無伴對幽禽。", "鄙爲浮薄八公事，獨入精微九聖心。", "春斸晴川閒種玉，夜開丹竈試還金。", "泠然風馭知何返，三十六關雲路深。"]'),
('43f5dfa7-2d64-4783-968c-a3fd967bcc6e','訪朱先生值晝寢','張方平','宋','宋诗','song-poetry','','[]','一枕清風靖館深，滿庭公檜鬰交陰。',32,'全唐诗/poet.song.18000.json','["一枕清風靖館深，滿庭公檜鬰交陰。", "此時真境誰人見，月在泥丸日在心。"]'),
('da19ac27-9ff1-448f-97a7-c2edc78b8ab0','寄代淵','張方平','宋','宋诗','song-poetry','','[]','塵走我何勞，巖棲君愈高。',48,'全唐诗/poet.song.18000.json','["塵走我何勞，巖棲君愈高。", "林齋且吟嘯，世路盡風濤。", "小桂閒招隱，西岷續返騷。", "氣機衝不露，承弁縱雙毛。"]'),
('6da2382f-d0ea-4d8c-b8b4-37cc91c3f971','貽劉几','張方平','宋','宋诗','song-poetry','','[]','家自唐來世大儒，惟君不肯讀家書。',64,'全唐诗/poet.song.18000.json','["家自唐來世大儒，惟君不肯讀家書。", "春遊爛漫少曾醒，俊氣飄揚頻得盧。", "早講猿公飛劔術，更通風后握機圖。", "何時羽獵長圍合，請看雲中一鶚孤。"]'),
('0867c570-419b-4623-a249-999f6be27884','謝韓仲文學士送白竹簟','張方平','宋','宋诗','song-poetry','','[]','带粉裁踈節，凌霜剪翠筩。',106,'全唐诗/poet.song.18000.json','["带粉裁踈節，凌霜剪翠筩。", "鯨鱗鋪海浪，鵬翅展天風。", "暖恐春冰釋，清宜曉魄融。", "露華流沆瀣，寒色凜崆峒。", "栩栩來莊蝶，{瞢目=羽}{瞢目=羽}失夏蟲。", "枕須松石碧，幌鄙霧綃紅。", "坐覺非塵境，魂如在月宮。", "北窗聊寄傲，俗骨愧方瞳。"]'),
('626e7324-67c5-4a03-b3ea-812699cbec78','金陵久旱喜雨呈運使韓綜學士提刑令狐挺祠部及示諸府僚','張方平','宋','宋诗','song-poetry','','[]','江城風日燥將燃，喜此滂沱僅有年。',64,'全唐诗/poet.song.18000.json','["江城風日燥將燃，喜此滂沱僅有年。", "諸澤氣交陰壓地，四溟水立闊圍天。", "廓開紫宙清凉界，頓去驕陽跋扈權。", "須信化工人可代，傅巖才業在三篇。"]'),
('c01ba943-bd46-459f-af73-ac4fe62931a4','提刑祠部再和前篇猥爲禱祈之應輒復次韻且以見志','張方平','宋','宋诗','song-poetry','','[]','長吏憂民深望歲，諸侯閔雨著編年。',64,'全唐诗/poet.song.18000.json','["長吏憂民深望歲，諸侯閔雨著編年。", "鵝鮮聊用遵明詔，尩鼻何能感上天。", "五事肅時斂在宥，九功美利屬持權。", "守藩無狀惟推分，必在蒙莊內外篇。"]'),
('d24b9df0-c929-4879-8135-17bbc41fedb8','謝浙漕劉忠順郎中送簟','張方平','宋','宋诗','song-poetry','','[]','玉水一方光瀲灧，霜華八尺翠琅玕。',32,'全唐诗/poet.song.18000.json','["玉水一方光瀲灧，霜華八尺翠琅玕。", "卧來病骨殊清快，勝餌西山五色丸。"]'),
('eaf2a182-baf5-4c86-b26a-de0265bf4fe3','近自鍾山採松花和湯甚美送湯一甖呈仲文學士  其一','張方平','宋','宋诗','song-poetry','','[]','青松北山麓，春蕊摘金團。',48,'全唐诗/poet.song.18000.json','["青松北山麓，春蕊摘金團。", "芳澤逾肪節，滋華本歲寒。", "功傳上品藥，餌勝曲晨丹。", "一泛彤霞液，天和入肺肝。"]'),
('052db1a9-e314-45cd-8ad2-ee5922d74e8b','近自鍾山採松花和湯甚美送湯一甖呈仲文學士  其二','張方平','宋','宋诗','song-poetry','','[]','日精月華所滋結，金匱瓊笈稱靈珍。',64,'全唐诗/poet.song.18000.json','["日精月華所滋結，金匱瓊笈稱靈珍。", "味勝仙人掌中露，色如遊女衣上塵。", "餌之伐邪鍊神魄，久且長年登高真。", "輕瑿茯菟乃淪滓，嘉賞當問清遐人。"]'),
('4cb8464b-97e6-4822-8adc-cf0892010a77','居憂過祥制示辰長老','張方平','宋','宋诗','song-poetry','','[]','流景無端隙駟馳，永懷顧復感慈闈。',64,'全唐诗/poet.song.18000.json','["流景無端隙駟馳，永懷顧復感慈闈。", "幸茲門外車馬少，更復朝中書信稀。", "衰颯顛毛素絲短，芒佯病眼亂花飛。", "舍西賴與招提接，時叩禪關話祖機。"]'),
('1a4f9d01-4897-449b-aeba-863727615250','貽辰長老','張方平','宋','宋诗','song-poetry','','[]','同流誰往還，終日掩柴關。',48,'全唐诗/poet.song.18000.json','["同流誰往還，終日掩柴關。", "壁觀少林寺，門風先洞山。", "道場隨處是，心地本來閒。", "指我常河水，都忘鬢髮斑。"]'),
('5fb37b7f-5bbf-452a-8bf1-5229abd50c94','離都招友人','張方平','宋','宋诗','song-poetry','','[]','車馬交塵路不停，勢家門巷密如萍。',64,'全唐诗/poet.song.18000.json','["車馬交塵路不停，勢家門巷密如萍。", "張湯筋力奈寒暑，樓護口舌摇風霆。", "機牙潛發如馳傳，聲影相連若建瓴。", "此地豈容山野客，盍歸乎來掩巖扃。"]'),
('42325c41-0278-4c1e-a82f-0125afdad574','慶臺韓子華寄示清居大士牧牛圖頌酬寄長句','張方平','宋','宋诗','song-poetry','','[]','香嚴昔向溈山住，只作田翁學牧牛。',64,'全唐诗/poet.song.18000.json','["香嚴昔向溈山住，只作田翁學牧牛。", "路絕纖塵寧見迹，野無寸草漫迴頭。", "晴天任去雲作伴，露地閒眠夜不收。", "却問清居真了未，樹邊蓑笠爲誰留。"]'),
('7c6c7b22-ba20-4749-855c-a0bd98aa370f','都下別友人','張方平','宋','宋诗','song-poetry','','[]','海內故人少，市樓新酒醇。',48,'全唐诗/poet.song.18000.json','["海內故人少，市樓新酒醇。", "與君聊一醉，公袂此殘春。", "北道邢臺路，東州泗水濱。", "相期復何處，京洛舊風塵。"]'),
('02825d8d-12f7-4c5a-907d-bff78fa0b77f','寄魯平','張方平','宋','宋诗','song-poetry','','[]','平也青雲器，鄉評推孝廉。',168,'全唐诗/poet.song.18000.json','["平也青雲器，鄉評推孝廉。", "高懷焦尾澹，壯節湛盧銛。", "與我偏心照，論交以道詹。", "逸羣容策蹇，美盼對無鹽。", "振楫期同濟，提衡豈致嫌。", "前年稅征鞅，彌月憩衡苫。", "環堵藜爲榻，圭門席掛簷。", "未曾憂四壁，聊與醉青帘。", "且默何嘗說，雖寒不附炎。", "伏龍當自起，躍馬要誰占。", "舌在居貧樂，情親茹蓼甜。", "雅遊傷遽散，流景顧將淹。", "信斷傷秋鴈，愁多伴夜蟾。", "不堪男女淚，北望一漸漸。"]'),
('c6e486a1-e34f-479a-91de-f56ea290448c','寄郭誠思華下茅齋','張方平','宋','宋诗','song-poetry','','[]','舍在世塵外，松扉夜不關。',48,'全唐诗/poet.song.18000.json','["舍在世塵外，松扉夜不關。", "心同秋水靜，身共野雲閒。", "自得逾三樂，誰堪話九還。", "它年玉泉約，何以救衰顔。"]'),
('31d24502-d52d-4071-a3cc-62f71d2a749d','寄題都下知友山亭時在新定','張方平','宋','宋诗','song-poetry','','[]','古郡利名外，萬山雲靄中。',48,'全唐诗/poet.song.18000.json','["古郡利名外，萬山雲靄中。", "思君痛飲處，累石小軒東。", "觀闕風光近，郊園野趣同。", "溪頭對魚鳥，未羨舞裙紅。"]'),
('7a38205e-3c51-43fc-bfa6-9479480fcd7a','菴堂書懷呈郭誠思','張方平','宋','宋诗','song-poetry','','[]','曉駕白龍車，氤氳入紫霞。',48,'全唐诗/poet.song.18000.json','["曉駕白龍車，氤氳入紫霞。", "翠微雲外路，碧落月中家。", "駛過剛風騎，閒如迥漢查。", "幽窗一欹枕，世慮自空花。"]'),
('aa120894-2e58-496f-bbbe-317107862e79','誠思約以初秋東來相過輒馳短韻以速行期','張方平','宋','宋诗','song-poetry','','[]','已聞露葉寒蟬急，休待霜空曉鴈催。',32,'全唐诗/poet.song.18000.json','["已聞露葉寒蟬急，休待霜空曉鴈催。", "不是相思閒命駕，無爲弟子望師來。"]'),
('499b55c2-e944-4240-8dd0-621fbf8e0c86','留別所知','張方平','宋','宋诗','song-poetry','','[]','雪擁歸程朔吹寒，來時孤劔繫征鞍。',32,'全唐诗/poet.song.18000.json','["雪擁歸程朔吹寒，來時孤劔繫征鞍。", "此行誓不忘知己，昨夜爲公重一彈。"]'),
('f8c95627-fb08-4765-80ea-df3b7f656ee6','熙寧壬子歲寄丁未同甲諸公秦亭呂宣徽寶臣汝陰歐陽少師永叔京下王尚書仲儀','張方平','宋','宋诗','song-poetry','','[]','百二十年名上壽，浮生百歲實稀聞。',64,'全唐诗/poet.song.18000.json','["百二十年名上壽，浮生百歲實稀聞。", "百年三萬六千日，今已三分過二分。", "嘯歌獨喜齒全在，文字看來眼未昏。", "酒量雖衰猶得醉，塵中人事自紛紛。"]'),
('00e20826-e4cb-4a61-ac4f-10fbdd5e6eb3','聞翰林承旨宋子京尚書捐館','張方平','宋','宋诗','song-poetry','','[]','平昔雍容兩禁游，共陪帷幄奉咨謀。',64,'全唐诗/poet.song.18000.json','["平昔雍容兩禁游，共陪帷幄奉咨謀。", "功名不到麒麟閣，詞賦空傳鸚鵡洲。", "事業三朝虛物望，聲華一代擅風流。", "清時只作文章老，誰識深懷藴九疇。"]'),
('2e9c022f-40a9-4fd0-bc64-04b4f1777a41','哭劉潛','張方平','宋','宋诗','song-poetry','','[]','嘗謂君才似武侯，草廬牢落卧龍愁。',64,'全唐诗/poet.song.18000.json','["嘗謂君才似武侯，草廬牢落卧龍愁。", "天公不念蒼生故，元叔堪憐郡吏休。", "蒿野已埋經國策，巖廓誰是富民侯。", "朝廷今始思英俊，不見庖丁刃一投。"]'),
('ef3901bf-8aa1-45bd-a1e8-9ea1e71a2b72','聞郭誠思解化','張方平','宋','宋诗','song-poetry','','[]','溪堂月榭幾分盃，暫住三峰約便回。',64,'全唐诗/poet.song.18000.json','["溪堂月榭幾分盃，暫住三峰約便回。", "齋榻忽留青竹去，庭除不待玉棺來。", "人間如幻寧同恨，天上修文亦用才。", "碧秀煙雲無限好，此生勿復望崔嵬。"]'),
('f933ce84-ede7-49ed-aa39-8f6898f6eeba','簡徐登道人','張方平','宋','宋诗','song-poetry','','[]','聞說頻來帝里遊，藥鑪何日得同流。',32,'全唐诗/poet.song.18000.json','["聞說頻來帝里遊，藥鑪何日得同流。", "勸君只就紅塵裏，撥轉河車萬事休。"]'),
('a4437029-b8a3-40b8-8098-f45e0be735e3','葛居士詩','張方平','宋','宋诗','song-poetry','','[]','三峰頂上五經秋，妙法白蓮清浄脩。',64,'全唐诗/poet.song.18000.json','["三峰頂上五經秋，妙法白蓮清浄脩。", "無數天花常自散，真空性水不停流。", "病癡誰問維摩詰，俗眼徒嗟冉伯牛。", "別有妙身諸相具，金剛堅固異浮漚。"]'),
('a4c18e81-eaad-4dea-bb56-23eb1e577cf4','月夜吳春卿蘇儀甫相過會飲忽聞五鼓遂同入朝','張方平','宋','宋诗','song-poetry','','[]','清風凉月滿前軒，邂逅相逢索酒罇。',64,'全唐诗/poet.song.18000.json','["清風凉月滿前軒，邂逅相逢索酒罇。", "東有啟明俄動色，北來寒鴈亦驚魂。", "相車未過塵先起，宮漏纔終市早喧。", "階下從人催上馬，百官已是簇朝門。"]'),
('78f24a44-d754-4604-8f5f-8d7f8085fbc5','寄崆峒天水公','張方平','宋','宋诗','song-poetry','','[]','先生莫可測，滄海遠沈沈。',48,'全唐诗/poet.song.18000.json','["先生莫可測，滄海遠沈沈。", "詹尹徒端策，昭文不鼓琴。", "一丸天上藥，幾日靜中吟。", "安得菊花酒，盈巵金液深。"]'),
('362ad083-53cc-4532-9e5a-739aa5219101','赴錢塘吳江道中寄侍讀王君貺侍郎','張方平','宋','宋诗','song-poetry','','[]','畫船浮震澤，煙水接秋空。',48,'全唐诗/poet.song.18000.json','["畫船浮震澤，煙水接秋空。", "一霎過雲雨，滿帆開岸風。", "酒旗蓮蕩裏，僧剎橘洲中。", "何似并州路，塵高馬陰雄。"]'),
('08ce7e7d-0ab2-4752-858e-a6e3e3fa318b','趙先生王屋杖','張方平','宋','宋诗','song-poetry','','[]','待月移肩倚，聽琴向膝橫。',48,'全唐诗/poet.song.18000.json','["待月移肩倚，聽琴向膝橫。", "溪橋經雨滑，山屐入雪輕。", "擊水乖龍起，書空老魅驚。", "夜歸聞石響，鶴舞遠來迎。"]'),
('6c9bcdcc-36eb-4143-baa0-1df24893b3ed','中秋夜清思臺獨坐對月寄太傅曾魯公宮師趙公','張方平','宋','宋诗','song-poetry','','[]','萬籟沈聲羣動息，纖塵絕跡片雲無。',32,'全唐诗/poet.song.18000.json','["萬籟沈聲羣動息，纖塵絕跡片雲無。", "此時何物名身世，一點靈光徹太虛。"]'),
('7e1ee626-3d60-4119-9598-f18065281e3d','蘇子瞻寄鐵藤杖','張方平','宋','宋诗','song-poetry','','[]','隨書初見一枝藤，入手方知鍛鍊精。',64,'全唐诗/poet.song.18000.json','["隨書初見一枝藤，入手方知鍛鍊精。", "遠寄只緣憐我老，閒携常似共君行。", "靜軒獨倚身同瘦，小圃頻遊脚爲輕。", "何日歸舟上新洛，拄來河岸笑相迎。"]'),
('c6128b0d-b704-4da9-9b61-05c06f83acae','西齋偶書','張方平','宋','宋诗','song-poetry','','[]','祖錄忘筌後，丹鑪住火時。',48,'全唐诗/poet.song.18000.json','["祖錄忘筌後，丹鑪住火時。", "浮生更無事，燕坐復何思。", "暖日移棊局，寒風促酒巵。", "世間安樂法，不獨浄名知。"]'),
('5db1994a-8f96-4bc7-8d52-2001c005196b','南原觀田','張方平','宋','宋诗','song-poetry','','[]','日長春事動，田野膏脈輕。',48,'全唐诗/poet.song.18000.json','["日長春事動，田野膏脈輕。", "草青布穀過，桑綠新蠶生。", "雨足有酒色，社近聞鼓聲。", "牛羊暮歸飽，舍中燈火明。"]'),
('cff3668c-2835-4445-abb8-ebfbefe7c08a','和叔平少師見示知足吟談宗旨也','張方平','宋','宋诗','song-poetry','','[]','昨日看公知足吟，寂然不動至人心。',64,'全唐诗/poet.song.18000.json','["昨日看公知足吟，寂然不動至人心。", "視身無實元泡幻，觀世皆空謾古今。", "忽忽歲窮駒度隙，塵塵事過鳥遺音。", "從來兩箇泥牛鬭，一任相將入海深。"]'),
('028cbf1e-ca3d-4c3e-a5cf-7692c379d9a9','初春遊李太尉宅東池','張方平','宋','宋诗','song-poetry','','[]','蓬島靈仙宅，星河帝女家。',48,'全唐诗/poet.song.18000.json','["蓬島靈仙宅，星河帝女家。", "波光泛金翠，樓影動雲霞。", "清淺遊魚過，參差垂柳斜。", "移舟更尋勝，遠見小桃花。"]'),
('56f05415-a2d3-4184-b956-4f31fb7858f8','題代祠部書院','張方平','宋','宋诗','song-poetry','','[]','上第西歸即棄官，此人趣味亦堪憐。',64,'全唐诗/poet.song.18000.json','["上第西歸即棄官，此人趣味亦堪憐。", "風波常自廟堂起，雲壑不隨朝市遷。", "野叟饋漿羞客氣，山僧投拂悟塵緣。", "青城山下空堂在，留入華陽續舊編。"]'),
('8c7824e1-c76d-424c-870f-84f4095133d9','登泰山太平頂','張方平','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','區區魯國爭蝸角，矗矗齊城磔蝟毛。',64,'全唐诗/poet.song.18000.json','["區區魯國爭蝸角，矗矗齊城磔蝟毛。", "萬壑相傾知地險，浮雲忽散覺天高。", "蒼煙自古埋塵世，紅日中宵破海濤。", "七十二君迷舊迹，空教秦漢侈心勞。"]'),
('003766ca-3746-4691-81bb-02b3062e2b5f','題樂全堂','張方平','宋','宋诗','song-poetry','','[]','樂全得意自莊書，靜閱流光樂有餘。',64,'全唐诗/poet.song.18000.json','["樂全得意自莊書，靜閱流光樂有餘。", "四句幻泡明般若，一篇力命信沖虛。", "心閒自覺浮雲薄，才拙誠知與世疎。", "只此空名漫兒戲，何王城闕不丘墟。"]'),
('c1a4058e-0ac5-447b-bf59-e106eaeb435b','逍遥堂','張方平','宋','宋诗','song-poetry','','[]','真樂不違俗，紅塵自滿城。',48,'全唐诗/poet.song.18000.json','["真樂不違俗，紅塵自滿城。", "捲簾寒日暖，高枕暑風清。", "世累離憂患，天和得性情。", "五時依約合，多謝白雲生。"]'),
('59a9dd1e-ecf3-4eb6-bc6e-8279bed80f18','李少傅佚老亭','張方平','宋','宋诗','song-poetry','','[]','得謝自廊廟，事高疏仲翁。',96,'全唐诗/poet.song.18000.json','["得謝自廊廟，事高疏仲翁。", "安車雖駟馬，歸路已冥鴻。", "令子承良冶，朱轓治左馮。", "緇衣方改造，列鼎有餘豐。", "屨杖居多適，軒裳夢覺空。", "天倪希柱史，性理問能公。", "窗檻開瀟灑，風煙接鬰葱。", "上方思賈誼，即奉小輿東。"]'),
('3f6555ab-4daf-4373-99de-28d5c22b30fb','彭門城上見鄉人社會懷古','張方平','宋','宋诗','song-poetry','','[]','南北分疆域，此城當要津。',48,'全唐诗/poet.song.18000.json','["南北分疆域，此城當要津。", "幻泡興廢速，蠻觴戰爭頻。", "世換山河舊，時平井邑新。", "喧喧村社散，多是白頭人。"]'),
('2e51bac0-e55f-4527-9356-6ccb1365f019','彭門公庭古檜爲風雨所摧','張方平','宋','宋诗','song-poetry','','[]','杳杳參天氣，亭亭構厦材。',48,'全唐诗/poet.song.18000.json','["杳杳參天氣，亭亭構厦材。", "千年對霜雪，一夕折風雷。", "枕靜疎聲減，庭寬翠影開。", "梧桐與楊柳，嬌色倚樓臺。"]'),
('a08fda69-f925-41b8-bb3a-e10ec5c05f95','暮秋登彭祖樓','張方平','宋','宋诗','song-poetry','','[]','危樓古城角，山色遶蒼倉。',48,'全唐诗/poet.song.18000.json','["危樓古城角，山色遶蒼倉。", "寒日下何速，清風來甚長。", "煙塵恩戰國，雲水似江鄉。", "重九登高近，階前菊已香。"]'),
('242bf862-ae8f-4ba5-8185-ea2d72d2d5fd','經遠樓','張方平','宋','宋诗','song-poetry','','[]','中夏聖人調律呂，八荒異國入圖書。',64,'全唐诗/poet.song.18000.json','["中夏聖人調律呂，八荒異國入圖書。", "從容德讓唐虞遠，馳騁戰爭秦漢餘。", "不道鼓旗無勇將，須知俎豆有真儒。", "功臣騎虎兇而國，常向冰淵審廟謨。"]'),
('21da8a1f-a40d-434d-8e99-870d1d6a4364','邽翠樓','張方平','宋','宋诗','song-poetry','','[]','一川墟宇暮煙中，樓堞籠山氣象雄。',64,'全唐诗/poet.song.18000.json','["一川墟宇暮煙中，樓堞籠山氣象雄。", "北路荒原戎子國，東坡斷塹隗囂宮。", "馬來洮海蕃城近，鶴去遼天越洞空。", "三十六程勞極目，隴雲猶在故關東。"]'),
('e17eb17c-ad09-40aa-aa91-34d389d8df15','道齋','張方平','宋','宋诗','song-poetry','','[]','瓊籤隱訣舊曾尋，共秘還金妙旨深。',64,'全唐诗/poet.song.18000.json','["瓊籤隱訣舊曾尋，共秘還金妙旨深。", "會向本源分造化，即拋塵劫出來今。", "含生皆是坎離氣，復會自知天地心。", "幻事徒勞聊一笑，他時雲壑有知音。"]'),
('6bbe51ed-04a5-4ff4-8aa7-82a1283006d2','禪齋','張方平','宋','宋诗','song-poetry','','[]','昔年曾見琅邪老，爲說楞伽最上乘。',64,'全唐诗/poet.song.18000.json','["昔年曾見琅邪老，爲說楞伽最上乘。", "頓悟紅鑪一點雪，忽驚闇室百千燈。", "便超十地猶塵影，更透三關轉葛藤。", "不住無爲方自在，打除都盡即南能。"]'),
('d3482d84-b58d-4166-86ba-cfc2c19af891','凉軒','張方平','宋','宋诗','song-poetry','','[]','樓下凉軒六月凉，風窗一枕傲羲皇。',64,'全唐诗/poet.song.18000.json','["樓下凉軒六月凉，風窗一枕傲羲皇。", "壽山雲影浮空近，羅谷泉聲遶砌長。", "迥覺風塵非此世，不須雪月更交光。", "最宜羽客冰霜骨，共引瑶巵沆瀣漿。"]'),
('72ff187b-9c3b-4423-8df9-515565a394cb','精思閣','張方平','宋','宋诗','song-poetry','','[]','仙術初脩自性情，本除陰濁養陽明。',64,'全唐诗/poet.song.18000.json','["仙術初脩自性情，本除陰濁養陽明。", "三田窈窈通虛白，一路層層徹太清。", "寂不動中方見道，思無邪處好存誠。", "君如欲到逍遥國，須自還元第一程。"]'),
('2d2399e6-db39-4ae7-a178-a1768392617d','凉軒秋意','張方平','宋','宋诗','song-poetry','','[]','南嶺雲嵐開曉霽，北窗松竹度凉颸。',64,'全唐诗/poet.song.18000.json','["南嶺雲嵐開曉霽，北窗松竹度凉颸。", "閒欹碧簟石琴薦，靜味丹經金鑰匙。", "夢幻泡中何得失，雀蚊蝱處苦喧卑。", "更令薰祓澄心閣，客自三峰到有期。"]'),
('3f3d55c2-6b6b-425d-acab-7e9b6abd6ee4','秦州即事','張方平','宋','宋诗','song-poetry','','[]','邊清羽書息，事簡使君慵。',48,'全唐诗/poet.song.18000.json','["邊清羽書息，事簡使君慵。", "地僻俗客少，日長春睡濃。", "平安三路火，昏曉兩山鐘。", "戍滿歸心動，先隨渭水東。"]'),
('070c7115-f635-4b67-a48f-ea05e569b4f0','秦州後園春宴贈部署劉几閣使','張方平','宋','宋诗','song-poetry','','[]','柳暗三眠困，花繁二月香。',48,'全唐诗/poet.song.18000.json','["柳暗三眠困，花繁二月香。", "情懷當酒盡，興味爲春長。", "疊鼓漁陽節，清謳北里粧。", "階前樂無誤，席上有周郎。"]'),
('3043affa-6266-4c47-b725-1d69da27c65a','秦州晚宴即席示諸賓僚','張方平','宋','宋诗','song-poetry','','[]','秦川節物似西川，二月風光已不寒。',64,'全唐诗/poet.song.18000.json','["秦川節物似西川，二月風光已不寒。", "猶去清明三候遠，忽驚爛漫一春殘。", "香隨芳樹頻移席，晴愛遥山久凭欄。", "却憶京華勝遊處，常爲暮景促歸鞍。"]'),
('5cdf0e1b-0b20-43f2-9e29-901e7daa7260','隴西郡麥積山有獻白鹿者潔如霜雪馴養逾年放歸舊山十二韻','張方平','宋','宋诗','song-poetry','','[]','地得金方正，山藏靈物珍。',144,'全唐诗/poet.song.18000.json','["地得金方正，山藏靈物珍。", "月宮遺玉兔，仙仗失霜麟。", "乳竇冰泉冷，晴原露草春。", "清風生澗壑，高格對松筠。", "久卧常存息，凝思若養神。", "煙崖一蹭蹬，華館久埃塵。", "我意本雲水，無心愛珮紳。", "平生厭俗客，待爾當嘉賓。", "蕭灑襟情遠，虛恬氣韻真。", "檜軒同鶴靜，竹渚伴鷗馴。", "龜智霑驪血，犧純被繡巾。", "放歸舊林麓，好去避虞人。"]'),
('4567862a-e267-451d-8755-b1886d072989','題松江曹生學舍','張方平','宋','宋诗','song-poetry','','[]','江邊無限地，君舍劣容蝸。',48,'全唐诗/poet.song.18000.json','["江邊無限地，君舍劣容蝸。", "爭鼓田家社，疎鐘野寺齋。", "執經多卉服，牽葑待荆釵。", "秋雨鱸魚美，時應釣蘚崖。"]'),
('42fe9f50-ea1d-4e86-b034-efc90295c39f','金陵府署池上草堂','張方平','宋','宋诗','song-poetry','','[]','東方千騎忝藩侯，情味都如寓一丘。',64,'全唐诗/poet.song.18000.json','["東方千騎忝藩侯，情味都如寓一丘。", "客氣盡將還野馬，機心聊自試沙鷗。", "時憑靜几隨飛蝶，强拂危冠笑沐猴。", "只向公齋得嘉遯，何須遠逐赤松遊。"]'),
('b9e757b2-ece8-4389-af13-3e0f2b4ddba3','送屐韓仲文','張方平','宋','宋诗','song-poetry','','[]','江南到梅暑，蒸濕鮮晴明。',48,'全唐诗/poet.song.18000.json','["江南到梅暑，蒸濕鮮晴明。", "聊倣登山樣，無妨涉水行。", "齒牢防易折，蠟滑亦加輕。", "早幸還吾土，閒將掛後楹。"]'),
('ebc47800-e8cd-4983-ac80-da8b829f6474','夢中吟','張方平','宋','宋诗','song-poetry','','[]','神歸自何處，記此夢中吟。',48,'全唐诗/poet.song.18000.json','["神歸自何處，記此夢中吟。", "道爲無心合，人因省語深。", "窗燈寒影薄，庭月曉光沈。", "悟境真泡幻，迷情妄古今。"]'),
('3c5eefbd-7dc5-44fd-959f-5d0c1903dcd1','秋夕聽彈五絃琴','張方平','宋','宋诗','song-poetry','','[]','古風久已壞，今夕聞遺聲。',48,'全唐诗/poet.song.18000.json','["古風久已壞，今夕聞遺聲。", "恍若忘身世，怡然通性情。", "緬懷有虞氏，曠想三代英。", "此時知此意，青天秋月明。"]'),
('bf77b6b1-a7b9-4032-a26c-45d2ad43ca69','李太尉園池','張方平','宋','宋诗','song-poetry','','[]','驃騎子侯第，長門大主園。',48,'全唐诗/poet.song.18000.json','["驃騎子侯第，長門大主園。", "煙波二宮賜，宸翰四朝恩。", "禪客常摇拂，名流必解軒。", "春風與秋月，好景中空罇。"]'),
('64739932-50bd-4425-ae07-c10633614339','城南林園避暑示道友','張方平','宋','宋诗','song-poetry','','[]','不必山林遠，且離朝市喧。',48,'全唐诗/poet.song.18000.json','["不必山林遠，且離朝市喧。", "前軒好風月，高客共琴罇。", "在所同浮世，何須憶故園。", "八瓊還返事，聊更話根源。"]'),
('f5e6f053-35cc-45e8-8788-aa0dfdc87314','函谷關','張方平','宋','宋诗','song-poetry','','[]','沛公弔伐軍戲下，百二魯無藩楗牢。',64,'全唐诗/poet.song.18000.json','["沛公弔伐軍戲下，百二魯無藩楗牢。", "天險固非一姓有，孫謀寧在兩崤高。", "縣崖通棧遥連蜀，絕巘橫空勢走襃。", "幾見狂圖矜四寒，泥丸封處竟徒勞。"]'),
('a7add40c-ac42-4d83-a903-d34b0ea11ac3','遊琅邪山寺','張方平','宋','宋诗','song-poetry','','[]','一徑過蕭森，幽提此獨尋。',48,'全唐诗/poet.song.18000.json','["一徑過蕭森，幽提此獨尋。", "俗遊殊不意，僧話粗寬心。", "役役真何了，空空究竟深。", "塵勞何日脫，來伴遠公吟。"]'),
('f49a69d8-1fa3-4a82-9386-5418f60e5f33','火車同郭誠思作','張方平','宋','宋诗','song-poetry','','[]','火車雙輪駕九虬，出海直上崑崙丘。',64,'全唐诗/poet.song.18000.json','["火車雙輪駕九虬，出海直上崑崙丘。", "經天三百六十度，匝日一萬四千周。", "電破重陰霹靂過，風開霽色煙雲收。", "乾關坤軸極排轢，勢闌却返無爲洲。"]'),
('b309096f-5adc-43f3-aca9-34ca9bb0026e','初秋即事','張方平','宋','宋诗','song-poetry','','[]','久雨新晴後，秋風初起時。',48,'全唐诗/poet.song.18000.json','["久雨新晴後，秋風初起時。", "天倪一清曠，精爽入希夷。", "壁上吳生畫，床頭杜老詩。", "平常性酷愛，對眼忽如遺。"]'),
('c379732c-d412-4ec7-a667-5cc24e578393','冬過豪貴故園有感','張方平','宋','宋诗','song-poetry','','[]','蕭蕭霜草曉風秋，憶是當年最勝遊。',64,'全唐诗/poet.song.18000.json','["蕭蕭霜草曉風秋，憶是當年最勝遊。", "車馬自隨寒日急，管絃肯入野雲幽。", "流渠水斷魚何往，高樹陰疎鳥不留。", "爲問主人曾到否，自家池館待誰修。"]'),
('c00a7f9e-d262-40a7-8b1a-1da34b0e4089','辛未清明感事','張方平','宋','宋诗','song-poetry','','[]','二十四年流水東，早爲名誤逐飛蓬。',64,'全唐诗/poet.song.18000.json','["二十四年流水東，早爲名誤逐飛蓬。", "事隨過鳥去無跡，愁似濁醪傾更濃。", "好是把花歌北榭，更休提劔哭西風。", "壯心鬰鬰身牢落，幾見中林鶴髮翁。"]'),
('24313582-05a7-41fe-932e-fef23d076b5d','秋夜禁直','張方平','宋','宋诗','song-poetry','','[]','朝著紫宸殿，直廬金馬門。',48,'全唐诗/poet.song.18000.json','["朝著紫宸殿，直廬金馬門。", "楞伽百八句，柱下五千言。", "何處求花藏，忘機即漆園。", "凉宵萬籟寂，明月在前軒。"]'),
('0390ae60-3ee8-41ac-a89d-e1d026b2d961','再入禁林即事','張方平','宋','宋诗','song-poetry','','[]','重到金坡二十春，閒思出處一傷神。',64,'全唐诗/poet.song.18000.json','["重到金坡二十春，閒思出處一傷神。", "略行大地山川遍，再覩青天日月新。", "疎籟豈知諧律呂，散材無意入轅輪。", "何時却出都門去，靜掩巖扉老此身。"]'),
('2e740d69-6734-4501-af4b-8116bd19ce96','兩浙張兵部秋日牡丹詩次韻','張方平','宋','宋诗','song-poetry','','[]','霜天慘澹過重九，忽見幽芳發故叢。',96,'全唐诗/poet.song.18000.json','["霜天慘澹過重九，忽見幽芳發故叢。", "多愛清香對亭檻，不堪疎葉下梧桐。", "他年仙去空華表，此夜魂歸尚漢宮。", "過眼須爲無色觀，返童疑有內丹功。", "寫題更愧詩情淺，折带應宜醉臉紅。", "須爲重重張翠帟，可憐羸怯不禁風。"]'),
('6589f5c5-3dc1-434f-8dd6-b22f6257c93f','病眼','張方平','宋','宋诗','song-poetry','','[]','飛花無復數，遇物輒成雙。',48,'全唐诗/poet.song.18000.json','["飛花無復數，遇物輒成雙。", "書畫疎幽閣，屏幃戀北窗。", "懶開辭俗客，寫望憶秋江。", "椒菊供朝餌，猶須發酒缸。"]'),
('7ae69525-7a5f-46e5-8c89-c7b383b2e434','江樓遲客','張方平','宋','宋诗','song-poetry','','[]','靜外游神迥，望中塵物稀。',48,'全唐诗/poet.song.18000.json','["靜外游神迥，望中塵物稀。", "天連遠水盡，鳥背夕陽飛。", "木葉初摇落，鄉懷動式微。", "興闌不忍去，遲子一舠歸。"]'),
('3e172925-8b6d-478b-ba54-99603b9993e5','夜意','張方平','宋','宋诗','song-poetry','','[]','羣動已沈響，蛩吟時一聲。',48,'全唐诗/poet.song.18000.json','["羣動已沈響，蛩吟時一聲。", "露寒仙掌重，月午庾樓清。", "慷慨聞雞舞，悲凉感笛情。", "幾多塵役者，夙駕待鐘行。"]'),
('eb1cf36d-9475-4297-b450-2d805c442c87','夜蟲','張方平','宋','宋诗','song-poetry','','[]','庭戶閒扃月，草根寒带霜。',48,'全唐诗/poet.song.18000.json','["庭戶閒扃月，草根寒带霜。", "時方感摇落，爾更助悲凉。", "漏版敲孤館，燈青背曲房。", "向晨轉哀急，幾斷旅人腸。"]'),
('2ce17c4d-82ac-426c-9bb7-2479ea67c085','風琴','張方平','宋','宋诗','song-poetry','','[]','露華月色澹軒庭，風過時同從籟鳴。',32,'全唐诗/poet.song.18000.json','["露華月色澹軒庭，風過時同從籟鳴。", "誰掛機心在絃索，有絃寧更有全聲。"]'),
('b81d93d8-6d58-4dc0-ba93-1dd6232dc4ad','寓興','張方平','宋','宋诗','song-poetry','','[]','代舍悲彈鋏，夷門默抱關。',48,'全唐诗/poet.song.18000.json','["代舍悲彈鋏，夷門默抱關。", "風雲未時會，意氣與身閒。", "劔爲屠龍礪，弓須待虎彎。", "君看緯蕭子，一旦探珠還。"]'),
('078a830b-e82e-420a-b0ff-e7be942d2454','題葛驛李校書壁','張方平','宋','宋诗','song-poetry','','[]','八十不扶杖，看書夜每深。',48,'全唐诗/poet.song.18000.json','["八十不扶杖，看書夜每深。", "自言非服藥，無事可關心。", "景爲詩曾愛，花因醉尚簪。", "去城無一舍，路若隔飛沈。"]'),
('82581c84-553a-4750-9708-1dfe52cc08c6','蟬','張方平','宋','宋诗','song-poetry','','[]','紅樹依依古驛西，一聲長是報秋期。',64,'全唐诗/poet.song.18000.json','["紅樹依依古驛西，一聲長是報秋期。", "新晴忽見橫飛過，落晚最傷孤嘯時。", "陰激英雄增感憤，潛催節物至蕭衰。", "草根蟋蟀霜前鴈，共與愁人染鬢絲。"]'),
('f3d6158e-aae4-4b8b-a4d6-81b5e3ab0fe3','柳','張方平','宋','宋诗','song-poetry','','[]','翠眉含愁展新葉，長袖善舞拖舊條。',64,'全唐诗/poet.song.18000.json','["翠眉含愁展新葉，長袖善舞拖舊條。", "黄鶯初囀一何喜，紅桃相映不勝嬌。", "行人歇馬近驛路，漁叟繫舟臨溪橋。", "斜風細雨與殘照，不妨意氣常飄飄。"]'),
('d1aafe37-450e-45dc-8634-3be7cba3c6c0','雲','張方平','宋','宋诗','song-poetry','','[]','無端聚散千形出，本是輕清一氣浮。',256,'全唐诗/poet.song.18000.json','["無端聚散千形出，本是輕清一氣浮。", "終古光陰寧變壞，四時景象自遷流。", "寶華馥郁周三界，綵仗氤氳過十洲。", "遠望非煙籠鳳闕，近觀如穗起龍湫。", "餘霞映日晴相照，素練橫空晚未收。", "迥漢歸槎遥泛泛，碧天孤鶴靜悠悠。", "驚禽逸獸情無待，陣馬風檣勢莫留。", "泗水高歌增感慨，陽臺殘夢作閒愁。", "斷虹落照江城暮，澹月踈星禁省秋。", "過嶺時隨樵叟去，傍溪聊伴野僧遊。", "久陰泱漭重重積，忽霽飄零片片幽。", "待物方行嗟滯影，乘波妄觸笑虛舟。", "仙家五色隨鸞駕，海面千尋立蜃樓。", "雪意低濃傷旅館，歲朝黄潤喜農疇。", "初微觸石纔膚寸，曾不崇朝遍九州。", "生施功成讓雷雨，無心却返舊山頭。"]'),
('f91233da-6590-4be9-a6f4-1451be14e8b0','蝶','張方平','宋','宋诗','song-poetry','','[]','遲景融融暖氣浮，中園曲密小庭幽。',64,'全唐诗/poet.song.18000.json','["遲景融融暖氣浮，中園曲密小庭幽。", "春風故引顛狂甚，芳樹相容爛漫遊。", "不分風流輸楚女，懶將身世問莊周。", "有時潛見多情處，每遇王孫盡日留。"]'),
('0f102704-5742-48c1-8c4a-1244e89a96bd','螢','張方平','宋','宋诗','song-poetry','','[]','土潤正溽暑，幽庭熠燿飛。',48,'全唐诗/poet.song.18000.json','["土潤正溽暑，幽庭熠燿飛。", "陳荄未全脫，生氣一何微。", "風急光不滅，月明景共稀。", "蠨蛸與蟋蟀，時節伴依依。"]'),
('3086186a-0425-4c1d-9e0b-d9025b7077a4','歸燕','張方平','宋','宋诗','song-poetry','','[]','社後日猶暖，雨前春尚寒。',48,'全唐诗/poet.song.18000.json','["社後日猶暖，雨前春尚寒。", "乘時眾來易，無伴獨留難。", "京洛柳花白，瀟湘楓葉丹。", "堪傷季秋雀，風急海漫漫。"]'),
('ee6c6e8a-97ab-44b2-8527-0131981eb0be','柳','張方平','宋','宋诗','song-poetry','','[]','雨細池塘靜，風斜院落深。',48,'全唐诗/poet.song.18000.json','["雨細池塘靜，風斜院落深。", "蝶飛隨亂絮，鶯囀入濃陰。", "翠带堪紉佩，金絲可度針。", "願依菩薩手，不上美人簪。"]'),
('686b8773-af6a-4b42-986d-fe090d234097','七里瀨','張方平','宋','宋诗','song-poetry','','[]','古有桐君住，漢時嚴子來。',48,'全唐诗/poet.song.18000.json','["古有桐君住，漢時嚴子來。", "山橫疑路盡，溪轉若天開。", "塵世不相接，海潮從此迴。", "維舟上層巘，戀戀白雲堆。"]'),
('6d2c7cb3-7d24-487c-9e8f-7081fda05b41','驚秋示三茅山人陳谷','張方平','宋','宋诗','song-poetry','','[]','晚來枕簟凉，杖屨望平野。',48,'全唐诗/poet.song.18000.json','["晚來枕簟凉，杖屨望平野。", "疾風卷浮雲，黄葉如雨下。", "奈此急景何，忽過如奔馬。", "九丹功未成，幽恨將誰寫。"]'),
('ac86b03d-48cc-4fb0-90f7-a40238166ef8','清明連上巳','張方平','宋','宋诗','song-poetry','','[]','踏青原上飲，祓禊水邊歌。',24,'全唐诗/poet.song.18000.json','["踏青原上飲，祓禊水邊歌。", "佳節相連好，遊人一倍多。"]'),
('e642baa3-157a-4fa2-b62b-8e1cc24b7a36','齊魯道中望睢陽有念','張方平','宋','宋诗','song-poetry','','[]','重疊荒山滿四圍，征鞍繫劔背斜暉。',32,'全唐诗/poet.song.18000.json','["重疊荒山滿四圍，征鞍繫劔背斜暉。", "遥知梁國白雲下，此際吾親獨倚扉。"]'),
('839a19db-7048-4ec1-b1c5-802ace2955b4','對酒','張方平','宋','宋诗','song-poetry','','[]','醉裏翻身天地窄，愁來天地不容身。',32,'全唐诗/poet.song.18000.json','["醉裏翻身天地窄，愁來天地不容身。", "可憐澤畔行吟客，爭似壚邊高卧人。"]'),
('feb7d2b2-9f57-4c2f-b961-338c1cf3852e','赴益部途中','張方平','宋','宋诗','song-poetry','','[]','中臺分虎節，全蜀領龜城。',48,'全唐诗/poet.song.18000.json','["中臺分虎節，全蜀領龜城。", "山色二千里，水聲三十程。", "煙村深谷火，雲棧半空鈴。", "野館無鐘漏，猿吟曉日明。"]'),
('8350ff5d-04ba-4fe5-8e02-9c6b7ea2dc28','行次岐山','張方平','宋','宋诗','song-poetry','','[]','坤維五十郡，麾節忝師垣。',48,'全唐诗/poet.song.18000.json','["坤維五十郡，麾節忝師垣。", "緩轡猶秦甸，前驅已劔門。", "儻來增客氣，重寄愧君恩。", "昨夜岐山夢，三歸修竹園。"]'),
('8775091e-536f-4edf-8ddc-e3316b1911c2','過灞橋長安道上作','張方平','宋','宋诗','song-poetry','','[]','漢牒熟當披舊跡，灞橋今忽過征鞍。',64,'全唐诗/poet.song.18000.json','["漢牒熟當披舊跡，灞橋今忽過征鞍。", "前朝宮展煙蕪遠，四望河山古木寒。", "自古功名應邂逅，大家岐路妄汍瀾。", "興亡甚費生靈血，只得高人夢幻看。"]'),
('f9fde422-7f35-4cf9-80d4-ec55bc7a9d9a','青泥嶺','張方平','宋','宋诗','song-poetry','','[]','斗峻凌霄出混茫，東西秦蜀此分疆。',64,'全唐诗/poet.song.18000.json','["斗峻凌霄出混茫，東西秦蜀此分疆。", "縈紆斷澗千尋曲，回合危巒萬疊蒼。", "煙外孤村通鳥徑，雲間盤道遶羊腸。", "朝家方面非輕寄，何事徘徊望故鄉。"]'),
('3b53bb01-450e-4a20-81e2-3a959d16f837','華州西溪','張方平','宋','宋诗','song-poetry','','[]','西溪殊近郭，少華更當軒。',24,'全唐诗/poet.song.18000.json','["西溪殊近郭，少華更當軒。", "竹徑通華表，松庭接紺園。"]'),
('5ff1ece7-973a-4806-b45d-2c6a907e26d5','過長安至岐山作','張方平','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','高原極望秦川闊，危棧橫空蜀道長。',32,'全唐诗/poet.song.18000.json','["高原極望秦川闊，危棧橫空蜀道長。", "多謝終南山色好，迢迢相送過岐陽。"]'),
('f4c63f88-5d18-4046-817d-419519328dcb','過張真人洞','張方平','宋','宋诗','song-poetry','','[]','谷口巑岏獅子山，洞門高掩白雲閒。',32,'全唐诗/poet.song.18000.json','["谷口巑岏獅子山，洞門高掩白雲閒。", "自慙末裔無仙骨，名利途中鬢已斑。"]'),
('9eb6819b-db64-48aa-892f-433cf44e1442','籌筆驛','張方平','宋','宋诗','song-poetry','','[]','本規一舉定乾坤，遽見長星墜壘門。',32,'全唐诗/poet.song.18000.json','["本規一舉定乾坤，遽見長星墜壘門。", "公在必無生仲達，師昭何業得中原。"]'),
('1157dbdf-25fb-48e8-9c62-c1f1a4bfa9c6','雨中登籌筆驛後懷古亭','張方平','宋','宋诗','song-poetry','','[]','山寒雨急曉冥冥，更躡蒼崖上驛亭。',32,'全唐诗/poet.song.18000.json','["山寒雨急曉冥冥，更躡蒼崖上驛亭。", "深秀林巒都不見，白雲堆裏亂峯青。"]'),
('be1296fa-f126-4ec0-bd83-61f523165f04','興州長舉縣西二十里閣道立表曰飛石閣告往來者急度勿停予赴益部興州將吏來迎皆至長舉因訪老吏飛石之狀云昔嘗有之亦飄風暴雨之時也予望山頂皆已墾耕而行人熟虛名至是皆馳過因成一絕','張方平','宋','宋诗','song-poetry','','[]','蜀道循山多險巇，行人獨此策征羈。',32,'全唐诗/poet.song.18000.json','["蜀道循山多險巇，行人獨此策征羈。", "人情多爲虛名怯，鶴唳風聲走老氐。"]'),
('af665ed0-2d7f-406d-8636-315c53ff8f01','劍門關','張方平','宋','宋诗','song-poetry','','[]','地維絕脈摧鼇足，天壘橫霄壯井輿。',64,'全唐诗/poet.song.18000.json','["地維絕脈摧鼇足，天壘橫霄壯井輿。", "誰軋禍萌通鳥道，古爲風土感魚鳧。", "壺中日月鄰方外，海內山河入帝圖。", "過此益知方面重，萬兵開府一寒儒。"]'),
('4594a8d9-abc7-451a-8fb6-69b8f69f0bf5','華山雲臺觀題希夷先生陳摶影堂','張方平','宋','宋诗','song-poetry','','[]','林壑雲深接玉泉，松齋閉息輒經年。',64,'全唐诗/poet.song.18000.json','["林壑雲深接玉泉，松齋閉息輒經年。", "一無標致惟隨俗，別有真機在指玄。", "詔板嘗延清暑殿，詩筒時到華陽川。", "蛻形雖在張超谷，粟粒珠中自在天。"]'),
('21ff67ae-c74e-4e59-a17e-c2b8e0133d80','相國杜公舊里錢唐有別野在華下既得謝留寓睢陽因家焉某近赴益部過三峰聞華人之望公捨而不還又顧吾鄉之獨幸國老處焉因道西人之意成長句四韻奉寄杜公','張方平','宋','宋诗','song-poetry','','[]','謀國有勞新史在，掛車無第舊鄉遥。',64,'全唐诗/poet.song.18000.json','["謀國有勞新史在，掛車無第舊鄉遥。", "睢陽圖記光耆彥，華下風烟遂寂寥。", "紫氣尚勞關吏思，甘棠猶播陜民謠。", "蓮花峯下仙人掌，高出雲端若奉招。"]'),
('e4401d39-31e8-405d-9f20-d6f77d50a6db','上亭驛','張方平','宋','宋诗','song-poetry','','[]','雨中駐蹕此聞鈴，當日梨園寫此聲。',32,'全唐诗/poet.song.18000.json','["雨中駐蹕此聞鈴，當日梨園寫此聲。", "忽忽悲心自多感，鈴聲何事愴人情。"]'),
('05bf977d-f27c-4934-b482-eb54793556fb','散水巖潄玉亭','張方平','宋','宋诗','song-poetry','','[]','高從雲際落崔嵬，疑决銀潢一派來。',64,'全唐诗/poet.song.18000.json','["高從雲際落崔嵬，疑决銀潢一派來。", "散漫難收珠網綻，琤瑽不斷玉山摧。", "尋源誰到煙霞路，稅駕聊傾沆瀣杯。", "向暮危亭上燈火，水精簾下燭房開。"]'),
('dc688258-2662-4f85-99c6-95a4dd2e0dca','泥溪驛','張方平','宋','宋诗','song-poetry','','[]','嘉陵江到水苽園，水勢東迴入閬川。',32,'全唐诗/poet.song.18000.json','["嘉陵江到水苽園，水勢東迴入閬川。", "前過劍門山路穩，免尋閣道上雲巔。"]'),
('a56aea62-0d15-4b4e-8411-313c725a8c6b','杜鵑','張方平','宋','宋诗','song-poetry','','[]','蜀道寒輕水木清，峽中無復杜鵑聲。',32,'全唐诗/poet.song.18000.json','["蜀道寒輕水木清，峽中無復杜鵑聲。", "歸期正是春風暖，任向空山叫月明。"]'),
('4e734918-914a-4a63-a493-596fb8f212fa','過嘉川驛','張方平','宋','宋诗','song-poetry','','[]','嘉陵江上嘉川峽，古木雲蘿千萬峯。',32,'全唐诗/poet.song.18000.json','["嘉陵江上嘉川峽，古木雲蘿千萬峯。", "閣道緣山已經月，縈迴未出畫屏中。"]'),
('f95849fd-5d60-499d-8ff0-e3913c1f3416','飛仙嶺閣','張方平','宋','宋诗','song-poetry','','[]','蒼崖老樹雲蘿合，絕澗驚湍閣路高。',32,'全唐诗/poet.song.18000.json','["蒼崖老樹雲蘿合，絕澗驚湍閣路高。", "羽駕飚輪殊惚怳，依程緩轡未爲勞。"]'),
('6316324f-faa0-4541-8f43-296b44364072','亂石溪','張方平','宋','宋诗','song-poetry','','[]','亂石崢嶸散粟堆，飛湍奔瀉萬山開。',64,'全唐诗/poet.song.18000.json','["亂石崢嶸散粟堆，飛湍奔瀉萬山開。", "轟空急若雷車過，振壑傾疑地軸摧。", "銀漢勢從天際落，雲濤聲破海門來。", "迸泉疊巘平生愛，欲轉巖隈首重迴。"]'),
('970191d6-6ab3-4a9d-a761-e27bedcdc4c9','魚關詩','張方平','宋','宋诗','song-poetry','','[]','中流石埭隱如磓，鼓鬣徜徉此復迴。',32,'全唐诗/poet.song.18000.json','["中流石埭隱如磓，鼓鬣徜徉此復迴。", "春水漸深沿泳快，爲傳尺素錦江來。"]'),
('56de6878-7cf0-419c-be5f-358686b336a8','青陽峽','張方平','宋','宋诗','song-poetry','','[]','奇峰疊巘無重數，橫澗飛泉會一谿。',64,'全唐诗/poet.song.18000.json','["奇峰疊巘無重數，橫澗飛泉會一谿。", "老樹藤蘿從古長，寒空雲靄與天迷。", "幽中應有神仙住，深處唯聞猿鳥啼。", "野性舊多山水癖，恨無心賞此相携。"]'),
('322781d8-0c8b-41db-a50b-fccd5dcd0c1c','藥水巖詩','張方平','宋','宋诗','song-poetry','','[]','靈泉一派蜀江通，源出蒼崖古洞中。',64,'全唐诗/poet.song.18000.json','["靈泉一派蜀江通，源出蒼崖古洞中。", "乳滴雲根苔臼滿，藥成仙竈石臺空。", "瓊纓珠絡千巖霤，瑶瑟琅簫萬壑風。", "杯勺已忻清病骨，刀圭敢望變衰容。"]'),
('67b3b0b0-f47e-49f8-9838-20e4aed8b182','宿龍門洞','張方平','宋','宋诗','song-poetry','','[]','路到葭萌古道邊，層崖疊磴入蒼煙。',64,'全唐诗/poet.song.18000.json','["路到葭萌古道邊，層崖疊磴入蒼煙。", "忽逢方丈在平地，何意中途過洞天。", "四面濃嵐圍碧嶂，半空急雨迸飛泉。", "一宵身世離塵境，却撫征驂懶下鞭。"]'),
('f9516772-8414-4ef4-9eef-927a50a3c18d','嶓冢','張方平','宋','宋诗','song-poetry','','[]','江漢朝宗入海長，嘗蒙起浪卷輕航。',32,'全唐诗/poet.song.18000.json','["江漢朝宗入海長，嘗蒙起浪卷輕航。", "金牛西路經嶓冢，却見微源此濫觴。"]'),
('efb258be-5aac-4df6-8515-10a4cdec1e15','過汧河','張方平','宋','宋诗','song-poetry','','[]','岐南一舍過長汧，路近陳倉始入山。',32,'全唐诗/poet.song.18000.json','["岐南一舍過長汧，路近陳倉始入山。", "三十三程橋棧外，平川始下鹿頭關。"]'),
('685fdffc-9228-4d8a-b251-e7919fa59cb6','采真堂贈郭誠思','張方平','宋','宋诗','song-poetry','','[]','香車曉駕九花虬，笳管聲中到十洲。',32,'全唐诗/poet.song.18000.json','["香車曉駕九花虬，笳管聲中到十洲。", "太一元君傳密命，許君長住八瓊樓。"]'),
('fd985e3c-d665-4835-93dd-4691ff9d3fb5','聞蛩','張方平','宋','宋诗','song-poetry','','[]','慘澹霜風月色寒，愁人無寐坐閒軒。',32,'全唐诗/poet.song.18000.json','["慘澹霜風月色寒，愁人無寐坐閒軒。", "別聽一部凄凉曲，幾種秋蟲咽草根。"]'),
('38eb4032-0f82-40b9-ab8d-af35684aad30','探春','張方平','宋','宋诗','song-poetry','','[]','妙句江春入舊年，江梅長向臘中殘。',32,'全唐诗/poet.song.18000.json','["妙句江春入舊年，江梅長向臘中殘。", "梁園地冷春來晚，試劈垂楊舊眼看。"]'),
('ba1b276d-e71e-4841-b949-9f72634db2cb','天寒','張方平','宋','宋诗','song-poetry','','[]','風裂幽窗水澤堅，寒郊空迥澹無煙。',32,'全唐诗/poet.song.18000.json','["風裂幽窗水澤堅，寒郊空迥澹無煙。", "何因得向桃源去，景氣長如二月天。"]'),
('e256103f-f30e-4391-88a2-7dd28b88a49d','慧聚寺東亭','張方平','宋','宋诗','song-poetry','','[]','野色秋光共泬寥，水村籬落晚煙交。',32,'全唐诗/poet.song.18000.json','["野色秋光共泬寥，水村籬落晚煙交。", "拄笻回就下山路，行看斜陽隱樹梢。"]'),
('5daa2a12-55bf-40c7-af14-a974935bf090','縣齋懷京都','張方平','宋','宋诗','song-poetry','','[]','東南古縣介江臯，西北神州倚斗杓。',32,'全唐诗/poet.song.18000.json','["東南古縣介江臯，西北神州倚斗杓。", "安得葉君傳秘術，時飛雙舄詣臺朝。"]'),
('6e8dce5d-337f-41b1-a7d4-db1b18156812','曉景','張方平','宋','宋诗','song-poetry','','[]','樹带曉霜寒矗矗，山含宿靄遠重重。',32,'全唐诗/poet.song.18000.json','["樹带曉霜寒矗矗，山含宿靄遠重重。", "誰家收得汾陽筆，八幅羅浮晦景濃。"]'),
('2d4965b3-cc9c-4248-897d-9c3baca15852','春郊','張方平','宋','宋诗','song-poetry','','[]','携樽縱步尋芳墅，聊藉芊芊手把紅。',32,'全唐诗/poet.song.18000.json','["携樽縱步尋芳墅，聊藉芊芊手把紅。", "行樂豈關閒客事，少侯長日占春風。"]'),
('83c22e45-0013-411a-b57c-f303ad593737','夢後','張方平','宋','宋诗','song-poetry','','[]','索索幽蟲急曉風，玉繩西下露華濃。',32,'全唐诗/poet.song.18000.json','["索索幽蟲急曉風，玉繩西下露華濃。", "遠鐘驚覺窗燈暗，依舊江山一萬重。"]'),
('0a848e38-a5be-4b04-ad01-94854db19822','書吳興僧興公院壁','張方平','宋','宋诗','song-poetry','','[]','我愛霅溪風景閒，年年魚鳥伴湖山。',32,'全唐诗/poet.song.18000.json','["我愛霅溪風景閒，年年魚鳥伴湖山。", "利名人到心猶靜，況是老僧長閉關。"]'),
('41ad3e8d-1647-44ef-bc82-9976752b7e7b','耳鳴','張方平','宋','宋诗','song-poetry','','[]','一陽初獨嘯，兩耳遂雙鳴。',168,'全唐诗/poet.song.18000.json','["一陽初獨嘯，兩耳遂雙鳴。", "寒谷疎鐘遠，霜空眾籟清。", "千鈴行險倦，萬鼓戰酣聲。", "瀑落山頭峻，濤翻海面平。", "風檣開大浪，曉角動嚴城。", "隴首悲凉意，蘇門曠逸情。", "鳳簫雲外過，龍笛月中橫。", "細轉繅車急，微遥扤櫓輕。", "衰殘傷老態，馳徇厭時榮。", "處世希蒙叟，觀身愧浄名。", "神明思內守，豪蕩悔平生。", "素問方家本，巢源導引精。", "早年曾有客，奇術可還嬰。", "何日開金鼎，靈丹見八瓊。"]'),
('7fe9204b-bfe4-4ae5-8a04-abf2cd22d3de','蟬','張方平','宋','宋诗','song-poetry','','[]','密槐遮急雨，疎柳带斜陽。',48,'全唐诗/poet.song.18000.json','["密槐遮急雨，疎柳带斜陽。", "緱嶺餘音遠，蘇門清嘯長。", "附冠金翼薄，橫鬢玉釵光。", "高潔自天稟，寧同蜂蝶狂。"]'),
('0537d131-5e17-4517-a6df-77804c974b96','題李先生隱居','張方平','宋','宋诗','song-poetry','','[]','金丹一指自崆峒，便控飛輪駕赤龍。',64,'全唐诗/poet.song.18000.json','["金丹一指自崆峒，便控飛輪駕赤龍。", "況是曾居小有洞，更應不在易遷宮。", "紫文寶訣三元秘，皇象靈符二景通。", "却恨勞生聞道晚，九還未就已衰翁。"]'),
('1924ae67-0785-44ce-acaa-48d6f6639346','芭蕉李都尉宅金淵閣分題得淵字','張方平','宋','宋诗','song-poetry','','[]','遠寄江城外，新栽水閣前。',48,'全唐诗/poet.song.18000.json','["遠寄江城外，新栽水閣前。", "虛心勞可尚，幻質定非堅。", "扇薄摇凉殿，盃深泛綺筵。", "忽疑鸞鳳過，翠影落金淵。"]'),
('447da983-8b22-4374-9a45-e21cf02ee5db','赴新定過七里瀨','張方平','宋','宋诗','song-poetry','','[]','舟過嚴陵瀨，凉秋水木清。',48,'全唐诗/poet.song.18000.json','["舟過嚴陵瀨，凉秋水木清。", "鼓旗知郭近，魚鳥見人驚。", "雲亂迷山色，灘長雜雨聲。", "一毫名利事，搔首愧平生。"]'),
('e4012027-d318-4c8d-ba1a-4c0532aa416a','仁宗皇帝挽辭三首  其一','張方平','宋','宋诗','song-poetry','','[]','享國承熙盛，斯民老太平。',48,'全唐诗/poet.song.18000.json','["享國承熙盛，斯民老太平。", "無私均覆載，大德共生成。", "陰騭無留迹，神功不可名。", "曰仁歸禰廟，時夏繹清明。"]'),
('3cd2095b-1a0b-4dba-94bd-18dd60b2dbd4','仁宗皇帝挽辭三首  其二','張方平','宋','宋诗','song-poetry','','[]','臨御自初終，恭勤一日同。',48,'全唐诗/poet.song.18000.json','["臨御自初終，恭勤一日同。", "慈心夷夏等，誠意地天通。", "垂拱成文治，安和即武功。", "含生遊壽域，四十二年中。"]'),
('c493eed4-bd33-49a0-8ca1-8d466afeaa33','仁宗皇帝挽辭三首  其三','張方平','宋','宋诗','song-poetry','','[]','謨訓垂寬大，基圖得顯承。',48,'全唐诗/poet.song.18000.json','["謨訓垂寬大，基圖得顯承。", "新宮開玉鏁，舊冊閱金滕。", "龍駕歸虛極，鸞旗建大升。", "平生懷孝慕，游仗展三陵。"]'),
('8cc7a747-c7d0-48d9-8bfb-b8c694a68ec3','英宗皇帝挽辭五首  其一','張方平','宋','宋诗','song-poetry','','[]','不問大橫兆，天人心是真。',48,'全唐诗/poet.song.18000.json','["不問大橫兆，天人心是真。", "謳歌早歸舜，氣志自如神。", "正合乾坤體，明開日月輪。", "孜孜朝昃意，克己爲生民。"]'),
('6c5a994a-8d40-40cf-a914-8840a165211a','英宗皇帝挽辭五首  其二','張方平','宋','宋诗','song-poetry','','[]','舊學多聞富，咨周聽德聰。',48,'全唐诗/poet.song.18000.json','["舊學多聞富，咨周聽德聰。", "乾元純用九，豐日正宜中。", "治迹傳英烈，神明遡閬風。", "平居修五事，洪範在潛宮。"]'),
('c4fa5f94-db5e-4438-9aae-b894f224b2d6','英宗皇帝挽辭五首  其三','張方平','宋','宋诗','song-poetry','','[]','八月初凉後，千年此去長。',48,'全唐诗/poet.song.18000.json','["八月初凉後，千年此去長。", "朝廷留事典，戶牖想容光。", "濯景遊霄極，乘雲返帝鄉。", "春秋大居正，天統付元良。"]'),
('5721344c-8008-490f-a98f-2dce52b5b12b','英宗皇帝挽辭五首  其四','張方平','宋','宋诗','song-poetry','','[]','遣奠宣哀冊，嚴行按字圖。',48,'全唐诗/poet.song.18000.json','["遣奠宣哀冊，嚴行按字圖。", "橋山仙去遠，渭水月游初。", "儉制遵遺訓，方中列舊書。", "龍輴三十里，笳鼓節聲徐。"]'),
('47516004-30e5-47e8-bb5f-474e88c5a70c','英宗皇帝挽辭五首  其五','張方平','宋','宋诗','song-poetry','','[]','瀍東五陵陌，嵩下萬安原。',48,'全唐诗/poet.song.18000.json','["瀍東五陵陌，嵩下萬安原。", "風水通佳氣，靈祇護至尊。", "國容回吉仗，像物闢神門。", "清廟標英德，流光萬古存。"]'),
('4086de48-1248-40e5-ab29-98b31a734d9b','神宗皇帝挽辭五首  其一','張方平','宋','宋诗','song-poetry','','[]','羲軒前載遠，虞夏信書傳。',48,'全唐诗/poet.song.18000.json','["羲軒前載遠，虞夏信書傳。", "比德皆尊大，惟皇克繼先。", "五陵同厚地，兩曜出高天。", "制作流方策，憂勤十九年。"]'),
('33b8cee0-47c8-4269-9b63-27a44eb09b6d','神宗皇帝挽辭五首  其二','張方平','宋','宋诗','song-poetry','','[]','經綸成盛業，震耀烜威神。',48,'全唐诗/poet.song.18000.json','["經綸成盛業，震耀烜威神。", "粹氣同乾健，含生自化醇。", "無文皆受職，重譯競來賓。", "東觀成書日，方知百度新。"]'),
('78838b19-44e4-433a-9522-3309e715e653','神宗皇帝挽辭五首  其三','張方平','宋','宋诗','song-poetry','','[]','經始開三殿，晨昏奉二宮。',48,'全唐诗/poet.song.18000.json','["經始開三殿，晨昏奉二宮。", "承顔專致樂，教孝遂移風。", "訪對朝曦昃，程書夜漏終。", "艱難思稼穡，意在紀元中。"]'),
('ab9e46bc-8d31-48a8-9a15-f7504a274f25','神宗皇帝挽辭五首  其四','張方平','宋','宋诗','song-poetry','','[]','睿智由天縱，規摹繼祖貽。',48,'全唐诗/poet.song.18000.json','["睿智由天縱，規摹繼祖貽。", "有爲皆社稷，無逸著屏帷。", "傳令通湟陿，賡歌及島夷。", "時髦俱入彀，流美辟雍詩。"]'),
('0fc8223e-50e6-4880-bf87-0cf5e40208f3','神宗皇帝挽辭五首  其五','張方平','宋','宋诗','song-poetry','','[]','廣大天同量，淵深海共澄。',48,'全唐诗/poet.song.18000.json','["廣大天同量，淵深海共澄。", "遽聞憑玉几，恨不瘞金繩。", "同軌陪儀仗，因山鏁闕庭。", "深恩淪朽骨，孤夢遶新陵。"]'),
('386a3cf0-42cd-4fb0-8c62-0a968e96d9b5','溫成皇后挽辭二首  其一','張方平','宋','宋诗','song-poetry','','[]','何事高前烈，忘身衛至尊。',48,'全唐诗/poet.song.18000.json','["何事高前烈，忘身衛至尊。", "平生彤管在，憂國玉刀存。", "一惠彰柔德，深衷憶善言。", "凄凉金殿月，還照給孤園。"]'),
('459b42e1-c80b-493a-b7f9-6ba98e33c549','溫成皇后挽辭二首  其二','張方平','宋','宋诗','song-poetry','','[]','美化成麟趾，勤心念兔罝。',48,'全唐诗/poet.song.18000.json','["美化成麟趾，勤心念兔罝。", "廞衣薦翬翟，靈仗咽簫笳。", "香海歸華藏，晴霄散綵霞。", "春風青瑣閉，侍女泣宮花。"]'),
('04c025fa-b62f-4d15-bb65-72cda14ba578','故相贈侍中廣平公挽辭三首  其一','張方平','宋','宋诗','song-poetry','','[]','風采來塵外，才名入洛初。',48,'全唐诗/poet.song.18000.json','["風采來塵外，才名入洛初。", "清言還正始，雅度合沖虛。", "玉氣千尋直，金精百鍊餘。", "雍容到巖廟，一世共華胥。"]'),
('b9d59b6d-4d95-427e-a227-d1d346501b79','故相贈侍中廣平公挽辭三首  其二','張方平','宋','宋诗','song-poetry','','[]','不與椿齡遠，先傷棣萼零。',48,'全唐诗/poet.song.18000.json','["不與椿齡遠，先傷棣萼零。", "宸章懷舊德，惠節入新銘。", "後世推名教，當朝重典刑。", "東維跨箕尾，一化本同靈。"]'),
('f0130011-650b-46f2-8c8f-466d84690c89','故相贈侍中廣平公挽辭三首  其三','張方平','宋','宋诗','song-poetry','','[]','謨明餘論在，記博近書傳。',48,'全唐诗/poet.song.18000.json','["謨明餘論在，記博近書傳。", "得謝三司重，歸休五福全。", "國門迴鹵簿，嵩麓望松阡。", "天下中庸法，寧惟伯始賢。"]'),
('55f3fc6d-36de-4f10-9cf2-7a10772e3e09','故端明殿學士工部尚書致仕清源王公挽辭二首  其一','張方平','宋','宋诗','song-poetry','','[]','臺閣留風論，蕃垣著治功。',48,'全唐诗/poet.song.18000.json','["臺閣留風論，蕃垣著治功。", "時皆推舊德，心自信孤忠。", "驥騁常疲險，鵬摶不遇風。", "晚年探妙理，頓看世緣空。"]'),
('78e2f950-8614-4201-a3ce-2c142ec9ff95','故端明殿學士工部尚書致仕清源王公挽辭二首  其二','張方平','宋','宋诗','song-poetry','','[]','世德承槐蔭，朝評許棟材。',48,'全唐诗/poet.song.18000.json','["世德承槐蔭，朝評許棟材。", "都堂陪八座，近府阻三階。", "燕閣清宵閉，佳城白日開。", "南阡有一去，冠蓋不重迴。"]'),
('864164f4-3079-4179-afa7-31c04298a5e6','故兵部侍郎致仕安定公挽辭三首  其一','張方平','宋','宋诗','song-poetry','','[]','晶粹分天婺，深長自帝虞。',48,'全唐诗/poet.song.18000.json','["晶粹分天婺，深長自帝虞。", "義聲高北海，政事達夷吾。", "歷職小司寇，退身賢大夫。", "獨嗟造化手，不得鼓洪爐。"]'),
('e35e06ce-9e42-4037-a0ad-00459b6052b4','故兵部侍郎致仕安定公挽辭三首  其二','張方平','宋','宋诗','song-poetry','','[]','經濟期成務，康寧遽引年。',48,'全唐诗/poet.song.18000.json','["經濟期成務，康寧遽引年。", "人知三事貴，我愛二疏賢。", "金石名儒刻，弓裘孝子傳。", "國書循吏傳，誰在老成先。"]'),
('3558c012-88ba-4783-bed8-2260d909eebd','故兵部侍郎致仕安定公挽辭三首  其三','張方平','宋','宋诗','song-poetry','','[]','湖暖春波闊，山晴宿霧開。',48,'全唐诗/poet.song.18000.json','["湖暖春波闊，山晴宿霧開。", "空觀素車過，不復畫船來。", "柳外悲蕭度，松間送騎回。", "鄭人懷子產，行灑有餘哀。"]'),
('4eb7c276-ed47-4e88-86ab-0b4118610283','古興','張方平','宋','宋诗','song-poetry','','[]','條牧始龔罰，干戈茲濫觴。',48,'全唐诗/poet.song.18000.json','["條牧始龔罰，干戈茲濫觴。", "以拯焚溺起，謂副天人望。", "君思彼伊呂，胡爲乎夏商。", "順守信有道，啟端乃無疆。"]'),
('71bef17f-e365-42bc-aad3-2f242d0a2691','讀公羊傳四首  其一','張方平','宋','宋诗','song-poetry','','[]','齊桓合兵車，召陵始服楚。',48,'全唐诗/poet.song.18000.json','["齊桓合兵車，召陵始服楚。", "忿緣蕩舟起，辭爲包茅舉。", "勤王豈其誠，繼絕聊可與。", "萌此挾君姦，夷吾合膏斧。"]'),
('ba859bb4-5ab1-4ca4-846f-790ffa838930','讀公羊傳四首  其二','張方平','宋','宋诗','song-poetry','','[]','晉之公室微，六族相吞螫。',48,'全唐诗/poet.song.18000.json','["晉之公室微，六族相吞螫。", "趙鞅率邑車，志豈在君側。", "封茲禍亂根，留爲姦雄迹。", "吳楚因誅錯，不昭寧復辟。"]'),
('25b1fe79-571d-4e32-94e5-a4746fffca9c','讀公羊傳四首  其三','張方平','宋','宋诗','song-poetry','','[]','季子治內難，牙也王堤誅。',48,'全唐诗/poet.song.18000.json','["季子治內難，牙也王堤誅。", "緩追逸慶父，二子奚親疎。", "探情異無將，歸獄茲何辜。", "減量自孟德，抽戈實公閭。"]'),
('f922d038-acf0-4522-8c04-cda354118fdf','讀公羊傳四首  其四','張方平','宋','宋诗','song-poetry','','[]','親親自禰率，恩禮有等節。',48,'全唐诗/poet.song.18000.json','["親親自禰率，恩禮有等節。", "雖云王父命，天性何斯絕。", "奈何彼衛輒，父子相傾奪。", "此而義可與，人倫固隳滅。"]'),
('75f05913-cd26-4f2e-8bd7-8c705d5b5bfa','讀孫子二首  其一','張方平','宋','宋诗','song-poetry','','[]','渾渾十三篇，兵謀與師律。',48,'全唐诗/poet.song.18000.json','["渾渾十三篇，兵謀與師律。", "匠巧雖自心，規矩寧可黜。", "腐儒知舞干，奔車暇擇虱。", "腠理與骨髓，所攻蓋異術。"]'),
('34ec963e-bf50-4204-8a25-6279ca950438','讀孫子二首  其二','張方平','宋','宋诗','song-poetry','','[]','伐謀自廟堂，長城在樽俎。',48,'全唐诗/poet.song.18000.json','["伐謀自廟堂，長城在樽俎。", "下敵無智名，服叛非蕭斧。", "主尊而民安，茲宜國之輔。", "勿使有功臣，功大將騎虎。"]'),
('1cde97cf-d91c-4f0f-b887-8104b6af6f15','得請南臺偶書','張方平','宋','宋诗','song-poetry','','[]','紫陽洞中客，水晶宮裏人。',168,'全唐诗/poet.song.18000.json','["紫陽洞中客，水晶宮裏人。", "一念墮塵世，資本猶天真。", "擢質出流俗，抗志凌蒼旻。", "邈從逍遥遊，浩與恬漠親。", "風簫不受調，溪鳥非所馴。", "敢希古作者，尚從諸逸民。", "犬馬皆有養，況我無天倫。", "俛首遂干祿，老先稱過秦。", "流遁亡舊守，趨鏘陪薦紳。", "驕氣與矜色，湛沒四十春。", "市合先縮手，戰酣早收身。", "桑榆近頹暮，丘壑慙荒榛。", "福兮禍所伏，名者實之賓。", "雖嗟負前志，大觀亦同均。"]'),
('b97e9a51-bb58-4ec6-a199-8f2cdf718659','贈姚白','張方平','宋','宋诗','song-poetry','','[]','平輿舊龍淵，今復見鱗角。',48,'全唐诗/poet.song.18000.json','["平輿舊龍淵，今復見鱗角。", "隱景入虛無，長吟振寥廓。", "寧爲嗜慾留，當假風雷作。", "我亦待扶摇，徘徊伴黄雀。"]'),
('f3c12f3e-c1a7-4465-baeb-7d4d22c9bd7a','幽薊行','張方平','宋','宋诗','song-poetry','','[]','昔者帝堯光宅本都冀，幽朔廼爲寰內地。',135,'全唐诗/poet.song.18000.json','["昔者帝堯光宅本都冀，幽朔廼爲寰內地。", "舜肇十有二州此其一，禹服周藩有年祀。", "崆峒之英其人武，氣含陰殺樂鉦鼓。", "秦漢發吏守邊亭，世與其民扞中土。", "召伯功勤黑社傳，昭王意氣金臺古。", "我興北望涕交頤，念汝幽薊之奇士兮。", "今爲勛華光耀照四海，忍遂反衽偷生爲。", "吾民孰不願左袒，汝其共取燕支歸。"]'),
('8335f530-8820-4a34-ae63-c30c0b26722c','槎客歌','張方平','宋','宋诗','song-poetry','','[]','八月風高星漢秋，海邊閒客騎槎遊。',80,'全唐诗/poet.song.18000.json','["八月風高星漢秋，海邊閒客騎槎遊。", "雲濤茫茫浩無涯，槎頭忽觸斗柄斜。", "回看乃在織女家，織女投梭顔如花。", "客愚不知天上樂，遽把一拳伴歸鵲。", "問得嚴生應悔來，重去何由尋得著。"]'),
('786b8618-f597-4be2-b17e-82768c07c0b6','東山吟','張方平','宋','宋诗','song-poetry','','[]','我思古人兮，有東晉太傅謝公者其庶幾。',121,'全唐诗/poet.song.18000.json','["我思古人兮，有東晉太傅謝公者其庶幾。", "英才乃是孔明輩，風流更覺茂弘卑。", "東山遊兮不歸，妓携手兮嬉嬉。", "晚年拂劔兮一起，爲蒼生兮安國危。", "笑言指揮兮八千師，氐秦百萬兮潰而夷。", "朝之君臣兮猶燕巢於幕上，公對枰兮解頤。", "吁嗟公之車兮逢白雞而遽止，青山空兮已而。"]'),
('6002b256-41fc-4757-99b3-dd1cd8a41b00','偶興','張方平','宋','宋诗','song-poetry','','[]','財利乃怨府，功名爲禍胎。',72,'全唐诗/poet.song.18000.json','["財利乃怨府，功名爲禍胎。", "東市悔晚矣，西鍾悲悠哉。", "庖刀割腴味，匠斧斬良材。", "在埶勿偃蹇，居易無低徊。", "一瓢顔子巷，孤竿嚴光臺。", "盛德與高風，顥清無毀頹。"]'),
('dc1fd80b-be76-49e7-b5d0-41cb5571f769','新定道中寄桐廬關太守三首  其一','張方平','宋','宋诗','song-poetry','','[]','辟書來北門，召命自宣室。',48,'全唐诗/poet.song.18000.json','["辟書來北門，召命自宣室。", "朝廷搜英材，溪山及野質。", "當世良有心，一得思造膝。", "署霞隱扶桑，已是長安日。"]'),
('0a45df24-91bd-49ec-9c84-09647b327834','新定道中寄桐廬關太守三首  其二','張方平','宋','宋诗','song-poetry','','[]','旦下烏石灘，暮泊嚴陵瀨。',48,'全唐诗/poet.song.18000.json','["旦下烏石灘，暮泊嚴陵瀨。", "潺湲卧溪聲，慘澹宿山靄。", "所歷已陳迹，不忘惟嘉話。", "淚濕青雲篇，撫襟慙慷慨。"]'),
('b1678c9f-9551-45eb-8575-004914b4b19d','新定道中寄桐廬關太守三首  其三','張方平','宋','宋诗','song-poetry','','[]','帆掛桐君山，櫓入富春渚。',48,'全唐诗/poet.song.18000.json','["帆掛桐君山，櫓入富春渚。", "寒風蕩江波，煙雨迷汀樹。", "煮茶論藥經，挑燈數碁路。", "全勝謝惠連，獨望新安去。"]'),
('069d4865-daaf-4c5f-a9a7-a85c5ef59f6f','初赴新定過錢塘江','張方平','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','颺帆上漁浦，隨潮宿鴈灣。',48,'全唐诗/poet.song.18000.json','["颺帆上漁浦，隨潮宿鴈灣。", "烟火指富陽，雲樹連蕭山。", "曲岸蓼花疎，清波鷗鳥閒。", "江外信清曠，吾心睢洛間。"]'),
('d26a18d1-d6c9-482f-a4c3-45600e0f5574','酬歐陽舍人寄題醉翁亭詩','張方平','宋','宋诗','song-poetry','','[]','我本高陽徒，野性蓋踈拙。',144,'全唐诗/poet.song.18000.json','["我本高陽徒，野性蓋踈拙。", "豈堪天子傍，命令裁機密。", "一麾出承明，猿鳥遂超逸。", "山州寂無事，氣象頗蕭瑟。", "閒尋琅邪溪，雲嵐可披拂。", "中路聞潺湲，幽亭對崷崒。", "鏘咽觸環珮，清泠泛琴瑟。", "知君多醉此，歸鞍屢突兀。", "醉中遣形骸，題名亦信筆。", "遺我溪風清，蒼顔坐髣髴。", "暝色失松竹，徘徊望寒月。", "携酒頻來游，行待山花發。"]'),
('f2c8b1f5-b902-4c21-9b1e-6ed68d49d013','出京東歸招趙參','張方平','宋','宋诗','song-poetry','','[]','季子揣摩佩六印，主父宦游食五鼎。',208,'全唐诗/poet.song.18000.json','["季子揣摩佩六印，主父宦游食五鼎。", "奈何君抱縱橫才，四方漂泊無人省。", "我客在陳君逆旅，秋霖淫滯宵燈永。", "解裘命酒邀與談，蕭蕭衢路驊騮騁。", "是時泣血略相弔，我走汝南君入郢。", "今者索然來上都，陰懷一刺謀謁請。", "深閎高蓋競豪權，大浪長風獨萍梗。", "龍待雲雷無一勺，虎思林麓困窮穽。", "壯心日覺春冰消，素髮年來曉霜冷。", "季子主父昔亦爾，子參今胡懷怲怲。", "一爲齊國無立錐，一爲洛陽無二頃。", "我有弊廬濉之陽，子參良田枕清潁。", "況是伊人高枕時，明朝歸鞅同君整。"]'),
('efd0e1de-1b41-4294-8758-23066c35b51f','酬范思遠','張方平','宋','宋诗','song-poetry','','[]','陰陽萬變始三畫，天地大法都九疇。',352,'全唐诗/poet.song.18000.json','["陰陽萬變始三畫，天地大法都九疇。", "斯文濫觴日增廣，淳源已潰分千流。", "舉而錯之爲事業，典誥始勛終乎周。", "尼父將聖生無位，一王遺法存春秋。", "化成天下文之大，豈事章句矜雕鎪。", "道經戰國遂榛莽，賴漢諸儒勤耘耰。", "然其文物比三代，高曾下視雲來幽。", "唐時師匠多磊落，昌黎把鉞爲之酋。", "姬公端冕明堂位，八門四面羣小侯。", "嗟時迦老駕異說，吾儒路阻行無郵。", "可憐韓子獨强介，抗顔不爲緇黄羞。", "惟余碌碌謬庸者，蓬頭風轉萍波浮。", "出言踈闊觸忌諱，倦遊四國無人收。", "夫君家公世才傑，士林嚮景稱英游。", "是故落然來北海，登門如到神仙洲。", "貽詩旅人定交分，所期者大將安酬。", "爽如高秋望霽景，壯如拔戟逐挾輈。", "兩敦六瑚見古器，黄鍾大呂聞鳴球。", "偉哉志趣規取遠，古人之善今人仇。", "直須擺脫忽迴視，遠趨董賈爲朋儔。", "此心可以厚風俗，此文可以揚天休。", "誓將它日同利涉，我爲之楫君爲舟。"]'),
('0e692506-e7d2-4d90-9b8e-50bd589fa1d3','贈邢山人思齊','張方平','宋','宋诗','song-poetry','','[]','夜凉風月靜，庭幽松檜陰。',72,'全唐诗/poet.song.18000.json','["夜凉風月靜，庭幽松檜陰。", "羽人江外來，爲我開素琴。", "上清通灝氣，太古傳遺音。", "逍遥得天和，虛寂還真心。", "更調三樂曲，無惜一巵深。", "胡然憂世患，慨歎傷靈襟。"]'),
('ed96035a-151b-4e89-b629-f53f8d66e508','梁甫吟與任向','張方平','宋','宋诗','song-poetry','','[]','秋風吹空一橫掃，秀桐芳蕙經宵老。',115,'全唐诗/poet.song.18000.json','["秋風吹空一橫掃，秀桐芳蕙經宵老。", "晨雞驚起窮丈夫，心骨調殘感霜草。", "獨起過君喜君在，鸘裘同就旗亭解。", "酒酣氣壯把袂歸，吾曹心過中區大。", "君不覺豐城兩龍思延平，氣凝愁紫牛間橫。", "神物際會當有時，洛陽樓上逢張卿。", "古人率自窮途起，景略執畚南陽耕。"]'),
('7136bd5b-974a-4539-a85d-4109dbe58a0c','朝元引貽趙抱一','張方平','宋','宋诗','song-poetry','','[]','星斗掛空碧，鸞鶴翔紫清。',92,'全唐诗/poet.song.18000.json','["星斗掛空碧，鸞鶴翔紫清。", "朝真弟子古壇上，爐煙裊裊金碧聲。", "露脚斜白寒不動，千山岑寂橫煙清。", "絳闕太真冠簡靜，紫宮夫人璫珮鳴。", "霞旌曉邁遺空谷，石磴雲埋瑶草綠。", "殘蟾冷帖西南隅，迴首塵寰煙一簇。"]'),
('90c268d3-6b63-4a40-acb0-7c853039409d','有所思行','張方平','宋','宋诗','song-poetry','','[]','有所思，在斗墟之東華。',91,'全唐诗/poet.song.18000.json','["有所思，在斗墟之東華。", "我欲從之路阻賒，寸心坐馳天南涯。", "彼美一人騫且都，明月環珮雲霞裾，蹇于翔兮不我留。", "登高杳視令人愁，褰裳欲涉江湖修。", "江湖修，不可過。", "不可過兮奈若何，私自憐兮長嘯歌。"]'),
('09bcea84-ea72-48ef-91b2-318948dcff34','送柳澥下第出京','張方平','宋','宋诗','song-poetry','','[]','少年心骨壯，功名期力殉。',72,'全唐诗/poet.song.18000.json','["少年心骨壯，功名期力殉。", "文邀馬卿評，劔謁猿公問。", "御良驥足逸，胡爲車三僨。", "浮沈道所尚，窮達天之分。", "跡從逍遥遊，心與洪濛論。", "姑佩湛盧歸，休復較銛鈍。"]'),
('6cbdee08-7278-44c3-92e3-ec0d79bcf61a','送龔懋','張方平','宋','宋诗','song-poetry','','[]','千里寒雪程，平生旅人心。',48,'全唐诗/poet.song.18000.json','["千里寒雪程，平生旅人心。", "丈夫雖四方，行役愁不任。", "禰刺弊生毛，趙囊空無金。", "錢子一罇酒，送子垂楊陰。"]'),
('0dae80f6-dcba-4a33-9040-37e4be7eb4a9','寄贈姚白','張方平','宋','宋诗','song-poetry','','[]','疇昔未識君，汝南熟聲耀。',96,'全唐诗/poet.song.18000.json','["疇昔未識君，汝南熟聲耀。", "相隨會上都，一揖心相照。", "愛君真快士，顧我略同調。", "劇孟重然諾，曼倩喜諧笑。", "往簡日共評，高樓常對釂。", "君銳如利劔，騰拔已出鞘。", "我獨策征驂，舌在慵復掉。", "歸養詠南陔，丘園憶高蹈。"]'),
('645c4083-d793-4a2c-b294-38db14dc2c19','哭友人任向','張方平','宋','宋诗','song-poetry','','[]','暮哭寢門外，南望愁雲昏。',48,'全唐诗/poet.song.18000.json','["暮哭寢門外，南望愁雲昏。", "何言英邁氣，奄成幽寂魂。", "寒月長夜臺，秋風黄蒿原。", "十載金石心，凄凉誰與言。"]'),
('066c3e83-fe6a-4eee-a1c6-dfcb229f285c','暮冬書事','張方平','宋','宋诗','song-poetry','','[]','物色無容華，逆風利如剪。',48,'全唐诗/poet.song.18000.json','["物色無容華，逆風利如剪。", "晨興心悵然，惜此歲華晚。", "自古東流波，滔滔去無返。", "計事須及時，咄哉行自勉。"]'),
('36ce2671-cb5a-4f2e-b191-d8bd15213198','廣陵散','張方平','宋','宋诗','song-poetry','','[]','廣陵散，妙哉嵇公其旨深，誰知此是亡國音。',112,'全唐诗/poet.song.18000.json','["廣陵散，妙哉嵇公其旨深，誰知此是亡國音。", "商聲慢大宮聲微，强臣專命王室卑。", "我聞仲達窺天祿，人見飛鳥在晉屋。", "子元廢芳昭殺髦，常道鄉公終蕩覆。", "義師三自廣陵起，功皆不成竟夷戮。", "廣陵散，宣誅凌。", "景誅儉，文誅誕。", "廣陵散，晉室昌，魏室亡。"]'),
('59fe54d5-0b43-4033-ae1e-24e2567a1a72','滄浪曲','張方平','宋','宋诗','song-poetry','','[]','五湖波浪涵秋空，風煙蕭索愁溶溶。',97,'全唐诗/poet.song.18000.json','["五湖波浪涵秋空，風煙蕭索愁溶溶。", "棹扁舟兮長邁，當年則有越相之范公。", "烏喙不仁固可恨，文種踟躕亦已庸。", "功大不賞威震主，不去必誅今古同。", "周霍中曾殆如線，黥韓竟不保其終。", "誰能持此滄浪曲，寄入三湘棹唱中。"]'),
('2e2a6bd2-ddac-453d-b37c-4a5ec58e7d1e','過齊篇','張方平','宋','宋诗','song-poetry','','[]','有叟羈窮垂白頭，潛神密理同天遊。',144,'全唐诗/poet.song.18000.json','["有叟羈窮垂白頭，潛神密理同天遊。", "朝歌鼓刀既屠紂，渭濱垂鈎來釣周。", "晚遭西伯與同載，首封東海荒營丘。", "洋洋大風僅千祀，當年固乃屠釣儔。", "世變後有薛公文，館中多坐倜儻人。", "魯連節重輕丘山，馮驩氣高微風雲。", "丈夫志義絕流俗，豈與層層雛鼠羣。", "楚漢興亡事已微，後世傾奪奚足譏。", "龍韜豹略苦迂闊，使公復生將安歸。"]'),
('e3b7a385-9920-4bb7-92b2-6ce6a974129d','瑶池宴曲','張方平','宋','宋诗','song-poetry','','[]','仙人仙在滄海湄，雙毫出耳綠絲垂。',96,'全唐诗/poet.song.18000.json','["仙人仙在滄海湄，雙毫出耳綠絲垂。", "瑶池西赴白雲宴，丹山遠借青鸞騎。", "香雲紅淡春光染，天風吹旌霞颭颭。", "曉過扶桑水一泓，下視中州塵九點。", "蟠桃初熟甘露瓜，對持斗柄泛流霞。", "妄向秋空舉金掌，茂陵衰草令人嗟。"]'),
('ebafb9a4-b4c3-409a-8f5a-9103c73962fa','秋過琴臺懷古','張方平','宋','宋诗','song-poetry','','[]','周道積衰禮義壞，夫子詠歌沂泗濱。',112,'全唐诗/poet.song.18000.json','["周道積衰禮義壞，夫子詠歌沂泗濱。", "宓君不齊宰單父，獨推深誠仁此民。", "彈琴燕坐澹無事，人不忍欺風化淳。", "流光逝水二千年，我稅征鞍來盤桓。", "滿屋清風氣象古，繞臺宿楚霜華寒。", "緬懷德音竟誰嗣，揮酒灑空獨長歎。", "安得長官盡愷悌，編氓父子聊相歡。"]'),
('cd71f617-a584-417e-96ff-5c5fd2c4881f','淥水辭','張方平','宋','宋诗','song-poetry','','[]','山翁貌清聳，膝橫古桐彈。',112,'全唐诗/poet.song.18000.json','["山翁貌清聳，膝橫古桐彈。", "泛弄淥水曲，滿絃流潺潺。", "初調意緒微，溫流動斜暉。", "劃然響嘈嘈，秋風駕怒濤。", "數聲細更大，澗泉咽復快。", "曲終急以停，驟雨齊無聲。", "西壁月華白，萬壑松風清。", "灝然太古氣，使人塵慮平。", "山翁彈罷抱琴去，歸處一峰煙翠橫。"]'),
('82a9e8d1-9219-4baa-8651-77a48cc066c2','老將篇','張方平','宋','宋诗','song-poetry','','[]','聖明天子仁且英，海寰內外歸神靈。',64,'全唐诗/poet.song.18000.json','["聖明天子仁且英，海寰內外歸神靈。", "辭客相夸鳳凰詔，功臣不貌麒麟形。", "繡旗塵卷霞紋闇，古劔秋澁銅花青。", "尚餘舊愛征西馬，待從日仗登云亭。"]'),
('31625e3e-e77f-4ba2-a06d-4d98baa0352d','讀高士傳','張方平','宋','宋诗','song-poetry','','[]','天地閉不泰，賢人隱山澤。',96,'全唐诗/poet.song.18000.json','["天地閉不泰，賢人隱山澤。", "如何堯舜代，箕潁有逸客。", "消長存乎時，出處惟所適。", "箕子之明夷，釣筑亦潛迹。", "乘桴海上遊，採芝商中匿。", "有道盍來儀，經綸建皇極。", "致君義軒庭，安民仁壽域。", "豈必同蚯蚓，蟠屈泥中食。"]'),
('25369ce5-391c-4468-9f45-b300e05cd8db','古意','張方平','宋','宋诗','song-poetry','','[]','灝灝元氣淳，茫茫太古迹。',72,'全唐诗/poet.song.18000.json','["灝灝元氣淳，茫茫太古迹。", "文巧不勝煩，發機自三畫。", "盟詛復誥誓，民心日澆弊。", "蕩然近太初，祖龍亦深意。", "傾奪損生理，世人多夭死。", "誠哉象繫言，乾坤有時毀。"]'),
('5455968f-31ae-4133-8938-af8a4958616a','詠松','張方平','宋','宋诗','song-poetry','','[]','受命託厚地，稟氣獨英妙。',48,'全唐诗/poet.song.18000.json','["受命託厚地，稟氣獨英妙。", "有心出太虛，無情合至道。", "君子正容色，烈士全節操。", "自是萬木王，何辱大夫號。"]'),
('bc158170-6cdb-4872-bf67-59bc4ab25aea','謝人贈玉界尺','張方平','宋','宋诗','song-poetry','','[]','美玉琢溫潤，界尺裁方直。',48,'全唐诗/poet.song.18000.json','["美玉琢溫潤，界尺裁方直。", "非惟立規矩，亦以端簡冊。", "玉性比君子，尺用同正人。", "兼有盤盂戒，宜爲几席珍。"]'),
('7ee50df0-42e9-4ef1-8bce-1ec73447cfce','崑山初秋觀稼回縣署與同寮及示姑蘇幕府','張方平','宋','宋诗','song-poetry','','[]','邑民三萬家，四邊湖海遶。',252,'全唐诗/poet.song.18000.json','["邑民三萬家，四邊湖海遶。", "家家勤穡事，市井商游少。", "薦歲逢水沴，饑勞何擾擾。", "我來忝撫字，見此心如搗。", "去秋僅有年，膏田尚停潦。", "今幸風雨調，皆話天時好。", "春喜鵲巢低，夏更蟬聲早。", "秧船拏參差，葑岸縈迴繚。", "藝插暮更急，車響轉清曉。", "紡筥猶掛壁，何暇張魚鳥。", "我時行近郊，小艇穿萍藻。", "渚長葭薍深，野沃𥝧稏倒。", "孺子遠餉歸，閒暇顔色飽。", "預喜省敲笞，租賦可時了。", "歸來軒館靜，曠蕩盈懷抱。", "衙退人吏散，庭廡闃窈窈。", "露篠映孤亭，風荷動幽沼。", "置身木鴈間，茲焉願終老。", "顛蹶走榮利，況余拙非巧。", "鱸膾飯紫芒，鵝脂酒清醥。", "悵然懷友生，虛齋爲誰掃。"]'),
('5ef93585-e10c-4039-b5c5-5772608abeb7','臨池翫游魚','張方平','宋','宋诗','song-poetry','','[]','曲池秋水平，虛碧杳澄浄。',252,'全唐诗/poet.song.18000.json','["曲池秋水平，虛碧杳澄浄。", "有鰋從何來，潛據久已橫。", "鼓鬣作波浪，晴景占蘋荇。", "貪吞無遺鱗，多折脩荷柄。", "西軒因納凉，遶步恣哦詠。", "時逢橫水面，氣意殊豪勁。", "向非神守嚴，雨霧尋飛迸。", "不揆入江海，且與蛟螭競。", "暇日呼罟師，搜摝窮泥濘。", "潑剌出數尺，怒跳何健輕。", "狀醜足涎沫，刀几嫌腥硬。", "遣童放西澤，不死儻知倖。", "猶慮持私烹，誠囑煩言令。", "去去避鈎網，再獲誰爾諍。", "遂取羣小鮮，投中使沿泳。", "上游若浮空，眾沈疑落穽。", "隊行有孤出，如嫡從諸媵。", "忽散何所驚，兩合成相迎。", "銜尾既競速，依蒲亦少定。", "莊濠念逍遥，嚴溪思隱行。", "聊以貽後人，持竿助閒興。"]'),
('b65b42c0-0c65-42f1-be0e-5c6d3860bf2c','吳中暑雨','張方平','宋','宋诗','song-poetry','','[]','澤國氣溫濕，暑候尤鬰蒸。',264,'全唐诗/poet.song.18000.json','["澤國氣溫濕，暑候尤鬰蒸。", "矧更並江海，霖霪久相仍。", "沉陰不暫解，雲霧常昏凝。", "蛾蝶敗禾麥，鰍鱣占田塍。", "菌本出床脚，蘚痕粘杖藤。", "蝸蚓離竅竇，伸縮殊自矜。", "蛙黽聒晝夜，耳慣猶愁憎。", "漫水接河漢，寧復分淄澠。", "暑弱爲寒冒，陽微遭陰凌。", "震雷寂不發，凄風時暴興。", "孰此宰四序，令煩無威稜。", "將由列缺惰，何處閒曲肱。", "飛廉獨掀撲，公爾作陰朋。", "共力起波浪，勢且襄岡陵。", "涉古考經說，助陽義有憑。", "古典救日法，于社縈朱繩。", "置麾伐五鼓，消慝使勿勝。", "庶幾災沴革，幸獲忻穀登。", "幽齋窗戶闇，懵瞀思不澄。", "有如坐盎缶，巾羃施層層。", "疚心忝撫字，搔首徒鬅鬙。", "安得昏霾闢，坐見白日昇。"]'),
('58ee579f-852a-4c6c-a327-9b02e8a7f883','東亭逐雀','張方平','宋','宋诗','song-poetry','','[]','芳園夏景初，茂樹成帷幄。',144,'全唐诗/poet.song.18000.json','["芳園夏景初，茂樹成帷幄。", "幽亭鮮人到，羣雀宅簷桷。", "飛集得所安，朋噪聲何樂。", "幸無彈弋虞，復免鷹鸇捉。", "入水時尚賒，孳育日以數。", "啄場徒耗粟，穿屋皆有角。", "屬我厭歊蒸，來居屏紛濁。", "置榻開小窗，當軒掛踈箔。", "莫肯少畏避，竟來鬭紛魄。", "爭粒時聚喧，奪栖或相摶。", "誰命爲嘉賓，輕率可無怍。", "主人不爾堪，盡逐歸蓬藿。"]'),
('03fdb921-cdce-4b0b-bfa4-7ac603ccb479','桃源二客行','張方平','宋','宋诗','song-poetry','','[]','劉郎阮郎丹籙客，桃花源中有舊宅。',96,'全唐诗/poet.song.18000.json','["劉郎阮郎丹籙客，桃花源中有舊宅。", "閒尋流水過碧溪，忽聞雞犬見人跡。", "瓊臺瑶榭知何所，紫雲深處開珠戶。", "鶴駕龍軿綵仗來，鸞歌鳳舞霞觴舉。", "世緣未斷塵心狂，苦厭仙家日月長。", "洞門一閉怳如夢，歸路古木何荒凉。"]'),
('59be517a-32ff-4f6a-bdbb-54954db292a1','滄洲白鳥歌','張方平','宋','宋诗','song-poetry','','[]','水爲都，雲爲廬，芙蓉帳，清蓋車，霜裾雪襟素襜襦。',112,'全唐诗/poet.song.18000.json','["水爲都，雲爲廬，芙蓉帳，清蓋車，霜裾雪襟素襜襦。", "秋空清，秋雨晴，弋者不來漁翁去，孤翹羣泳蘆花汀。", "往來東浦何容與，莫愛稻粱過西渚。", "漁翁布羅滿葭下，潛教媒子來呼汝。", "罥絲漠漠不可見，羽翰一掛脫不去。", "汝掛羅，媒子喜，更笑汝愚落他計。"]'),
('187a6fd4-f4ea-4c19-a86a-41eff91aef5b','門有車馬客行','張方平','宋','宋诗','song-poetry','','[]','崇軒華蓋爲誰子，高閣朱扉爲誰第。',115,'全唐诗/poet.song.18000.json','["崇軒華蓋爲誰子，高閣朱扉爲誰第。", "孟公君卿善請謁，少叔王孫有權勢。", "憑凌豪氣務相傾，晚日署門復誰恚。", "君不見隆中草廬客，陽里蓆門居。", "斂翼蓬蒿下，蕭條意自如。", "觸羅向稻梁，肯隨黄口雛。", "將軍三降顧，真主六用謨。", "豈由趨逐交遊得，壯心自與功名俱。"]'),
('4f62dbc3-2514-4095-8d8e-a495945bef02','平臺秋','張方平','宋','宋诗','song-poetry','','[]','層臺複道盤盤斜，馬頭冷光摇玉花。',144,'全唐诗/poet.song.18000.json','["層臺複道盤盤斜，馬頭冷光摇玉花。", "曲葆翩翩映紅日，綵旗苒苒舒晴霞。", "鏗鐘考鼓臺上宴，花間樓榭層層見。", "香霧低濛爛不收，觥籌隨酒東西轉。", "山銜半日王未醉，桂花蟾露滴濃翠。", "鼕鼕滿板敲金丸，千娥攢碧臺門閉。", "古銅青澁對秋曉，王樂不極將如老。", "孟嘗墳上牧童歌，千歲空臺長荒草。", "土花愁碧古甬平，陰夜鬼熒光擾擾。"]'),
('f15c12ed-bcd1-4db6-ac21-5d07284a812e','黄鶴篇','張方平','宋','宋诗','song-poetry','','[]','黄鶴飛來兮，越滄海之無垠，標格孤高誰與羣。',145,'全唐诗/poet.song.18000.json','["黄鶴飛來兮，越滄海之無垠，標格孤高誰與羣。", "風前清嘯欲命侶，凝神翹立如含嚬。", "鷹鸇獨矜觜爪利，燕雀止爲腥羶馴。", "扃籠猶負語言巧，墮羽直爲依襟珍。", "杳杳水雲上，亦有網羅屯。", "黄鶴飛去兮，汝無戀此擾擾之塵寰。", "沖丹霄兮凌紫煙，行啄秀芝咽醴泉。", "靜棲琪樹金羽麗，閒舞瑶池菊裳鮮。", "鵷羣鳳侶久相待，休隨燕雀陪鷹鸇。"]'),
('c59094b4-ffcc-4aed-b8e1-8e26bf1780f8','胡生畫牛歌','張方平','宋','宋诗','song-poetry','','[]','有儒落落何爲者，策驢曉到吾門下。',320,'全唐诗/poet.song.18000.json','["有儒落落何爲者，策驢曉到吾門下。", "鳳標高古氣深淳，詢之乃是陶唐民。", "并汾形勝太行麓，西距潼關大河曲。", "春秋戰國漢晉史，所書義勇雄俠士。", "多出三晉與秦燕，古云氣俗稟之然。", "我顱儒冠腰博带，軀幹不如腦腑大。", "曾遊兩河望王屋，不到并州心不足。", "喜君歷歷說其鄉，引我心飛過太行。", "因愛其鄉愛其人，已重其人重其文。", "文比玉溪既高爽，詩比玉川仍清新。", "胡君不但歌詩好，又工畫筆名精妙。", "畫牛百年鼻不乾，浙東獨有戴巡官。", "胡君不肯居戴後，自署名爲畫牛叟。", "忽摧兩幅教余看，回首故園心戀戀。", "我家一廛寄淮汭，往曾親把枯犂尾。", "月下歌商叩牛角，雨裏尋春坐牛背。", "長來提劔事羈遊，虛名役我荒西疇。", "見君畫得牛如活，却憶煙蓑淮汭秋。", "胡君胡君君賢者，畫得信奇宜少畫。", "勿令畫價聞於人，掩君詩價兼文價。"]'),
('36b7e851-b7a6-44ca-b60b-0402a9b99957','勸酒行','張方平','宋','宋诗','song-poetry','','[]','眾客醉歸盃席闌，有客不醉坐長嘆。',144,'全唐诗/poet.song.18000.json','["眾客醉歸盃席闌，有客不醉坐長嘆。", "不醉長嘆客何苦，請以眼前近事觀。", "客見南遷丁晉公，擁旄秉軸天禧中。", "昔歲羈遊客此宇，窮秋蕭索隨飛蓬。", "漸達得意忘舊困，手提國柄矜權雄。", "矜權未足俄南竄，青衫白髮窮衰翁。", "向者枯榮試回省，何異春宵夢一終。", "人事紛紜似飛絮，鐘漏聲中朝復暮。", "且脫鸘裘換酒來，與子相從醉鄉去。"]'),
('5df5f3a1-b995-4a7e-8a72-f4f7ce396457','思遠辭','張方平','宋','宋诗','song-poetry','','[]','露下蟬不鳴，愴然覺秋暮。',72,'全唐诗/poet.song.18000.json','["露下蟬不鳴，愴然覺秋暮。", "獨立夕陽樓，遥見南征路。", "動乖心所期，事與年同去。", "彈鋏歌歸來，愁思發宵寤。", "高吟惠連詩，重憶安仁賦。", "佳人何當還，荆陽歎流寓。"]'),
('e6266b85-e432-4642-baec-c3a239dee84b','歲除','張方平','宋','宋诗','song-poetry','','[]','世事隨波濤，流光逐魁杓。',48,'全唐诗/poet.song.18000.json','["世事隨波濤，流光逐魁杓。", "二年革新舊，一夕連昏朝。", "容華益凋歇，況味殊蕭條。", "信似唐生語，躍馬期非遥。"]'),
('e5861fc1-fcd1-4821-9cfb-d0f4f453bf24','姑蘇蔣公北池詩','張方平','宋','宋诗','song-poetry','','[]','浙江湯湯，南國之紀。',240,'全唐诗/poet.song.18000.json','["浙江湯湯，南國之紀。", "句章之鄉，居巢之里。", "天子命公，二邦更治。", "越人之嗟，吳人之喜。", "公之爲政，簡而易從。", "不嚴而威，敏以有功。", "孽不及牙，姦折其緒。", "孰施斧斤，不見鋩露。", "老稚晏起，壯服于畝。", "椸有澣衣，廥有多稌。", "公之退公，樂是北池。", "飛閣渠渠，虛廊遲遲。", "魚跳于藻，渚有鳧鷖。", "釣亭檜島，其水漣漪。", "公之退公，以豫以游。", "邦人喜公，尚無疾憂。", "邦人祝公，百祿是遒。", "匪公其私，王家之休。", "我思建官，公理眾政。", "與民最親，惟時守令。", "其有不臧，根心之螟。", "小猶蟣蝨，膚皮是營。", "於鑠有宋，一統萬方。", "千里所付，幾人曰良。"]'),
('63d2e158-42bb-40b9-891d-71a7fbd94f18','睢陽雙忠廟詩','張方平','宋','宋诗','song-poetry','','[]','烈士趨死易，黜己下人難。',288,'全唐诗/poet.song.18000.json','["烈士趨死易，黜己下人難。", "況乃持柄位，而當功名間。", "天寶唐中圮，大盜起幽薊。", "伐鼓傾中州，意有摧枯易。", "桓桓許公遠，持節睢陽郡。", "孤壘扼賊衝，攻急勢危窘。", "張公何壯哉，雍丘以眾來。", "誓將同忠義，分持虜羹杯。", "慷慨二丈夫，感諾明悲吁。", "對舉兩手起，力與扶中區。", "空郊乘垝垣，賦鋒四周攢。", "萬夫齊一心，就死無悔顔。", "夫豈威令使，化公心如丹。", "兵盡糧餉絕，重圍氣逾烈。", "龍枯無一勺，虎騰墜窮穴。", "帳下萬金士，霽雲特雄傑。", "乞師賀蘭府，嚙指如枯蘗。", "七日哭秦庭，何謝楚臣節。", "鄰藩救不來，呱呱守埤哀。", "天胡不我弔，竟使孤城摧。", "沈痛數忠良，委骨鯨與豺。", "王師遂破賊，天王歸京國。", "持久全江淮，實由二公力。", "遺烈在宋人，食公河之津。"]'),
('e4b0b540-53ca-4e14-b374-54776c4fe3bd','閒居述懷','張方平','宋','宋诗','song-poetry','','[]','踈慵余本性，放曠涵天真。',252,'全唐诗/poet.song.18000.json','["踈慵余本性，放曠涵天真。", "自疑姑射來，藐然太古淳。", "思與老彭游，坐閱冥靈春。", "世家守儒業，此志成越秦。", "蹭蹬湛世僞，遂與英俊羣。", "闊步處清禁，迎班趨紫宸。", "高議預時事，客氣矜要津。", "薪火不停焰，風波浩亡垠。", "釋筈前無的，將車後多塵。", "履地弗敢蹐，仰屋徒含顰。", "兼濟悼遲暮，獨善慙隱淪。", "瀝懇得嘉命，閒曹容病身。", "性以浄爲體，慵乃德之純。", "融師善知識，中散誠仁鄰。", "首慵廢冠弁，腰慵捐佩紳。", "手慵如槁枝，足慵若奇輪。", "耳目遺聲色，鼻舌忘馨辛。", "內樂極委順，中扃收精神。", "大觀齊諸物，萬化同一均。", "禍兮福所倚，名與身孰親。", "何須人林壑，自是逍遥人。"]'),
('d8514c05-e82b-46f4-98e6-492932451def','酬琅邪山僧智先相示禪冊','張方平','宋','宋诗','song-poetry','','[]','種種諸法皆心生，心自無生豈有法。',32,'全唐诗/poet.song.18000.json','["種種諸法皆心生，心自無生豈有法。", "祖師來意我不知，昨夜秋風掃黄葉。"]'),
('1b04a860-c68c-4e56-b68a-ddfd084891f7','遊九老祠堂閱古碑舊記字多訛缺詢諸故老靈跡甚異因成長句以誌其事','張方平','宋','宋诗','song-poetry','','[]','黄裘紗帽霜眉白，九老相携意氣同。',64,'全唐诗/poet.song.18000.json','["黄裘紗帽霜眉白，九老相携意氣同。", "碧水宮中初邂逅，黄金殿裏久從容。", "苦催歸路憎驪母，留賞名園喜葛公。", "爲問家鄉還遠近，迢迢七十七程中。"]'),
('e07762bb-834e-42d1-97ea-0eb31ecfb275','寓意詠月贈李先生','張方平','宋','宋诗','song-poetry','','[]','二八已微闕，十四猶未圓。',48,'全唐诗/poet.song.18000.json','["二八已微闕，十四猶未圓。", "盛滿在三五，素蛾逞嬋娟。", "兩半陰陽合，平分上下弦。", "臼中有靈藥，一粒九光全。"]'),
('bf9a1a59-010f-4cd8-bd9b-89bd07fecab9','送蘇子由監筠州酒稅','張方平','宋','宋诗','song-poetry','','[]','可憐萍梗飄浮客，自嘆匏瓜老病身。',32,'全唐诗/poet.song.18000.json','["可憐萍梗飄浮客，自嘆匏瓜老病身。", "從此空齋挂塵榻，不知重掃待何人。"]'),
('ec0bb775-0e7e-46bb-813a-6a35a8a21131','偈','張方平','宋','宋诗','song-poetry','','[]','自從無始千千劫，萬法本來無一法。',32,'全唐诗/poet.song.18000.json','["自從無始千千劫，萬法本來無一法。", "祖師來意我不知，一夜西風掃黄葉。"]'),
('b99aa786-6d25-42f3-a128-070999d3e391','送何山人','張方平','宋','宋诗','song-poetry','','[]','煙策西歸背九衢，錦城春色徧平蕪。',32,'全唐诗/poet.song.18000.json','["煙策西歸背九衢，錦城春色徧平蕪。", "它年定有乘槎客，知是嚴君隱蜀都。"]'),
('eab3a74e-9f9b-458f-92d0-b3dff243290b','詩二首  其一','張方平','宋','宋诗','song-poetry','','[]','故人久別忽相逢，不及開樽舟已東。',32,'全唐诗/poet.song.18000.json','["故人久別忽相逢，不及開樽舟已東。", "四十五年春夢過，此回一見更怱怱。"]'),
('6b10becf-43d0-4282-a584-7549af59ebec','詩二首  其二','張方平','宋','宋诗','song-poetry','','[]','剡中盛事自南朝，太守詩人趣亦高。',32,'全唐诗/poet.song.18000.json','["剡中盛事自南朝，太守詩人趣亦高。", "我豈匏瓜常繫此，酒舡搥鼓興猶豪。"]'),
('3ae5b122-1d90-4d59-8bb0-f06be413a85d','句  其一','張方平','宋','宋诗','song-poetry','','[]','紅塵三尺險，中有是非波。',12,'全唐诗/poet.song.18000.json','["紅塵三尺險，中有是非波。"]'),
('4f58f8fe-f9af-489f-967f-8ee544a12ada','句  其二','張方平','宋','宋诗','song-poetry','','[]','謹言渾不畏，忍事又何妨。',12,'全唐诗/poet.song.18000.json','["謹言渾不畏，忍事又何妨。"]'),
('06392d38-0f54-4677-b1a8-daf1f93668a6','感興三首  其一','蘇舜欽','宋','宋诗','song-poetry','','[]','後寢藏衣冠，前廟宅神主。',288,'全唐诗/poet.song.18000.json','["後寢藏衣冠，前廟宅神主。", "吾聞諸禮經，此制出中古。", "秦嬴蝕先法，乃復祭於墓。", "漢衣以月遊，於道蓋無取。", "宣帝尊祖廟，失制徧九土。", "孝元酌前文，一旦悉除去。", "魏帝樂銅臺，遺令置歌舞。", "昏嗣竟從之，此事狂夫阻。", "唐制益紛華，諸陵鎖嬪御。", "曠女日哀吟，於先亦奚補。", "吾朝三聖人，乘雲不可覩。", "威靈已霄漢，嗣皇念宗祖。", "繪事移天光，刻象肖神武。", "徧敕舊遊地，輸材起宮宇。", "階墄釦以金，牆壁衣之黼。", "功既即奉迎，法仗疊簫鼓。", "玩好擇珍奇，目奪不可數。", "三京佛老家，已有十數處。", "朝家雖奉先，越禮古不許。", "君不祭臣僕，父不祭支庶。", "丹楹豈非孝，聖貶甚蕭斧。", "大祀當以時，寢廟即其所。", "惜哉共儉德，乃爲侈所蠱。", "痛乎神聖姿，遂與夷爲侶。"]'),
('d8778c8b-3744-438e-9a2d-242737f9cac0','感興三首  其二','蘇舜欽','宋','宋诗','song-poetry','','[]','在昔帝舜日，光宅闢四門。',228,'全唐诗/poet.song.18000.json','["在昔帝舜日，光宅闢四門。", "所賓無兇邪，德教日益敦。", "末世多濫姦，九重嚴大閽。", "扞掫主譏察，誰何辨語言。", "一關百力士，列立甃石溫。", "設官按尺籍，唱號於未昏。", "唐末稍懈怠，嘗值外使奔。", "京城兇豪兒，奮劍闖帝藩。", "狂呼嘯虎豹，便欲傾乾坤。", "賴有宰相在，不然神器翻。", "我朝講制度，門籍反不存。", "近知賤丈夫，突入犯赤軒。", "陛官未暇執，呶呶何其諠。", "祖宗創業難，慎重在後昆。", "勇夫猶重閉，況乃天子尊。", "何羅猶宜察，況乃外寇屯。", "興語一及此，舌出反自捫。", "吾家本寒微，世受朝廷恩。", "欲奏鴟鴞詩，當塗誰薦論。"]'),
('e55127c6-cdec-4d27-b202-3ab831760be2','感興三首  其三','蘇舜欽','宋','宋诗','song-poetry','','[]','瞽說聖所擇，愚謀帝不罪。',288,'全唐诗/poet.song.18000.json','["瞽說聖所擇，愚謀帝不罪。", "況乎言有文，白黑時利害。", "前日林書生，自謂胸臆大。", "潛心摭世病，榮成謂可賣。", "投顙觸諫函，獻言何耿介。", "云昨見兇星，上帝下警戒。", "意若日昏㧻，出處恣蜂蠆。", "安坐弄神器，開門納珍賄。", "宗支若繫囚，親親禮日殺。", "大臣尸其柄，咋舌希龍拜。", "速速伐虎叢，無使自沈瘵。", "陛下幸察之，聰明即不壞。", "如忽賤臣言，不瞬防禍敗。", "一封朝飛入，羣目已睚眥。", "力夫暮塞門，執縛不容喟。", "十手捽其胡，如負殺人債。", "幽諸死牢中，繫灼若龜蔡。", "亦既下風指，黥而播諸海。", "長途萬餘里，一錢不得带。", "必令朝夕閒，渴饑死于械。", "從前有口者，蹜脰如氣鞴。", "獨夫已去除，易若吹糠粺。", "奈何上帝明，非德不可蓋。", "倏忽未十旬，炎官下其怪。"]'),
('ffb70fbc-6da9-4380-8c3c-6c31b08c661e','慶州敗','蘇舜欽','宋','宋诗','song-poetry','','[]','無戰王者師，有備軍之志。',268,'全唐诗/poet.song.18000.json','["無戰王者師，有備軍之志。", "天下承平數十年，此語雖存人所棄。", "今歲西戎背世盟，直隨秋風寇邊城。", "屠殺熟戶燒障堡，十萬馳騁山嶽傾。", "國家防塞今有誰，官爲承制乳臭兒。", "酣觴大嚼乃事業，何嘗識會兵之機。", "符移火急蒐卒乘，意謂就戮如縛尸。", "未成一軍已出戰，驅逐急使緣嶮巇。", "馬肥甲重士飽喘，雖有弓劍何所施。", "連顛自欲墮深谷，虜騎笑指聲嘻嘻。", "一麾發伏鴈行出，山下掩截成重圍。", "我軍免胄乞死所，承制面縛交涕洟。", "逡巡下令藝者全，爭獻小技歌且吹。", "其餘鼻馘放之去，東走矢液皆淋漓。", "首無耳準若怪獸，不自媿恥猶生歸。", "守者沮氣陷者苦，盡由主將之所爲。", "地機不見欲僥勝，羞辱中國堪傷悲。"]'),
('4177614c-bf12-47cf-af30-a296db0a4020','及第後與同年宴李丞相宅','蘇舜欽','宋','宋诗','song-poetry','','[]','十年苦學文，出語背時向。',144,'全唐诗/poet.song.18000.json','["十年苦學文，出語背時向。", "策力不自知，藝圍輒掉鞅。", "薄技遭休明，一第君所唱。", "拔身泥滓底，飄迹雲霞上。", "氣和朝言甘，夢好夕魂王。", "軒眉失舊斂，舉意有新況。", "爽如秋後鷹，榮若凱旋將。", "台府張宴集，吾輩縱謔浪。", "花梢血點乾，酒面玉紋漲。", "狂歌互喧傳，醉舞迭閬伉。", "茲時實無營，此樂亦以壯。", "去去登顯涂，幸無隳素尚。"]'),
('51592d14-1650-4ad0-b002-54d5ba8c3206','昇陽殿故址','蘇舜欽','宋','宋诗','song-poetry','','[]','昔在開元中，此名昇陽殿。',264,'全唐诗/poet.song.18000.json','["昔在開元中，此名昇陽殿。", "西通大明宮，夾道直如箭。", "至尊黄金輿，乘春日幸宴。", "翠嬪戛鐘鼓，歡呼奏新徧。", "巧舞風燕翻，妖歌露鶯囀。", "酒光射錦幄，上下花會炫。", "雕盤堆緐英，豔粉弱自戰。", "天歡日無窮，臣諫莫敢獻。", "樂極哀繼之，在理亦可見。", "胡來塞宮闕，腥羶污香薦。", "縱火寢廟平，揮戈君臣迸。", "庸嗣忽前醜，泚巢更禍亂。", "冉冉竟覆亡，返爲耕牧便。", "瓦礫雖費犂，土壤頗肥衍。", "蓋由殺人多，膏血浸漬遠。", "髑髏今成堆，皆昔燕趙面。", "每因鉏耨時，數得寶玉片。", "今秋雨澤多，穀穗密如辮。", "農惟喜豐稔，吾獨閔遷變。", "不有失德君，焉爲穡夫佃。", "大國尚如此，小人易流轉。", "道德可久長，作詩將自勸。"]'),
('0af2189e-49fd-4b8c-a6ea-b9da49c75713','大霧','蘇舜欽','宋','宋诗','song-poetry','','[]','欲曉霜氣重不收，餘陰乘勢相淹留。',114,'全唐诗/poet.song.18000.json','["欲曉霜氣重不收，餘陰乘勢相淹留。", "化爲大霧塞白晝，咫尺不辨人與牛。", "羣鳥啁啾滿庭樹，欲飛恐遭羅網囚。", "四簷晻藹下重幕，微風吹過冷自流。", "竊思朝廷政無濫，未嘗一日封五侯。", "何爲終朝不肯散，焉知其下無蚩尤。", "思得壯士翻白日，光照萬里銷我之沈憂。"]'),
('84a70b0e-cb6b-40d1-8741-f169fdf3996c','藍田悟真寺作','蘇舜欽','宋','宋诗','song-poetry','','[]','旅食長安城，迴遑奔走無停行。',386,'全唐诗/poet.song.18000.json','["旅食長安城，迴遑奔走無停行。", "清懷壯抱失素尚，胸中堆積塵土生。", "偷閒得至玉峯下，爲聞悟真之寺之嘉名。", "杖邛赤脚渡藍水，細流激激心骨清。", "仰看蒼山高峯旁，白雲明滅藏日光。", "行人遥指置寺處，正在白雲之中央。", "逡巡緣棧更險絕，攀蘿捫壁隨低昂。", "朋行咫尺乃相失，已與雲霧相翱翔。", "時聞啼鳥如吹竹，數步一休還縱目。", "行行未知高則危，下視昏煙覆平陸。", "滿巖佳樹尤樸樕，赫赤如霞間濃綠。", "是時八月初，路旁已見芬芬菊。", "貪奇戀景不知倦，側睥又復心瑟縮。", "神魂飛下大壑幽，定省移時進雙足。", "寺門高開朝日輝，丹青黯澹唐時屋。", "老僧引我周遊看，且云白氏子詩乃實錄。", "此詩疇昔予所聞，殷殷更向碑前讀。", "按言索像今無復，惟有流泉數道如車輻。", "我嫌世累欲暫居，又云此地無留宿。", "殿宇之後林莽中，日暮嘗有虎豹伏。", "鑿石龕邊崖至深，近有浮屠於此相棖觸。", "悁心宿忿兩不解，一乃顛擠死其谷。", "我聞爲之久顰蹙，此向期將避煩辱。", "不爲傷生事，爭如平地隨流俗。"]'),
('2cf15b39-2c46-4016-91bb-9ae42640ab1d','興慶池','蘇舜欽','宋','宋诗','song-poetry','','[]','餘潤漲龍渠，疏溜連清滻。',48,'全唐诗/poet.song.18000.json','["餘潤漲龍渠，疏溜連清滻。", "助曉遠昏山，浮秋明刮眼。", "漁歸別浦閑，鴈下滄波晚。", "岸北有高臺，離魂蕩無限。"]'),
('3c0f38ad-e3cf-43f3-9dd7-4b7c2ab2ff54','長安春日效東野','蘇舜欽','宋','宋诗','song-poetry','','[]','前秋長安春，今春長安秋。',84,'全唐诗/poet.song.18000.json','["前秋長安春，今春長安秋。", "節物自榮悴，我有樂與憂。", "窮閻何卑漏，時燕不見投。", "門庭謝過從，蘭萌舒綠柔。", "燕託喜廣厦，亦非善是仇。", "蘭生靜愈茂，堪將義爲儔。", "芳香誠可慕，對之蠲窮愁。"]'),
('18fa5df8-6eb5-430e-b4ed-fac988dbf9d0','太行道','蘇舜欽','宋','宋诗','song-poetry','','[]','行行太行道，一步三太息。',202,'全唐诗/poet.song.18000.json','["行行太行道，一步三太息。", "念厥造化初，春何險此極。", "左右無底壑，前後至頑石。", "高者欲作天明黨，深者疑斷地血脈。", "夜中巖下埋斗杓，日午陰壁風雪號。", "攀緣有路到絕仞，四望羣峯合沓如波濤。", "忽至逼側處，咫尺顛墜恐莫逃。", "嗟乎古昔未開時，隔絕往來人不思。", "淳源一破山岳碎，巧心遂去緣嶮巇。", "嶮巇不窮甚可畏，悼此二者亡其宜。", "天地不自嶮，嶮由人爲之。", "彼車摧輪馬傷足，中路勿歎勿慟哭。", "世上安塗故有焉，孰使汝行此道軀高軒，喪墜不收宜爾然。"]'),
('c560e986-c7c7-44c4-b893-3a387c579e6c','對酒','蘇舜欽','宋','宋诗','song-poetry','','[]','丈夫少也不富貴，胡顔奔走乎塵世。',112,'全唐诗/poet.song.18000.json','["丈夫少也不富貴，胡顔奔走乎塵世。", "予年已壯志未行，案上敦敦考文字。", "有時愁思不可掇，崢嶸腹中失和氣。", "倚官得來太行顛，太行美酒清如天。", "長歌忽發淚迸落，一飲一斗心浩然。", "嗟乎吾道不如酒，平褫哀樂如摧朽。", "讀書百車人不知，地下劉伶吾與歸。"]'),
('083e0865-246c-43c9-84ce-c506bb904511','夜中','蘇舜欽','宋','宋诗','song-poetry','','[]','夜分眾諠死，耿耿抱真履。',130,'全唐诗/poet.song.18000.json','["夜分眾諠死，耿耿抱真履。", "中君湛以寧，不爲外官使。", "七兵乘間入，攻剽勢向圮。", "主將不謀陣敵惡，蕩然失守遽藏避。", "駭浪奔騰，一刻萬里，紛紛變化無窮已。", "俄如獨繭絲，忽復滿天地。", "乳虎不受縛，狂龍難馴致。", "我思精甲，以扞異類。", "邪慝弗萌，元辟復位。", "輔以逍遥之至道，爛然光輝照無際。"]'),
('6e3002de-fef7-4275-a3d3-e26d8a622ee5','蜀士','蘇舜欽','宋','宋诗','song-poetry','','[]','蜀國天下險，奇怪生中間。',288,'全唐诗/poet.song.18000.json','["蜀國天下險，奇怪生中間。", "有士賈其姓，抱材東入關。", "獻冊叩諫鼓，其言蔚可觀。", "願以微賤軀，一得至上前。", "掉舌滅西寇，畫地收幽燕。", "且云太平久，兵戰無人言。", "臣嘗學其法，自集數百篇。", "治亂與成敗，密然不可刪。", "三獻輒罷去，志屈心悲酸。", "將相門戶深，欲往復見攔。", "負販冒日熱，引重衝雪寒。", "羈苦輦轂下，以圖晨夕餐。", "如此三歲餘，夜夜抱膝歎。", "義者或賑給，遂復歸巴川。", "嗟乎區宇大，此徒亦已緐。", "城市與巖穴，隱默孰辨旃。", "幸得出自鬻，何惜置末班。", "吾相柄天下，處事當幾先。", "古之設爵位，蓋欲英雄躔。", "次第立名級，不使智慮閑。", "稍有才器者，必以祿仕牽。", "所患在不出，既出那棄捐。", "放蛟入大水，軀虎還深山。", "失一故無害，其類莫可攀。"]'),
('e6076d21-c55e-4ae8-b30d-42f362b953f2','己卯冬大寒有感','蘇舜欽','宋','宋诗','song-poetry','','[]','延川未撤警，夕烽照冰雪。',240,'全唐诗/poet.song.18000.json','["延川未撤警，夕烽照冰雪。", "窮邊苦寒地，兵氣相躔結。", "主將初臨戎，猛思風前發。", "朝笳吹餘哀，疊鼓暮不絕。", "淹留未見敵，愁端密如髮。", "予聞古烈士，自誓立壯節。", "丸泥封函關，長纓繫南越。", "本爲朝廷羞，寧計身命活。", "功名非與期，冊書豈磨滅。", "然由在遇專，醜類易翦伐。", "訓士無他才，賞罰在果决。", "近聞邊方奏，中覆多沈沒。", "罪者既稽誅，功者不見閱。", "雖使頗牧生，勇智當坐竭。", "或云廟堂上，與彼勢相戛。", "恐其立異勳，欻然自超拔。", "不知百萬師，寒刮膚革裂。", "關中閑誅斂，農產半匱竭。", "我欲叫上帝，願帝下明罰。", "早令黠虜亡，無爲生民孽。"]'),
('1f8da538-d05a-4bc3-a4b3-2df9f3e9bbc4','獵狐篇','蘇舜欽','宋','宋诗','song-poetry','','[]','老狐宅城隅，涵養體豐大。',276,'全唐诗/poet.song.18000.json','["老狐宅城隅，涵養體豐大。", "不知窟穴處，草木但掩藹。", "秋食承露禾，夏飲灌園派。", "暮夜出旁舍，雞畜遭橫害。", "晚登埤堄鳴，呼吸召百怪。", "或爲嬰兒啼，或變豔婦態。", "不知幾十年，出處頗安泰。", "古語比社鼠，蓋亦有恃賴。", "邑中年少兒，耽獵若沈瘵。", "遠郊盡雉兔，近水殲鱗介。", "養犬號青鶻，逐獸馳不再。", "勇聞此老孤，取必將自快。", "縱犬索幽邃，張人作疆界。", "茲時頗窘急，迸出赤電駭。", "羣小助呼嗥，奔馳數顛沛。", "所向不能入，有類狼失狽。", "鉤牙咋巨顙，髓血相潰沫。", "喘叫遂死矣，爭觀若期會。", "何暇正丘首，腥臊滿蓬艾。", "數穴相穿通，城堞幾隳壞。", "久縱此兇妖，一旦果禍敗。", "皮爲榻上藉，肉作盤中膾。", "觀此爲之吟，書以爲警戒。"]'),
('8b12185d-154e-436b-84f6-f66cc9771217','難易言  其一','蘇舜欽','宋','宋诗','song-poetry','','[]','擬把鉛刀伐丹桂，欲坐眢井攀青天。',32,'全唐诗/poet.song.18000.json','["擬把鉛刀伐丹桂，欲坐眢井攀青天。", "排羅嬰兒拒九虎，未若以道干貴權。"]'),
('fe5860cb-6d49-432e-8c5d-c03cc6970b0c','難易言  其二','蘇舜欽','宋','宋诗','song-poetry','','[]','地上拾芥亦細碎，掌裏數文猶苦辛。',32,'全唐诗/poet.song.18000.json','["地上拾芥亦細碎，掌裏數文猶苦辛。", "脫使摘丸下峻坂，未若以財而發身。"]'),
('a64ca0e6-a334-49f4-b035-d127aa985cbc','大小言  其一','蘇舜欽','宋','宋诗','song-poetry','','[]','彎弓射月落，揮劍决天開。',24,'全唐诗/poet.song.18000.json','["彎弓射月落，揮劍决天開。", "何言四溟廣，並合不成杯。"]'),
('a30a3acf-92c3-4f8a-8d7d-6fa9e910ae39','大小言  其二','蘇舜欽','宋','宋诗','song-poetry','','[]','託身螟兩睫，卜都牛一毛。',24,'全唐诗/poet.song.18000.json','["託身螟兩睫，卜都牛一毛。", "奔馳萬里外，終不出秋毫。"]'),
('beae4c9b-4b70-497b-a467-c4ed509ba813','了語不了語  其一','蘇舜欽','宋','宋诗','song-poetry','','[]','公餗欲成忽覆鼎，銀缾汲絕還沈井。',32,'全唐诗/poet.song.18000.json','["公餗欲成忽覆鼎，銀缾汲絕還沈井。", "乳虎咆哮落深穽，青萍一揮斷人頸。"]'),
('2e0b0a96-8683-41a9-b234-ccc7e5c11364','了語不了語  其二','蘇舜欽','宋','宋诗','song-poetry','','[]','無言以手尋珮環，寒暑迭運雕朱顔。',32,'全唐诗/poet.song.18000.json','["無言以手尋珮環，寒暑迭運雕朱顔。", "八駿踏地幾時徧，六龍駕日何年閑。"]'),
('cf8671c3-d84e-4f4b-9134-ce37ab3ebba1','舟中感懷寄館中諸君','蘇舜欽','宋','宋诗','song-poetry','','[]','扁舟迎春色，東下淮楚鄉。',288,'全唐诗/poet.song.18000.json','["扁舟迎春色，東下淮楚鄉。", "側身風波地，回首英俊場。", "顧我本俗材，百事無一長。", "濫迹入冊府，舉動初不皇。", "乍脫泥滓底，稍見日月光。", "峻閣鬰前起，隱嶙天中央。", "春風花竹明，曉雨宮殿凉。", "溢目盡圖史，接翼皆鸞凰。", "明窗置刀筆，大案羅縑緗。", "文字雖幼學，鈍庸今廢忘。", "不能溫舊習，考古評興亡。", "靦顔於其間，汗下如流漿。", "徒然日飽食，出入隨羣行。", "朝廷比多事，亦合强激昂。", "況有詔書在，爛然貼北牆。", "奮舌說利害，以救民膏肓。", "不然棄硯席，挺身赴邊疆。", "喋血鏖羌戎，胸膽森開張。", "彎弓射攙槍，躍馬埽大荒。", "功勳入丹青，名迹萬世香。", "是亦丈夫事，不爲鼠子量。", "數事皆不能，徒只飽腹腸。", "有如鳧鴈兒，唼喋守稻粱。", "歲月今逝矣，齒摇髮已蒼。"]'),
('c561bf52-e3a1-4cc7-9f72-9c7da626fdfa','送李生','蘇舜欽','宋','宋诗','song-poetry','','[]','李生以病廢，東入徂徠峯。',60,'全唐诗/poet.song.18000.json','["李生以病廢，東入徂徠峯。", "志氣尚突兀，形骸已龍鍾。", "男兒生世間，有如絕壑松。", "誤爲風雷傷，不與匠石逢。", "哀哉千尺榦，摧折似秋蓬。"]'),
('ced8a4fd-a695-4820-b748-ef978e195caf','楊子江觀風浪','蘇舜欽','宋','宋诗','song-poetry','','[]','晚至瓜州渡，擊舟泊西灣。',216,'全唐诗/poet.song.18000.json','["晚至瓜州渡，擊舟泊西灣。", "日落暴風起，大浪得縱觀。", "憑凌積石岸，吐吞天外山。", "霹靂左右作，雪灑六月寒。", "吁嗟至柔物，威壯不可干。", "若爲神龍憑，氣勢非一端。", "大艦失所操，翻覆如轉丸。", "高山雖有路，轍險馬足酸。", "居朝號安逸，重祿多憂患。", "爭得清靜交，共騎雙翔鸞。", "矯翅入赤霄，不見此險難。", "奈何蚩蚩眾，共處天壤間。", "因知古聖人，立法萬世安。", "濟川作舟梁，鑄鼎窮神姦。", "朝廷布禮度，粲粲莫可刪。", "後來漸破壞，所向行路難。", "兇邪得騁志，物命遭摧殘。", "視此念古昔，杖藜空盤桓。"]'),
('7db7a6ee-2e55-4673-9739-69626f95f9a7','哭曼卿','蘇舜欽','宋','宋诗','song-poetry','','[]','去年春雨開百花，與君相會歡無涯。',112,'全唐诗/poet.song.18000.json','["去年春雨開百花，與君相會歡無涯。", "高歌長吟插花飲，醉倒不去眠君家。", "今年慟哭來致奠，忍欲出送攀魂車。", "春暉照眼一如昨，花已破蕾蘭生芽。", "唯君顔色不復見，精魄飄忽隨朝霞。", "歸來悲痛不能食，壁上遺墨如棲鴉。", "嗚呼死生遂相隔，使我雙淚風中斜。"]'),
('0366ce4d-aa87-410e-a619-603a4d5a9113','吾聞','蘇舜欽','宋','宋诗','song-poetry','','[]','吾聞壯士懷，恥與歲時沒。',108,'全唐诗/poet.song.18000.json','["吾聞壯士懷，恥與歲時沒。", "出必鑿兇門，死必填塞窟。", "風生玉帳上，令下厚地裂。", "百萬呼吸間，勝勢一言决。", "馬躍踐胡腸，士渴飲胡血。", "腥膻屏除盡，定不存種孽。", "予生雖儒家，氣欲吞逆羯。", "斯時不見用，感歎腸胃熱。", "晝卧書冊中，夢過玉關北。"]'),
('0794c60b-5206-440c-a875-12096a8de1d8','送安素處士高文悅','蘇舜欽','宋','宋诗','song-poetry','','[]','皇天稔巨憝，羌虜稽顯戮。',216,'全唐诗/poet.song.18000.json','["皇天稔巨憝，羌虜稽顯戮。", "廟算忽小醜，王師數傾衄。", "秦民著暴斂，慘慘生意蹙。", "賊氣愈張王，鋒銳不可觸。", "帷幄監前敗，降心問白屋。", "尺詔下中天，公車塞章牘。", "策慮盡頗牧，勇决過賁育。", "先生胸臆大，經術內自足。", "逸韻脫滓塵，素節抱冰玉。", "獨恥論兵戰，因時射君祿。", "不唯吾志乖，亦使王道局。", "放懷但文史，散髮自溪谷。", "近臣上薦書，天子渴高躅。", "旌帛三及門，不免至京轂。", "萬鍾非所好，大議戛鈞軸。", "孤鸞入紫煙，網罟安可束。", "天風萬里長，沆瀣朝滿腹。", "更期下翔集，以爲蒼生福。"]'),
('29fc7e9a-1b08-441b-b08b-ef794f6a460e','贈釋祕演','蘇舜欽','宋','宋诗','song-poetry','','[]','高車大馬闐上京，釋曰演者何聲名。',176,'全唐诗/poet.song.18000.json','["高車大馬闐上京，釋曰演者何聲名。", "當年余嘗與之語，實亦可喜無俗情。", "作詩千篇頗振絕，放意吐出吁可驚。", "不肯低心事鎸鑿，直欲淡泊趨杳冥。", "落落吾儒坐滿室，共論愨若木陷釘。", "賣藥得錢輒沽酒，日費數斗同醉醒。", "傷哉不櫛被佛縛，不爾烜赫竈名卿。", "數年不見今老矣，自說厭苦居都城。", "垂頤孤坐若癡虎，眼吻開合猶光精。", "雄心瞥起忽四顧，便擬擊浪東南行。", "開春余行可同載，相與曠快觀滄溟。"]'),
('0ebd6cec-6e6a-42d8-b9b8-435d99e480f1','城南感懷呈永叔','蘇舜欽','宋','宋诗','song-poetry','','[]','春陽泛野動，春陰與天低。',240,'全唐诗/poet.song.18000.json','["春陽泛野動，春陰與天低。", "遠林氣藹藹，長道風依依。", "覽物雖蹔適，感懷翻然移。", "所見既可駭，所聞良可悲。", "去年水後旱，田畝不及犂。", "冬溫晚得雪，宿麥生者稀。", "前去固無望，即日已苦饑。", "老稚滿田野，斲掘尋鳧茈。", "此物近亦盡，卷耳共所資。", "昔云能驅風，充腹理不疑。", "今乃有毒厲，腸胃坐瘡痍。", "十有七八死，當路橫其尸。", "犬彘咋其骨，烏鳶啄其皮。", "胡爲殘良民，令此鳥獸肥。", "天豈意如此，决蕩莫可知。", "高位厭粱肉，坐論攙雲霓。", "豈無富人術，使之長熙熙。", "我今饑伶俜，閔此復自思。", "自濟既不暇，將復奈爾爲。", "愁憤徒滿胸，嶸峵不能齊。"]'),
('5b0efb68-954e-4cd4-b13b-a4ef86a59c96','吳越大旱','蘇舜欽','宋','宋诗','song-poetry','','[]','吳越龍蛇年，大旱千里赤。',240,'全唐诗/poet.song.18000.json','["吳越龍蛇年，大旱千里赤。", "尋常秔穄地，爛漫長荆棘。", "蛟龍久遁藏，魚鼈盡枯腊。", "炎暑發厲氣，死者道路積。", "城市接田野，慟哭去如織。", "是時西羌賊，兇燄日熾劇。", "軍須出東南，暴斂不暫息。", "復聞籍兵民，驅以教戰力。", "吳儂水爲命，舟檝乃其職。", "金革戈盾矛，生眼未嘗識。", "鞭笞血塗地，惶惑宇宙窄。", "三丁二丁死，存者亦乏食。", "寃對結不宣，衝迫氣候逆。", "二年春及夏，不雨但赫日。", "安得涼冷雲，四散飛霹靂。", "滂沱消祲癘，甘澗起稻稷。", "江波開舊漲，淮嶺發新碧。", "使我揚孤帆，浩蕩入秋色。", "胡爲泥滓中，視此久戚戚。", "長風卷雲陰，倚柂淚橫臆。"]'),
('5800df69-a970-4eb5-9453-189fea037d46','中秋夜吳江亭上對月懷前宰張子野及寄君謨蔡大','蘇舜欽','宋','宋诗','song-poetry','','[]','獨坐對月心悠悠，故人不見使我愁。',160,'全唐诗/poet.song.18000.json','["獨坐對月心悠悠，故人不見使我愁。", "古今共傳惜今夕，況在松江亭上頭。", "可憐節物會人意，十日陰雨此夜收。", "不惟人間重此月，天亦有意於中秋。", "長空無瑕露表裏，拂拂漸漸寒光流。", "江平萬頃正碧色，上下清澈雙璧浮。", "自視直欲見筋脈，無所逃遁魚龍憂。", "不疑身世在地上，祗恐槎去觸斗牛。", "景情境勝返不足，歎息此際無交游。", "心魂冷烈曉不寢，勉爲筆此傳中州。"]'),
('efb6c57f-df77-44f6-89d6-6e11db4749d2','越州雲門寺','蘇舜欽','宋','宋诗','song-poetry','','[]','翠嶂環合封白雲，中有蕭寺三爲鄰。',64,'全唐诗/poet.song.18000.json','["翠嶂環合封白雲，中有蕭寺三爲鄰。", "老松偃蹇若傲世，飛泉噴薄如避人。", "蒼猿嘯斷夜月古，丹花開徧陽崖春。", "盤桓數日不忍去，舟出邪溪猶慘神。"]'),
('5b4724f6-9212-4dc8-81c4-e98c3b69d71d','和韓三謁歐陽九之作','蘇舜欽','宋','宋诗','song-poetry','','[]','予方居憂艱，胸懷積瘡刺。',276,'全唐诗/poet.song.18000.json','["予方居憂艱，胸懷積瘡刺。", "昏明走月月，慘慘絕生意。", "杜門厭過從，掩耳避時事。", "韓子我所佳，招我懃有謂。", "城南訪永叔，共可豁蒙蔽。", "是時窮陰久，泥淖沒馬鼻。", "區區不憚遠，饑渴奔高誼。", "永叔聞我來，解榻顔色喜。", "殷勤排清罇，甘酸飣果餌。", "圖書堆滿牀，措論極根柢。", "伊余昏迷中，忽若出夢寐。", "劃然毛骨開，精神四邊至。", "既歸尚泠然，數日飽滋味。", "韓子歎不足，作詩暢情義。", "爛如珊瑚鈎，光豔不可閉。", "迫余使之和，庶以同氣類。", "自顧屯鈍極，出語少姿媚。", "抉剔雖强成，徒使腸胃沸。", "永叔經術深，爛熳不可既。", "雖得終日談，百未出一二。", "倉皇逼行役，蕭颯包素志。", "不日便乖拆，安能訖精粹。", "他年老門牆，君子無我棄。"]'),
('4e3467dd-e32c-4ea8-ba81-18999422c6a2','城南歸值大風雪','蘇舜欽','宋','宋诗','song-poetry','','[]','一夜大雪風喧豗，未明跨馬城南回。',209,'全唐诗/poet.song.18000.json','["一夜大雪風喧豗，未明跨馬城南回。", "四方迷惑共一色，揮鞭欲進還徘徊。", "舊時崖谷不復見，縱有直道令人猜。", "低頭搶朔風，兩眼不敢開。", "時時偷看問南北，但見白羽之箭紛紛來。", "既以脂粉傅我面，又以珠玉綴我顋。", "天公似憐我貌古，巧意裝點使莫偕。", "欲令學此兒女態，免使埋沒隨灰埃。", "據鞍照水失舊惡，容質潔白如嬰孩。", "雖然外飾得暫好，自覺面目如刀裁。", "又不知胸中肝膽掛鐵石，安能柔軟隨良媒。", "世人飾詐我尚笑，今乃復見天公乖。", "應時降雪故大好，慎勿改易吾形骸。"]'),
('88b2c623-0ed1-4fa7-b50c-9a7771fa04e7','出京後舟中有作寄仲文韓二兄弟永叔歐陽九和叔杜二','蘇舜欽','宋','宋诗','song-poetry','','[]','久居倦京城，歸心日傾寫。',204,'全唐诗/poet.song.18000.json','["久居倦京城，歸心日傾寫。", "扁舟理棹楫，已與峻流下。", "斷岸如崩山，遠樹若奔馬。", "回頭雲間闕，出沒見圖畫。", "還家快雖蹔，去國傷以乍。", "況我二三友，眷戀數返駕。", "前夕南巷堤，昨日東城舍。", "論精如可收，意密不見罅。", "恍惚夢寐中，蕭然已相捨。", "他人所至樂，惟我氣類寡。", "迂僻不能鎸，往往自嗟罵。", "平生居京都，君輩乃知者。", "異鄉孰與言，救謗定不暇。", "柔軟眾所佳，佞面誰可借。", "中懷百憂集，包釀似葅鮓。", "身世苦飄浮，歲月不可把。", "後期浩難知，高吟但悲灑。"]'),
('e857b9d2-c5c0-4d81-9a41-2fb11fef15a4','寄富彥國','蘇舜欽','宋','宋诗','song-poetry','','[]','自古猾者胡與羌，胡羌相連動朔方。',288,'全唐诗/poet.song.18000.json','["自古猾者胡與羌，胡羌相連動朔方。", "姦謀陰就一朝發，直欲截割吾土疆。", "遣使持書至闕下，四方物論如沸湯。", "天子仄席旰未嘗，相君日暮猶廟堂。", "彥國感慨請奉使，誓將摧折其鋒鋩。", "受詔驅馬出都門，都人走觀歎且傷。", "猾胡聞風已厭伏，聚聽大議羞亂常。", "願如故約不敢妄，脫甲爭獻寶玉觴。", "旆旌威遲還上國，所至觀者如傾江。", "杖父奔蹶喜出泣，婦女聚語氣激昂。", "至尊虛懷坐赭牀，中人催入見未央。", "對久赤日下輦道，翠華影轉熏風涼。", "歸來堂上拜壽母，賓車塞破甘泉坊。", "衣塵未滌又出使，往來絕域如門牆。", "已知高賢抱器識，因時與國爲輝光。", "不煩一甲屈萬眾，以此可見才短長。", "彥國本爲廊廟器，何祗口舌平强梁。", "使之當國柄天下，夷狄豈復能猖狂。"]'),
('278f457e-45f7-4247-b9ab-5415b6cd1473','大風','蘇舜欽','宋','宋诗','song-poetry','','[]','秋半收穫登郊原，欹側小屋愁夕眠。',208,'全唐诗/poet.song.18000.json','["秋半收穫登郊原，欹側小屋愁夕眠。", "是夜大風拔樹走，吹倒南壁如崩山。", "夢中驚起但呼叫，病僕未動徒豗喧。", "驅令燃火徧照燎，瓦甓狼藉滿我前。", "披衣抱枕欲避去，去此乃是曠野田。", "況時風怒尚未息，直恐涇渭遭吹翻。", "露坐不免念禾黍，必已刮刷無完根。", "六事不和暴風作，嘗聞洪範有此言。", "昔時大風禾盡偃，上帝蓋直周公寃。", "方今天子至神聖，惟恐臣下辜其恩。", "是何此風乃震作，吹盡秋實傷元元。", "有能返風起禾者，亦足表異知所存。", "至誠皎潔固不昧，時雖今古同乾坤。"]'),
('e74b5932-b6f2-40e7-984d-b42b10c15746','檢書','蘇舜欽','宋','宋诗','song-poetry','','[]','煩心思所持，屏事入小閣。',216,'全唐诗/poet.song.18000.json','["煩心思所持，屏事入小閣。", "踾撲下塵梁，侈哆張敗笈。", "雨爛百數番，蟲食三四筴。", "軒昂醉墨鬧，纖悉新書雜。", "魚子或破碎，蠶兒尚狎恰。", "快心伯長文，跋尾清臣搨。", "幼辭反知進，故句時自愜。", "墜亡多玩愛，存聚必券帖。", "疎密交及戚，前後生與𣩄。", "誨束儼父師，寒暑怖兒妾。", "謔浪笑忽還，私暱情再接。", "愴事涕涔涔，憫時歎𠴲𠴲。", "一餉誠寂寞，千里遽會合。", "遊心到句甬，開眼見苕霅。", "京華歷歷復，節物怱怱涉。", "恍爾驚異方，遁去乃幾臘。", "回頭厭襞積，舉體覺疲薾。", "東閣聊欠伸，夢斷風一颯。"]'),
('ff7b5926-e7f7-4433-8e0f-ae502ab2acf7','高山別鄰幾','蘇舜欽','宋','宋诗','song-poetry','','[]','高山扶層巔，下與地盤結。',168,'全唐诗/poet.song.18000.json','["高山扶層巔，下與地盤結。", "氣貫不變移，澤枯乃朽裂。", "有如善人交，生死兩固節。", "語默無異方，黯沮在爲別。", "世風隨日儉，俗態逐勢熱。", "負予好古心，噓歎星斗滅。", "近得鄰幾生，胸懷貯霜雪。", "饑渴入詩書，趣向著羈絏。", "又與斯人離，先日心破折。", "古也當貽言，在子可捫舌。", "奈何區區誠，敢以御者說。", "器成必刓琢，德潤資澡刷。", "安文謾徽墨，古訓乃佩玦。", "帝門急豪英，濟物無自孑。"]'),
('e77c6474-0148-4b86-a76a-aa578c7c6768','雜興','蘇舜欽','宋','宋诗','song-poetry','','[]','虎豹性食人，智者畜爲戲。',36,'全唐诗/poet.song.18000.json','["虎豹性食人，智者畜爲戲。", "形影本相親，愚夫見而畏。", "疑同不疑異，遠哉愚與智。"]'),
('761374a1-4600-41e2-b844-7b6aa1afba7c','呂公初示古詩一編因以短歌答之','蘇舜欽','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','覽君古風之章句，兩謝不足以下顧。',134,'全唐诗/poet.song.18000.json','["覽君古風之章句，兩謝不足以下顧。", "長江走瀾天外來，共鵠軒風日邊去。", "上有致君却敵之良策，下有逍遥傲世之真趣。", "惜乎志大名位卑，明珠投闇人疑之。", "昔時名價滿天下，此日塞默趨塵泥。", "古人但以才術喻富貴，自餘之外胡足思。", "公初之道既如此，宜乎窮約而不悲。", "媿無玉案報神藻，聊此感激成荒辭。"]'),
('0cb0f25f-b94c-4eb6-ba77-56e174315f93','老萊子','蘇舜欽','宋','宋诗','song-poetry','','[]','常羨老萊子，七十親不衰。',108,'全唐诗/poet.song.18000.json','["常羨老萊子，七十親不衰。", "颯然雙白鬢，尚服五綵衣。", "戲游日膝下，弄物心熙熙。", "或時暫僕跌，輒作嬰兒啼。", "清朝萬鐘祿，不肯賣片時。", "人生有此樂，何暇外慕爲。", "伊余生不造，才壯蒼天虧。", "搏膺念之子，歎詠形諸詩。", "想象且三復，苦血下交頤。"]'),
('ec6af431-bc06-4a25-bf7f-d7bed268c586','往王順山值暴雨雷霆','蘇舜欽','宋','宋诗','song-poetry','','[]','蒼崖六月陰氣舒，一霔淫雨如繩粗。',112,'全唐诗/poet.song.18000.json','["蒼崖六月陰氣舒，一霔淫雨如繩粗。", "霹靂飛出大壑底，烈火黑霧相奔趨。", "人皆喘汗抱樹立，紫藤翠蔓皆焦枯。", "逡巡已在天中吼，有如上帝來追呼。", "震摇巨石當道落，驚嗥時聞虎與貙。", "俄而青巔吐赤日，行到平地晴如初。", "回首絕壁尚可畏，吁嗟神怪何所無。"]'),
('4c6ece4b-c4a4-4d7d-90ef-8d9d9300c68c','依韻和勝之暑飲','蘇舜欽','宋','宋诗','song-poetry','','[]','九夏苦炎烈，入伏氣候惡。',228,'全唐诗/poet.song.18000.json','["九夏苦炎烈，入伏氣候惡。", "況茲大旱時，其酷甚炮烙。", "爭得羿復生，射此赤日落。", "欲擘青天開，騰身出寥廓。", "狂走無處逃，坐恐肝腦涸。", "不如以酒澆，庶可免焦爍。", "相呼坐僧居，頃刻釂百酌。", "佳瓜判青膚，熟李吸絳膜。", "尚嫌味不爽，更與冰雪嚼。", "裂耳發浩歌，解顔縱善謔。", "逕趨無何鄉，回覺萬事借。", "不知余中虛，外冷得所託。", "真氣潛遁亡，半夜忽發霍。", "嘔洩不暫停，迸筋走兩脚。", "初如巨繩纏，忽似秋蚓躍。", "委頓體不支，藜牀爲穿鑿。", "君言暑飲佳，但得一晌樂。", "艱難踰旬時，僅飲數斗藥。", "快意事皆然，遺殃慎無作。"]'),
('d78c4a42-f2bd-4c27-8d56-fef4d7782103','答宋太祝見贈','蘇舜欽','宋','宋诗','song-poetry','','[]','窮冬三日雪，旅腸迫枯餓。',228,'全唐诗/poet.song.18000.json','["窮冬三日雪，旅腸迫枯餓。", "不免東郭行，難效袁安卧。", "我謁故所宜，君來無乃左。", "復貺長句詩，如留萬金貨。", "恣睢莫能名，豪橫不可挫。", "怒奔時旁出，力翥復下墮。", "使人但驚絕，欲斷誰敢作。", "況君名家駒，少小聲已播。", "丈夫氣剛精，不必在長大。", "譬如利錐末，所向物已破。", "余資本滯濁，既壯困家禍。", "區區走俗格，僅若螘循磨。", "詩枯實零丁，文僻又坎坷。", "翹然當路人，顧我甚涕唾。", "雅意返願交，得無自卑涴。", "俛首已內傾，撫躬輒私賀。", "無以答高誼，胸中强搜羅。", "披豁聊短篇，安足謂酬和。", "莞爾當棄投，毋留重吾過。"]'),
('f7459f32-6061-4869-bdb4-56d294a3ad08','送李冀州詩','蘇舜欽','宋','宋诗','song-poetry','','[]','冠蓋傾動車馬稠，都門曉送李冀州。',160,'全唐诗/poet.song.18000.json','["冠蓋傾動車馬稠，都門曉送李冀州。", "冀州綠髮三十一，𧽼𧽼千騎居上頭。", "眼如堅冰靦河月，氣勁倢鶻橫清秋。", "不爲膏粱所汩沒，直與忠義相沈浮。", "干戈未定民力屈，此行正解天子憂。", "男兒勝衣志四海，實恥坐得萬戶侯。", "斾旌明滅朔野闊，笳鼓凄斷邊風愁。", "孤雲南飛莫回首，下有慈親雙淚眸。", "自古忠孝不兩立，功名及時乃可收。", "眾人刮目看能事，著鞭無爲儒生羞。"]'),
('2b6e35be-d573-4d56-b72f-b08957fe303f','和鄰幾登緐臺塔','蘇舜欽','宋','宋诗','song-poetry','','[]','孝王有遺墟，寥落千年餘。',168,'全唐诗/poet.song.18000.json','["孝王有遺墟，寥落千年餘。", "今爲太常宅，復此緐華都。", "踴甓冠舊丘，西人號浮圖。", "下鎮地脈絕，上與烟雲俱。", "我來歷初級，穰穰瞰市衢。", "車馬盡螻螘，大河乃汙渠。", "躋攀及其顛，四顧萬象無。", "迥然塵坌隔，頓覺襟抱舒。", "俄思一失足，立見糜體軀。", "投步求自安，不暇爲他謨。", "平時好交親，豈復能邀呼。", "舉動强自持，恐爲眾揶揄。", "一身雖暫高，爭如且平居。", "君子不倖險，吾將監諸書。"]'),
('8bfb473d-7c67-40b5-a882-c325fb2cb553','依韻和伯鎮中秋見月九日遇雨之作','蘇舜欽','宋','宋诗','song-poetry','','[]','眾香愛春發枯荄，我知惟動兒女懷。',258,'全唐诗/poet.song.18000.json','["眾香愛春發枯荄，我知惟動兒女懷。", "天地昏酣醉夢裏，人有爽思皆沈埋。", "豈如秋風勁利劇刀劍，刮破天膜清光開。", "衰根危蔕埽除盡，辨別松竹并蒿萊。", "青娥供霜洗夜月，兼以皓露驅纖埃。", "常年此夕或陰晦，今歲澄徹將快哉。", "是時呼賓賞此景，漸見照我白玉杯。", "清輝向人若有意，徑歷窗戶猶徘徊。", "放歌狂飲不知曉，爛熳酌客山岳頹。", "時節飄流晦朔轉，已覺九日來相催。", "北軒隙地破蒼蘚，带花移得黄金栽。", "倒冠露頂坐狂客，擷香咀蕊浮新醅。", "最憐小雨灑疎竹，爽籟颯颯吹醉顋。", "君時傳詩頗精麗，意苦泥淖不得來。", "開緘文采自飛動，欲和但愧頑無才。", "久之黽勉强爲答，嫌春愛秋真可咍。"]'),
('7eb17b24-ebf3-459e-895c-00f2c64eccff','夜聞秋聲感而成詠同鄰幾作','蘇舜欽','宋','宋诗','song-poetry','','[]','八月天氣肅，萬物日已闌。',168,'全唐诗/poet.song.18000.json','["八月天氣肅，萬物日已闌。", "庭前兩高桐，夜籟如哀絃。", "志士感節物，中夕耿不眠。", "起聽抱膝吟，悲烈聲相干。", "念此華葉改，想見顔色鮮。", "顧人生世間，榮悴理亦然。", "豈傷歲月速，愧無功名傳。", "少小學文章，出值用武年。", "儒官多見侮，敢爲戰士先。", "欲棄俎豆事，强習孫吳篇。", "迂鈍不可爲，屈曲性亦難。", "虛言盜祿食，實又畏上天。", "未能追世好，且樂樽酒間。", "九日近不遠，同醉黄花前。"]'),
('61374e79-0ddf-4d0c-a3f0-db695f5b1748','和聖俞庭菊','蘇舜欽','宋','宋诗','song-poetry','','[]','不謂花草稀，實愛菊色好。',108,'全唐诗/poet.song.18000.json','["不謂花草稀，實愛菊色好。", "先時自封植，坐待秋氣老。", "類粧翠羽枝，已喜金靨小。", "嚴霜發層英，益見化匠巧。", "摇凝光豔落，折恐叢薄少。", "一日三四吟，一吟三四遶。", "賞專情自迷，美極語難了。", "得書所賦詩，爛漫感懷抱。", "朗詠償此心，清尊爲之倒。"]'),
('ef3a0912-9aea-46f6-ae2e-64d117fb8503','答梅聖俞見贈','蘇舜欽','宋','宋诗','song-poetry','','[]','自嗟處身拙，與世嘗齟齬。',144,'全唐诗/poet.song.18000.json','["自嗟處身拙，與世嘗齟齬。", "至於作文章，實亦少精趣。", "低摧朝市間，所向觸謗怒。", "夫子興眾殊，琢飾貺佳句。", "將然紙上動，讀畢恐飛去。", "自覺異平居，恍忽忘世故。", "迥如出泥塗，熏滌失臭污。", "衣之青霞裾，飲以紫蕊露。", "輶軒駕飛黄，蹀躞上夷路。", "古貴知者稀，流俗豈足顧。", "雅意雖可珍，三復未敢報。", "退慚百不堪，尚恐君悔誤。"]'),
('9b7b5690-336f-4026-aa73-09dd438d83ca','舟至崔橋士人張生抱琴携酒見訪','蘇舜欽','宋','宋诗','song-poetry','','[]','晚泊野橋下，暮色起古愁。',96,'全唐诗/poet.song.18000.json','["晚泊野橋下，暮色起古愁。", "有士不相識，通名叩余舟。", "鏗鏗語言好，舉動亦風流。", "自鳴紫囊琴，瀉酒相獻酬。", "余少在仕宦，接納多交游。", "失足落坑穽，所向逢弋矛。", "不圖田野間，佳士來傾投。", "山林益有味，足可銷吾憂。"]'),
('ea1e0123-6862-41f8-9a35-ee30171c2374','潁川留別王公輔','蘇舜欽','宋','宋诗','song-poetry','','[]','得罪身去國，犯寒挽孤舟。',84,'全唐诗/poet.song.18000.json','["得罪身去國，犯寒挽孤舟。", "親友祭我去，乃獨與子遊。", "子實飽文義，辭閩入中州。", "氣勁恥苟合，半歲爲我留。", "我窮不相棄，同載適宛丘。", "在困見人情，此意不可醻。", "解携春波上，會合知何秋。"]'),
('6b62a9ab-aab1-4899-9eec-95b9e2ec2661','維舟野步呈子履','蘇舜欽','宋','宋诗','song-poetry','','[]','白日出高岡，遠野春氣動。',96,'全唐诗/poet.song.18000.json','["白日出高岡，遠野春氣動。", "倉鳩鳴相懽，幽草色已弄。", "繫舟大何曲，登步目一縱。", "逍遥玩物華，所樂與君共。", "已忘竄逐傷，但喜懷抱空。", "古人負才業，未必爲世用。", "吾儕性疎拙，擯棄安足痛。", "四顧不見人，高歌免驚眾。"]'),
('b1a656ff-8297-40e9-8d1a-26b38ad07843','滯舟','蘇舜欽','宋','宋诗','song-poetry','','[]','落照滿長河，流水暖沖融。',132,'全唐诗/poet.song.18000.json','["落照滿長河，流水暖沖融。", "中有鳧鶩羣，上下隨和風。", "捕魚沒淺浦，矯翅入紫空。", "嬉遊意自得，肯顧冥冥鴻。", "伊余何所適，舟滯數見窮。", "十步九暗灘，咫尺不可通。", "獠工裂吻噪，捨檝將何從。", "巨絙挽屢斷，有如拔山峯。", "夕憂寇盜至，蹶弩映岸叢。", "徊徨但搔首，歎息無所容。", "曾無鳥禽樂，虛在人曹中。"]'),
('f7857deb-dfaa-431f-bcbe-6af430865e04','過濠梁別王原叔','蘇舜欽','宋','宋诗','song-poetry','','[]','交道今莫言，難以古義責。',180,'全唐诗/poet.song.18000.json','["交道今莫言，難以古義責。", "錙銖較利害，便有太行隔。", "余生性闊疎，逢人出胸膈。", "一旦觸駭機，四向盡戈戟。", "平生交遊面，化爲虎狼額。", "謗氣慘不開，中者若病疫。", "遂令老成人，坐是亦見斥。", "既出芸香署，又下金華席。", "摧辱實難任，官名亦非惜。", "罪始職于予，時情未當隙。", "今來濠水涯，日夜自羞惕。", "高風激頹波，相遇過疇昔。", "白璧露肺肝，晴雲見顔色。", "乃知天壤間，自有道義伯。", "明日又告行，吁嗟四海窄。"]'),
('5823ca8b-10b8-4663-b341-0ebc3c1f709f','和子履雍家園','蘇舜欽','宋','宋诗','song-poetry','','[]','長橋南走羣山間，中有雍子之名園。',128,'全唐诗/poet.song.18000.json','["長橋南走羣山間，中有雍子之名園。", "蒼雲蔽天竹色浄，暖香撲地花氣緐。", "飛泉來從遠嶺背，林下曲折寒波翻。", "珍禽不可見毛質，數聲清絕如哀禪。", "我來踞石弄琴瑟，唯恐日暮登歸軒。", "塵紛剝落耳目異，只疑夢入仙家村。", "君之襟尚我同好，作詩閎放莫可攀。", "高篇絕景兩不及，久之想像空冥冥。"]'),
('0af48f4e-389a-4da3-80bc-9c87e8e66df1','尹子漸哀辭','蘇舜欽','宋','宋诗','song-poetry','','[]','漂流江湖外，負罪氣慘悽。',156,'全唐诗/poet.song.18000.json','["漂流江湖外，負罪氣慘悽。", "況聞故人死，驚呼不成啼。", "當案舍匕箸，緬懷大河西。", "箴言尚在耳，鏗若環珮隨。", "志氣凜已失，神魂飄何之。", "昔云死者樂，復以生爲悲。", "予知達士懷，將以二物齊。", "今也果何如，無乃往意迷。", "荆棘飽雨露，叢蘭委污泥。", "紫鸞忽腸絕，永年賊狐狸。", "天理漭難問，我意多乖暌。", "哀吟蒼山闊，注目白日低。", "不得慟寢門，雪涕江上隄。"]'),
('01846bae-cbab-4568-b8c7-20c6965e6a2c','天平山','蘇舜欽','宋','宋诗','song-poetry','','[]','吳會括眾山，戢戢不可數。',180,'全唐诗/poet.song.18000.json','["吳會括眾山，戢戢不可數。", "其間號天平，突兀爲之主。", "傑然鎮西南，羣嶺爭拱輔。", "吾知造物意，必以屏大府。", "清溪至其下，仰視勢飛舞。", "偉石如長人，堅立欲言語。", "捫蘿緣險磴，爛漫松竹古。", "中腰有危亭，前對紺壁舉。", "石竇落玉泉，泠泠四時雨。", "源生白雲間，顔色若粉乳。", "旱年或播灑，潤可足九土。", "奈何但泓澄，未爲應龍取。", "予方棄塵中，巖壑素自許。", "盤桓擇雄勝，至此快心膂。", "庶得耳目清，終甘死于虎。"]'),
('1e6b486c-f1cb-4377-8845-1cca498f6ba5','奉酬公素學士見招之作','蘇舜欽','宋','宋诗','song-poetry','','[]','人生交分恥苟合，貴以道義久可要。',384,'全唐诗/poet.song.18000.json','["人生交分恥苟合，貴以道義久可要。", "薄俗盈虛逐勢利，清風緜邈日已凋。", "長吟宇宙獨引領，浩浩萬古與我遥。", "安得此身有兩翅，颯然遠舉隨風飆。", "近逢公素我同好，厭憤偷俗常鬰陶。", "君方調官鎮京口，我以重罪廢本朝。", "身雖俱在大江外，不得會合煩相邀。", "秋風八月天地肅，千里明迴草木焦。", "夕霜慘烈氣節勁，激起壯思沖斗杓。", "豈如兒女但悲感，唧唧吟歎隨螳蜩。", "擬攀飛雲抱明月，欲踏海門觀怒濤。", "念君治所近不遠，江山蟠闢氣象豪。", "樓頭陰明變霞霧，檻下日夕鬭蜃蛟。", "便將一往刷滯悶，去興草茁不可薅。", "呼兒襥衣辦舟楫，一日百里豈憚勞。", "君方酒酣亦思我，奔墨紙上爲長謠。", "上言風物麗復壯，下述宴集樂且遨。", "意我羈愁正無賴，欲以此事相誇招。", "此篇筆絕墨未滲，我舟適到范老橋。", "古人千里有神會，以茲可信非相遼。", "倜然不以窮見棄，曠然不以位自驕。", "開緘朗詠毛髮竦，通夕噤痒睫不交。", "病膜誰將寶篦刮，痒背恰得仙人抓。", "長川奔渾走一氣，巨鎮截嶭上赤霄。"]'),
('a0ba8dd9-3d15-4d01-9ef9-ab37bdfb656f','遷居','蘇舜欽','宋','宋诗','song-poetry','','[]','前歲旅淮楚，去年還上都。',276,'全唐诗/poet.song.18000.json','["前歲旅淮楚，去年還上都。", "上都一歲內，前後七徙居。", "歲暮被重謫，狼狽來中吳。", "中吳未半歲，三次遷里閭。", "京師重騰移，長物動數車。", "江湖亦稍便，一舟樂有餘。", "破壞新器皿，散亡舊圖書。", "家人頗倦煩，行路亦歎呼。", "吾知人之生，天壤乃蘧廬。", "其間蹔寄寓，一世還須臾。", "縱遊極南北，所歷足自娛。", "猶恨苦濡滯，带動摧妻孥。", "安得出八極，浩與元氣俱。", "仰首羨日月，晨夕苦奔趨。", "二物本無情，亦爲氣所驅。", "況我有血肉，又生名利區。", "手足日不閑，在地無根株。", "流宕固宜矣，何必厭道塗。", "此身亦外物，安用傷羈孤。", "庸人所見狹，但以鄉井拘。", "屑屑寸粒食，何異雞在笯。", "擬隨犯斗槎，欲上浮海桴。", "寄語懷安者，嗟嗟爾何愚。"]'),
('ae542e68-bab3-41ca-9b2a-6bc0e774f1b5','遣悶','蘇舜欽','宋','宋诗','song-poetry','','[]','隆冬雪跨月，度日關門廬。',72,'全唐诗/poet.song.18000.json','["隆冬雪跨月，度日關門廬。", "乘昏氣慘烈，悲風吹江湖。", "白鵠翅翼傷，塌然困泥塗。", "不入鶬鶊羣，哀鳴憶雲衢。", "夕饑乏粒食，浩蕩天地俱。", "何時闢重陰，得見白日舒。"]'),
('abf1440e-cf1f-46fc-9ae5-4cf37b002f12','苦調','蘇舜欽','宋','宋诗','song-poetry','','[]','陰闇必有鬼，高明者惟天。',96,'全唐诗/poet.song.18000.json','["陰闇必有鬼，高明者惟天。", "鑒應未始忽，冥理有後先。", "姦兇喜欺罔，放意快目前。", "虎狼嚼生人，自適甘且鮮。", "烈士共劍起，忿髮如危絃。", "人理已不勝，神報豈泯然。", "驚呼徹上帝，灑血透九泉。", "捫舌不敢語，咄咄徒自憐。"]'),
('cc88cca2-32c7-4ecc-adaa-48d5e615f96f','若神棲心堂','蘇舜欽','宋','宋诗','song-poetry','','[]','予心充塞天壤間，豈以一物相拘關。',96,'全唐诗/poet.song.18000.json','["予心充塞天壤間，豈以一物相拘關。", "放然一物無不有，遂得此身相與閒。", "上人搆堂號棲心，不欲塵累相追攀。", "冷灰槀木極潰敗，雖有善迹輒自刪。", "予嘗浩然無所撓，與子異指亦往還。", "卷舒動靜固有道，期於達者誠非艱。"]'),
('d901b32f-30ac-4c1a-ad9c-699c03cbedd3','郡侯訪予于滄浪亭因而高會翌日以一章謝之','蘇舜欽','宋','宋诗','song-poetry','','[]','荒亭俗少遊，遷客心自愛。',156,'全唐诗/poet.song.18000.json','["荒亭俗少遊，遷客心自愛。", "繞亭植梧竹，私心亦有待。", "昨朝十騎來，䟃𧽼擁林外。", "水禽駭笳鼓，野老瞻車蓋。", "公餘喜靜境，賓至因高會。", "跋石已行厨，臨流聊褫带。", "優游鄙情通，放曠未禮殺。", "酒醇引易釂，肉美舉必嘬。", "千蹠恣食雞，二螯時把蟹。", "開顔閒善謔，傾耳得嘉話。", "暮夜歡未厭，裴回意將再。", "跋已見懵騰，跨鞍極倒載。", "明日尚狂酲，嘉貺不遑拜。"]'),
('fda39c08-0424-4802-8d9d-b3a4eaa8ada0','送閔永言赴彭門','蘇舜欽','宋','宋诗','song-poetry','','[]','鄙性背時向，處世介且迂。',288,'全唐诗/poet.song.18000.json','["鄙性背時向，處世介且迂。", "自固以爲節，人皆指爲愚。", "少年宦京邑，與眾頗異涂。", "一朝被放棄，漂然落江湖。", "江湖信美矣，心迹抑更孤。", "永言金閨彥，器識當世無。", "機發弦上矢，辯走盤中珠。", "高風樂溪山，恥與勢利趨。", "殊科二十年，不肯仕京都。", "顧我窮悴者，一笑情相於。", "日日奉杯宴，但覺懷抱攄。", "瓊琚照坐席，內顧瓦礫粗。", "未飲心自醉，相對氣已舒。", "得忘羈旅憂，蓋以道義俱。", "雲間宿古寺，花下招歌姝。", "勝境尋已徧，賞心未嘗孤。", "璽書趣赴治，候吏擁舳艫。", "秋風卷在旆，喧喧指東徐。", "郊亭對別酒，我獨增悲吁。", "人生大塊間，氣類有萬殊。", "賢愚各有合，惟予邈無徒。", "君子誤見知，交契若勘符。", "一旦又暌索，千里成闊疎。", "期君早自奮，佐時發雄圖。"]'),
('cd73eacc-4ada-469e-b23b-7577ed90f464','寄題豐樂亭','蘇舜欽','宋','宋诗','song-poetry','','[]','神物藏勝地，深林隱蒼峯。',156,'全唐诗/poet.song.18000.json','["神物藏勝地，深林隱蒼峯。", "威夷渡淺嶺，愛此泉一鍾。", "古今未見賞，荒然草苔封。", "公來闢一徑，疏鑿隨指蹤。", "揮洗落塵慮，甘涼灑煩胸。", "搆亭於其間，四面開軒墉。", "名之豐樂者，此意實在農。", "使君何所樂，所樂惟年豐。", "年豐訟訴息，可使風化醲。", "遊此乃可樂，豈徒悅賓從。", "野老共歌呼，山禽相迎逢。", "把酒謝白雲，援琴對孤松。", "境清豈俗到，世路徒衝衝。"]'),
('8dc1a7b7-09c3-4fa5-874b-1d5967927e1d','夏熱晝寢感詠','蘇舜欽','宋','宋诗','song-poetry','','[]','盛夏日苦永，解带坐小軒。',288,'全唐诗/poet.song.18000.json','["盛夏日苦永，解带坐小軒。", "對案不能食，揮汗白雨翻。", "軋軋過午景，宛轉無由昏。", "偃卧一榻上，既覺復夢魂。", "恬然世慮寂，時被蒼蠅喧。", "睡味勝仙去，忽怳難具論。", "晨事如隔日，半雜夢寐言。", "人生貴壯健，及時取榮尊。", "夏禹惜寸陰，窮治萬水源。", "櫛沐風雨中，子哭不入門。", "況復庸下者，不出强趨奔。", "奈何耽晝寢，嬾惰守壞垣。", "念昔年少時，奮迅期孤騫。", "筆下驅古風，直趣聖所存。", "山子逐雷電，安肯服短轅。", "便將决渤澥，出手洗乾坤。", "文章竟誤身，大議誰周爰。", "捽首下牢獄，殗殗如孤豚。", "法吏使除籍，其過祗一飱。", "賓朋四散逐，投竄向僻藩。", "九虎口牙惡，便欲膏其蹯。", "上賴天子明，不使鉗且髠。", "此身自流浪，豈能濟元元。", "天下無所歸，泛舟旅江邨。"]'),
('e886c19a-f4b5-4285-aa80-83814cd3882e','哭師魯','蘇舜欽','宋','宋诗','song-poetry','','[]','前年子漸死，予哭大江頭。',288,'全唐诗/poet.song.18000.json','["前年子漸死，予哭大江頭。", "今年師魯死，予方旅長洲。", "初聞尚疑惑，涕淚已不收。", "舉杯欲向口，荆棘生咽喉。", "憶初定交時，後前穆與歐。", "君顔白如霜，君語清如流。", "予年又甚少，學古眾所羞。", "君欲舉拔萃，聲耦日抉搜。", "不鄙吾學異，推尊謂前修。", "今踰二十年，迹遠心甚稠。", "後會國南門，夜談雪滿樓。", "青燈照素髮，酒闌氣益遒。", "昨君握兵柄，節制關外侯。", "予才入冊府，俄作中都囚。", "飛章立辨雪，危言動前旒。", "時雖不見省，凜凜壓眾媮。", "旋聞君下獄，六月送渭州。", "渭州舊治所，昔擁萬貔貅。", "堂中坐玉帳，堂下森蛇矛。", "令嚴山石裂，恩煦春色浮。", "釁生無根芽，眾言起愆尤。", "返來入狴犴，吏對安可酬。", "法官巧追拍，刺骨不肯抽。", "削秩貶漢東，驅迫日置郵。"]'),
('38cd9d83-1641-483b-963b-8921f1627e05','和永叔琅邪山庶子泉陽冰石篆詩','蘇舜欽','宋','宋诗','song-poetry','','[]','一氣破散萬事起，獨有篆籀含其真。',240,'全唐诗/poet.song.18000.json','["一氣破散萬事起，獨有篆籀含其真。", "周鼓秦山壞已久，下至唐室始有人。", "宗臣轉注得天法，質雖渾厚氣乃振。", "人間所存十數處，豐疎異體世共珍。", "其中琅邪石泉記，比之他法殊不倫。", "鐵鎖關連玉鉤壯，曲處力可持萬鈞。", "復疑蛟虯植爪角，隱入翠壁蟠未伸。", "近來欲眼苦不賞，惟有風月時相親。", "紫微仙人謫此守，此地勝絕舊喜聞。", "公餘往觀領賓從，獵獵畫隼摇青春。", "遠休車騎步泉側，酌泉愛篆移朝昏。", "揮弄潺湲玩點畫，情通恍惚疑前身。", "作詩緘本遠相寄，邀我共賦意甚勤。", "昨承見教久閣筆，壓以大句尤難文。", "高風勝事日傾倒，安得身寄西飛雲。"]'),
('0529c73a-088f-42a1-9fc9-d24103f268e3','答章傅','蘇舜欽','宋','宋诗','song-poetry','','[]','廢官旅吳門，迹與世俗掃。',180,'全唐诗/poet.song.18000.json','["廢官旅吳門，迹與世俗掃。", "構亭滄浪間，筑室喬樹杪。", "窮徑交聖賢，放意狎魚鳥。", "志氣內自充，藜藿日亦飽。", "不圖名利場，有士同所好。", "南閩章其氏，傅名字傳道。", "清晨闖予門，疎爽見姿表。", "大篇隨自出，爛熳風力老。", "安敢當所褒，讀之俗驚倒。", "開軒延與語，指亦有深到。", "半生蹋京塵，識子恨不早。", "扶疎珊瑚枝，本不自雕巧。", "當珍玉府中，何故委衰草。", "秋風還故鄉，無或歎枯槁。", "貴富烏足論，令名當自保。"]'),
('62cb9885-5a66-4990-aea5-df9e60cdca59','遊山','蘇舜欽','宋','宋诗','song-poetry','','[]','上春遊南峯，出自閶扉西。',288,'全唐诗/poet.song.18000.json','["上春遊南峯，出自閶扉西。", "崎嶇緣田塍，時又涉狹磎。", "午初至峯下，先讀爛古碑。", "僧廬頗新鮮，丹青見朝曦。", "云昔支公居，石迹有馬蹄。", "踰嶺到天平，上觀石屋危。", "蒼壁瀉白泉，對之已忘疲。", "西巖列窗戶，玲瓏漏斜暉。", "嵌然似餖飣，人力安可施。", "朝餐下木瀆，市物俗所宜。", "琴臺昔嘗遊，回首憶舊題。", "南向又渡嶺，盤屈麋鹿蹊。", "摺身趨寶華，未到聞法鼙。", "松間見廣路，平如隱金鎚。", "寺壓兩山脚，三面張屏幃。", "夜闌宿虛堂，清甚無夢思。", "西南登堯峯，俗云堯所基。", "洪川不能沒，上有萬眾棲。", "中道舍籃輿，從者亦汗衣。", "關陸巧步趨，健馬莫可追。", "自傷幹軀大，兩股酸不隨。", "巖雨灑磴滑，惟賴枯筇支。", "四顧物象殊，雖困强自持。", "竹木互支撐，小閣架險梯。"]'),
('27b24d85-924e-4868-ac15-bcd65e77a606','寒夜','蘇舜欽','宋','宋诗','song-poetry','','[]','九河巨流凍長山，山高微黯石色頑。',112,'全唐诗/poet.song.18000.json','["九河巨流凍長山，山高微黯石色頑。", "沙籠如煙吐朱灣，中天撾鼓雲垂關。", "壺炙不溫乳烏死，城上琴聲愁九子。", "羅暮翻風花滿波，玉麈灑窗濕明綺。", "獸角消紅犀鳳乾，縷生篆字香盤盤。", "坐聆翰音拂南極，馳念疆場中已酸。", "欲决沈雲叫陰帝，虜滅不使天下寒。"]'),
('5566eccd-9f9a-4c64-b0d5-629cc3caacb3','送施秀才','蘇舜欽','宋','宋诗','song-poetry','','[]','賤生罹兇喪，日與死亡逼。',144,'全唐诗/poet.song.18000.json','["賤生罹兇喪，日與死亡逼。", "羈孤困猜嫌，動步畏蛇蜮。", "之子脫俗情，平生未相識。", "足繭千里來，顧我喜顔色。", "衣裘風霜凋，顔髮塵土蝕。", "開席揖之坐，意勤語腷塞。", "徐徐動辭氣，突兀露胸臆。", "紺囊出文章，發覆見寶璧。", "自羞無所有，曷以報相德。", "告行東風前，花草正狼籍。", "又無一尊酒，澆沃慰遠客。", "扁舟下長淮，企立空歎息。"]'),
('26d841ae-c4ad-46fe-b649-6f1fe8a19b04','送韓三子華還家','蘇舜欽','宋','宋诗','song-poetry','','[]','人在天壤間，共爲氣軀逐。',240,'全唐诗/poet.song.18000.json','["人在天壤間，共爲氣軀逐。", "歲月自崩奔，冉冉若轉轂。", "榮樂隨雲煙，凋零共草木。", "亨屯固常物，達者安可速。", "奈何此軀骸，未免混世俗。", "前年奔大兇，況復墮手足。", "零丁旅山陽，逐熟聚衰族。", "相逢眼盡白，閉戶甘退縮。", "左丞鎮景亳，相去路重復。", "數遣令子來，十里弔荼毒。", "子華勇此行，東下甚匍匐。", "入門未及言，相向且慟哭。", "嗟我顔色枯，鬚蒼鬢又禿。", "相別始踰年，世事何反覆。", "晤言出世表，但覺白日速。", "勘書春雨靜，煮藥夜火續。", "襟懷兩澄澹，炯炯抱明玉。", "時苦外物喧，又嗟別期促。", "和風送歸帆，盎動淮氣綠。", "早寄別後篇，微吟慰孤獨。"]'),
('f74ec21d-e831-44d8-b196-d1c48e3390cb','觀放牐','蘇舜欽','宋','宋诗','song-poetry','','[]','沈沈滄淮口，植木限眾流。',180,'全唐诗/poet.song.18000.json','["沈沈滄淮口，植木限眾流。", "啟閉固有時，出納千萬舟。", "眷予懷抱昏，羈別相牽鉤。", "觀此巨派注，頗覺滯悶瘳。", "喧豗怒霆起，始駭久不收。", "既前目眩轉，足縮不敢留。", "朔雪下噴薄，散爲白霧浮。", "上懸赤油幕，旁斷縹玉旒。", "恐激地軸轉，人有魚鼈憂。", "驚嗟勢力壯，孰謂此物柔。", "吾思作至監，實以處上游。", "又欲接之口，沃蕩胸中愁。", "俄然漸枯涸，哮爾空泥溝。", "渟滀既因人，開洩豈自由。", "立間見底裏，咄哉爲爾羞。"]'),
('ba5e125e-92fd-4ae2-a8bc-ebf8ac7ee717','金山寺','蘇舜欽','宋','宋诗','song-poetry','','[]','孤峯湧滄江，突兀臺殿積。',180,'全唐诗/poet.song.18000.json','["孤峯湧滄江，突兀臺殿積。", "驚波四面起，日夜走霹靂。", "陰壑滀風雲，陽厓產金碧。", "離披萬年樹，根抱太古石。", "修廊圍峻閣，窈窕壓山脊。", "寶像浮海來，珠纓冷光滴。", "叩闌見黿鼉，揚首意自得。", "偃蹇互出沒，日此飽餘食。", "又有翠羽禽，羣飛喜賓客。", "口銜紺蔕花，近我若相識。", "開軒心曠絕，上下無異色。", "氣象特清壯，所覽輒快適。", "予心本高灑，誤爲塵土隔。", "不知人間世，有此物外迹。", "落日將登舟，低回空自惜。"]'),
('0e170a59-9a89-49d6-95a1-3877b5e67859','九月五日夜出盤門泊於湖間偶成密會坐上書吳黄尉','蘇舜欽','宋','宋诗','song-poetry','','[]','紺油幙見黄金鉤，貝璣磊落澄不流。',192,'全唐诗/poet.song.18000.json','["紺油幙見黄金鉤，貝璣磊落澄不流。", "紛紛媚影動波上，的的遠勢橫沙頭。", "前山漸昏漁唱息，唯有疎葦吟窮秋。", "予方弭檝對此景，時欲乘興長夜遊。", "青蛾蕩槳忽遠至，雖有雅約猶嚬羞。", "綵舟鮮明四窗闢，蘭酎辛滑嘉賓留。", "歌餘清冽貫眾耳，笑動姿采生香㡚。", "玉盤膾鱸光一色，飣簇殽核隨所搜。", "河斜參倒氣逾治，我起飲子子必酬。", "共知此會不易得，邂逅得此難再求。", "區區才知自勞役，擾擾塵俗多悲憂。", "已醉更歌更起舞，明日分散空離愁。"]'),
('1e5e9c71-6016-45ec-aff1-6d4069670c12','送張統尉嘉禾','蘇舜欽','宋','宋诗','song-poetry','','[]','濯濯桂枝郎，尉邑上攜李。',48,'全唐诗/poet.song.18000.json','["濯濯桂枝郎，尉邑上攜李。", "青衫未足榮，蘭衣應自喜。", "威聲入萑蒲，吟思發山水。", "美才仕云初，令聞當日起。"]'),
('6f94814a-4c0d-4605-9cb6-dc4e6b99db3f','秋夜','蘇舜欽','宋','宋诗','song-poetry','','[]','新秋積雨後，夜聞蚯蚓聲。',108,'全唐诗/poet.song.18000.json','["新秋積雨後，夜聞蚯蚓聲。", "似爭絡緯緐，不讓蟋蟀清。", "嗟爾微陋物，身與土壤并。", "藐然本無心，天時使之鳴。", "空庭雜槀木，亦能感人情。", "老蛟蟄污泥，寂默不自驚。", "一旦走霹靂，飛雨洗八紘。", "幽蟠孰可聞，自有濟物誠。", "歲若弗大旱，此志豈妄行。"]'),
('95a8595f-4d1a-4149-92bf-21099ff134f0','寄題周源家亭','蘇舜欽','宋','宋诗','song-poetry','','[]','君家有虛亭，跨澗復面山。',60,'全唐诗/poet.song.18000.json','["君家有虛亭，跨澗復面山。", "泉聲碎環玦，清繞窗戶間。", "潛鱗俯自釣，佳樹坐可攀。", "我思醉其上，與子開塵顔。", "微吟對一枰，放此白日閒。"]'),
('9e1ce822-55a3-4379-b0d8-7fde5f754e6f','黄雍於西安修水之側起佚老亭以奉親','蘇舜欽','宋','宋诗','song-poetry','','[]','修水崩騰落雲端，傾入羣山自縈轉。',194,'全唐诗/poet.song.18000.json','["修水崩騰落雲端，傾入羣山自縈轉。", "山回水抱三百里，邑號西安俯千磵。", "四時夾磵花濛濛，數步行人不相見。", "但聞千珂萬馬橫陣來，石激驚湍自相濺。", "忽然瀰漫爲平川，遠近人家壓清淺。", "其間有亭號佚老，山水之間爲勝選。", "黄氏有子樂其親，締葺之勤由富善。", "蓋憂高年厭家事，力營此地欲自遣。", "親意雖知風物嘉，豈若有子常在眼。", "君胡飄飄事遠遊，手龜面黎兩足趼。", "故鄉不到已踰年，又非跼蹐牽仕宦。", "何如輕舟早還家，日對白雲奉遊宴。"]'),
('82606e54-865a-4af5-9c6f-aa31163430f6','送黄莘還家','蘇舜欽','宋','宋诗','song-poetry','','[]','東風摇江波，碧草日夜芳。',132,'全唐诗/poet.song.18000.json','["東風摇江波，碧草日夜芳。", "藹藹春物歸，遊子思故鄉。", "黄生士林華，志業收精剛。", "步虎南山隈，氣立人獸旁。", "不步受羈轡，但欲插翅翔。", "顧亦念所親，歸心劇風檣。", "想當舍檝初，喜氣充門牆。", "晨昏奉顔色，以時薦豆觴。", "雖享萬鍾祿，此樂不可償。", "予家白日下，偶來戀滄浪。", "因君江上別，撩我歸興長。"]'),
('a76e93d2-72c9-4569-bc42-b13f676bbc3e','和菱磎石歌','蘇舜欽','宋','宋诗','song-poetry','','[]','滁州信至詫雙石，云初得自菱水濱。',304,'全唐诗/poet.song.18000.json','["滁州信至詫雙石，云初得自菱水濱。", "長篇稱夸語險絕，欲使來者不復言。", "畫圖突兀亦頗怪，張之屋壁驚心魂。", "麒麟才生頭角異，混沌雖死竅鑿存。", "琅邪之郡偏且僻，得石固可駭眾觀。", "予嘗飛帆入震澤，窮探異境登龜黿。", "居民百戶石爲業，日夜采琢山不貧。", "山前森列戰白浪，猶似萬百鐵馬羣。", "雨昏浪打歲月古，千株萬穴僵復奔。", "自嗟才力本衰弱，安敢抵敵爲之文。", "況茲出產極易致，鄉俗見慣不甚尊。", "彼以至少合貴重，胡爲久棄如隱淪。", "偶逢積識見獎拔，眾目今乃稱奇珍。", "百人擁持大車載，城市觀走風濤翻。", "立於新亭面幽谷，共爲澡刷泥沙痕。", "凉泉下照嘉樹陰，翠影澄澹留煙雲。", "褒以篇章繪縑素，積歲汨沒一旦伸。", "苟非高賢獨賞激，終古棄卧於窮津。", "世人愛憎逐興廢，使我吟歎傷精神。"]'),
('ff504959-c845-4efb-809a-f1e733adb361','頂破二山詩','蘇舜欽','宋','宋诗','song-poetry','','[]','此邑有頂山，下潛子母虯。',168,'全唐诗/poet.song.18000.json','["此邑有頂山，下潛子母虯。", "其子去爲雨，以救鄉人憂。", "前擘窮峯開，化出百丈湫。", "後因號破山，致祠獻庶羞。", "歲來省其母，風雹六月秋。", "煙雲騰蹋去，不復經月留。", "邑民賴其靈，雖旱歲有收。", "因成兩佛宇，幽邃號勝遊。", "磵泉走鸞車，松桂擁石樓。", "夜堂人噤滲，陰壁風颼飀。", "近年返暴雨，頗亦傷田疇。", "老農務祈禱，梵唄日不休。", "常爲釋徒利，乃作生民讎。", "嗚呼二虯者，其說何悠悠。"]'),
('01d136f1-8732-4d75-ae33-3ae9868cf15e','永叔石月屏圖','蘇舜欽','宋','宋诗','song-poetry','','[]','日月行上天，下照萬物根。',342,'全唐诗/poet.song.18000.json','["日月行上天，下照萬物根。", "向之生榮背則死，故爲萬物生死門。", "東西兩交征，晝夜不蹔停。", "胡爲虢山石，留此皎月痕常存。", "桂樹散疎陰，有若圖畫成。", "永叔得之不能曉，作歌使我窮其原。", "或疑月入此石中，分此二曜三處明。", "或云蟾兔好溪山，逃遁出月不可關。", "浮波穴石恣所樂，嫦娥孤坐初不覺。", "玉杵夜無聲，無物來擣藥。", "嫦娥驚推輪，下天自尋捉。", "繞地掀江蹋山岳，二物驚奔不復見。", "留此玉輪之迹在青壁，風雨不可剝。", "此說亦詭異，予知未精確。", "物有無情自相感，不間幽微與高邈。", "老蚌向月月降胎，海犀望星星入角。", "彤霞爍石變靈砂，白虹貫巖生美璞。", "此乃西山石，久爲月照著。", "歲久光不滅，遂有團團月。", "寒輝籠籠出輕霧，坐對不復嗟殘缺。", "蝦蟇縱汝惡觜吻，可能食此清光沒。", "玉川子若在，見必喜不徹。", "此雖隱石中，時有靈光發。", "土怪山鬼不敢近，照之僵仆肝腦裂。"]'),
('6242ee25-067c-46d9-8aa9-bbddf2cc5f92','演化琴德素高昔嘗供奉先帝聞予所藏寶琴而揮弄不忍去因爲作歌以寫其意云','蘇舜欽','宋','宋诗','song-poetry','','[]','雙塔老師古突兀，索我瑶琴一揮拂。',226,'全唐诗/poet.song.18000.json','["雙塔老師古突兀，索我瑶琴一揮拂。", "風吹仙籟下虛空，滿坐沈沈竦毛骨。", "按抑不知聲在指，指自不知心所起。", "節奏可盡韻可收，時於疎澹之中寄深意。", "意深味薄我獨知，陶然直到羲皇世。", "曲終瞑目師不言，忽言昔常奉至尊。", "祥符天子政多暇，詔求絕藝傳中閽。", "紫宸仗退霜日紅，隨鞭入對蓬萊宮。", "平戎一弄沃舜聰，貂璫壁立亦動容。", "紫蘭之袍出禁府，聲華一日千門通。", "今來老病卧澤國，賞音不遇前事空。", "一雙玉鶴天上飛，人間但見枯死桐。", "幸逢寶器愜心手，因聲感舊涕灑胸。", "顧我踟躕不忍去，將行更欲留悲風。"]'),
('511f69b1-497f-45a0-b9b8-fb7290909c15','寄王幾道同年','蘇舜欽','宋','宋诗','song-poetry','','[]','新安道中物色佳，山昏雲澹晚雨斜。',64,'全唐诗/poet.song.18000.json','["新安道中物色佳，山昏雲澹晚雨斜。", "眼看好景嬾下馬，心隨流水先還家。", "步頭浴鳧暖出沒，石側老松寒交加。", "懷君覽古意萬狀，獨轉澗口吟幽花。"]'),
('8dc0d74d-ff18-431d-809f-a8c85733f6ee','丙子仲冬紫閣寺聯句','蘇舜欽','宋','宋诗','song-poetry','','[]','白石太古水，蒼厓六月冰。',288,'全唐诗/poet.song.18000.json','["白石太古水，蒼厓六月冰。", "昏明咫尺變，身世逗留增。", "橋與飛霞亂，人間獨鳥升。", "風泉冷相搏，樓閣暮逾澄。", "反覆青冥上，躋攀赤日稜。", "唄音充別壑，塔影弔寒藤。", "仙掌挂太一，佛壇依古層。", "巖喧聞鬭虎，臺靜下饑鷹。", "晴檻通年雨，濃蘿四面罾。", "日光平午見，霧氣半天蒸。", "潭碧寒疑裂，鐘清遠自凝。", "陽陂冬聚筍，陰壁夏垂繒。", "有客饒佳思，高吟出遠凭。", "雄心翻青裏，遠目著軒騰。", "岑寂來清夜，沈冥接定僧。", "宿猿深更杳，落木靜相仍。", "松竹高無奈，煙嵐翠不勝。", "甘酸收脫實，坳隩布清塍。", "北野才沈著，南天更勃興。", "恣睢超一氣，黤黕起孤鵬。", "並澗寒堪摘，看雲重欲崩。", "行中向背失，呼處下高應。", "庭樹巢金爵，樵兒弄玉繩。", "斷香浮缺月，古像守昏燈。"]'),
('6293251f-50cc-487d-b0e7-51a6bc5e4770','水輪聯句','蘇舜欽','宋','宋诗','song-poetry','','[]','痛矣真源喪，紛紜物象來。',216,'全唐诗/poet.song.18000.json','["痛矣真源喪，紛紜物象來。", "水輪今若此，此事亦宜哉。", "上下車交輻，周旋斗轉魁。", "咸淵日微墮，仙窟月初開。", "旁柅從爲用，垂絙重亦回。", "枘多初不曉，機密暗相該。", "圃外滄浪洩，庭間霹靂摧。", "玉飛千仞表，纓挂九泉隈。", "翻覆殊難定，牽連巧自媒。", "建瓴今比速，抱甕此相哀。", "平眡曾無覺，深窺遂可猜。", "團團釋子壁，軋軋雁王臺。", "解見陶埏運，寧觀將轂推。", "造端原有發，汲用始知材。", "本異道家意，定遭怡士咍。", "轉圓非雅具，欹器有深災。", "持滿忘前監，相傾自下催。", "流風無以復，視此一裴回。"]');
